const RECIPES = [{"slug": "7-can-chicken-taco-soup-serves-6", "title": "7 Can Chicken Taco Soup", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-02-24", "ingredients": ["1 can black beans, drained and rinsed", "1 can pinto beans, drained and rinsed", "1 can petite diced tomatoes (do not drain)", "1 can sweet corn, drained", "1 deli oven roasted chicken, deboned and shredded", "1 10 oz can green enchilada sauce", "14 oz chicken broth", "1 packet taco seasoning", "½ tsp ground cumin", "½ tsp chili powder", "½ tsp garlic powder"], "instructions": "Add all the ingredients into a large saucepot and bring to a boil.\nSimmer until ready to serve.", "image": "img/7-can-chicken-taco-soup-serves-6.jpg"}, {"slug": "a-slow-cooker-thanksgiving-serves-6", "title": "A Slow Cooker Thanksgiving", "serves": "Serves 6", "category": "Crockpot", "date": "2022-03-01", "ingredients": ["5 cups dried seasoned bread cubes", "¼ cup instant stuffing mix", "1 cup sliced fresh mushrooms", "½ cup chopped onion", "½ cup chopped celery", "2 cans of diced water chestnuts", "2 apples, peeled, cored and chopped (about 1” pieces)", "¼ cup extra virgin olive oil", "1tsp poultry seasoning", "½ tsp salt", "¼ tsp dried sage", "2 apples, peeled, cored and diced", "¼ tsp black pepper", "1(12oz) jar turkey gravy", "1(10.75oz) can cream of mushroom soup", "½ (16oz) jellied cranberry sauce", "4 skinless boneless chicken breasts, cubed"], "instructions": "Toss together 2 ½ cups of bread cubes and 2tbsp of instant stuffing mix and set aside.\nIn a large bowl mix the remaining bread cubes, instant stuffing mix, mushrooms, onion, celery, olive oil, poultry seasoning, salt, sage, pepper, gravy, soup, apples, water chestnuts and cranberry sauce.\nPlace the reserved bread cubes and stuffing mix in the bottom of a slow cooker. Add the chicken evenly over the bread cubes, and top with the vegetable, bread cube and gravy mixture.\nCover and cook on low for 4-6 hours.\nServe with biscuits, gravy and extra cranberry sauce.", "image": "https://static.wixstatic.com/media/75d545_cec5dc514c58431883b05f3f09df4bff~mv2.jpg"}, {"slug": "all-purpose-gravy-makes-4-5-cups", "title": "All Purpose Gravy", "serves": "Makes 4.5 cups", "category": "Gravy, Sauce & Dressing", "date": "2022-02-24", "ingredients": ["½ cup fat", "½ cup flour", "enough pan juices and chicken or beef stock to make 4 cups", "½ cup heavy cream", "salt & pepper to taste"], "instructions": "Add the flour to the fat until blended. Stir in the pan juices slowly; cook and stir the gravy until smooth. Simmer 5 minutes.\nAdd the cream and season to taste.", "image": "img/all-purpose-gravy-makes-4-5-cups.jpg"}, {"slug": "almond-crusted-flounder-serve-4", "title": "Almond Crusted Flounder", "serves": "Serve 4", "category": "Seafood", "date": "2022-02-25", "ingredients": ["4 Flounder fillets", "2 eggs", "1 tsp lemon pepper", "1 tsp garlic pepper", "1 cup Almond meal", "1 cup Panko", "1 cup freshly grated Parmesan", "½ cup flour", "3 tbsp butter", "3 tbsp vegetable oil", "salt to taste", "2 lemons, cut into wedges", "3 tbsp chopped fresh parsley", "**Preheat the oven to 350°**"], "instructions": "Beat the eggs, lemon pepper and garlic pepper in a shallow bowl and set aside.\nIn a shallow pie plate or baking dish, combine the almond meal, Panko and Parmesan cheese and set aside.\nPlace the flour in another shallow bowl.\nMelt the butter with the vegetable oil in a large skillet over medium high heat.\nDredge the flounder through the flour and shake off the excess. Dip the flounder in the egg wash and then coat with the almond mixture.\nCook just until golden on both sides (add more oil as needed) and remove to a baking sheet.\nBake in the oven for about 10-15 minutes to finish. Garnish with the parsley and serve with lemon wedges.", "image": "img/almond-crusted-flounder-serve-4.jpg"}, {"slug": "almond-lemon-crusted-halibut-with-fresh-spinach-serves-4", "title": "Almond & Lemon Crusted Halibut with Fresh Spinach", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-24", "ingredients": ["Zest and juice of 1 lemon, divided", "½ cup sliced almonds", "1 tbsp fresh dill, finely chopped", "1 tbsp plus 2 tsp extra virgin olive oil", "1 tsp kosher salt", "freshly ground pepper, to taste", "4 halibut filets (about 1 ¼lb in total)", "4 tsp Dijon mustard", "2 cloves garlic, minced", "1lb fresh baby spinach", "lemon wedges", "**Preheat the oven to 400°**"], "instructions": "Coat a foil cookie sheet with olive oil spray.\nIn a medium bowl combine the zest, almonds, dill 1 tbsp olive oil, ½ tsp salt and pepper.\nPlace the fish on the prepared baking dish and spread each filet with 1 tsp of Dijon mustard.\nDivide the almond mixture among the 4 filets and press onto to the top of each.\nBake the fish until opaque in the center. About 10 minutes depending on the size of each filet.\nWhile the fish is cooking, heat the remaining olive oil in a lrge skillet and add the garlic and cook until fragrant. Add the spinach and the remaining salt. Season with pepper to taste. Cook until just wilted.", "image": "img/almond-lemon-crusted-halibut-with-fresh-spinach-serves-4.jpg"}, {"slug": "antipasto-pasta-salad-serves-16", "title": "Antipasto Pasta Salad", "serves": "Serves 16", "category": "Salads", "date": "2022-02-25", "ingredients": ["16oz Penne", "pasta", "3 cups grape tomatoes, halved", "½ lb provolone cheese, cubed", "½ lb dilusso salami, cubed", "¼ lb sliced pepperoni, cut in halves", "1 large green pepper, cut into 1” pieces", "1 10oz can black olives, drained", "1 4oz jar pimentos, drained", "1 8oz bottle Newman’s Own Italian dressing"], "instructions": "Cook the pasta according to the package directions for al dente. Drain and rinse with cold water.\nIn a large salad bowl, combine the pasta with the next 7 ingredients. Add the salad dressing and toss.", "image": "https://static.wixstatic.com/media/75d545_b2325a6081ff40f5849c05b40bb2656f~mv2.jpg"}, {"slug": "apple-and-herb-stuffing-makes-2-qts", "title": "Apple and Herb Stuffing", "serves": "Makes 2 ½ qts", "category": "Breads & Stuffings", "date": "2022-02-25", "ingredients": ["2 cup diced celery", "1 ½ cup diced onion", "½ cup butter", "1 ¾ cup hot water", "1 tbsp instant chicken bouillon", "12 cups dry bread cubes", "3 cups coarsely chopped apples, peeled and cored", "1 cup toasted slivered almonds", "1 tbsp chopped fresh parsley", "2 tbsp poultry seasoning"], "instructions": "In a large skillet cook the celery and onion in butter until tender. Add the water and bouillon. Cook until the bouillon dissolves.\nIn a large bowl combine the remaining ingredients and the bouillon mixture. Mix well. Stuff the turkey.\nStuffing may be baked in a greased baking dish at 350° for 35 minutes.", "image": "img/apple-and-herb-stuffing-makes-2-qts.jpg"}, {"slug": "apple-bake-serves-4-6", "title": "Apple Bake", "serves": "Serves 4-6", "category": "Desserts", "date": "2022-02-25", "ingredients": ["Ingredients", "2 packs cinnamon roll dough with icing", "4 eggs", "½ cup milk", "1 tablespoon cinnamon", "1 teaspoon vanilla extract", "2 tablespoons butter", "2 granny smith apples, diced", "1 cup brown sugar, packed", "Vanilla ice cream", "1. Preheat oven to 375°C"], "instructions": "2. Cut the cinnamon roll dough into 3 even strips, then cut those strip in 3 pieces, making 9 pieces total per cinnamon roll. Set aside the icing.\n3. In a medium bowl, combine eggs, milk, cinnamon, and extract, stirring until smooth. Set aside.\n4. In a pan over medium heat, combine butter, apples, and brown sugar, cooking until sugar starts to caramelize, about 10 minutes. Remove from heat.\n5. Sprinkle the cinnamon roll dough pieces evenly in a 9x9 baking tray. Pour the egg mixture on top, followed by the apples. Drizzle the reserved icing on top.\n6. Bake for 25-30 minutes, until golden brown. 7. Serve with ice cream!", "image": "img/apple-bake-serves-4-6.jpg"}, {"slug": "apple-brownies-makes-12-bars", "title": "Apple Brownies", "serves": "Makes 12 bars", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 stick salted butter, melted and cooled", "1 cup flour", "1 tsp cinnamon", "½ tsp baking powder", "½ tsp salt", "¼ tsp baking soda", "1 cup sugar", "1 large egg", "1 tsp vanilla", "½ tsp nutmeg", "½ cup chopped walnuts", "2 large apples, peeled, cored and chopped", "**Topping**", "3 tbsp chilled butter", "1/3 cup brown sugar", "½ tsp cinnamon", "3 tbsp flour"], "instructions": "Preheat the oven to 350°\nButter an 8x11 baking dish.\nIn a medium bowl combine the flour, cinnamon, nutmeg, baking powder, salt and baking soda.\nIn another bowl beat the butter, sugar and egg with an electric mixer until pale (about 2 minutes). Stir in the vanilla.\nAdd the apples and the walnuts to the flour mixture. Mix in the butter and sugar mixture. Combine well.\nSpread the batter in the prepared dish.\nIn a small bowl combine the topping ingredients until crumbly and sprinkle on to of the brownie batter.\nBake for about 40 minutes or until golden brown and slightly firm in the center.", "image": "img/apple-brownies-makes-12-bars.jpg"}, {"slug": "apple-cake-12-15-servings", "title": "Apple Cake 12-15 servings", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 ½ cup chopped pecans", "½ cup butter, melted", "2 cups sugar", "2 large eggs", "1 tsp vanilla", "2 cups flour", "2 tsp cinnamon", "1 tsp baking soda", "1 tsp salt", "2 1/2lb granny smith apples (about 4 large)", "Cream Cheese Frosting"], "instructions": "**Preheat the oven to 350°**\nLightly grease a 13 x9 glass baking dish and set aside.\nBake the pecans in a single layer on a cookie sheet for 5-7 minutes, stirring halfway through.\nIn a medium bowl combine the butter, sugar, eggs and vanilla.\nIn a large bowl combine the flour, cinnamon, baking soda and salt. Add the butter mixture. Mix well.\nPeel the apples and cut into 1/4\" wedges. Add to the flour and butter mixture. Add 1 cup of the pecans. (the batter will be very thick)\nSpread the batter in the prepared baking dish and bake for 45 minutes or until a wooden toothpick inserted in the center comes out clean. Cool completely.\nSpread the frosting over the top of the cake and sprinkle with the remaining pecans.", "image": "https://static.wixstatic.com/media/75d545_92657c7d8bf94138ac6d20552c7d96f4~mv2.jpg"}, {"slug": "apple-crisp", "title": "Apple Crisp", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["6 cup thinly sliced, peeled apples", "1/3 cup sugar", "1tsp cinnamon", "½ tsp salt", "2 tbsp butter"], "instructions": "Topping:\n¾ cup sugar\n½ cup flour\n1/3 cup butter, firm\nPreheat the oven to 375°.\nMix the apples, 1/3 cup sugar, cinnamon, salt and melted butter. Place in a greased 8” baking dish and set aside.\nIn a medium bowl, combine ¾ cup sugar and flour. Cut in the butter until crumbly. Sprinkle over the apples and bake for 45 minutes.\nServe warm with vanilla ice cream.", "image": "img/apple-crisp.jpg"}, {"slug": "arugula-and-fennel-salad-serves-4", "title": "Arugula and Fennel Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-25", "ingredients": ["5 oz Arugula", "1 small Fennel bulb, cored and thinly sliced", "2 tbsp extra virgin olive oil", "1 tsp lemon zest", "2 tbsp freshly squeezed lemon juice", "¼ tsp salt", "freshly ground black pepper, to taste", "Freshly shaved Parmesan cheese"], "instructions": "In a large bowl, combine the arugula and fennel and toss.\nIn a small bowl combine the olive oil, lemon zest, lemon juice, salt and pepper. Whisk briskly until the dressing is smooth and creamy.\nPour the dressing over the salad and toss.\nGarnish the salad with shaved Parmesan before serving.", "image": "img/arugula-and-fennel-salad-serves-4.jpg"}, {"slug": "arugula-pear-quinoa-salad-serves-4", "title": "Arugula, Pear & Quinoa Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-03-07", "ingredients": ["Salad", "4 oz baby arugula", "2 medium pears, diced", "1 ½ cup cooked quinoa", "½ cup dried cranberries", "½ cup chopped pecans", "1/3 cup crumbled goat cheese", "2 scallions, thinly sliced", "Dressing", "1 tbsp extra virgin olive oil", "1 tbsp Dijon mustard", "1 tbsp honey", "3 tbsp apple cider vinegar", "Salt & fresh ground pepper, to taste"], "instructions": "Cook the quinoa according to the package directions. To cool, place the quinoa in a fine sieve and run under cold water.\nIn a large bowl, combine the arugula, pears, cranberries, pecans, goat cheese and scallions.\nIn a small bowl, combine all the dressing ingredients and whisk until well combined.\nAdd the dressing to the salad and toss.", "image": "https://static.wixstatic.com/media/75d545_20f00927fd0141fab4855020a9efa741~mv2.png"}, {"slug": "arugula-salad-with-manchego-pear-and-glazed-pecans", "title": "Arugula Salad with Manchego, Pear and Glazed Pecans", "serves": "", "category": "Salads", "date": "2023-12-21", "ingredients": ["Serves 6", "4 cups baby arugula", "1 large ripe pear", "½ cup pomegranate arils", "4oz Manchego cheese, shaved", "½ cup glazed pecans or pecan pieces", "Vinaigrette", "2 tbsp apple cider vinegar", "1 tbsp fresh lemon juice", "2 tsp Dijon mustard", "1 tsp honey", "1 garlic clove, minced", "¼ cup extra virgin olive oil", "Salt and pepper, to taste"], "instructions": "For the vinaigrette, whisk all ingredients together in a small bowl until blended.\nPlace all the salad ingredients in a bowl and toss. Add the dressing a little at a time until dressed to your liking.", "image": "https://static.wixstatic.com/media/75d545_ef72c33cb9424855a8d25aacbce971cf~mv2.jpg"}, {"slug": "arugula-with-roasted-chicken-serves-2", "title": "Arugula with Roasted Chicken", "serves": "Serves 2", "category": "Salads", "date": "2022-02-25", "ingredients": ["6 cups baby Arugula", "1 store roasted chicken", "½ cup pine nuts", "1 cup shaved Parmesan", "1/3 cup Newman's Own olive oil & vinegar dressing", "1 lemon, cut in quarters and seeds removed"], "instructions": "Remove the breast meat from the chicken and slice.\nIn a large bowl combine the arugula, pine nuts and parmesan and toss.\nAdd the dressing a little at a time being carefully not to over dress. Toss and add to a dinner plate.\nTop with the chicken and serve with the lemon. (the lemon really makes the salad!)\nServe with warm crusty bread and a nice white wine.", "image": "img/arugula-with-roasted-chicken-serves-2.jpg"}, {"slug": "asian-chicken-lettuce-wraps-serves-8", "title": "Asian Chicken Lettuce Wraps", "serves": "Serves 8", "category": "Poultry", "date": "2022-02-25", "ingredients": ["16 Large Bibb lettuce leaves", "2lb chicken filets, finely chopped", "½ cup chopped cashews", "6 green onions, thinly sliced", "6 tbsp Soy Sauce", "2 tsp cornstarch", "4 tbsp peanut oil", "6oz sliced shitake mushrooms, chopped", "3 cloves garlic, minced", "2 tsp fresh ginger, minced", "Duck sauce for dipping, optional", "Soy Sauce for dipping, optional"], "instructions": "Arrange the lettuce leaves on a platter. Pour the duck sauce (if using) in a small bowl and place on the platter. Do the same with the cashews.\nIn a large bowl, combine the chicken, green onions, soy sauce and cornstarch; marinate for 20 minutes. Stir occasionally.\nHeat the oil in a large skillet and add the garlic. Stir until fragrant. Add the mushrooms, carrots and ginger; stir fry for 3-5 minutes.\nAdd the chicken mixture to the skillet and cook, stirring often until the chicken is cooked through. About 10 minutes.\nTransfer the chicken mixture to a large serving bowl and serve with the lettuce leaves and condiments.\nNet Carbs per serving 7.8 (without dipping sauce)", "image": "img/asian-chicken-lettuce-wraps-serves-8.jpg"}, {"slug": "asian-chicken-salad-serves-6", "title": "Asian Chicken Salad", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["¾ cup vegetable oil", "¼ cup plus 1 tbsp rice vinegar", "1 tbsp lite soy sauce", "3 3oz pkg of chicken flavored Ramen noodles, broken", "1 large head of cabbage, shredded (Napa cabbage is also good)", "1 head of iceberg lettuce, shredded", "2 bunch of green onions, sliced thin", "1 store roasted chicken shredded", "1 cup sliced almonds, toasted", "3tbsp chopped fresh cilantro, optional"], "instructions": "In a small saucepan over medium heat, whisk together the oil, vinegar, soy sauce and ramen flavor packets. Bring to a boil and remove from heat. Refrigerate until chilled.\nIn a large salad bowl, combine the cabbage, lettuce, green onions, broken noodles, chicken and almonds.\nWhen the dressing is chilled pour over the salad and toss. Sprinkle with the cilantro or with an herb mill add some parsley.", "image": "img/asian-chicken-salad-serves-6.jpg"}, {"slug": "asian-roasted-potatoes", "title": "Asian Roasted Potatoes", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["4 medium-sized potatoes, cut into small cubes (I’ve used russets, yukon golds and reds)", "2 tbsp sesame oil", "3 tbsp soy sauce", "1/2 tsp ground ginger", "1/2 tsp garlic powder", "pinch red pepper flakes (optional)"], "instructions": "Preheat your oven to 450F.\nPlace your potatoes in a large baking dish, then drizzle with soy sauce and sesame oil.\nSprinkle the potatoes with ground ginger, garlic power and, if using, red pepper flakes. Toss to combine.\nPlace the baking dish in the oven for about 25 minutes. Remove, shuffle the potatoes around, then return to the oven for another 20-25 minutes.", "image": "img/asian-roasted-potatoes.jpg"}, {"slug": "asparagus-chicken-and-pasta-serves-8", "title": "Asparagus, Chicken and Pasta", "serves": "Serves 8", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1 (16oz) package of Penne pasta", "1 ½ tbsp extra virgin olive oil", "1 ¼ tsp minced garlic", "1 ½ red bell pepper, chopped", "2 bunches of asparagus, trimmed and cut into 1\" pieces", "1 ½ cup chicken broth", "½ cup chopped fresh basil", "salt to taste", "¾ tsp black pepper", "½ cup butter", "1 ¼lb grilled chicken breast strips", "2 cup freshly grated Parmesan cheese"], "instructions": "Cook the pasta according to the package directions for al dente. Drain.\nHeat the olive oil in a large pot over medium heat. Stir in the garlic, red pepper and the asparagus. Cook for 5 minutes, stirring often.\nPour the chicken broth and bring to a boil over medium high heat. Simmer until the vegetables are tender.\nAdd the basil, salt, pepper, butter and chicken. Cook and stir for a few minutes until the chicken is heated through.\nStir in the pasta and then fold in the Parmesan cheese. Serve.", "image": "img/asparagus-chicken-and-pasta-serves-8.jpg"}, {"slug": "asparagus-goat-cheese-and-farro-salad-serves-4", "title": "Asparagus, Goat Cheese and Farro Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-28", "ingredients": ["6 tbsp extra virgin olive oil", "1 bunch of asparagus, trimmed and cut into 2\" pieces", "Pinch dried red pepper flakes", "Kosher salt and freshly ground black pepper", "1 cup Farro", "1 qt vegetable stock", "1 cup frozen or fresh peas", "1 ½ cup chopped Kale", "2 tbsp fresh lemon juice", "1 tbsp Dijon mustard", "1/3 cup slivered almonds", "4 scallions thinly sliced(white and light green parts only)", "½ to ¾ cup crumbled goat cheese"], "instructions": "Heat 2 tbsps of the olive oil in a large Dutch oven or heavy saucepan. Add 2 cups of the chopped asparagus and the red pepper flakes. Cook until lightly browned, about 4-5 minutes.\nSeason with the salt and pepper and remove to a dish and set aside.\nIn the same pan, add the Farro and the vegetable stock and bring to a boil. Reduce the heat, season with salt and pepper and simmer uncovered for about 30 minutes. If necessary, add water to keep the Farro covered.\nDrain the Farro and place in a lrge serving bowl. Add the Kale and the peas. Stir and let stand until the Kale has slightly wilted.\nIn a medium bowl whisk together 4 tbsps of olive oil, lemon juice, and mustard. Season with salt and pepper.\nFold the vinaigrette into the Farro and add the cooked asparagus, almonds, scallions, ¼ to ½ cup of the raw asparagus (what remains really) and the goat cheese.\nToss and serve.", "image": "https://static.wixstatic.com/media/75d545_0c142d9fe4734b2d954b129fdd9d72e2~mv2.jpg"}, {"slug": "asparagus-with-bacon-and-onion-serves-4", "title": "Asparagus with Bacon and Onion", "serves": "Serves 4", "category": "Vegetable", "date": "2022-02-25", "ingredients": ["3 slices bacon, cut into ¼” pieces", "½ small onion, cut into ¼” cubes", "2 tsp hazelnut oil or walnut oil", "1 tsp fresh lemon juice", "24 stalks of asparagus", "salt and pepper to taste"], "instructions": "Cook the bacon in a large skillet until crisp; transfer to a paper towel.\nPour off all but 2 tsp of drippings from the skillet. Return the bacon to the skillet with the onion and mix together. Remove from the heat.\nIn a small bowl whisk together the oil and lemon juice. Season with the salt and pepper.\nCook the asparagus in a pot of boiling salted water until crisp tender. ( about 3 minutes after water returns to a boil) Transfer to paper towels to drain.\nArrange the asparagus on a platter and add the dressing. Lightly toss to coat.\nStir the bacon and onion over a med-low heat for about 3 minutes, to heat. Spoon over the asparagus and serve.", "image": "img/asparagus-with-bacon-and-onion-serves-4.jpg"}, {"slug": "bacon-cheese-frittata-serves-6", "title": "Bacon Cheese Frittata", "serves": "Serves 6", "category": "Breakfast", "date": "2022-02-25", "ingredients": ["6 eggs", "1 cup whole milk", "2 tbsp butter, melted", "½ tsp salt", "¼ tsp black pepper", "¼ cup chopped green onions", "6 slices bacon, cooked and crumbled", "1 cup shredded Cheddar cheese"], "instructions": "Preheat the oven to 350°.\nIn a large bowl beat the eggs, milk, butter, salt and pepper with a whisk.\nPour the mixture into a greased 11x7 inch casserole dish. Sprinkle the onions and the bacon over the top and bake uncovered for 30 minutes or until a knife inserted in the center comes out clean.\nServe with warm corn bread.", "image": "img/bacon-cheese-frittata-serves-6.jpg"}, {"slug": "bacon-tomato-cups-makes-30-cups", "title": "Bacon Tomato Cups", "serves": "Makes 30 cups", "category": "Appetizers & Dips", "date": "2022-05-29", "ingredients": ["10 slices center cut bacon", "1 large tomato, seeded and chopped", "½ of a medium onion, chopped", "3 oz shredded swiss cheese", "½ cup mayonnaise", "1 tsp dried basil", "2 packages mini phyllo cups", "**Preheat oven to 375º**"], "instructions": "Place mini phyllo cups into mini muffin pans.\nIn a skillet over medium heat, cook the bacon until crisp. Drain on a paper towel. Crumble the bacon when cool and place in a medium mixing bowl.\nAdd the chopped tomato, onion, cheese, mayonnaise and basil.\nFill each phyllo cup and bake for 10-12 minutes or until golden brown.", "image": "https://static.wixstatic.com/media/75d545_53a6b6c944db45a8a0e47cb8ebb9bb5c~mv2.jpeg"}, {"slug": "bacon-wrapped-pineapple-serves-16", "title": "Bacon Wrapped Pineapple", "serves": "Serves 16", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["10-12 strips of center cut bacon", "20 chunks of fresh pineapple", "¾ cup brown sugar"], "instructions": "Preheat the oven to 400°\nCut the bacon strips in half width-wise.\nPlace the brown sugar in a shallow bowl.\nWrap each pineapple chunk with 1 piece of bacon and roll in the brown sugar.\nPlace the rolls, seam side down on a foil cookie sheet and bake for approximately 20 minutes or until the bacon is cooked.\nRemove to a paper towel and then to a serving dish.", "image": "img/bacon-wrapped-pineapple-serves-16.jpg"}, {"slug": "bacon-wrapped-water-chestnuts-makes-36", "title": "Bacon Wrapped Water Chestnuts", "serves": "Makes 36", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["Preheat the oven to 400°", "4 can of whole water chestnuts, drained", "¼ cup of lite soy sauce", "¼ cup of sugar", "1lb center cut bacon, cut into 2-3” strips"], "instructions": "Marinate the water chestnuts in soy sauce for 30 minutes. Cut the bacon into ½” x 4” strips. Roll each chestnut in sugar, then wrap with a piece of bacon securing with a toothpick.\nPlace on a foil cookie sheet and bake for 20 minutes or until the bacon is crisp. Watch carefully, making sure the sugar does not burn on the bottom of the pan.", "image": "https://static.wixstatic.com/media/75d545_d04a02d5ec354e3099712ef0eef506d1~mv2.jpeg"}, {"slug": "baked-acorn-squash-serves-6", "title": "Baked Acorn Squash", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["3 Acorn squash, halved and seeded", "salt and pepper to taste", "6 tbsp butter, cubed", "½ cup firmly packed brown sugar", "1 tsp ground cinnamon"], "instructions": "Preheat the oven to 350°.\nPlace the acorn squash cut side down in a baking dish. Bake for 30 minutes, or until tender and golden.\nRemove from the oven and turn the squash cut side up. Season with salt and pepper, distribute the cubed butter evenly over the 6 halves. Sprinkle with the brown sugar and cinnamon.\nBake for another 20 minutes.", "image": "img/baked-acorn-squash-serves-6.jpg"}, {"slug": "baked-asparagus-with-balsamic-butter-sauce-serves-4", "title": "Baked Asparagus with Balsamic Butter Sauce", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["1 bunch fresh asparagus, trimmed", "butter cooking spray", "2 tbsp butter", "1 tbsp soy sauce", "1 tsp balsamic vinegar", "salt and pepper to taste"], "instructions": "Preheat the oven to 400°\nArrange the asparagus on a baking sheet. Coat with cooking spray and season with the salt and pepper.\nBake for 12 minutes or until tender.\nMelt the butter in a saucepan over medium heat. Remove from the heat and stir in the soy sauce and the balsamic vinegar.\nPour the sauce over the baked asparagus and serve.", "image": "img/baked-asparagus-with-balsamic-butter-sauce-serves-4.jpg"}, {"slug": "baked-brie-dip-serves-4-5", "title": "Baked Brie Dip", "serves": "Serves 4-5", "category": "Appetizers & Dips", "date": "2022-02-24", "ingredients": ["8 ounces triple cream (room temperature) brie, rind removed 3 ounces mascarpone, softened 2 teaspoons fresh thyme leaves 1 teaspoon minced chives salt and pepper to taste Fresh Gourmet Honey roasted Pecan pieces"], "instructions": "Directions:1. Preheat oven to 375˚F.2. Lightly grease a small shallow baking dish. Set aside.3. Place brie, mascarpone, thyme, chives, salt, and pepper into a mixing bowl and mix together until fully incorporated.4. Pour and evenly spread mixture into the baking dish and top with the pecan pieces.5. Pour pecans into a skillet and place over medium heat. Sprinkle sugar and cinnamon 6. Bake for 10 to 12 minutes or until dip is bubbly and gooey.\nServe with sliced pears and apples or your favorite crackers.", "image": "img/baked-brie-dip-serves-4-5.jpg"}, {"slug": "baked-brie-in-phyllo", "title": "Baked Brie in Phyllo", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["¼ cup of apricot preserves", "½ lb wheel of brie", "10 to 12 sheets of phyllo dough, thawed", "½ cup butter, melted"], "instructions": "Spread the the preserves on top of the brie. (you may add more if you desire)\nWrap the brie with the thawed phyllo dough one sheet at a time, brushing the entire sheet with butter after wrapping. After each addition turn the brie over before adding the next sheet.\nKeep the unused phyllo sheets covered with a damp paper towel as you work.\nCover and refrigerate.\nWhen you are ready to serve: Preheat the oven to 425°. Place the brie in a shallow baking dish and bake for 10-12 minutes or until golden brown. Let the cheese stand for 10 minutes and serve with crackers of your choice.\nYou may choose to garnish with grapes.", "image": "img/baked-brie-in-phyllo.jpg"}, {"slug": "baked-chicken-chinese-style-serves-4", "title": "Baked Chicken Chinese Style", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1/3 cup lite soy sauce", "¼ cup of vegetable oil", "1 ½ tsp dry mustard", "1 tsp fresh ginger", "¼ tsp black pepper", "1 clove garlic, minced", "1lb Perdue chicken thin filets"], "instructions": "Preheat the oven to 350°.\nMix together the soy sauce, oil, mustard, ginger, pepper and garlic. Cut the chicken into strips about 2” by 3-4” and add to the mixture. Marinate for ½ hour stirring frequently.\nPlace the chicken on a foil cookie sheet(easier clean up) and bake for 30-35 minutes. Baste often.", "image": "https://static.wixstatic.com/media/75d545_746f6dac94cf46d2b303f466decaec44~mv2.jpeg"}, {"slug": "baked-pear-and-brie-crostini", "title": "Baked Pear and Brie Crostini", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 French bread baguette, sliced into (16)¼ “ rounds", "2-3tbsp olive oil", "8oz brie, with rind removed", "½ cup sugared chopped walnuts*", "1-2 pears, halved, cored and sliced thin", "4tbsp honey", "1tbsp balsamic vinegar", "1/8tsp salt"], "instructions": "Preheat the oven to 350°\nBrush the tops of the baguette slices with the olive oil and place on a baking sheet. Place in the oven and bake until lightly golden. About 10 minutes.\nMeanwhile combine the honey, balsamic vinegar and salt in a small bowl. Set aside.\nIncrease the oven temperature to broil and make sure the top rack is at least 6” from the element.\nLayer the crostini with a slice of cheese and top with a slice of pear. Broil until the cheese starts to melt. Remove from the oven and drizzle with the honey syrup. Add a few pieces of the walnuts and serve!\nTo make the sugared walnuts, add 2tbsp of white granulated sugar to a small sauté pan and add ½ cup of chopped walnuts. Stir constantly over medium high heat until the sugar has melted and the walnuts are covered. Cool on a piece of waxed paper.\nThese walnuts can be purchased already sugar covered in some grocery stores.", "image": "img/baked-pear-and-brie-crostini.jpg"}, {"slug": "baked-risotto-with-asparagus-spinach-and-parmesan", "title": "Baked Risotto with Asparagus, Spinach and Parmesan", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["1 ½ tbsp. Extra Virgin Olive oil", "1 cup finely chopped Vidalia onion", "1 cup Arborio rice(risotto)", "8 cup baby spinach leaves", "2 cup Chicken broth", "¼ salt", "¼ tsp nutmeg", "2/3 cup grated parmesan cheese, divided", "1 ½ cup sliced asparagus(cut on the diagonal)"], "instructions": "Preheat the oven to 400°. Grease a 13x9 glass baking dish or casserole.\nHeat the olive oil in a large skillet, over medium high heat. Add the onion, cook and stir for 3 min or until tender. Add the rice, stir to coat with the oil.\nStir in the spinach a handful at a time, adding more as it wilts. (at this time you made add more to your liking). Add the broth, salt and nutmeg. Reduce the heat and simmer for approximately 7 minutes. Stir in 1/3 cup of the Parmesan.\nTransfer to the prepared baking dish and cover tightly. Bake for 15 minutes. Remove from the oven and stir in the asparagus; Sprinkle with the remaining Parmesan. Cover and bake 15 minutes more or until the liquid has been absorbed.\nThis recipe makes 6 entrée or 10 to 12 side servings.", "image": "img/baked-risotto-with-asparagus-spinach-and-parmesan.jpg"}, {"slug": "baked-sausage-peppers", "title": "Baked Sausage & Peppers", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["3 red bell peppers", "3yellow bell peppers", "3orange bell peppers", "2 ½ large Vidalia onions", "8 large garlic cloves, chopped", "2 tablespoons dried oregano", "3/4 teaspoon dried crushed red pepper", "1/4 cup extra virgin olive oil", "4 pounds sweet Italian sausages"], "instructions": "Preheat oven to 350°F.\nCut peppers in 2” pieces and place in a large foil roaster pan. Cut the onion into small 1” wedges and add to the pan.\nAdd the next 3 ingredients. Pour oil over and stir to coat. Season with salt and pepper.\nBrown sausages in heavy large nonstick skillet over high heat, turning often, about 8 minutes. Slice each sausage into 3 to 4 pieces and add to the pan.\nBake until sausages are cooked through and peppers are tender, stirring occasionally, about 45 minutes.", "image": "img/baked-sausage-peppers.jpg"}, {"slug": "baked-spicy-honey-panko-boursin", "title": "Baked Spicy Honey Panko Boursin", "serves": "", "category": "", "date": "2024-01-30", "ingredients": ["1 Boursin cheese"], "instructions": "Seasoned panko\nSpicy honey\nFlour\n1 egg, beaten\nPreheat oven to 410°\nCut a piece of parchment paper and place on a cookie sheet.\nPlace some flour and panko into a separate bowls or pie plates.\nRoll the Boursin in the flour to coat.\nRoll the flour coated cheese in the egg to cover and then roll in the panko to cover.\nPlace the cheese on the prepared cookie sheet and bake for 25 minutes or until golden brown. At this point you can turn the oven to broil and cook for 1 minute.\nServe warm with your favorite crackers.", "image": "https://static.wixstatic.com/media/75d545_9000cdadb1e54768ae8a567547595a01~mv2.jpeg"}, {"slug": "baked-zucchini-with-mozzarella-serves-4", "title": "Baked Zucchini with Mozzarella", "serves": "Serves 4", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["2 medium zucchini sliced into ¼- ½ inch pieces", "McCormick Himalayan Pink Salt with black Pepper and Garlic", "2c shredded mozzarella cheese", "**Preheat the oven to 350°**"], "instructions": "Place the sliced zucchini on a baking sheet and sprinkle with the seasoning.\nBake for 10-15 minutes or until crisp.\nRemove from the oven and top each slice with the mozzarella cheese.\nTurn the oven up to a broil and place the baking sheet in the oven. Broil until the cheese is bubbly and a little browned. This will happen rather quickly so watch carefully.", "image": "img/baked-zucchini-with-mozzarella-serves-4.jpg"}, {"slug": "balsamic-grilled-halibut-fillets", "title": "Balsamic Grilled Halibut Fillets", "serves": "", "category": "Seafood", "date": "2022-02-25", "ingredients": ["1 cup fat free balsamic vinaigrette", "2 tbsp grated lemon peel", "2 tbsp extra virgin olive oil", "6 6oz Halibut fillets", "juice from 1 lemon"], "instructions": "Heat the grill.\nIn a shallow baking dish, whisk together the vinaigrette, lemon peel and oil. Add the halibut and turn to coat both sides.\nCover and let stand at room temperature for 10-15 minutes.\nBrush some oil on the grill rack and place the fish on the grill and cook on medium high for about 7 minutes or until the fish flakes. **Turn only once.**\nBaste the fish with the marinade often throughout cooking.\nPlace the fish on a serving platter and squeeze the lemon juice all over the fillets.", "image": "img/balsamic-grilled-halibut-fillets.jpg"}, {"slug": "balsamic-roasted-carrots-serves-8", "title": "Balsamic Roasted Carrots", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["4lbs of carrots, cut into 2\" pieces", "3 large shallots, cut into wedges", "3 tbsp butter", "2 tbsp light brown sugar", "1 tbsp light colored molasses", "1/3 cup balsamic vinegar", "½ tsp salt", "**Preheat the oven to 450°**"], "instructions": "Place the carrots and the shallots in a 13 x 9 x 2 baking dish and set aside.\nIn a large skillet, melt 2 tbsps of butter until lightly browned. Add the sugar, molasses and vinegar and bring to a boil. Stir constantly until the liquid has reduced to ½ cup. About 2 minutes.\nPour the balsamic mixture over the carrots and toss to coat.\nRoast for 50 minutes or until the carrots are tender, stirring halfway through the cooking process. Stir in the remaining butter and salt and serve.", "image": "img/balsamic-roasted-carrots-serves-8.jpg"}, {"slug": "balsamic-vinaigrette", "title": "Balsamic Vinaigrette", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-25", "ingredients": ["¼ cup balsamic vinegar", "2 tbsp white wine vinegar", "1 tbsp light brown sugar", "½ tsp salt", "½ tsp pepper", "1 clove garlic, made into a paste", "2/3 cup extra virgin olive oil"], "instructions": "Whisk together all of the ingredients and serve.", "image": "img/balsamic-vinaigrette.jpg"}, {"slug": "baltimore-crab-cakes-bon-appétit-makes-6", "title": "Baltimore Crab Cakes (Bon Appétit)", "serves": "Makes 6", "category": "Seafood", "date": "2022-02-25", "ingredients": ["¼ cup mayonnaise", "2 scallions, thinly sliced", "1 large egg, lightly beaten", "1tbsp Dijon mustard", "2 tsp fresh lemon juice", "1 ½ tsp Old Bay seasoning", "½ jalapeño, seeded, finely chopped", "1lb lump crabmeat", "1 ½ cup panko", "1tbsp thinly sliced fresh chives", "1/4 tsp kosher salt", "1/8 tsp black pepper", "3tbsp vegetable oil", "1 head of Bibb lettuce", "lemon wedges"], "instructions": "Whisk the first 7 ingredients together in a medium bowl. Add the crab and blend.\nStir in ¾ cup of panko, chives, salt and pepper. Divide into equal portions. Form into 1” thick patties. Refrigerate for 10 minutes.\nLine a platter with lettuce leaves.\nHeat the oil in a large skillet over medium heat. Place the remaining panko in a shallow dish or plate. Coat the cakes with the panko.\nFry until golden brown, 3-4 minutes per side. Arrange on top of the lettuce. Serve with lemon wedges and cocktail sauce.", "image": "https://static.wixstatic.com/media/75d545_60d2dfb1a1824aeda25399ca19f76b87~mv2.jpg"}, {"slug": "banana-cream-pie-with-pretzel-crust", "title": "Banana Cream Pie with Pretzel Crust", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["Crust", "2 ½ cup crushed pretzels", "¾ cup butter, softened", "3 tbsp light brown sugar", "Filling", "8oz cream cheese, softened", "1 cup powdered sugar", "2 8oz containers of Cool Whip", "6 large bananas", "1 (3oz) package Vanilla instant pudding", "1 ¼ cup milk"], "instructions": "Preheat the oven to 350°.\nIn a medium bowl mix the butter, sugar and crushed pretzels until well combined.\nPress the mixture into a 9” or 10” pie plate (9” will get you a thicker crust if you desire)and bake for 10 minutes.\nIn another medium bowl combine the cream cheese and powdered sugar with an electric mixer. Fold in 2 sliced bananas and 1 cup of Cool Whip. Spread on the crust.\nSlice 1 to 2 bananas onto the top of the cream cheese mixture.\nMix the pudding and the milk with a whisk until thickened and pour over the banana layer.\nLayer 1 to 2 more sliced bananas on top of the pudding layer, and cover the top with Cool Whip.\nRefrigerate for 1 hour. Garnish with crushed pretzels or sliced banana.", "image": "img/banana-cream-pie-with-pretzel-crust.jpg"}, {"slug": "banana-fudge-pie-serves-8", "title": "Banana Fudge Pie", "serves": "Serves 8", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 Pillsbury All Ready refrigerated pie crust", "¾ cup Nestlé semi sweet mini morsels", "1 8oz+ container of whipped topping", "2 eggs, beaten", "¼ cup sugar", "2-3 large bananas, sliced"], "instructions": "Preheat the oven to 350°.\nPrepare the pie crust according to the package directions for a filled crust.\nIn a saucepan melt 1 ½ cup of the mini morsels over low heat. Remove from the heat and stir in 1 cup of whipped topping, the eggs and sugar. Mix well. Pour into the pie crust and bake for 28-32 minutes or until the crust is lightly browned.\nCool for 10 minutes. Chill for 1 hour.\nLayer the bananas over the chocolate pie and top with the remaining whipped topping. Garnish with mini morsels.", "image": "img/banana-fudge-pie-serves-8.jpg"}, {"slug": "basil-baked-salmon-serves-4", "title": "Basil Baked Salmon", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-25", "ingredients": ["1lb salmon fillet", "1 tbsp butter, melted", "1 tbsp fresh lemon juice", "½ tsp dried basil", "¼ tsp onion powder", "½ green bell pepper, sliced"], "instructions": "Preheat the oven to 375°.\nPlace the salmon in a shallow baking dish.\nCombine the butter and lemon juice in a small cup and pour over the salmon. Sprinkle the basil and onion powder over the salmon.\nArrange the pepper slices on top of the salmon and cover with foil.\nBake for 20-25 minutes or until the fish flakes with a fork.", "image": "https://static.wixstatic.com/media/75d545_cd838e81d18444d4bdb9cb81727e9882~mv2.jpg"}, {"slug": "basil-buttered-beans-serves-20", "title": "Basil Buttered Beans", "serves": "Serves 20", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["20 cups fresh green beans", "1 ¼ cup chopped onion", "1 ¼ cup chopped celery", "2 ½ cup water", "1 ¼ cup butter, melted", "¼ cup plus 1 tbsp minced fresh basil", "2 ½ tsp salt", "1 ¼ tsp black pepper"], "instructions": "Trim the green beans and cut into 2” pieces.\nIn a large saucepan combine the beans, onion, celery and water. Cover and cook for 5 minutes or until the beans are tender. Drain and move to a large serving bowl.\nAdd the butter, basil, salt and pepper to the beans and toss to coat. Serve immediately.", "image": "img/basil-buttered-beans-serves-20.jpg"}, {"slug": "beef-black-bean-and-corn-tacos", "title": "Beef, Black Bean and Corn Tacos", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["4 tbsp vegetable oil", "1 large Vidalia onion", "4 garlic cloves, minced", "1 ½ jalapeño, seeded and diced small", "Kosher salt & pepper", "2 tsp chili powder", "1 tsp ground cumin", "1 tsp paprika", "2 lb lean ground beef", "2 15 oz cans black beans", "4 cups cherry tomatoes", "10.8 oz gold & white corn", "12 corn tortillas", "1 cup shredded cheddar", "1 avocado, diced"], "instructions": "Heat the oil in a large skillet over medium high heat and add the onion. Cook until softened and lightly browned. Add the garlic and jalapeño and season with salt & pepper. Cook until the garlic is fragrant.\nAdd the cumin, chili powder and paprika, stir for about a minute to combine and add the beef. Season with salt and pepper and cook, breaking up the meat into small pieces. Cook until meat is brown and add the beans.\nAdd tomatoes, corn and 1 cup of water and simmer. Season again with the salt and pepper and cook until the liquid has reduced and the tomatoes have burst.\nServe with cheese, avocado and sour cream.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "beet-salad-skewers", "title": "Beet Salad Skewers", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["8 oz package of cooked baby beets", "Baby spinach leaves", "8 oz goat cheese, cut into small cubes", "Balsamic glaze", "Candied walnuts, crushed", "Bamboo cocktail skewers"], "instructions": "Cut each beet in half.\nBuild the skewers in the following manor, 1 beet half, 2 leaves of baby spinach folded in half and small chunk of goat cheese.\nPlate the skewers and drizzle with the balsamic glaze and sprinkle with the crushed walnuts.", "image": "img/beet-salad-skewers.jpg"}, {"slug": "berries-and-lemon-custard-in-coconut-shell", "title": "Berries and Lemon Custard in Coconut Shell", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["**Coconut Pastry**", "1 cup flour", "¾ cup shredded coconut", "6 tbsp butter", "2 tbsp sugar", "1 large egg yolk", "**Lemon Custard**", "1 tsp lemon zest", "2 tbsp freshly squeezed lemon juice", "6 tbsp butter", "1/3 cup sugar", "1 tbsp corn starch", "4 large egg yolks", "1 cup heavy cream", "2 ½ pint raspberries", "1 pint blueberries", "**Preheat the oven to 350°**"], "instructions": "To prepare the coconut pastry, combine the flour, coconut, butter, sugar, and egg yolk in a large bowl. Mix with fingertips until blended.\nPress the dough onto the bottom and up the sides of a 10\" tart pan with a removable bottom. Pierce the dough with a fork all over to prevent puffing and shrinking during baking.\nLine the tart shell with aluminum foil and bake for 10 minutes. Remove the foil and prick the dough again. Continue to bake for another 10 minutes, or until golden. (if the pastry puffs up gently press it down with a spoon).\nRemove the tart from the oven and cool in the pan.\nTo prepare the filling, use a 2qt saucepan over medium low heat, and add the butter, sugar and cornstarch. Stir **constantly** until the mixture thickens and boils. Boil for 1 minute. Remove from the heat.\nIn a small bowl, whisk the egg yolks and stir in a small amount of the hot sugar mixture.\nPlace the sugar mixture back over the heat and slowly add the egg yolk mixture to the hot sugar mix, stirring briskly to prevent lumps. Cook, stirring constantly until thickened and coats a spoon well. About 1 minute.\nRemove from the heat and stir in the lemon zest and the lemon juice. Cover and refrigerate for at least an hour. Custard should be very cold.\nIn a small bowl, with an electric mixture, beat the heavy cream until stiff peaks form. Fold the whipped cream into the lemon custard with a spatula.\nSpoon the mixture into the tart shell.\nDecorate the top of the custard from the outer edge in with the raspberries in a circular manner. Fill in the center with the blueberries and raspberries. Refrigerate for an hour more or until the custard is set.", "image": "img/berries-and-lemon-custard-in-coconut-shell.jpg"}, {"slug": "best-ever-meatballs-makes-about-30-meatballs", "title": "Best Ever Meatballs Makes about 30 meatballs", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["**Preheat the oven to 350°**", "4 slices of soft white bread, crusts removed", "1 cup buttermilk", "1lb ground pork", "1 ½ lb lean ground beef", "½ cup freshly grated Parmesan cheese", "3 egg yolks", "2 garlic cloves, minced", "4 tbsp fresh parsley, finely chopped"], "instructions": "Tear the bread into small pieces and place in a small bowl. Add the buttermilk to the bread and stir to coat. Let the bread soak for a few minutes.\nIn a large bowl combine the pork and the beef; add the bread and blend.\nAdd the cheese, egg yolk, garlic and parsley to the meat and mix well.\nMake meatballs and add directly to your favorite sauce and cook until they are done, or bake for 20 minutes until cooked through.\nI prefer to bake first and then add to my sauce. Either way Enjoy!", "image": "img/best-ever-meatballs-makes-about-30-meatballs.jpg"}, {"slug": "best-vodka-sauce", "title": "Best Vodka Sauce", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-25", "ingredients": ["1 small onion, finely chopped", "1 large can plum tomatoes(crushed) or fresh", "1tbsp extra virgin olive oil", "1tbsp butter", "1 cup heavy cream", "¼ cup vodka", "salt and pepper to taste", "1/8tsp crushed red pepper"], "instructions": "Melt the butter and oil in a saucepan. Add the onion and sauté for about 5 minutes until the onion is translucent.\nStrain and drain the tomatoes. Chop and add the tomatoes to the onion mixture. Cook for about 25 minute; add the heavy cream and the vodka. Cook for an additional 3-5 minutes. Add the salt, pepper and the red pepper.\nYou can now serve with your favorite pasta or refrigerate for use the next day.", "image": "img/best-vodka-sauce.jpg"}, {"slug": "big-mac-dip", "title": "Big Mac Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-03-01", "ingredients": ["Sauce", "¾ cup mayonnaise", "3 tbsp French dressing", "5 tsp sweet pickle relish", "1 ½ tbsp finely minced onion", "2 tsp vinegar", "1 ½ tsp sugar", "1/4 tsp salt", "Filling", "1 lb ground beef", "1 tbsp olive oil", "Kosher salt", "Freshly ground pepper", "2 8 oz packages of cream cheese", "1 ½ cup shredded cheddar cheese", "Buns", "1 16 oz can Pillsbury homestyle biscuits", "4 tbsp butter, melted", "1 tbsp sesame seeds", "Topping", "½ cup shredded lettuce", "½ of a large Vidalia onion, diced", "½ cup pickle chips", "Preheat oven to 350º"], "instructions": "Spray an oven safe skillet or a round shallow casserole dish with cooking spray.\nIn a small bowl, mix together all the sauce ingredients and set aside.\nHeat the olive oil in a large skillet over medium heat and add the ground beef and cook until no longer pink, breaking into small pieces as it cooks. Season with salt & pepper.\nAdd the cream cheese, 1 cup of cheddar cheese and all **but ¼ cup** of the sauce.\nCut each biscuit in half and roll into a ball and place around the skillet or casserole dish to form a ring. Brush each biscuit ball with the butter and sprinkle with the sesame seeds.\nSpread the beef mixture into the center of the ring and top with the remaining cheddar cheese.\nBake for 30 minutes or until the biscuits are golden brown. top with the lettuce and pickles chips and drizzle the remaining sauce over the dip.\nEnjoy!", "image": "https://static.wixstatic.com/media/75d545_0e44ae27992e48b4b9ce3d368bbeee4d~mv2.jpeg"}, {"slug": "black-bean-and-pearl-couscous-salad-serves-6", "title": "Black Bean and Pearl Couscous Salad", "serves": "Serves 6", "category": "Salads", "date": "2022-02-25", "ingredients": ["1 cup uncooked Pearl couscous", "1 ¼ cup chicken broth", "6 tbsp extra virgin olive oil", "4 tbsp fresh lime juice", "2 tsp red wine vinegar", "1 tsp ground cumin", "8 scallions, thinly sliced(white and light green parts only)", "1 red bell pepper, diced", "¼ cup chopped fresh cilantro", "1 cup frozen corn kernels, thawed", "2 (15oz) cans black beans, drained and rinsed", "salt and pepper to taste"], "instructions": "In a 2qt saucepan, bring the chicken broth to a boil and add the couscous. Cover and remove from the heat. Let stand for 5 minutes.\nIn a large bowl, whisk the olive oil, lime juice, vinegar and cumin together. Add the scallions, red pepper, cilantro, corn and beans. Toss.\nFluff the couscous and add to the bowl. Mix well and season with salt and pepper to taste. You may serve immediately or refrigerate and serve.", "image": "img/black-bean-and-pearl-couscous-salad-serves-6.jpg"}, {"slug": "bloody-mary-shrimp-cocktail", "title": "Bloody Mary Shrimp Cocktail", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 ½ lb Large shrimp, cooked, peeled and deveined", "½ cup tomato juice", "¼ cup vodka", "½ tsp hot sauce", "½ tsp sugar", "½ tsp celery salt", "2 tbsp chopped fresh parsley", "1 cup cocktail sauce"], "instructions": "Arrange the shrimp in a single layer in a 11x7 baking dish.\nIn a medium saucepan, add the tomato juice, vodka and hot sauce and heat to a boiling over medium high heat. Stir in the sugar and reduce the heat. Simmer uncovered for 5 minutes, stirring often. Add the celery salt and parsley, pour over the shrimp.\nCover and refrigerate for 3 hours.\nRemove the shrimp from the marinade and arrange on a decorative platter. Serve with cocktail sauce and lemon.", "image": "img/bloody-mary-shrimp-cocktail.jpg"}, {"slug": "blue-cheese-spinach-meat-loaf-muffins-serves-6", "title": "Blue Cheese, Spinach Meat Loaf Muffins", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1 ½ lb lean ground beef", "¾ cup crumbled blue cheese", "½ cup onion, finely diced", "½ cup Italian breadcrumbs", "½ cup chopped fresh spinach", "2 eggs", "2tbsp Worcestershire sauce"], "instructions": "Preheat the oven to 375°\nGrease a large muffin pan with cooking spray(or a mini muffin pan for appetizer style).\nIn a large bowl combine the ground beef, blue cheese, onion, breadcrumbs, spinach, eggs and Worcestershire sauce until well blended.\nDivide the meat mixture evenly into the prepared pan. (I form balls to fit the size of the muffin cup).\nBake for about 30 minutes, or until the center is no longer pink. A thermometer inserted into the center should read160°", "image": "img/blue-cheese-spinach-meat-loaf-muffins-serves-6.jpg"}, {"slug": "bourbon-glazed-carrots-serves-5", "title": "Bourbon Glazed Carrots", "serves": "Serves 5", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["½ cup butter", "2lbs baby carrots", "½ tsp salt", "½ cup Jack Daniels bourbon whiskey", "1/3 cup packed brown sugar", "freshly ground black pepper"], "instructions": "Melt the butter in a heavy skillet over medium high heat.\nWhen the butter begins to bubble add the carrots, season with the salt and cook until the liquid from the carrots evaporates and the carrots begin to brown. About 5-6 minutes. Stir often.\nReduce the heat to medium low and pour in the bourbon. Cook and stir the carrots until the bourbon has almost evaporated.\nAdd the brown sugar and stir until the carrots have cooked through. Raise the heat to thicken the glaze. Once thickened remove from the heat, season with the black pepper and serve.", "image": "img/bourbon-glazed-carrots-serves-5.jpg"}, {"slug": "braised-short-ribs-serves-4", "title": "Braised Short Ribs", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1 bottle Cabernet", "kosher salt", "freshly ground black pepper", "3 tbsp unsalted butter", "3lbs beef short ribs, no bones", "4 cloves garlic, minced", "½ cup flour", "**Preheat the oven to 300°**"], "instructions": "Pat the short ribs dry with a paper towel and season with salt and pepper.\nIn a large saucepan, bring the wine to a boil and continue cooking until reduced by half.\nIn a large Dutch oven, heat 2 tbsp of butter and sear the ribs on all sides. Transfer to a plate.\nAdd the garlic to the oil and stir until softened but not brown.\nReturn the ribs to the pot and sprinkle with the flour. Cook, stirring well to make sure the flour is incorporated and begins to brown.\nAdd the reduced wine and bring to a boil.\nCover leaving the lid slightly ajar and place in the oven. Cook for about 3 hours. Meat should shred easily.\nRemove the ribs to a plate and cover to keep warm. Strain the liquid into a saucepan and simmer for 10 minutes, skimming the fat.\nAdd 1 tbsp of butter and whisk to combine. Add extra seasoning to taste.\nServe over Mashed potatoes or Risotto.", "image": "img/braised-short-ribs-serves-4.jpg"}, {"slug": "brie-and-mushroom-soup-serves-8", "title": "Brie and Mushroom Soup", "serves": "Serves 8", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["2 cups Cream Sherry", "¼ butter, cubed", "1lb assorted fresh mushrooms( I used Crimini, Shitake and Baby Bella)", "1 cup minced shallots", "1/3 cup minced Italian parsley(flat leaf)", "1 tbsp fresh squeezed lemon juice", "1/3 cup flour", "4 cups beef broth", "1 8oz round of Brie, rind removed and cubed", "1 cup heavy cream", "1 tsp salt", "½ tsp white pepper"], "instructions": "Bring the Cream Sherry to a boil in a small saucepan and cook until it is reduced by half. Set aside.\nMeanwhile in a 4-6qt cooking pot, melt the butter and add the shallots and the mushrooms. Sauté until tender over medium heat.\nAdd the parsley and the lemon juice to the mushrooms.\nRemove from the heat and stir in the flour until well blended.\nPlace the pot back over medium high heat and gradually add the broth and the sherry. Bring to a boil.\nReduce the heat and simmer uncovered for 8 minutes or until the soup has thickened.\nStir in the cheese until melted and add the cream, salt and pepper.\nHeat through and serve.", "image": "https://static.wixstatic.com/media/75d545_2882a774f5474753b1b5756942f54ef8~mv2.jpg"}, {"slug": "brie-apple-honey-crostini-serves-12", "title": "Brie, Apple, & Honey Crostini", "serves": "Serves 12", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 French bread baguette, cut into ¼\" slices", "1 Jar apple butter", "8oz Brie", "2 Large granny smith apples", "1 lemon", "1 3.5oz bag of honey roasted pecan pieces", "Honey"], "instructions": "Preheat the oven to 375°\nSpread one side of the baguette slices with about 2tsp of apple butter and place on a baking sheet.\nTrim the brie and slice into thin slices. Place a slice of cheese on top of each crostini.\nBake for 5-7 minutes or until the cheese is melted.\nMeanwhile core the apples and slice into thin slices. Squeeze the lemon over the slices to prevent browning.\nRemove the crostini from the oven and place an apple slice on each.\nDrizzle the honey over the crostini and sprinkle with the honey pecans. Serve while hot and enjoy!", "image": "img/brie-apple-honey-crostini-serves-12.jpg"}, {"slug": "brie-pomegranate-phyllo-cups-makes-30", "title": "Brie Pomegranate Phyllo Cups", "serves": "Makes 30", "category": "Appetizers & Dips", "date": "2022-03-01", "ingredients": ["2 boxes mini phyllo cups", "1 jar Fig jam", "8 oz wheel brie, cut into cubes (about ¾”)", "Chopped pecans", "8 0z Pom Poms Pomegranate seeds"], "instructions": "**Preheat oven to 350º**\nPlace the phyllo cups on a baking sheet or in mini muffin cups and bake for about 3 minutes to toast.\nFill each cup with ½ tsp jam and a cube of brie, top with some chopped pecans bake for about 10 minutes or until the cheeses has melted.\nTop each cup with some pomegranate seeds and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "brie-stuffed-mushrooms-serves-4", "title": "Brie Stuffed Mushrooms", "serves": "Serves 4", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["3 tbsp butter", "1 package button mushrooms, washed and stems removed", "3 cloves garlic, minced", "salt", "¼ cup flat leaf parsley, finely chopped", "4 green onions, chopped", "1 average wedge of brie cheese", "**Preheat the oven to 350°**"], "instructions": "Melt the butter in a medium skillet. Add the mushrooms and turn to coat in the butter. Sprinkle with salt. Brown for just a few minutes being careful not to over cook.\nRemove the mushrooms to a baking dish.\nIn the same pan, add the garlic, parsley and the green onions. Salt to taste. Stir for a few moments to let the parsley wilt. Remove from the heat.\nCut the rind off the brie and cut into small pieces to fit inside each mushroom cap. Press the cheese into the mushroom and top with the parsley mixture.\nBake for 15 minutes or until the brie has melted.\n**1 Net Carb per serving**", "image": "https://static.wixstatic.com/media/75d545_0bfdcabec8284a44a7b48ec880a9a0d8~mv2.jpg"}, {"slug": "broiled-parmesan-tomatoes-serves-6", "title": "Broiled Parmesan Tomatoes", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["5 medium size ripe tomatoes, halved", "10 pats of butter (10 individual teaspoons)", "½ cup butter(for melting)", "8 green onions, chopped", "6 tbsp Italian bread crumbs", "2 tbsp fresh grated Parmesan cheese", "¼ tsp salt", "¼ tsp garlic powder", "2 tbsp chopped fresh basil", "½ cup shredded mozzarella cheese"], "instructions": "Place the tomatoes cut side up in an ungreased baking dish(I used foil for easy clean up). Place a tsp of butter (or pat) on the top of each tomato half. Broil 4 inches from the element for 4-6 minutes, or until the butter has melted and the edges of the tomato soften.\nIn a medium microwave safe bowl, combine the ½ cup of butter, and the onions. Microwave on high until the butter has melted and the onions are tender.\nStir the breadcrumbs into the melted butter. Add the Parmesan cheese, salt, garlic powder and basil.\nSpoon the breadcrumb mixture onto the top of each tomato. Sprinkle with the shredded mozzarella and broil for another 1-2 minutes or until the cheese has melted.", "image": "https://static.wixstatic.com/media/75d545_0791a2c3ff14468285f39ba7a6a177d1~mv2.jpg"}, {"slug": "brown-rice-and-mushroom-pilaf-serves-6", "title": "Brown Rice and Mushroom Pilaf", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["1 tbsp butter", "2 tbsp extra virgin olive oil", "2 clove garlic, minced", "1 small onion, finely chopped", "¼ cup chopped celery", "2 cups fresh sliced mushrooms", "1 (14.5oz) can chicken broth", "2 cups Minute Rice Brown Rice, uncooked", "½ cup chopped walnuts, toasted", "2 tbsp chopped fresh parsley"], "instructions": "Heat the butter and the oil in a large saucepan over medium heat. Add the onion, and celery and cook for 3 minutes, stirring occasionally.\nAdd the mushrooms and cook for another 3 minutes. Add the broth and stir. Bring to a boil and add the rice. Cover and cook over medium low heat for 5 minutes. Remove from the heat and let stand for another 5 minutes.\nAdd the walnuts and the parsley. Toss and serve!", "image": "img/brown-rice-and-mushroom-pilaf-serves-6.jpg"}, {"slug": "brownie-mallow-bars-makes-2-dozen", "title": "Brownie Mallow Bars", "serves": "Makes 2 ½ dozen", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 package Betty Crocker brownie mix", "1 (10.5oz) bag of mini marshmallows", "2 cups semi sweet chocolate chips", "1 cup peanut butter", "1 tbsp butter", "1 ½ cup Rice Crispy cereal", "**Preheat the oven to 350°**"], "instructions": "Grease a 13 x 9 baking dish and set aside.\nPrepare the brownie mix according to the package directions for fudge like brownies.\nBake for 28-30 minutes. Top with the marshmallows and bake for another 3 minutes. (the marshmallows will not be completely melted) Cool.\nIn a medium saucepan over low heat, combine the chocolate chips, peanut butter and butter. Cook until smooth, stirring often.\nRemove from the heat and stir in the cereal. Spread the mixture over the brownies. Refrigerate for 1-2 hours before cutting.", "image": "img/brownie-mallow-bars-makes-2-dozen.jpg"}, {"slug": "buffalo-cauliflower-and-blue-cheese-dip-serves-4", "title": "Buffalo Cauliflower and Blue Cheese Dip", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["**Cauliflower**", "1 medium head of cauliflower or 8c of fresh florets", "2 tbsp butter", "¼ cup of Hot Sauce", "1 tbsp freshly squeezed lemon juice", "¼ cup extra virgin olive oil", "Kosher salt", "**Dip**", "1/3 cup sour cream", "3 tbsp crumbled blue cheese", "1 tbsp milk", "2 tsp mayonnaise", "Kosher salt and pepper to taste"], "instructions": "In a small mixing bowl, mix all the dip ingredients until well blended. Cover and refrigerate for at least 30 minutes. I prefer longer so you really get that blue cheese taste.\n**Preheat the oven to 400°**\nIn a very large bowl combine the cauliflower, olive oil and a teaspoon of salt.\nIn the microwave, melt the butter in a small bowl. Once melted add the hot sauce and the lemon juice. Whisk until well blended.\nPour the hot sauce mixture over the cauliflower and toss to coat. Make sure all the florets are coated well.\nSpread the cauliflower out onto a foil baking sheet. Roast in the oven for 20-25 minutes or until the florets are slightly browned on the edges.\nServe with the dip.", "image": "https://static.wixstatic.com/media/75d545_56b14a12f73f40beb9920dc2f1404fc7~mv2.jpg"}, {"slug": "buffalo-chicken-salad-serves-15", "title": "Buffalo Chicken Salad", "serves": "Serves 15", "category": "Salads", "date": "2022-02-25", "ingredients": ["1 ½ package of penne pasta", "½ cup plus 2 tbsp mayonnaise", "1 ¼ cup blue cheese dressing (I prefer chunky)", "½ cup buffalo wing sauce, more if you love it hot!", "1 ½ tsp salt", "½ tsp black pepper", "1 store roasted chicken, boned and cut up", "¾ cup red bell pepper, diced", "¾ cup green bell pepper, diced", "1 ¼ cup red onion, diced"], "instructions": "Cook the pasta according to the package directions for firm or al dente. Drain and set aside.\nIn a large bowl combine the mayonnaise, blue cheese dressing, wing sauce, salt and pepper. Add the chicken, peppers, onion and pasta. Toss to coat with the dressing.\nCover and refrigerate for 1-2 hours before serving.", "image": "img/buffalo-chicken-salad-serves-15.jpg"}, {"slug": "buttermilk-chocolate-texas-sheet-cake", "title": "Buttermilk Chocolate Texas Sheet Cake", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["½ cup buttermilk", "2 eggs", "2 cups sugar", "2 cups flour", "1 tsp baking soda", "½ tsp kosher salt", "1 tsp cinnamon", "2 sticks unsalted butter", "2 tbsp canola oil", "1 cup water", "6 tbsp unsweetened cocoa", "1 tsp vanilla"], "instructions": "Preheat the oven to 350°.\nGrease a jellyroll pan. 18x13x1\nIn a small bowl combine ½ cup buttermilk and eggs and whisk. Set aside.\nIn a large bowl combine the sugar, flour, baking soda, salt and cinnamon. Make a well in the center and set aside.\nIn a medium saucepan, combine the butter, oil and water and bring to a “near” boil. Remove from the heat and whisk in the cocoa until the mixture is smooth. Add the vanilla and mix. Pour this mixture into the well made in the flour mixture; stir to blend.\nSlowly add the buttermilk and egg mixture and mix well.\nPour the batter into the greased jellyroll pan and bake for 20-25 minutes, or until a toothpick inserted in the center of the cake comes out clean. Upon removing the cake from the oven poke holes all over the cake and then frost.\nWhen the cake is about 5 minutes from being done, prepare the frosting.", "image": "https://static.wixstatic.com/media/75d545_9ec43763ff2a496ab9a7ea72233afcb9~mv2.jpeg"}, {"slug": "butternut-orzo-risotto-serves-5", "title": "Butternut Orzo Risotto", "serves": "Serves 5", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["3 cups cubed, peeled butternut squash (1/2” cubes)", "1tbsp extra virgin olive oil", "1/4 tsp salt", "¼ tsp pepper(divided)", "3 cup reduced sodium chicken broth", "1 small onion, chopped", "2tbsp butter", "1 cup uncooked orzo", "1 clove garlic, minced", "2tbsp minced fresh parsley", "1 ½ tsp minced fresh sage", "½ tsp minced fresh thyme", "shaved Parmesan"], "instructions": "Preheat the oven to 400°\nPlace the squash in a greased 15” x 10” baking pan. Drizzle with the oil. Sprinkle with the salt & 1/8 tsp of pepper.\nBake for 15-20 minutes or until tender, stirring halfway through.\nWhile the squash is baking, heat the broth in a small saucepan and keep warm.\nIn a large skillet, sauté the onion in the butter until tender. Add the orzo and garlic; cook and stir for 2-3 minutes. Slowly stir in 1 cup of warm broth. Cook and stir until ½ the liquid is absorbed. Add the remaining broth ½ cup at a time, stirring constantly allowing the liquid to absorb between additions. Cook until the risotto is almost tender. (cooking time is about 20 minutes)\nAdd the herbs, cooked squash and the remaining pepper. Heat through. Garnish with the shaved Parmesan.", "image": "img/butternut-orzo-risotto-serves-5.jpg"}, {"slug": "butternut-squash-soup-with-crispy-pancetta-serves-6", "title": "Butternut Squash Soup with Crispy Pancetta", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-03-04", "ingredients": ["¼ lb Pancetta, from deli, sliced very thin", "4 tbsp extra virgin olive oil", "1 cup diced carrots", "1 small Vidalia onion, diced", "2 cloves garlic, minced", "8 cups cubed butternut squash, fresh", "2 golden delicious apples, peeled and chopped", "2 tsp chopped fresh thyme", "2 tsp chopped fresh rosemary", "8 cups chicken broth", "4 tbsp maple syrup", "½ tsp kosher salt", "¼ tsp ground black pepper", "2 tbsp crème fraiche", "2 tsp cinnamon", "13.66 oz can light coconut milk (Thai Kitchen)"], "instructions": "Heat the olive oil in a large sauce pot, over medium heat and add the pancetta slices. Cook until crisp, remove from the pot and drain on a paper towel.\nIn the same pot, add the carrot, garlic, celery and onion. Cook until the vegetables have softened.\nStir in the butternut squash, apple, thyme, rosemary and cinnamon and cook for 3-4 minutes, or until the squash begins to brown.\nAdd the chicken broth, salt and pepper and bring to a boil. Reduce the heat and simmer for about 30 minutes or until the squash is fork tender.\nUse an immersion blender to purée the soup mixture.\nAdd the coconut milk and the maple syrup.\nPlace in bowls and top with a dollop of crème fraiche and a pancetta slice.", "image": "img/butternut-squash-soup-with-crispy-pancetta-serves-6.jpg"}, {"slug": "buttery-corn-casserole-serves-6", "title": "Buttery Corn Casserole", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2 eggs, lightly beaten", "1 5oz can evaporated milk", "4 tbsp butter, melted and divided", "2 15.25oz cans whole kernel corn", "2 cups shredded cheddar cheese", "1 ½ cup crushed butter flavored crackers, divided"], "instructions": "Preheat the oven to 350°.\nGrease a 11x7 baking dish.\nIn a large bowl combine the eggs, milk, 2 tbsp butter, corn, cheese and ½ cup cracker crumbs. Spoon into the prepared baking dish.\nToss the remaining crumbs and butter. Sprinkle over the corn mixture and bake for 25-30 minutes, or until bubbly.", "image": "img/buttery-corn-casserole-serves-6.jpg"}, {"slug": "cajun-chicken-corn-chowder-serves-6-8", "title": "Cajun Chicken Corn Chowder", "serves": "Serves 6-8", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["4 pieces thick cut bacon, cut into small pieces(remove excess fat)", "2 tbsp extra virgin olive oil", "1 medium Vidalia onion, chopped", "1 medium Red Bell pepper, seeded and chopped", "1 Jalapeño pepper, seeded and chopped", "3 garlic cloves, minced", "1 tsp ground cumin", "½ tsp dried oregano", "½ tsp dried thyme", "¼ tsp cayenne", "2 tsp Creole seasoning", "1 lb thin sliced chicken filets, cut into 1” pieces", "2 tbsp flour", "5 cups chicken stock", "1 ¼ cup heavy cream", "1 bay leaf", "30 oz canned corn", "15 oz creamed corn", "salt and pepper to taste"], "instructions": "In a large pot, cook the bacon in the olive oil. Remove the bacon to a paper towel to drain.\nAdd the onion, red bell pepper, garlic and jalapeño to the pot and toss to combine with the bacon grease and olive oil. Add the cumin, oregano, thyme, cayenne and creole seasoning. Cook until the vegetables begin to soften.\nAdd the chicken and cook stirring frequently until browned. Stir in the flour and blend well.\nAdd the chicken stock, cream and the bay leaf stirring constantly to avoid lumps.\nAdd the corn and the bacon, cover and cook over low heat for 20 minutes.\nAdd the salt and pepper to taste. Serve with warm sourdough bread or your favorite tortilla chips.", "image": "img/cajun-chicken-corn-chowder-serves-6-8.jpg"}, {"slug": "cajun-chicken-pasta-on-the-lighter-side-skinnytaste-com", "title": "Cajun Chicken Pasta on the Lighter Side(Skinnytaste.com)", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["8 ounces uncooked linguine (I used Dreamfields)", "• 1 pound chicken breast strips", "• 1-2 tsp Cajun seasoning (or to taste)", "• 1 tbsp olive oil", "• 1 medium red bell pepper, thinly sliced", "• 1 medium yellow bell pepper, thinly sliced", "• 8 oz fresh mushrooms, sliced", "• 1/2 red onion, sliced", "• 3 cloves garlic, minced", "• 2 medium tomatoes, diced", "• 1 cup fat free low sodium chicken broth", "• 1/3 cup skim milk", "• 1 tbsp flour", "• 3 tbsp light cream cheese", "• fresh cracked pepper", "• 2 scallions, chopped", "• salt to taste", "• Smart Balance cooking spray", "Directions:"], "instructions": "**Prep** all your vegetables. In a small blender make a slurry by **combining**milk, flour and cream cheese. **Set** aside. **Season** chicken generously with Cajun seasoning, garlic powder and salt.\n**Prepare**pasta in salted water according to package directions.\n**Heat**a large heavy nonstick skillet over medium-high heat; **spray**with cooking spray and **add** half of the chicken. **Sauté** 5 to 6 minutes or until done, **set aside** on a plate and repeat with the remaining chicken. **Set aside.**\n**Add**olive oil to the skillet and reduce to medium; **add**bell peppers, onions, and garlic to skillet, **sauté**3-4 minutes**.**\n**Add**mushrooms and tomatoes and **sauté** 3-4 more minutes or until vegetables are tender. **Season** with 1/4 tsp salt, garlic powder and fresh cracked pepper to taste.\n**Reduce**heat to medium-low; **add**chicken broth and **pour** in slurry **stirring**about 2 minutes.\n**Return**chicken to skillet; **adjust** salt and Cajun seasoning to taste, **cook** another minute or two until hot, then **add** linguine; **toss** well to coat.**Top** with chopped scallions and enjoy!", "image": "img/cajun-chicken-pasta-on-the-lighter-side-skinnytaste-com.jpg"}, {"slug": "cajun-pot-roast-with-corn-and-potatoes-serves-6-10", "title": "Cajun Pot Roast with Corn and Potatoes", "serves": "Serves 6-10", "category": "Crockpot", "date": "2022-02-25", "ingredients": ["1 4lb Pot Roast", "Cajun seasoning", "1 14oz bag Green Giants niblets frozen corn", "1 cup chopped onion", "1 cup chopped green pepper", "2 14.5oz cans of diced tomatoes, undrained", "¼ tsp black pepper", "1tsp hot pepper sauce"], "instructions": "Rub the entire surface of the roast with the Cajun seasoning. Place in s crock-pot and top with the corn, onion, and green pepper.\nIna small bowl combine the tomatoes. Pepper, and hot sauce with a whisk; pour over the vegetables and the roast.\nCover and cook on low for 8-10 hours.", "image": "img/cajun-pot-roast-with-corn-and-potatoes-serves-6-10.jpg"}, {"slug": "candy-bar-fudge", "title": "Candy Bar Fudge", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["½ cup butter", "1/3 cup cocoa powder", "¼ cup brown sugar, packed", "¼ cup whole milk", "3 ½ cup confectioner’s sugar", "1 tsp vanilla extract", "30 caramels, unwrapped", "1 tbsp water", "2 cups salted peanuts", "½ cup semi sweet chocolate chips", "½ cup milk chocolate chips"], "instructions": "Grease an 8 x 8 baking pan and set aside.\nIna small saucepan over medium heat, combine the butter, cocoa, brown sugar and milk. Cook until the mixture comes to a boil, stirring frequently.\nRemove from the heat and add the powdered sugar and the vanilla. Pour into the prepared pan.\nIn a microwaveable bowl, microwave the caramels and water until the caramels melt. Add the peanuts and spread over the chocolate layer in the pan.\nPlace the chocolate chips in a microwaveable bowl and microwave until melted and smooth. Spread over the caramel layer and refrigerate for at least 2 hours or until firm before cutting into 1-2 inch squares.", "image": "img/candy-bar-fudge.jpg"}, {"slug": "caprese-salad-ii-serves-6", "title": "Caprese Salad II", "serves": "Serves 6", "category": "Salads", "date": "2022-02-25", "ingredients": ["**Dressing**", "¼ cup extra virgin olive oil", "2 tbsp champagne vinegar", "1 tbsp water", "2 tsp garlic and herb seasoning blend", "1 tsp erythritol", "1 tsp lemon zest", "¼ tsp salt", "**Salad**", "6 oz fresh ½” mozzarella balls(ciliegine)", "6.5 oz marinated artichoke hearts", "3 oz large pitted black olives, add more if you like", "6 oz grape tomatoes", "1 tsp garlic and herb seasoning blend"], "instructions": "In a small blender add all of the dressing ingredients and blend. Set aside.\nIn a medium bowl combine the mozzarella balls and tomatoes.\nDrain the artichoke hearts and the olives. Cut the artichoke hearts in half if they appear to be more than bite size. Add the hearts and olives to the tomatoes.\nPour half the dressing over the mixture and add the seasoning. Stir and add the remaining the dressing. Refrigerate until ready to serve.\nGive the mixture a good toss before serving.\nCalories 239 Carb 6.5 Fiber 2g", "image": "img/caprese-salad-ii-serves-6.jpg"}, {"slug": "caprese-salad-skewers", "title": "Caprese Salad Skewers", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 package grape tomatoes", "1 container of \"cherry\" size mozzarella balls", "1 package fresh basil, washed", "1 package appetizer size bamboo skewers", "1 bottle Cento balsamic glaze"], "instructions": "Place a mozzarella ball on the skewer and follow with a small piece of basil and then a grape tomato.\nContinue making the skewers up until the desired amount is on a serving dish in a single layer.\nDrizzle the balsamic glaze over the skewers and serve.", "image": "https://static.wixstatic.com/media/75d545_b20b8c9a30974f7ebf48d485f5570ab2~mv2.jpg"}, {"slug": "caprese-salad-with-balsamic-reduction-serves-4", "title": "Caprese Salad with Balsamic Reduction", "serves": "Serves 4", "category": "Salads", "date": "2022-02-25", "ingredients": ["1 cup balsamic vinegar", "¼ cup honey", "3 large ripe tomatoes, cut into ½” slices", "1 16oz fresh mozzarella, cut into ¼” slices", "salt and pepper, to taste", "fresh basil leaves", "¼ cup extra virgin olive oil"], "instructions": "In a small saucepan over high heat, combine the vinegar and honey and bring to a boil. Reduce the heat to low and simmer until the mixture has reduced to 1/3 cup. Set aside.\nArrange the slices of tomato, mozzarella and basil leaves on a platter alternating to create a decorative salad. Season with the salt and pepper and drizzle with the balsamic reduction.", "image": "https://static.wixstatic.com/media/75d545_87ebc43bae954ed69c5038528f62500d~mv2.jpg"}, {"slug": "caramel-apple-brownies", "title": "Caramel Apple Brownies", "serves": "", "category": "Desserts", "date": "2022-03-03", "ingredients": ["Brownies", "1 cup butter, softened", "2 cups sugar", "2 large eggs", "2 cups flour", "1 tsp baking powder", "2 tsp cinnamon", "2 granny smith apples, peeled and diced", "1 cup Kraft Caramel Bits", "Topping", "3 tbsp chilled butter, sliced", "1/3 cup brown sugar", "½ tsp cinnamon", "3 tbsp flour", "Preheat oven to 350º"], "instructions": "Butter a 9 x 13 glass casserole dish and set aside.\nWith an electric mixer, in a large bowl, mix the butter and sugar until creamy. Add the eggs one at a time until blended.\nAdd the flour, baking powder and cinnamon. Once mixed, fold in the apples.\nSpoon the batter into the prepared baking dish. Evenly top with the caramel bits and press slightly into the batter.\nIn a small bowl, mix all the topping ingredients together until crumbly. Spread evenly over the top of the batter.\nBake for 45 minutes or until lightly browned.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "carrot-turnip-casserole", "title": "Carrot Turnip Casserole", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["1 8oz package instant stuffing mix", "1 turnip, chopped", "2lbs carrots, chopped", "2 tbsps butter, melted", "2 tbsp brown sugar", "1 8oz Velveeta, grated", "2 tbsp milk", "**Preheat the oven to 350°**"], "instructions": "Lightly grease a 2qt casserole dish.\nPrepare the stuffing mix according to the package directions.\nPlace the turnips and the carrots in a pot with just enough water to cover. Bring to a boil and cook until tender. Drain and mash.\nMix in the butter and the brown sugar until melted.\nIn a medium microwaveable bowl melt the cheese. Stir in the milk and then add the cheese mixture to the turnips. Transfer to the prepared casserole dish.\nTop with the stuffing mixture and bake for 20 minutes or until golden brown.", "image": "https://static.wixstatic.com/media/75d545_e449e3f10846469794c75a1898052445~mv2.png"}, {"slug": "cauliflower-mash-serves-6", "title": "Cauliflower Mash", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2 small heads of cauliflower, cut up", "2 tbsp sour cream", "2 tbsp heavy cream", "1 ½ tbsp. butter", "1 tsp salt"], "instructions": "Add 2\" of water to a large pot with a steamer basket. Place the cauliflower in the basket and bring the water to a boil.\nCover and cook until tender. 10-12 minutes.\nPurée the cauliflower in a food processor in small batches.\nAdd the remaining ingredients and process until the mixture is smooth.\nServe immediately.\n**4.5 Net Carbs per serving**", "image": "img/cauliflower-mash-serves-6.jpg"}, {"slug": "cauliflower-rice-serves-8", "title": "Cauliflower \"Rice\"", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2 head of cauliflower", "2tbsp butter", "extra virgin olive oil", "salt and pepper to taste"], "instructions": "Remove the stem and leaves from the cauliflower and break into florets. Wash and drain.\nIn small batches add to a food processor and pulse until the cauliflower looks like rice. Remove to a bowl. Continue until all the cauliflower has been \"riced\".\nIn a large skillet, heat 2-3 tbsps of olive oil and add the butter. Place all the \"rice\" in the skillet and stir to coat with the oil and butter. Cook for 5-10 minutes. Season with salt and pepper to taste.\nServe.\nNet carb per serving: 5.6", "image": "https://static.wixstatic.com/media/75d545_572692ccc01d4bbfbcf576302af21388~mv2.jpg"}, {"slug": "celery-root-potato-and-pear-gratin-serves-6-8", "title": "Celery Root, Potato and Pear Gratin", "serves": "Serves 6-8", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["Unsalted butter", "½ large celery root", "6 tbsp extra virgin olive oil", "1 lb red potatoes", "2 large Bartlett pears", "sea salt and freshly ground black pepper", "¾ cup heavy cream", "1 large clove of garlic, mashed", "1 cup Gruyére cheese, grated", "2/3 cup freshly grated parmesan cheese", "1 tsp chopped fresh thyme"], "instructions": "Preheat the oven to 375°.\nLightly butter a shallow baking dish with the unsalted butter and set aside.\nPeel the celery root ad slice into ¼” thick slices. Heat the 2 tbsp of oil in a large skillet over medium heat and add the celery root. Cook, turning the pieces of celery root until they are lightly browned. About 10 minutes. Drain on a paper towel.\nPeel the potatoes and also slice into ¼” thick slices. Add another 2 tbsp of oil to the pan and repeat as for the celery root.\nPeel the pears and slice into ¼” thick slices. Add the remaining 2 tbsp of oil to the pan and again repeat as for the celery root and the potatoes.\nLightly season the celery root, potatoes, and pears with salt and pepper.\nHeat the cream and garlic in a small saucepan over medium high heat, until just simmering. Remove from the heat.\nIn a small bowl, combine the Gruyére, parmesan, thyme and 1 tsp each of salt and pepper.\nLayer the celery root in the prepared baking dish and sprinkle with 1/3 of the cheese mixture. Remove the garlic from the cream and drizzle ¼ of the cream over the cheese.\nLayer the potatoes on top and top with another 1/3 of the cheese mixture. Drizzle with another ¼ of the cream.\nLayer the pears n top and sprinkle with the remaining cheese. Drizzle with the remaining cream.\nCover the dish with foil and bake for 30 minutes. Then uncover and bake until the gratin is bubbly and browned.(5-10 more) Let cool 10-15 minutes before serving.", "image": "img/celery-root-potato-and-pear-gratin-serves-6-8.jpg"}, {"slug": "cheesecake-cranberry-bars-makes-2-dozen", "title": "Cheesecake Cranberry Bars", "serves": "Makes 2 ½ dozen", "category": "Desserts", "date": "2022-02-25", "ingredients": ["2 cups flour", "1 ½ cups quick oats", "¼ cup packed light brown sugar", "1 cup butter, softened", "2 cups white chocolate morsels", "1 8oz package cream cheese, softened", "1 (14oz) can sweetened condensed milk", "¼ cup fresh lemon juice", "1 tsp vanilla extract", "1 (14oz) can whole berry cranberry sauce", "2 tbsp cornstarch", "**Preheat the oven to 350°**"], "instructions": "Grease a 13 x 9 baking dish and set aside.\nIn a large bowl combine the flour, oats and brown sugar. Add the butter and mix until crumbly.\nStir in the morsels. Measure out 2 ½ cups of morsel mixture and set aside for the topping.\nPress the remaining mixture into the baking dish. A floured spoon will be helpful.\nIn another large bowl, beat the cream cheese until creamy with an electric mixer. Add the condensed milk, lemon juice and the vanilla. Mix until smooth.\nPour over the crust. Combine the cranberries with the cornstarch in a bowl and spoon over the cream cheese batter.\nSprinkle the reserved morsels over the cranberries.\nBake for 35-40 minutes or until the center is set. Cool.\nCover and refrigerate for at least 3 hours. When ready to serve cut into bars.", "image": "img/cheesecake-cranberry-bars-makes-2-dozen.jpg"}, {"slug": "cheesy-chili-dip", "title": "Cheesy Chili Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 lb. ground pork sausage", "1 heaping tbs. taco seasoning such as El Paso in packet", "¼ tsp. cayenne", "1 14 oz. can black beans, rinsed", "1 ½ cups chunky salsa from jar", "2 tbs. butter", "3 tbs. flour", "1 ¾ cups milk", "1 cup shredded sharp cheddar cheese"], "instructions": "In a large skillet, brown the sausage until lightly golden brown and crumbled into small pieces. Drain off excess oil. Add the taco seasoning, cayenne, black beans, & salsa. The consistency should be like a very thick chili. Set aside.\nMelt the butter in a small saucepan over medium high heat. Add the flour and stir to form a paste. Slowly stream the milk in a little bit at a time, whisking a little bit after each addition The sauce should thicken up gradually. Continue to whisk the sauce and keep heat on simmer as it starts to thicken. Stir in the cheese until melted. Add the cheese sauce to the chili in the skillet. Mix well to combine.\nTransfer to mini slow cooker or serving dish. You can keep it on stove until ready to serve so it stays warm. Don’t make it super hot, just warm so it stays thick. Can be heated in microwave too if you are taking it on the go to a party.", "image": "img/cheesy-chili-dip.jpg"}, {"slug": "cheez-it-chicken-serves-4", "title": "CheezIt Chicken", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["A 7oz box of Sunshine Cheezit crackers", "1 stick of butter", "1lb chicken breast thin filets"], "instructions": "Preheat the oven to 350°\nIn a blender crush the crackers to a fine crumb consistency. (if you have a few larger pieces it’s ok). Pour into a medium size bowl.\nIn another medium microwavable bowl melt the butter in the microwave.\nDip the chicken 1 piece at a time in the melted butter an then in the cracker crumbs, coating well. Place the chicken on a cookie sheet ( I like to use disposable foil sheets).\nBake for 30-35 minutes.\nGreat with chicken tenders also!", "image": "img/cheez-it-chicken-serves-4.jpg"}, {"slug": "cherry-blossom-martini", "title": "Cherry Blossom Martini", "serves": "", "category": "Beverage", "date": "2022-03-03", "ingredients": ["1 oz Favorite vodka", "2 oz Hakutsuru Sayuri Junmai Nigori", "-----------------------------------", "0.5 oz Grenadine", "----------------", "0.3 oz fresh squeezed lemon juice", "---------------------------------"], "instructions": "Place all ingredients in a martini shaker, shake and pour!\n----------------------------------------------------------", "image": "https://static.wixstatic.com/media/75d545_ec9093d7ee1d4ab4bed9b1ae8cb326f0~mv2.jpeg"}, {"slug": "chicken-and-stuffing-casserole-serves-8", "title": "Chicken and Stuffing Casserole", "serves": "Serves 8", "category": "Casserole", "date": "2022-03-30", "ingredients": ["1 cooked deli rotisserie chicken, shredded", "1 (10.5 oz) can cream of chicken soup", "1/3 cup light sour cream", "¾ cup light buttermilk", "1 cup chicken stock", "16 oz frozen mixed vegetables", "1 tsp salt", "½ tsp ground pepper", "1 tbsp poultry seasoning", "5 garlic cloves, minced", "½ large Vidalia onion, minced", "1 cup finely diced celery", "4 tbsp butter", "1 package of cornbread mix, prepared according to package directions for 8x8 pan", "1 (6oz) package Stove Top Chicken Stuffing mix", "Preheat oven to 350º"], "instructions": "Spray a 9 x 13 casserole dish with cooking spray and set aside.\nIn a large bowl, mix the chicken and the next 9 ingredients together. Spread the mixture into the bottom of the casserole dish.\nMelt the butter in a large skillet over medium high heat and add the onion and celery. Cook until the onion is translucent.\nAdd 1 ½ cup of water to the onion and celery and bring to a boil.\nRemove from the stove and add the stuffing mix; stir to combine.\nCube about half of the cornbread and place evenly across the top of the chicken mixture. Be generous!\nSpread the stuffing mixture evenly over the top of the cornbread and bake for 35 minutes or until bubbly and stuffing is golden brown.", "image": "https://static.wixstatic.com/media/75d545_e15232bc6d184082b1b96b21ca44b56d~mv2.jpeg"}, {"slug": "chicken-apple-sausage-pasta-serves-4", "title": "Chicken, Apple, Sausage Pasta", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1 tbsp olive oil", "1 lb Boars Head Honeycrisp Apple sausage, sliced", "½ of a large Vidalia onion, diced", "2 cloves of garlic, minced", "1 Granny Smith apple, coarsely chopped (you can leave the skin on)", "2 c chicken broth", "2(10 oz) cans Rotel Tomatoes with green chiles, drained", "½ cup heavy cream", "8-10 oz your favorite low carb rotini", "Salt & pepper, to taste", "8 oz Monterey Jack cheese, shredded", "¼ c thinly sliced green onions", "**Preheat the broiler**"], "instructions": "In a large oven safe skillet, add the olive oil and warm over medium high heat. Add the onions and the sausage and saute´ until browned.\nAdd the garlic and the apples and continue cooking until the apples begin to soften. About another minute or two more.\nAdd the chicken broth, cream, tomatoes and pasta. Stir well to combine, and season with the salt and pepper.\nCover the pan and simmer until the pasta is al dente.\nRemove the pan from the heat and stir in ½ cup of the cheese. Sprinkle the top with the remaining cheese and place under the broiler until the cheese is melted and begins to bubble.\nServe garnished with the sliced green onions.", "image": "img/chicken-apple-sausage-pasta-serves-4.jpg"}, {"slug": "chicken-apple-sausage-pasta-serves-8", "title": "Chicken Apple Sausage & Pasta", "serves": "Serves 8", "category": "Poultry", "date": "2022-03-07", "ingredients": ["2 tbsp olive oil", "22 oz chicken apple sausage, sliced", "½ of a large Vidalia onion, finely chopped", "3 cloves garlic, minced", "2 Granny Smith apples, cored and chopped", "2 cups chicken Rotel tomatoes & green chiles, undrained", "2 cups chicken stock", "2/3 cup heavy cream", "10 oz whole wheat pasta", "1 ½ cup shredded Monterey jack cheese", "Salt & pepper, to taste", "3 green onions, sliced thin", "**Set the oven to broil.**"], "instructions": "In a large iron skillet, heat the olive oil over medium high heat.\nAdd the onion and sausage and cook until the sausage begins to brown.\nAdd the apples and the garlic and cook until heated through.\nAdd the chicken stock, tomatoes, cream and pasta. Season with the salt & pepper to taste and bring to a boil.\nReduce the heat to medium low and cover. Let the mixture cook until the pasta is cooked al dente. Stirring occasionally so all the pasta gets cooked.\nRemove from the heat, add ½ the cheese and stir until well combined. Top with the remaining cheese and place under the broil (about 6” from element) until the cheese has melted.\nGarnish with green onions and serve.\nThe pasta can be made earlier in the day and then baked without cheese topping, uncovered at 350º for about 30 minutes. Remove from the oven, add the cheese topping and broil until the cheese has melted.", "image": "https://static.wixstatic.com/media/75d545_8ddb9320265c43048ba516a2ecc9071b~mv2.jpeg"}, {"slug": "chicken-asparagus-stir-fry-serves-8", "title": "Chicken & Asparagus Stir Fry", "serves": "Serves 8", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["2 cup uncooked rice", "4 tbsp vegetable oil", "2lb boneless, skinless chicken breast, cut into ½\" strips", "3 medium red bell peppers, cut into thin strips", "2 bunch of asparagus, cut diagonally into 1\" pieces", "1 bottle of stir fry sauce (can use more if you wish)"], "instructions": "Cook the rice according to the package directions.\nHeat 2 tbsp of oil in a large skillet over medium high heat until hot. Stir fry the chicken until no longer pink in the center. Remove to a bowl and set aside.\nHeat the remaining 2 tbsp of oil until hot and stir fry the peppers and asparagus. About 1 minute. Reduce the heat to medium, cover and cook for 2 minutes or until the vegetables are crisp tender; stirring once or twice.\nStir in the chicken and the sauce and heat through. Serve immediately over rice.", "image": "img/chicken-asparagus-stir-fry-serves-8.jpg"}, {"slug": "chicken-breasts-florentine-serves-4", "title": "Chicken Breasts Florentine", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4 thin sliced chicken breasts", "flour", "2 eggs, beaten", "½ stick butter", "2(10oz) bags fresh baby spinach", "parmesan cheese, grated", "4 slices mozzarella", "½ cup chicken broth", "½ cup white wine", "½ cup lemon juice, freshly squeezed"], "instructions": "Preheat the oven to 325°.\nCook the spinach according to directions and drain.\nDip the filets in flour and then in egg wash. In a large skillet, sauté in butter for about 4 minutes turning and lightly browning the chicken. Remove to a large flat casserole dish and top each with cooked spinach.\nSprinkle each filet with parmesan cheese and top with a slice of mozzarella.\nAdd the chicken broth to the same pan used to sauté the filets to deglaze. Then add the wine and lemon juice. Stir. Pour over the chicken.\nBake for 30 minutes. The cheese should be melted and the filets heated thoroughly.\nGoes will with pasta as a side.", "image": "img/chicken-breasts-florentine-serves-4.jpg"}, {"slug": "chicken-cobbler-serves-8", "title": "Chicken Cobbler", "serves": "Serves 8", "category": "", "date": "2024-01-30", "ingredients": ["1 stick of butter, melted", "1 rotisserie chicken, shredded", "1 12oz bag frozen mixed vegetables", "1 tbsp Dano’s seasoning", "1 10.5 oz can cream of chicken soup", "2 cups chicken stock", "1 box (11.36oz) Cheddar Bay Biscuit mix (set seasoning packet aside)", "2 cups whole milk", "½ cup shredded cheddar cheese"], "instructions": "Topping\n2 tbsp butter, melted\nSeasoning packet from biscuit mix\nPreheat the oven to °350\nPour the melted butter into a 9 x 13 baking dish and make sure to evenly coat the bottom of the dish.\nLayer the cooked chicken on top of the butter, then a layer of the frozen vegetables.\nSprinkle the Dano’s seasoning over the top. Do not stir.\nIn a mixing bowl, combine the cream of chicken soup and the chicken broth with a whisk and then pour into the baking dish.\nIn another mixing bowl, combine the biscuit mix, whole milk and cheddar cheese; stir until well mixed.\nSpread the biscuit mix over the top of the chicken and vegetables.\nBake for 50-60 minutes or until the top has browned and the cobbler is cooked through.\nIn a small bowl, mix the 2 tbsp of melted butter and the seasoning packet contents.\nAfter you remove the cobbler from the oven, brush the top with the seasoned butter and let stand for about 10 minutes before serving.", "image": "img/chicken-cobbler-serves-8.jpg"}, {"slug": "chicken-edamame-salad-serves-6", "title": "Chicken Edamame Salad", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["For the dressing:", "2 teaspoon minced garlic", "1/2 cup reduced-sodium soy sauce", "4 tablespoons rice vinegar", "3 tablespoons honey", "1/4 of ground ginger", "For the salad:"], "instructions": "2 cup cooked chicken breast, chopped or shredded( I used a store cooked rotisserie chicken)\n2 cup shelled edamame beans, ready to eat or frozen cooked according to package directions and cooled\n2 medium red bell peppers, diced\n1 1/2 cup shredded carrots( used store shredded)\n4 cups coleslaw mix\n2 cups shredded red cabbage\n¾ cup chopped cilantro\n6 green onions, chopped, optional\n1/2 cup toasted slivered almonds,\n2 tablespoon sesame seeds\nDIRECTIONS\nMix the garlic, soy sauce, rice vinegar, honey, and ginger in a small bowl to make the dressing.\nPlace the edamame, red peppers, carrots, red cabbage and coleslaw mix in a large bowl. Toss to combine.\nAdd the chicken and toss.\nAdd the dressing to the salad, and combine until the salad is fully coated. Add the cilantro, and mix again.\nSprinkle the green onions, toasted almonds, and sesame seeds and toss again.\nServe immediately, or let it chill for the best taste possible.", "image": "https://static.wixstatic.com/media/75d545_af0f028886a84102ab68e5b865f3adae~mv2.jpg"}, {"slug": "chicken-fiesta-salad-serves-6", "title": "Chicken Fiesta Salad", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["3 skinless, boneless chicken breast halves", "1 ½ (1.27oz) packets dry fajita seasoning, divided", "1tbsp + 1 ½ tsp vegetable oil", "1 ½ (15oz) cans black beans, drained and rinsed", "1 ½ (11oz) cans Green Giant Mexicorn", "¾ cup salsa", "1 ½ package of mixed greens", "1 ½ onion, diced", "1 ½ containers of grape tomatoes, halved"], "instructions": "Rub the chicken evenly with ½ of the fajita seasoning.\nIn a large skillet heat the vegetable oil over medium heat and cook the chicken for 8 minutes on each side or until the chicken is no longer pink in the center. Remove from the pan and slice.\nIn a large saucepan, mix the beans, corn, salsa, the remaining fajita seasoning and heat over medium heat until warm.\nIn a large salad bowl combine the mixed greens, onion and tomatoes.\nTo serve, arrange the greens on a plate and set the sliced chicken on top. Add the bean and corn mixture to the top of the chicken..", "image": "img/chicken-fiesta-salad-serves-6.jpg"}, {"slug": "chicken-florentine-meatballs-with-sauce-about-24-meatballs", "title": "Chicken Florentine Meatballs with Sauce About 24 meatballs", "serves": "", "category": "", "date": "2024-02-12", "ingredients": ["**Sauce**", "3 tbsp extra virgin olive oil", "1 medium Vidalia onion, minced", "1 tbsp freshly minced garlic", "2 28oz cans San Marzano crushed tomatoes", "1 (4.6oz) tube of tomato paste", "1 ½ tsp kosher salt", "1 tsp dried oregano", "**Meatballs**", "2lb ground chicken breast", "2 large eggs", "2 garlic cloves, minced", "10 cups baby spinach, finely chopped", "2 cups panko", "1 cup whole milk", "½ cup freshly grated Parmesan cheese", "2 tsp kosher salt", "½ tsp fresh ground pepper", "**Preheat the oven to 400°**"], "instructions": "Prepare the sauce. Heat the olive oil in a large saucepot, over medium high heat, and add the garlic and onion. Sauté until the onions are translucent and being caring not to burn the garlic.\nAdd the tomatoes, tomato paste, salt and oregano. Stir to combine and lower the heat. Let the sauce simmer while you make the meatballs.\nLine 2 baking sheets ( I used foil cookie sheets) with parchment paper and give them a nice spray of cooking spray (I used olive oil cooking spray).\nIn a large bowl combine the ground chicken, eggs, garlic, chopped spinach, panko, milk, Parmesan cheese, salt and pepper.\nRoll into 1-2 inch meatballs and place on the prepared baking sheets.\nBake for about 20 minutes and then turn the oven to broil. Cook for about another 2-3 minutes or until golden in color.\nServe with the sauce alone, topped with Parmesan or make your favorite pasta and serve over pasta with sauce.", "image": "img/chicken-florentine-meatballs-with-sauce-about-24-meatballs.jpg"}, {"slug": "chicken-gnocchi-soup-serves-6-8", "title": "Chicken Gnocchi Soup", "serves": "Serves 6-8", "category": "", "date": "2024-01-30", "ingredients": ["1 tbsp olive oil", "2 tbsp butter", "1 tbsp fresh mince garlic", "¼ cup small diced Vidalia onion", "¼ cup small diced celery", "½ cup small diced carrots", "1 tsp Italian seasoning", "½ tsp freeze dried parsley", "¼ cup flour", "½ cup white wine", "8 cups chicken broth", "1 rotisserie chicken, shredded", "½ tsp kosher salt", "½ tsp ground black pepper", "16 oz refrigerated gnocchi", "1½ cup Half and Half", "5oz container baby spinach", "Salt & pepper, to taste", "Parmesan cheese, for garnish"], "instructions": "In a large saucepot over medium heat, melt the butter with the olive oil and add the garlic, celery, onion, carrots, Italian seasonings and the parsley. Cook until the vegetables are tender.\nSprinkle the flour over the vegetables and mix until blended.\nAdd the wine and stir, making sure that there are no lumps. Let simmer for a few minutes and add in the chicken broth and the chicken.\nBring the soup to a boil, lower the heat and in the gnocchi.\nStir in the half & half and the spinach and season to taste.", "image": "https://static.wixstatic.com/media/75d545_6b432e1fa40649f3a1b45a93df6cdb5c~mv2.jpeg"}, {"slug": "chicken-imperial", "title": "Chicken Imperial", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1lb chicken fillets", "flour", "½ cup butter", "1lb small mushrooms, quartered", "1 tbsp mince onion", "1 cup heavy cream", "¼ cup cooking sherry", "1 ½ tsp salt", "1/8 tsp pepper"], "instructions": "Add ¼ cup flour to a medium bowl and coat the chicken with the flour.\nIn a large skillet over medium high heat, melt the butter and cook the chicken a few pieces at a time until lightly browned on both sides. Set the chicken aside.\nIn the pan drippings, over medium heat cook the mushrooms and onion until tender; stirring frequently. Stir in the cream sherry, salt and pepper and blend well.\nReturn the chicken to the skillet, reduce the heat to low; cover and simmer for 20 minutes or until the chicken is fork tender.\nRemove the chicken to a warm platter. In a cup, blend 1 tbsp of flour with 2 tbsp of water and gradually add it to the pan liquid, stirring constantly until the mixture has thickened.\nServe the sauce over the chicken.", "image": "img/chicken-imperial.jpg"}, {"slug": "chicken-in-a-packet-serves-4", "title": "Chicken in a Packet", "serves": "Serves 4", "category": "Main Dish", "date": "2022-03-01", "ingredients": ["4 tbsp butter", "4 split chicken breast, bone in, skinless", "3 cups herbed stuffing", "½ cup water", "1 large golden delicious apple, cored and quartered", "Paprika", "Salt& pepper"], "instructions": "Heat oven to 450º\nTear off 4 12” in length pieces of foil and fold each in half cross wise.\nGrease the bottom and the top sides inside the fold.\nPlace 1 tbsp of butter in the center of each bottom half of the folded foil and top with ¾ cup of stuffing.\nSprinkle the stuffing with 2 tbsp of water and place a chicken breast on top.\nSeason the breast with paprika, salt & pepper, and tuck an apple wedge alongside of each breast.\nFold the foil closed and pinch along the edges to seal tight. Arrange the packets on a large baking sheet and bake for 35 minutes.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "chicken-lettuce-wraps-ii-serves-6", "title": "Chicken Lettuce Wraps II", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["3 tbsp peanut oil", "2lb ground chicken", "6 cloves garlic, minced", "1 large Vidalia onion, minced", "¾ cup Hoisin sauce", "6 tbsp soy sauce", "3 tbsp rice wine vinegar", "¾ tsp ground ginger", "3 tbsp Sriracha", "2 5oz cans diced water chestnuts, drained", "6 green onions, sliced thin", "Salt & pepper to taste", "2 heads Bibb lettuce"], "instructions": "Heat the oil in a large saucepan and add the ground chicken; cook until browned. Make sure to crumble the meat as it cooks. Drain.\nAdd the chicken back to the pan and add the garlic, onion, hoisin, soy sauce, rice wine vinegar, ginger and Sriracha. Cook until the onions are translucent.\nStir in the water chestnuts and green onions; cook for another minute or 2. Season with the salt and pepper to taste and serve with the Bibb lettuce and enjoy!", "image": "img/chicken-lettuce-wraps-ii-serves-6.jpg"}, {"slug": "chicken-noodle-casserole-serves-8-10", "title": "Chicken Noodle Casserole", "serves": "Serves 8-10", "category": "Casserole", "date": "2023-03-13", "ingredients": ["12oz bag of egg noodles, your preference in width", "2 10.5 oz cans of cream of chicken soup", "1 cup whole milk", "1 ½ cup shredded cheddar cheese", "1 tsp ground black pepper", "½ tsp kosher salt", "1 rotisserie chicken from deli, shredded", "½ of a Vidalia onion, diced small", "2 stalks of celery, diced small", "1 12 oz bag of frozen peas and carrots, thawed", "2 ¼ cup finely crushed Ritz crackers", "3 tbsp butter, melted", "Chopped fresh parsley, chopped"], "instructions": "**Preheat the oven to 375°**\nBoil water in a large pot and add some salt and noodles. Cook according to package directions for al dente. Drain and set aside.\nIn a large bowl, combine the chicken soup, milk, cheese, salt and pepper.\nAdd the chicken to the soup mixture and combine. Stir in the onion, celery, peas and carrots.\nAdd the egg noodles to the chicken mixture and gently fold in to combine.\nIn a separate bowl, combine the cracker crumbs with the melted butter until all crumbs are coated with the butter.\nSpread the chicken mixture evenly into a 13 x 9 baking dish and top with the cracker crumbs.\nBake for 30-35 minutes or until the casserole is heated through and the cracker crumbs are lightly browned.\nGarnish with the parsley and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "chicken-noodle-casserole-with-fried-onion-topping", "title": "Chicken Noodle Casserole with Fried Onion Topping", "serves": "", "category": "Casserole", "date": "2023-10-25", "ingredients": ["Serves 6-8", "4 cups regular egg noodles", "1 rotisserie chicken, shredded", "2 (10.75 oz) cream of chicken soup", "2 ½ cup milk", "4 cups French’s French Fried Onions", "10 oz bag frozen mixed vegetables", "2 ½ cup finely shredded cheddar cheeses", "2 tbsp Badia Complete Seasoning", "**Preheat the oven to 350°**"], "instructions": "Spray a 2qt casserole dish with cooking spray and set aside.\nCook the noodles according to the package directions and set aside.\nIn a large mixing bowl, combine the chicken breast, soup, milk, 2 cups fried onions and frozen vegetables.\nAdd the cooked noodles and 1 ½ cup of cheese. Stir to combine.\nPour the chicken mixture into the prepared casserole, sprinkle with the seasoning and cover with foil; bake for 30 minutes.\nRemove the casserole from the oven and sprinkle with the remaining fried onions and cheese.\nBake for another 5 minutes or until the cheese has melted.", "image": "https://static.wixstatic.com/media/75d545_f3264cea912149f3a1b275cfb2bd7c5b~mv2.png"}, {"slug": "chicken-parmesan-casserole-serves-8", "title": "Chicken Parmesan Casserole", "serves": "Serves 8", "category": "", "date": "2024-01-30", "ingredients": ["1lb penne pasta", "1 rotisserie chicken, shredded", "3 cups shredded mozzarella cheese", "2 14oz cans petite diced tomatoes, drained", "1 cup panko", "1 tbsp freeze dried parsley", "1 cup grated parmesan cheese", "3 cloves garlic, minced", "1 tsp oregano", "Ground black pepper, to taste", "Kosher salt", "5 tbsp butter, melted", "32oz jar Rao marinara sauce", "fresh basil, cut chiffonade style"], "instructions": "Preheat oven to °425\nBring a large pot of water to a boil and cook the pasta until al dente. Before draining, reserve 1 cup of the pasta water.\nDrain the pasta and set aside.\nIn a medium bowl, combine the chicken and 2 cups of the mozzarella. Set aside.\nIn a small bowl, combine the panko, parmesan, garlic, oregano, parsley, 1 tsp salt, and pepper to taste. Add the melted butter and mix until blended.\nPlace the chicken, drained tomatoes, marinara, pasta and pasta water into a 9 x 13 baking dish and mix together.\nSprinkle the remaining cup of mozzarella over the top of the mixture and then top with the panko mixture.\nBake until the panko is lightly browned, about 25 minutes.\nLet cool for 10 minutes and serve garnished with the fresh basil", "image": "https://static.wixstatic.com/media/75d545_fe7eee1d79e445909799a1839e2cc4b9~mv2.jpg"}, {"slug": "chicken-piccata-and-spinach-pasta-serves-4", "title": "Chicken Piccata and Spinach Pasta", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["Garlic marinated chicken breasts sautéed and served over angel hair pasta in a lemon wine sauce with vegetables.", "**Chicken and Marinade**", "2 cloves of garlic, minced", "4 tbsp extra virgin olive oil", "2 tbsp chopped fresh parsley", "3 tbsp fresh lemon juice", "1/8 tsp pepper", "1 ½ lb boneless chicken breast, cut into 2” strips or 1” chunks"], "instructions": "Place the chicken in a large ziploc bag. Mix the all of the remaining ingredients from above in a small bowl and pour over the chicken. Marinate for at least 1 hour.\nSauté the chicken until no longer pink, and remove to a warm dish.\n**Sauce and Pasta**\n1 cup white wine\n1 cup chicken broth\n1 cup sliced mushrooms\n2 tsp of seasoned salt\n1 tsp garlic powder\n1 medium onion, chopped\n1 medium red pepper, chopped\n2-3 cups fresh baby spinach, chopped\n3 tbsps fresh lemon juice\n2 tbsp corn starch\n2 tbsp water\n3 tbsp butter\n1 tbsp fresh chopped parsley\n1 ½ tsp dried basil\n½ lb angel hair pasta\n1 tsp extra virgin olive oil\nIn a medium saucepan, cook the wine over medium high heat until 1/3 of the wine has evaporated. Add the chicken broth, mushrooms, onion, red pepper, spinach, salt and garlic powder. Simmer 4-5 minutes. Add the lemon juice and continue cooking for 2 minutes.\nIn a glass measuring cup mix the water and corn starch until dissolved. Add the cornstarch mixture to the sauce stirring constantly until thickened. Immediately remove from the heat. Add the butter, parsley, and basil stirring until the butter has melted.\nCook the pasta according to package directions with the olive oil. Add the chicken to the sauce mixture and simmer while the pasta is cooking , stirring frequently.\nArrange the pasta on a platter or individual serving plates topped with the sauce and chicken mixture.\nGarnish with grated parmesan cheese and chopped parsley if desired.", "image": "img/chicken-piccata-and-spinach-pasta-serves-4.jpg"}, {"slug": "chicken-piccata-serves-4", "title": "Chicken Piccata", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4 thin sliced chicken breast", "1 stick butter", "1 cup flour", "1 tsp salt", "½ tsp pepper", "1 cup milk", "¾ cup dry white wine", "1-2 lemons", "1-2 tsp capers", "fresh curly parsley"], "instructions": "Ina large skillet, melt the butter over low heat. While the butter is melting, combine the flour, salt and pepper in a shallow bowl.\nPlace the milk in a shallow bowl. Dip each chicken breast in the milk and then coat evenly with the flour mixture. Add to the skillet and sauté over medium heat until browned and cooked through, turning often. (add more butter if needed)\nRemove the chicken to a warm plate and prepare the sauce.\nTurn the heat up to medium high and deglaze the pan with the wine, stirring constantly to loosen all the browned bits. Turn the heat to medium low and continue to cook, stirring often.\nSqueeze the juice from ½ of a lemon into the sauce. Add the capers(to taste) and continue to cook until the sauce has thickened.\nYou should taste the sauce frequently through this process and add more wine or lemon if necessary.\nWhen the sauce has thickened add the chicken back to the pan and turn to coat.\nTo serve, remove to a serving platter and drizzle with the sauce. Garnish with chopped fresh parsley and lemon slices", "image": "img/chicken-piccata-serves-4.jpg"}, {"slug": "chicken-pot-pie-i", "title": "Chicken Pot Pie II", "serves": "", "category": "Main Dish", "date": "2022-12-02", "ingredients": ["1 can cream mushroom soup", "1 can cream chicken soup", "1 12 bag frozen mixed vegetables", "Handful of Badia Complete Seasoning", "1 rotisserie chicken shredded", "1 Pillsbury pie crust", "1 box frozen phyllo dough", "Butter, melted"], "instructions": "Preheat 425°\nUnroll and lay pie crust into pie plate.\nIn a large bowl combine soup, seasoning, vegetables and chicken.\nPour into crust.\nCarefully peel and separate phyllo sheets from package and lightly crumple into balls. Place the balls on top of the vegetable mixture and baste with butter.\nBake for 25 minutes", "image": "https://static.wixstatic.com/media/75d545_51fb3abe578846f59f073a51c5a8bc4a~mv2.jpeg"}, {"slug": "chicken-pot-pie-serves-6", "title": "Chicken Pot Pie", "serves": "Serves 6", "category": "Casserole", "date": "2022-03-15", "ingredients": ["1 package Pillsbury pie crust", "1 (10 oz) can cream of chicken with herbs soup", "1 deli roasted rotisserie chicken", "3 cups frozen mixed vegetables", "1 cup chicken broth", "¾ cup light buttermilk", "¼ cup chardonnay", "1 ½ tbsp cornstarch", "Preheat oven to 400º"], "instructions": "Lightly grease an 11 x 7 casserole dish and set aside.\nShred the chicken to make 3 cups of meat.\nIn a large bowl, combine the soup, chicken, mixed vegetables, broth, buttermilk, wine and cornstarch. Mix well.\nPlace the chicken and vegetable mixture into the prepared baking dish.\nUnroll 1 pie crust onto a lightly floured surface and roll into a 14 x 12 rectangle. Place the dough on top of the casserole and fold under the edges. Crimp the edges and cut 4 slits in the top for venting.\nBake for 45 minutes or until golden on top and bubbling underneath. If the edges brown before the middle cover them with foil for the remainder of the cooking time.\nRemove from the oven and cool for about 10 minutes.\nServe and enjoy!", "image": "https://static.wixstatic.com/media/75d545_928f71f93b914eacb0a396f991fb5b66~mv2.jpeg"}, {"slug": "chicken-rice-supper", "title": "Chicken Rice Supper", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["¼ cup butter", "1/3 cup flour", "1 ½ tsp salt", "1/8 tsp pepper", "1 ½ cup milk", "1 cup chicken broth", "2 cups chicken, cut up", "1 ½ cup wild rice", "1/3 cup chopped green pepper", "1 cup sliced mushrooms", "**Preheat the oven to 350°**"], "instructions": "Heat the butter in a 2qt saucepan until melted. Stir in the flour, salt and pepper. Cook over low heat stirring constantly until bubbly. Remove from the heat.\nStir in the milk and the broth. Return to heat and bring to a boil. Stir for 1 minute and add the remaining ingredients.\nPour into an ungreased 2qt casserole dish. Bake uncovered for 40-45 minutes. The casserole should be bubbly when ready.", "image": "img/chicken-rice-supper.jpg"}, {"slug": "chicken-scampi-serves-3", "title": "Chicken Scampi", "serves": "Serves 3", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["½ cup butter", "¼ cup extra virgin olive oil", "1tbsp fresh parsley, chopped", "1tbsp fresh basil, chopped", "2tsp fresh oregano, chopped", "3 cloves garlic, minced", "1tsp salt", "1tbsp fresh squeezed lemon juice", "4 thin sliced chicken filets, sliced into 1” pieces"], "instructions": "In a large skillet, heat the butter and the oil over medium high heat until the butter melts.\nAdd the parsley, basil, oregano, garlic and salt to the skillet. Stir in the lemon juice.\nAdd the chicken and sauté for about 3 minutes or until white. Lower the heat and cook for 10 minutes. Additional butter or olive oil can be added if needed.\nServe over pasta or rice.", "image": "img/chicken-scampi-serves-3.jpg"}, {"slug": "chicken-shrimp-sausage-jambalaya", "title": "Chicken, Shrimp & Sausage Jambalaya", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4lb thin cut chicken filets, cut into 2” pieces", "2 tsp creole seasoning, or more to taste", "2 tbsp vegetable oil", "1 large onion, chopped", "6 oz Andouille sausage, sliced", "1 red pepper, cut into small strips", "1 yellow pepper, cut into small strips", "1 green pepper, cut into small strips", "1 tbsp fresh thyme leaves", "2 tbsp flour", "¼ tsp cayenne pepper", "1 cup of long grain rice(Texmati)", "3 cups chicken broth", "1 16 oz can fire roasted tomatoes, undrained", "3/4lb uncooked large shrimp, peeled and deveined", "chopped fresh parsley for garnish"], "instructions": "In large bowl toss the chicken pieces with the creole seasoning. In a large pot over medium high heat, heat the oil and add the sausage. Brown for about 2 minutes and then remove to a plate.\nAdd the chicken to the pot and cook until lightly browned, stirring often. About 4 minutes. Remove to a plate.\nAdd the onion, peppers, thyme, flour and cayenne to the pot and cook, stirring often until the onions are translucent.\nStir in the rice, broth and tomatoes and bring to a boil. Reduce the heat to low and simmer for 10 minutes.\nStir in the chicken and the sausage. Cover and continue to cook for about 10 minutes.\nStir in the shrimp, cover and cook for another 10 minutes or until the shrimp is cooked through. Stir occasionally.\nServe the Jambalya garnished with the fresh parsley. Serve with warm cornbread.", "image": "img/chicken-shrimp-sausage-jambalaya.jpg"}, {"slug": "chicken-spinach-salad-serves-2", "title": "Chicken Spinach Salad", "serves": "Serves 2", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["3 cups torn fresh baby spinach", "1 cup shredded red cabbage", "¼ cup thinly sliced Vidalia onion", "1 cup cooked chicken, cut into small strips", "2tbsp salad oil", "2tbsp cider vinegar", "2tbsp light brown sugar", "2 slices of bacon, cooked and crumbled", "1 hard boiled egg, chopped (optional)"], "instructions": "Ina large mixing bowl combine the spinach, cabbage, chicken and onion. Cover and chill while you make the dressing.\nIn a small bowl combine the salad oil, vinegar, and brown sugar. Stir until the sugar has dissolved.\nPour the dressing over the spinach mixture and toss to coat. Spoon the salad onto plates and sprinkle with the egg and bacon.", "image": "img/chicken-spinach-salad-serves-2.jpg"}, {"slug": "chili-dip-serves-4", "title": "Chili Dip", "serves": "Serves 4", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 can Hormel Chili (no beans)", "3 oz cream cheese", "8 oz mozzarella, shredded", "sliced black olives, to taste"], "instructions": "Microwave all ingredients together in a microwavable bowl on high for 6 minutes. Halfway through the cooking time, remove from the microwave to stir.\nServe with tortilla chips.", "image": "img/chili-dip-serves-4.jpg"}, {"slug": "chili-rubbed-tilapia-serves-4", "title": "Chili Rubbed Tilapia", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-25", "ingredients": ["4 Tilapia filets", "4 tbsp chili powder", "1 tsp garlic powder", "½ tsp salt", "2 tbsp extra virgin olive oil"], "instructions": "In a pie plate or dinner dish combine the chili powder, garlic powder and salt.\nDredge the fish in the spice mixture to coat.\nHeat the oil in a large pan over medium high heat. Add the fish and cook until flaky turning halfway through the cooking process. Should be about 6-8 minutes in total.\nServe with fresh vegetables.\n**2.0 Net Carbs per filet**", "image": "img/chili-rubbed-tilapia-serves-4.jpg"}, {"slug": "chili-serves-12", "title": "Chili", "serves": "Serves 12", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["2lb lean ground beef", "1lb bulk Italian sausage", "3 15oz cans chili beans, drained", "1 15oz can chili beans in spicy sauce", "2 28oz cans diced tomatoes with liquid", "1 6oz can tomato paste", "1 Vidalia onion, diced", "3 stalks celery, diced", "1 green bell pepper, diced", "1 red bell pepper, diced", "2 green Chile peppers, diced", "1 tbsp bacon bits", "4 cubes beef bouillon", "½ cup beer", "¼ cup chili powder", "1tbsp Worcestershire sauce", "1 tbsp minced garlic", "1 tbsp dried oregano", "2 tsp ground cumin", "2 tsp hot pepper sauce", "1 tsp dried basil", "1 tsp salt", "1 tsp black pepper", "1 tsp cayenne pepper", "1 tsp paprika", "1 tsp sugar"], "instructions": "Ina large soup or pasta pot over medium high heat, cook the ground beef and sausage until browned. Drain the grease.\nAdd the beans, tomatoes and tomato paste to the meat. Stir in the onion, celery, peppers, bacon bits, bouillon and beer; mix well. Add the chili powder, Worcestershire, garlic, oregano, cumin, hot sauce, basil, salt, pepper, cayenne, paprika and sugar. Stir and cover.\nSimmer over low heat for 2 hours, stirring occasionally.\nAdd additional spice to taste. Serve garnished with shredded cheddar cheese.\nServe with corn chips or corn bread.", "image": "img/chili-serves-12.jpg"}, {"slug": "chinese-chicken-salad-serves-4", "title": "Chinese Chicken Salad", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1lb chicken filets", "2 tbsp soy sauce", "1 tsp sesame oil", "¼ tsp white pepper", "4 cups chopped romaine lettuce", "1 cup shredded red cabbage", "1/3 cup shredded carrot", "½ cup edamame", "2 green onions, thinly sliced", "¼ cup chow mein noodles", "¼ cup sliced almonds", "**Dressing**", "¼ cup + 2tbsp rice wine vinegar", "1 clove garlic, minced", "1 tbsp sesame oil", "1 tbsp Truvia (artificial sweetener)", "1 tsp minced ginger", "1 tsp soy sauce", "**Preheat the oven to 350°**"], "instructions": "In a small bowl, make the dressing. Whisk all the dressing ingredients together and set aside.\nIn a large Ziploc bag combine the chicken with the soy sauce, sesame oil, and white pepper. Marinate for at least 30 minutes and turn the bad occasionally.\nAdd the chicken and the marinade to a glass baking dish and bake for approximately 15 minutes or until cooked through. Cool.\nDice the chicken into bite size pieces.\nIn a large salad bowl combine the romaine lettuce, red cabbage, carrots, edamame, green onions and the chicken.\nPour the dressing over the salad and toss. Top with the chow mein noodles and sliced almonds. Serve.\nNet carbs per serving: 9.3", "image": "img/chinese-chicken-salad-serves-4.jpg"}, {"slug": "chocolate-chip-banana-bread", "title": "Chocolate Chip Banana Bread", "serves": "", "category": "Breads & Stuffings", "date": "2022-03-22", "ingredients": ["3 ripe bananas", "1/3 cup melted butter", "½ cup sugar", "1 egg, beaten", "2 tsp vanilla extract", "1 tsp baking soda", "½ tsp salt", "1 ½ cup flour", "½ cup mini chocolate morsels", "½ chopped walnuts", "Preheat oven to 350º"], "instructions": "Grease a loaf pan and set aside.\nIn a large mixing bowl, mash the bananas and add the butter. Stir to combine.\nAdd the sugar, egg, vanilla extract, baking soda, salt and flour. Stir until blended and the batter appears smooth. (there will be some lumpiness due to the bananas)\nAdd the chocolate chips and walnuts and stir.\nPour the batter into the prepared baking dish and bake for 50 minutes. Cool for 10 minutes and turn onto a wire cooling rack.\nCool completely before slicing.", "image": "https://static.wixstatic.com/media/75d545_f3f20b7225b64e7c8d5eb6b00ee17d92~mv2.jpeg"}, {"slug": "chocolate-cream-pie", "title": "Chocolate Cream Pie", "serves": "", "category": "Desserts", "date": "2022-03-01", "ingredients": ["1 pkg Oreo cookies", "4 tbsp butter, melted", "½ tsp kosher salt", "½ cup milk", "1 ½ cup mini marshmallows", "1 8 oz bar milk chocolate, broken into pieces", "1 cup heavy whipping cream", "Preheat oven to 350º"], "instructions": "Add 24 Oreos to a food processor and process to fine crumbs.\nAdd the melted butter and salt to the crumbs and blend with a fork until the crumbs are evenly moistened.\nPlace the crumbs into a 9” pie plate and press into the bottom and up the sides with the back of a spoon.\nBake for 10-12 minutes, remove from oven to cool.\nIn a medium saucepan, over low heat, melt the chocolate and marshmallows with the milk until melted and blended; stirring occasionally.\nRefrigerate for about 20 minutes or the chocolate has thickened.\nBeat the cream in a medium COLD bowl with an electric mixer until soft peaks form.\nFold the refrigerated chocolate mixture into the cream until well blended and pour into the cooled pie crust.\nRefrigerate uncovered for at least 8 hours.\nGarnish with whipped cream and chocolate shavings.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "chocolate-fudge-bundt-cake", "title": "Chocolate Fudge Bundt Cake", "serves": "", "category": "Desserts", "date": "2023-06-26", "ingredients": ["1 package chocolate cake mix", "1 3.4 oz package instant chocolate pudding mix", "4 large eggs, room temperature", "1 cup sour cream", "¾ cup canola oil", "¾ cup brewed coffee", "½ cup sugar", "6 tbsp unsalted butter", "4 oz semisweet chocolate", "2 oz unsweetened chocolate", "**Preheat oven to 350°**"], "instructions": "Grease a 10” fluted tube pan (any style) and set aside.\nIn a large bowl, combine the first 7 ingredients and mix on low speed for 30 seconds and then on medium for 2 minutes.\nPour the batter into the prepared pan and bake for 45-50 minutes, or until a toothpick inserted near the center comes out clean.\nCool for 10 minutes and then remove from the pan and let cool on a wire rack.\nAfter the cake has completely cooled, prepare the glaze.\nPlace a bowl over lightly boiling water and add the butter, semisweet and unsweetened chocolate (in pieces) to the bowl.\nStir occasionally until the mixture is glossy and smooth. Cool slightly and drizzle over the cake.\nSprinkle with powdered sugar after the glaze has set. (optional)", "image": "https://static.wixstatic.com/media/75d545_37cb4c32203b445bab0db739fc9ea1ec~mv2.jpeg"}, {"slug": "chocolate-malt-ball-ice-cream-cake-betty-crocker", "title": "Chocolate Malt Ball Ice Cream Cake (Betty Crocker)", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["16 Oreos, crushed", "4 tbsp butter, melted", "1 cup chocolate fudge topping", "1.5 quart vanilla ice cream, slightly softened", "2 cup malted milk balls, coarsely chopped", "1 cup heavy cream", "¼ cup chocolate fudge topping, melted", "additional malt balls for decoration"], "instructions": "Preheat the oven to 350°\nMix the crushed cookies with the butter until the crumbs are moistened.\nPress the cookie crumbs into the spring form pan and bake for 8 to 10 minutes or until fragrant.\nCool before next step.\nSpread 1 cup of the fudge topping over the cake and freeze for 1 hour or until the topping is firm.\nIn a large bowl mix the softened ice cream and the chopped malt balls( I use a Ziploc bag and a rolling pin to break the candies). Spread over the cake and freeze for 4 hours or until the ice cream is firm.\nIn a chilled medium bowl, beat the cream with an electric mixer until stiff peaks form.\nLoosen the cake from the side of the pan with a sharp knife and remove the side of the pan.\nTop with the whipped cream and drizzle with the melted hot fudge topping. Garnish with additional malt balls.", "image": "https://static.wixstatic.com/media/75d545_9303b7025a59408985509ab2bf61a450~mv2.jpg"}, {"slug": "chocolate-nut-squares-makes-2lb", "title": "Chocolate Nut Squares", "serves": "Makes 2lb", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 cup semisweet chocolate chips", "1 cup milk chocolate chips", "1 tbsp shortening", "1 14oz package caramels", "2 tbsp butter", "3 tbsp milk", "2 cups coarsely chopped pecans"], "instructions": "Line an 8\" pan with foil and butter the foil.\nMelt all the chocolate chips with the shortening in a small heavy gauge saucepan over very low heat. Stir frequently.\nSpoon half the chocolate into the prepared pan and spread evenly over the bottom and ¼\" up the sides of the pan. Refrigerate until firm.\nIn a medium saucepan, combine the caramels, butter and milk over medium heat, stirring constantly. When the mixture is smooth stir in the pecans. Remove from the heat and cool to warm.\nSpread the caramel mixture over the chocolate.\nMelt the remaining chocolate mixture again over very low heat, stirring constantly. Spread over the caramel layer.\nRefrigerate until almost firm. Cut into squares and store in the refrigerator until ready to serve.", "image": "img/chocolate-nut-squares-makes-2lb.jpg"}, {"slug": "chocolate-raspberry-tart-serves-8-10", "title": "Chocolate Raspberry Tart", "serves": "Serves 8-10", "category": "Desserts", "date": "2022-02-25", "ingredients": ["2 packages (4oz size) Jell-O Vanilla pudding (stove top method) not instant", "1 ¾ cups half and half", "Chocolate crumb crust (see below)", "2 pints of raspberries", "2 squares Baker’s semi sweet chocolate"], "instructions": "Preheat the oven to 375°.\n**Chocolate crust:**\n6 squares semi sweet chocolate\n6tbsp butter\n2 cups graham cracker crumbs\nMicrowave the chocolate and butter together in a microwavable bowl on high for 2 minutes or until the butter has melted. Stir until the chocolate has completely melted.\nStir in the crumbs and mix well to combine. Press the crumb mixture onto the bottom and up the sides of a 9” tart pan with a removable bottom. Freeze for 10 minutes. Bake for 8 minutes.\nMicrowave the pudding mix and the half and half in a microwavable bowl for 3 minutes. Stir well and microwave for an additional 3 minutes. Stir again. Microwave for another minute or until the mixture begins to boil. Cover the surface with plastic wrap and refrigerate for at least 4 hours.\n**Saucepan preparation for the pudding**:\nCombine the pudding mix and the half and half in a 2quart saucepan. Cook over medium heat until the mixture comes to a boil; stirring constantly. Continue in the same manner as above.\nSpoon the pudding mixture into the crumb crust just before serving and arrange the raspberries on the top. Drizzle with melted chocolate.\n‘", "image": "img/chocolate-raspberry-tart-serves-8-10.jpg"}, {"slug": "christmas-french-toast-casserole-serves-8-10", "title": "Christmas French Toast Casserole", "serves": "Serves 8-10", "category": "Breakfast", "date": "2022-03-19", "ingredients": ["1 loaf brioche bread", "2 cups light brown sugar", "1 stick butter", "6 eggs", "2 cups whole milk", "1 tbsp Vanilla extract", "Fresh strawberries", "Fresh blueberries", "Powdered sugar"], "instructions": "Butter a 13 x 9 baking dish and set aside.\nCut the bread into triangles.\nIn a small saucepot, melt the butter and the brown sugar. Cook and stir until the mixture is thick and brown.\nIn a large bowl, whisk the eggs, vanilla and milk.\nSpread the brown sugar mixture onto the bottom of the prepared baking dish.\nLayer the bread in the prepared baking dish. Layer by leaning each triangle, long side down against one another. Like a fanned out deck of cards.\nPour the egg mixture over the bread and top with an even amount of strawberries and blueberries. Refrigerate overnight.\n**Preheat oven to 450º**\nBake the casserole for 30 minutes or until golden brown. Sprinkle with powdered sugar and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "cilantro-lime-dressing", "title": "Cilantro Lime Dressing", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-25", "ingredients": ["1/4 cup fresh lime juice ( 1 good sized lime)", "1/4 cup fresh cilantro", "1/3 cup honey", "1 garlic clove peeled & minced", "1 med sized jalapeno de-seeded de-ribbed", "3/4 grated fresh ginger", "2 teaspoon balsamic vinegar", "salt to taste ( I used 6 pinches of kosher salt)", "1/2 cup extra virgin olive oil"], "instructions": "Combine all ingredients in a food processor and pour over salad.", "image": "img/cilantro-lime-dressing.jpg"}, {"slug": "cinnamon-roll-french-toast-breakfast-serves-8-10", "title": "Cinnamon Roll French Toast Breakfast", "serves": "Serves 8-10", "category": "Breakfast", "date": "2022-03-01", "ingredients": ["2 cans of Pillsbury cinnamon rolls (17.5 oz) each", "½ cup butter, melted", "6 large eggs", "¼ cup whole milk", "3 tsp cinnamon", "1 ½ tsp nutmeg", "3 tsp vanilla", "½ cup pure maple syrup", "½ cup chopped pecans"], "instructions": "Separate the rolls from the icing and place the icing back into the refrigerator. Cut each roll into 4 pieces and place in a large bowl.\nPour the melted butter over the rolls and gently toss to coat. Add the rolls to a 13 x9 baking dish and set aside.\nIn a medium bowl, mix the eggs, milk, cinnamon, nutmeg and vanilla. Pour over the rolls.\nDrizzle the syrup over the rolls and evenly sprinkle the pecans over the top.\nCover the dish and refrigerate overnight.\n**Preheat oven to 375º**\nBake uncovered for 35-45 minutes or until heated through.\nRemove from the and let it cool slightly before spreading the reserved icing over the top.\nGreat Christmas morning treat!", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "clams-casino-serves-2", "title": "Clams Casino", "serves": "Serves 2", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["12 Little Neck clams, split", "¼ cup butter", "¼ cup of extra virgin olive oil", "1 clove garlic, minced", "½ red pepper, finely chopped", "½ green pepper, finely chopped", "2 tbsp fresh parsley, finely chopped", "2 tsp fresh lemon juice", "1 tsp dried oregano", "Bacon"], "instructions": "Preheat the oven to 425°.\nIn a saucepan combine the butter, olive oil, red pepper, green pepper, garlic, parsley, oregano and lemon juice. Cook until the vegetables are tender.\nSpoon the mixture onto each clam and top with a small piece of bacon.\nBake for 8-10 minutes or until the bacon is crisp.", "image": "img/clams-casino-serves-2.jpg"}, {"slug": "coconut-macadamia-encrusted-tilapia", "title": "Coconut Macadamia Encrusted Tilapia", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4 Tilapia filets", "14.5oz coconut milk", "¼ cup honey", "½ cup panko", "1 ¼ cup macadamia nuts", "¼ cup shredded coconut", "4 tbsp honey", "3 tbsp butter"], "instructions": "Preheat oven to 350°\nCombine the coconut milk and ¼ cup honey in a large baking dish, and add the tilapia. Marinate for 30 minutes or longer.\nPlace the macadamia nuts in a food processor and pulse until finely crushed.\nCombine with the panko and shredded coconut on a large plate.\nGrease a large cookie sheet or foil sheet.\nDredge each tilapia filet through the nut mixture until well coated and place on prepared pan.\nSprinkle the remaining nut mixture over the filets.\nCombine the remaining honey and the butter in a small bowl and microwave until melted; drizzle over the tilapia.\nBake for 15-20 minutes depending on the size of your filets.", "image": "img/coconut-macadamia-encrusted-tilapia.jpg"}, {"slug": "company-beef-tenderloin-serves-12", "title": "Company Beef Tenderloin", "serves": "Serves 12", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["2 (3lb) beef tenderloin roasts", "1 ½ cup soy sauce", "1 cup melted butter", "**Preheat the oven to 350°**"], "instructions": "Place the roasts in a 13 x 9 glass baking dish and pour the soy sauce and the melted butter over the tenderloins.\nBake for 10 minutes and then turn the meat over. Continue cooking for 30-35 minutes, basting occasionally. The internal temperature of the roasts should be 140° for medium.\nLet stand for 10-15 minutes before slicing.", "image": "img/company-beef-tenderloin-serves-12.jpg"}, {"slug": "complete-breakfast-serves-6-8", "title": "Complete Breakfast", "serves": "Serves 6-8", "category": "Breakfast", "date": "2022-02-25", "ingredients": ["Bread slices, crust removed and buttered on one side", "Cheddar cheese, sliced or grated"], "instructions": "Cooked bacon\n4 eggs, slightly beaten\n2 ½ cup milk\n1 tsp dry mustard butter\ncorn flakes\nbutter, melted or reserved bacon drippings\nLine the bottom of a baking dish (any size) with slices of bread, buttered side down. Add a layer of cheddar cheese; Add a layer of bacon. Add another layer of bread, buttered side up.\nMix the eggs with the milk and dry mustard; Pour over the bread.\nToss enough corn flakes to cover the top of the bread with either melted butter or bacon drippings( just enough to coat the flakes). Layer the cornflakes over the top of the bread.\nRefrigerate overnight. Bake at 325° for 45 minutes or until firm.", "image": "img/complete-breakfast-serves-6-8.jpg"}, {"slug": "confetti-chicken-casserole-serves-6", "title": "Confetti Chicken Casserole", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["**Casserole**", "1 cup diced carrots", "¾ cup chopped onion", "½ cup diced celery", "¼ cup chicken broth", "1 can cream of chicken soup", "1 cup sour cream", "3 cups cubed cooked chicken", "½ cup sliced fresh mushrooms", "1 tsp Worcestershire sauce", "1 tsp salt", "1/8 tsp pepper", "**Topping**", "1 cup sifted flour", "2 tsp baking powder", "½ tsp salt", "2 eggs, slightly beaten", "½ cup milk", "1 tbsp chopped green pepper", "1 tbsp chopped pimento", "1 ¼ cup shredded cheddar cheese, divided", "**Intructions Casserole:**"], "instructions": "Preheat the oven to 350°.\nIn a medium saucepan, combine the carrots, onion, celery and chicken broth. Simmer for 20 minutes.\nIn a 3 quart casserole dish, mix the soup, sour cream, chicken, mushrooms, Worcestershire, salt and pepper. Add the simmered vegetables and the liquid; mix well.\n**Instructions topping:**\nIn a mixing bowl combine the flour, baking powder and salt. Add the eggs, milk, green pepper, pimento and 1 cup of the cheese. Mix until just blended.\nDrop the mixture by the tablespoon onto the top of the casserole around the edge.\nBake for 40 minutes or until golden brown. Sprinkle with the remaining cheese and return to the oven until the cheese has melted.", "image": "https://static.wixstatic.com/media/75d545_c6f8f4c7e8af4e88835aff8862a341dd~mv2.jpg"}, {"slug": "confetti-pearl-couscous-salad-serves-8-10", "title": "Confetti Pearl Couscous Salad", "serves": "Serves 8-10", "category": "Salads", "date": "2022-02-25", "ingredients": ["5 tbsp extra virgin olive oil", "2 cups Pearl couscous", "2 ½ cup water", "½ cup French lentils", "2 plum tomatoes, diced", "1-2 English cucumbers", "1 red bell pepper, diced", "½ cup dried cranberries", "1/3 cup diced red onion", "2 tbsp chopped parsley", "2 green onions, thinly sliced", "¼ cup extra virgin olive oil", "2 lemons, juiced", "2 tbsp honey", "salt & pepper to taste"], "instructions": "Heat 1 tbsp of olive oil in a large skillet and add the couscous. Cook until golden, about 4 minutes.\nAdd 2 ½ cups of water and bring to a boil. Cover and cook for 10 minutes or until the couscous is tender. Rinse with cold water in a sieve and transfer to a bowl. Mix in ¼ cup of olive oil. Toss to coat.\nPlace the lentils in a small saucepan and cover with water. Bring to a boil. Reduce the heat and simmer until the lentils are tender. About 15 minutes.\nDrain and rinse the lentils. Add to the couscous.\nAdd the next 7 ingredients to the couscous lentil mixture.\nIn a small bowl, whisk the ¼ cup of olive oil, lemon juice, salt and pepper together and pour over the couscous mixture. Toss to coat. Refrigerate the salad for at least 8 hours before serving.", "image": "img/confetti-pearl-couscous-salad-serves-8-10.jpg"}, {"slug": "cookie-crumb-ice-cream-cake-serves-12", "title": "Cookie Crumb Ice Cream Cake", "serves": "Serves 12", "category": "Desserts", "date": "2022-02-25", "ingredients": ["2 pkg. Oreo Cookies", "6 tbsp butter, melted", "2 (1.5 quart containers) of vanilla ice cream, softened", "1 jar (16oz)of caramel sauce", "1 large container of frozen whipped topping, thawed"], "instructions": "Butter a 13x9 baking dish and set aside.\nPlace the cookies in a ziploc bag to make the crumbs. With a rolling pin crush the cookies well. (not looking for fine crumbs here)\nIn a large bowl, combine 5 ½ cups of crumbs and the melted butter.\nPress the cookie mixture into the buttered baking dish. Spread enough ice cream to cover the crumbs. (I slice the ice cream into 1” slices which makes it easier to spread and guarantees me the same depth all over).\nCover the dish and freeze until set.\nSpread the caramel over the ice cream, as much as desired.( I make a layer) Cover and freeze until set.\nSpread the whipped topping on the caramel and sprinkle with the remaining cookie crumbs to desired coverage. Cover and freeze for at least 2 hours. Remove from the freezer 10 minutes or so before serving.", "image": "img/cookie-crumb-ice-cream-cake-serves-12.jpg"}, {"slug": "copycat-olive-garden-sangria-1-gallon", "title": "Copycat Olive Garden Sangria 1 Gallon", "serves": "", "category": "Beverage", "date": "2022-02-25", "ingredients": ["1 ½ liter Red Table wine (Lambrusco)", "1 cup Grenadine", "2 cups Cranberry juice cocktail", "1 ¼ cup sweet vermouth", "**Sugar Water:**½ cup sugar and ½ cup water", "strawberries, cut into thirds", "oranges, thinly sliced and the quartered", "crushed ice"], "instructions": "Mix everything together in a large pot and transfer to a pitcher when ready to serve.", "image": "img/copycat-olive-garden-sangria-1-gallon.jpg"}, {"slug": "corn-and-crab-bisque", "title": "Corn and Crab Bisque", "serves": "", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["3/4 cup onion, chopped", "3 (14 ounce) cans chicken broth", "3 cloves garlic", "2 bay leaves", "1/2 teaspoon cayenne pepper", "1 teaspoon Cajun seasoning", "salt and pepper to taste", "4 ears corn, kernels cut from cob", "1/2 cup half-and-half", "3 tablespoons all-purpose flour", "1/2 cup milk", "16 ounces fresh lump crabmeat", "Directions"], "instructions": "Heat butter in a large pot over medium heat. Stir in onion; cook until soft and translucent.\nPour in chicken broth, and bring to a boil. Stir in garlic, bay leaves, cayenne pepper, Cajun seasoning, salt, and pepper. Stir corn into boiling broth. Simmer about 10 minutes. Reduce heat to medium low.\nRemove 1 cup of soup, and set aside to cool slightly. Then pour into a food processor. Pour in half-and-half. Puree for 30 to 45 seconds, and set aside.\nIn a small bowl, stir together flour and milk. Slowly stir into simmering soup. Stirring constantly, simmer for 1 to 2 minutes. Then stir in pureed mixture.\nReduce heat to low, stir in crab meat, and cook until warmed through, about 5 minutes.", "image": "img/corn-and-crab-bisque.jpg"}, {"slug": "corn-casserole-serve-9", "title": "Corn Casserole", "serves": "Serves 9", "category": "Casserole", "date": "", "ingredients": ["2 eggs, beaten", "1 15oz can cream style corn", "1 8oz container sour cream", "¼ cup butter, melted", "1 15.25 oz can whole kernel corn, drained", "1 ½ cup shredded cheddar cheese", "½ cup diced onion", "1 4oz can diced green chiles, drained", "1 8.5 oz package dry corn muffin mix"], "instructions": "Preheat the oven to 350°.\nGrease a 2 quart casserole dish.\nIn a large mixing bowl, combine the eggs, creamed corn, sour cream and melted butter. Stir in the whole kernel corn, cheese, onion and chilés.\nStir in the corn muffin mix until just moistened. Transfer to the prepared casserole dish and bake for 75 minutes or until, a knife inserted comes out clean and top is golden.\nLet stand 5 minutes before serving.", "image": "img/corn-casserole-serve-9.jpg"}, {"slug": "corn-chowder", "title": "Corn Chowder", "serves": "", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["4 cup chicken broth", "2 14oz cans creamed corn", "1 10oz package of frozen corn", "2 cups diced potato", "1 lb cubed chicken", "½ lb Andouille sausage, diced", "1 cup heavy cream", "¼ cup chopped fresh cilantro"], "instructions": "If the chicken is precooked, put all the ingredients into a crock-pot and cook until the potatoes are tender.\nIf the chicken is raw, put all the ingredients except for the cream and cilantro into a crock-pot and cook for 7 hours. Then add the cream and cilantro and cook for 20-60 minutes.\nServe with warm Sourdough bread.", "image": "img/corn-chowder.jpg"}, {"slug": "corn-potato-pancakes-makes-12", "title": "Corn Potato Pancakes", "serves": "Makes 12", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2 cups mashed potatoes (prepared with butter and milk)", "¼ cup flour", "¼ cup cream style corn", "1 egg, beaten", "3 tbsp finely diced onion", "1 tsp minced fresh parsley", "½ tsp salt", "½ tsp fresh minced garlic", "1/8 tsp pepper", "3 tbsp vegetable oil, divided"], "instructions": "In large bowl, combine the first 9 ingredients.\nIn a large skillet heat 1 tbsp of oil; drop four ¼ cupfuls of “batter” into the skillet. Cook for 1-2 minutes on each side or until golden brown. Repeat with the remaining oil and “batter”.", "image": "img/corn-potato-pancakes-makes-12.jpg"}, {"slug": "corned-beef-and-cabbage-with-beer-serves-6", "title": "Corned Beef and Cabbage with Beer", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4lb corned beef", "4 bay laves", "5 cloves garlic, minced", "2 carrots cut in half and sliced", "3 unpeeled red potatoes, quartered", "1 cabbage, cut into 8 wedges", "½ tsp peppercorns", "1 can beer", "1 cup chicken broth", "6 whole cloves"], "instructions": "Pour the beer and chicken broth into a crock-pot and stir in the cloves, peppercorns, bay leaves and the garlic.\nPlace the corned beef in the center of the pot and arrange the carrots and potatoes around the meat. Place the cabbage wedges on the top.\nAdd enough water to raise the crockpot liquid level 1/3 of the way to the top. Cover and cook on low for 8 ½ hours.\nServe with homemade Irish Soda Bread.", "image": "https://static.wixstatic.com/media/75d545_5669cb9165c44b0eb33cc238f3737d22~mv2.jpg"}, {"slug": "cosmopolitan-punch", "title": "Cosmopolitan Punch", "serves": "", "category": "Beverage", "date": "2022-02-25", "ingredients": ["8 cups cold cranberry juice", "1 cup cold orange juice", "2 cups Citron Vodka", "½ cup cold triple sec", "1 sliced lemon", "1 sliced lime", "1 cup frozen cranberries", "1 bottle cold ginger ale"], "instructions": "Mix the cranberry juice, orange juice, vodka, triple sec, lemon, lime and cranberries in a large pot and refrigerate.\nBefore serving add the ginger ale and transfer to a punch bowl.", "image": "img/cosmopolitan-punch.jpg"}, {"slug": "country-apple-dumplings-makes-16", "title": "Country Apple Dumplings", "serves": "Makes 16", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2 Large Granny Smith apples, peeled and cored", "Cinnamon to sprinkle on the apples", "1 10oz cans Pillsbury Crescent rolls", "1 cup butter", "½ cup granulated sugar", "¼ cup brown sugar", "1 ½ tsp cinnamon, or more to taste", "1 tsp vanilla", "12 oz Mountain Dew(I use diet)"], "instructions": "Preheat the oven to 350°\nGrease a 9x13 baking dish.\nSeparate the crescent rolls. Cut each apple into 8 wedges and sprinkle with cinnamon.\nRoll each apple piece in a crescent roll triangle. (roll from smallest end to largest)\nPinch to seal and place in the baking dish.\nMelt the butter in small saucepan and add the sugar and simmer until the sauce is a thick rich caramel and pulls away from the pot. Add the vanilla and cinnamon and stir to combine.\nPour over the apple dumplings.\nPour the Mountain Dew over the dumplings and bake for 40 minutes or until golden brown.\nPrevious Next", "image": "https://static.wixstatic.com/media/75d545_d01ad81bb8f34287a67da4306e457bea~mv2.jpg"}, {"slug": "crab-and-orzo-salad-serves-20", "title": "Crab and Orzo Salad", "serves": "Serves 20", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["5 cups uncooked orzo", "3 lb cooked jumbo lump crabmeat", "14 plum tomatoes, chopped", "3 carrots, peeled and diced", "3 medium red peppers, diced", "3 medium green peppers, diced", "10 green onions, chopped", "1 2/3 cup mayonnaise", "½ cup chili sauce", "3tbsp and 1tsp of freshly squeezed lemon juice", "1 ½ tbsp. plus 1tsp of salt", "1 ¾ tsp black pepper", "10 drops of hot pepper sauce"], "instructions": "Bring a large saucepan of lightly salted water to a boil, and cook the orzo according to the package directions for al dente. Drain and refrigerate for 1 hour.\nIn a large bowl toss the chilled orzo, crabmeat, tomatoes, carrots, peppers and the green onions.\nIn a small bowl, mix the mayonnaise, chili sauce, lemon juice, salt, pepper, and the pepper sauce. Add to the orzo/crabmeat mixture and toss.", "image": "img/crab-and-orzo-salad-serves-20.jpg"}, {"slug": "crab-bisque-serves-8-10", "title": "Crab Bisque", "serves": "Serves 8-10", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["6 tbsp butter", "1 large Vidalia onion, minced", "1 cup finely chopped celery", "Kosher salt", "Freshly ground pepper", "2 tsp Old Bay seasoning", "4 cloves garlic, minced", "¼ cup tomato paste", "¼ cup plus 2 tbsp flour", "8 cup fish stock", "2 cup white wine", "3 bay leaves", "1 cup heavy cream", "2lb jumbo lump crab meat", "Fresh parsley, minced"], "instructions": "In a large heavy soup pot, over medium heat, melt the butter. Add the onion and celery and cook until the vegetables are tender.\nSeason with salt, pepper and Old Bay to taste. Stir in the garlic and the tomato paste; cook until the garlic is fragrant.\nSprinkle the flour over the vegetable mixture and cook for 1 minute.\nAdd the fish stock, wine and bay leaves. Reduce the heat and simmer until the liquid has reduced; stirring occasionally for about 30 minutes. Remove from heat.\nRemove the bay leaves. With an immersion blender, puree the soup until smooth. Return to medium low heat and add the cream and the crabmeat.\nCook until warmed through and serve garnished with the minced parsley and buttered croutons or crostini.", "image": "img/crab-bisque-serves-8-10.jpg"}, {"slug": "crab-crusted-tilapia-serves-4", "title": "Crab Crusted Tilapia", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["2 tbsp Italian bread crumbs with Romano Cheese", "2 tsp finely grated Parmesan cheese", "2 tbsp diced red bell pepper", "2 tbsp diced yellow pepper", "2 green onions, sliced", "¼ jalapeno pepper, seeded and minced", "4 tbsp butter, melted", "8oz lump crabmeat, flaked", "2 heaping tbsp. of shredded mozzarella cheese", "4 Tilapia fillets"], "instructions": "Preheat the oven to 375°\nIn a medium bowl combine all the ingredients except the Tilapia.\nArrange the Tilapia in a single layer on foil cookie sheet. Spread the crab and crumb stuffing mixture evenly over the top of the fish.\nBake for about 20 minutes or until the fish flakes. Turn the oven to broil and lightly brown the topping before removing from the oven.", "image": "img/crab-crusted-tilapia-serves-4.jpg"}, {"slug": "crab-salad-serves-4-1", "title": "Crab Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-28", "ingredients": ["1 lb jumbo lump crab meat", "1 English cucumber, diced", "3 large Roma tomatoes, seeded and diced", "3 scallions, diced", "3 cloves of garlic, finely minced", "½ cup light mayonnaise", "Salt & pepper to taste"], "instructions": "In a medium bowl, combine the crab meat, cucumber, tomato and scallions.\nIn a small bowl combine the mayonnaise and garlic and add to the crab meat and season with salt & pepper.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "crab-salad-serves-4", "title": "Crab Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-25", "ingredients": ["1lb lump crab meat", "½ cup chopped celery", "1/3 cup Ranch dressing", "¼ cup mayonnaise", "1 tbsp Truvia", "1 tbsp minced fresh parsley"], "instructions": "Gently mix all the ingredients together in a medium bowl and refrigerate overnight. Stir occasionally. Stir one more time before serving.\nServing suggestions: on top of ½ avocado, on a leaf of Bibb lettuce or on top of a garden salad.\nNet carbs per serving(crab salad only) 5.2", "image": "img/crab-salad-serves-4.jpg"}, {"slug": "crab-wontons-makes-32", "title": "Crab Wontons", "serves": "Makes 32", "category": "Appetizers & Dips", "date": "2022-03-01", "ingredients": ["32 wonton wrappers", "8 oz cream cheese, softened", "½ cup heavy cream", "1 large egg", "1 tbsp Dijon mustard", "1 tsp Worcestershire sauce", "Hot pepper sauce, to taste", "1 cup lump crabmeat", "¼ green onions, thinly sliced", "¼ cup red bell pepper, finely chopped", "1 cup freshly grated parmesan cheese", "Minced chives", "Preheat oven to 350º"], "instructions": "Spray the insides of a mini muffin cup pan and press the wonton wrappers into each cup. Lightly spray the wonton wrappers with cooking spray.\nBake the wontons for about 8 minutes or until lightly browned on the edges.\nIn a small bowl, with an electric mixer, mix the cream cheese, heavy cream, egg, mustard, Worcestershire sauce, and pepper sauce until smooth.\nAdd the green onions, red bell pepper and crab.\nFill the wontons with the crab mixture and top with parmesan cheese.\nBake for about 10 minutes or until heated through. Remove from the oven and garnish with minced chives.", "image": "img/crab-wontons-makes-32.jpg"}, {"slug": "cranberry-pear-tossed-salad-serves-12", "title": "Cranberry & Pear Tossed Salad", "serves": "Serves 12", "category": "Salads", "date": "2022-02-25", "ingredients": ["2/3 cup apricot nectar", "2/3 cup red wine vinegar", "2/3 cup canola oil", "1 tbsp plus 1 tsp dijon mustard", "½ tsp salt", "¼ tsp pepper", "¼ cup sugar", "1 cup chopped walnuts", "14 cups mixed baby greens", "6 pears, sliced", "1 cup dried cranberries", "1 ½ cup crumbled blue cheese", "Dressing"], "instructions": "In a small bowl, whisk together the first 6 ingredients and set aside.\nCandied walnuts\nIn a large skillet, melt the sugar over medium heat, stirring constantly. Add the walnuts and stir to coat. Remove from the heat. Spread out on a piece if wax paper to cool.\nSalad\nIn a large salad bowl, combine the mixed greens, pears and cranberries. Drizzle with the dressing. Add the nuts and blue cheese; toss.\nServe", "image": "img/cranberry-pear-tossed-salad-serves-12.jpg"}, {"slug": "creamed-onions-with-wine-8-servings", "title": "Creamed Onions with Wine 8 servings", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2lbs small white pearl onions, peeled", "1 (750ml) bottle of Chardonnay", "1 bay leaf", "¼ tsp dried thyme", "salt to taste", "1 cup heavy cream", "1tsp butter"], "instructions": "Place the peeled onions in a 2qt saucepan and pour enough wine to cover half of the onions. Add the bay leaf, thyme and salt. Simmer, stirring frequently for 25 minutes.\nAdd the cream and bring to a boil; reduce the heat and cook until the sauce thickens.\nRemove from the heat and stir in the butter. Remove the bay leaf before serving.", "image": "img/creamed-onions-with-wine-8-servings.jpg"}, {"slug": "creamy-cheesecake-with-raspberry-sauce", "title": "Creamy Cheesecake with Raspberry Sauce", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 ½ cup finely crushed chocolate wafers", "3tbsp butter, melted", "3 8oz packages cream cheese", "½ cup sugar", "2tbsp flour", "1tsp vanilla", "2 egg whites", "1 cup heavy cream", "**Raspberry Sauce:**", "1 12oz package frozen unsweetened raspberries, thawed", "½ cup sugar", "1tsp freshly squeezed lemon juice"], "instructions": "Preheat the oven to 375°.\nIn a small bowl combine the crushed wafers and the melted butter. Press into the bottom of a greased 8 or 9 inch spring form pan.\nIn a large bowl, combine the cream cheese, sugar, flour and vanilla with an electric mixer until fluffy. Add the egg whites, beating on low until just combined.\nAdd in the cream with mixer on low. Pour into the crust.\nPlace the spring form pan on a shallow baking sheet and bake for 40-45 minutes for an 8” pan and 30-35 minutes for a 9” pan, or until the center of the cheesecake appears “nearly” set when shaken. Cool for 15 minutes.\nLoosen the crust from the pan sides and cool for another 30 minutes.\nRemove the spring form and cool completely. Chill at least 4 hours.\nMeanwhile in a blender blend the raspberries just until smooth. Press through a sieve to remove the seeds.\nIn a saucepan, combine the pureed raspberries, sugar and lemon juice. Heat just until the sugar dissolves; cool. Pour into a small bowl, cover and chill.\nGarnish the cheesecake with fresh raspberries and serve with the raspberry sauce.\n‘", "image": "img/creamy-cheesecake-with-raspberry-sauce.jpg"}, {"slug": "creamy-chicken-and-corn-chowder-serves-6", "title": "Creamy Chicken and Corn Chowder", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["1 Deli Rotisserie chicken , shredded (3 cups)", "8 slices bacon , cooked and crumbled", "1/4 cup butter , cut into 1 Tbsp pieces", "1 large red bell pepper , diced (1 1/2 cups", "1 medium Vidalia onion , diced (1 1/4 cups)", "1 jalapeno , seeded for less heat if desired, finely chopped", "4 cloves garlic , minced", "1/3 cup all-purpose flour", "6 cups low-sodium chicken broth", "12 baby new potatoes , diced slightly less than 1/2-inch thick (3 cups)", "2 bay leaves", "Salt and freshly ground black pepper , to taste", "1 14.75oz can petite diced tomatoes", "4tbsp hickory flavored barbecue sauce", "2 1/2 cups fresh or frozen gold and white corn", "1 1/2 cups half and half"], "instructions": "Green onions and seeded finely chopped jalapenos (optional), for serving\nIn a large pot, melt butter over medium heat. Add red bell pepper, onions, jalapenos and sauté until tender, about 3 minutes.\nAdd garlic and cook 30 seconds longer. Stir in flour, and cook 2 minutes stirring constantly. While stirring, slowly add in chicken broth and whisk until well blended.\nAdd potatoes, bay leaves and season with salt and pepper to taste. Bring mixture to a boil stirring frequently, then reduce heat to medium-low and cook, uncovered, 10 minutes or just until potatoes are tender, stirring occasionally.\nAdd in cooked chicken, corn , diced tomatoes, barbecue sauce and half and half and simmer, uncovered 10 - 15 minutes longer, stirring occasionally.\nServe warm topped with bacon, green onions, and optional jalapeno peppers.", "image": "img/creamy-chicken-and-corn-chowder-serves-6.jpg"}, {"slug": "creamy-orzo-risotto-with-butternut-squash-serves-4", "title": "Creamy Orzo Risotto with Butternut Squash", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["Buttery cooking spray", "3 ½ cups uncooked butternut squash, cut into small cubes", "1 tsp extra virgin olive oil", "½ tsp salt or to taste", "1 tbsp. unsalted butter", "1 cup uncooked orzo", "1½ cup water", "1 cup chicken broth", "1 tsp fresh thyme", "2 tbsp half and half", "1/3 cup freshly grated parmesan cheese", "salt and pepper to taste"], "instructions": "Preheat the oven to 425°.\nEvenly coat a cookie sheet with the cooking spray.\nIn a medium bowl, toss the squash with oil and salt. Spread evenly on the cookie sheet. Roast, (stir ½ way through) until the squash is tender and lightly browned. About 20-25 minutes.\nMeanwhile add the orzo to a medium saucepan and cook, stirring constantly until the orzo begins to lightly brown. About 3 minutes.\nAdd the water, broth and thyme. Bring to a boil. Reduce the heat to low and simmer uncovered(stirring occasionally) until all liquid is just about absorbed. About 15 minutes. Stir in the half and half, cheese and the roasted squash. Season well with the salt and pepper and serve.", "image": "img/creamy-orzo-risotto-with-butternut-squash-serves-4.jpg"}, {"slug": "creamy-stovetop-crab-dip", "title": "Creamy Stovetop Crab Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["1 tbsp extra virgin olive oil", "1 cup minced onion", "12 oz lump crab meat", "8 oz cream cheese, at room temperature", "½ tsp Worcestershire sauce", "1 tsp freshly squeezed lemon juice", "½ cup light mayonnaise", "½ cup grated Parmesan cheese", "salt and freshly ground pepper to taste"], "instructions": "Heat the olive oil in a large skillet over medium high heat. Add the onion and sauté until tender, about 5-7 minutes.\nAdd the crab meat and the juices to the onion. Stir in the cream cheese, Worcestershire sauce, lemon juice, mayonnaise and Parmesan. Cook over medium heat for about 5 minutes, or until all the ingredients are warmed through and the cheeses are bubbly.\nSeason with salt and pepper to taste.\nServe with crackers or warm crusty bread.", "image": "img/creamy-stovetop-crab-dip.jpg"}, {"slug": "creamy-tomato-basil-soup-serves-6", "title": "Creamy Tomato Basil Soup", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["2tbsp chopped green onion", "2 garlic cloves, minced", "1 ½ tsp extra virgin olive oil", "1 can (28oz) crushed tomatoes", "1 can (10.5oz) condensed chicken broth, undiluted", "1 1/3 cup water", "¼ tsp black pepper", "¾ cup heavy cream", "2tbsp sherry", "2tbsp fresh minced basil", "2tsp sugar"], "instructions": "In a large saucepan, sauté the onion and the garlic in olive oil until tender. Add the tomatoes, broth, water and pepper. Bring to a boil. Reduce the heat and simmer for 10 minutes.\nStir in the cream, sherry, basil and sugar. Cook for another minute or two or until the soup is heated through. Do not boil!\nServe with warm bread or buttermilk biscuits.", "image": "img/creamy-tomato-basil-soup-serves-6.jpg"}, {"slug": "creamy-tomato-dip", "title": "Creamy Tomato Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["2 tbsp ketchup", "½ cup light mayonnaise", "2 tbsp light cream", "cayenne pepper to taste", "fresh squeezed lemon juice"], "instructions": "In a small bowl combine the first 4 ingredients and then squeeze just enough lemon juice to give the dip some tang.\nRefrigerate until ready to serve.", "image": "img/creamy-tomato-dip.jpg"}, {"slug": "creamy-tomato-soup-with-basil-sausage-serves-8", "title": "Creamy Tomato Soup with Basil & Sausage", "serves": "Serves 8", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["3 tbsp extra virgin olive oil", "1 lb Premio ground Italian sausage", "16 fresh basil leaves, stacked, rolled and thinly sliced", "2 26oz jars of Mezzetta Italian sauce", "2 ½ cup water", "3 cups Half & Half", "salt & pepper to taste"], "instructions": "In a large pot heat the olive oil and cook the sausage until browned. Breaking it apart into smaller pieces while you cook.\nStir in the fresh basil, pasta sauce, water, half & half and salt & pepper.\nCook until heated through. Serve with warm bread.", "image": "img/creamy-tomato-soup-with-basil-sausage-serves-8.jpg"}, {"slug": "crepes", "title": "Crepes", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["2 eggs", "1 cup milk", "½ tsp salt", "1 cup flour", "2tbsp butter, melted"], "instructions": "Beat the eggs well. Then beat in the milk, salt, flour and butter.\nAdd the batter to a crepe pan and cook over medium heat until the crepes begin to brown on each side", "image": "img/crepes.jpg"}, {"slug": "crisp-chocolate-chip-cookies-makes-2-dozen", "title": "Crisp Chocolate Chip Cookies", "serves": "Makes 2 dozen", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 cup butter, softened", "1 cup white sugar", "1 cup light brown sugar, packed", "2 eggs", "2tsp vanilla extract", "3 cups flour", "1tsp baking soda", "2tsp hot water", "½ tsp salt", "2 cups semisweet chocolate chips"], "instructions": "Preheat the oven to 350°.\nIn a medium bowl cream the butter and sugars together until smooth. Add the eggs one at a time, beat well to combine. Stir in the vanilla.\nDissolve the baking soda in the hot water and add to the batter with the salt.\nGradually add in the flour; when blended add the chocolate chips.\nDrop by the spoonful onto an ungreased cookie sheet and bake for 8-10 minutes or until the edges are browned.", "image": "img/crisp-chocolate-chip-cookies-makes-2-dozen.jpg"}, {"slug": "crispy-corn", "title": "Crispy Corn", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2 slices bread, cubed", "1/3 cup chopped onion", "1 10oz can whole kernel corn", "1 11oz can cream style corn", "½ cup milk", "1 tsp sugar", "1 tsp salt", "¼ tsp black pepper", "1 cup rice crispy cereal", "2 tbsp butter, melted", "**Preheat the oven to 350°**"], "instructions": "Grease a 2qt casserole dish and set aside.\nIn a large bowl combine the bread cubes and onion. Add the whole corn, creamed corn, and milk.\nSeason with the sugar, salt and pepper. Stir to combine. Add to the prepared baking dish.\nIn a small bowl toss the cereal with the melted butter and sprinkle over the top of the corn mixture.\nBake uncovered for 45 minutes.", "image": "img/crispy-corn.jpg"}, {"slug": "crispy-herb-baked-chicken", "title": "Crispy Herb Baked Chicken", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["2/3 cup Instant potato flakes", "1/3 cup freshly grated Parmesan cheese", "2 tsp dried parsley", "1 tsp garlic salt", "1lb thin sliced chicken filets", "1/3 cup butter, melted", "**Preheat the oven to 350°**"], "instructions": "Use a foil cookie sheet or line a regular cookie sheet with foil.\nIn a medium bowl combine the potato flakes, Parmesan, parsley and garlic salt; mix well.\nDip each piece of chicken in the butter and then coat both sides well in the potato flake mixture. Place on the cookie sheet.\nBake for about 25-30 minutes. Serve with gravy and cranberry sauce.", "image": "img/crispy-herb-baked-chicken.jpg"}, {"slug": "crispy-rice-caramel-ice-cream-dessert", "title": "Crispy Rice Caramel Ice Cream Dessert", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 cup butter", "1 cup brown sugar", "5 cup rice crispy cereal", "½+ gallon vanilla ice cream, softened", "1 jar caramel topping"], "instructions": "In a large saucepan over medium heat, melt the butter and sugar, stirring to combine. Stir in the cereal 1 cup at a time; remove from the heat.\nPress ½ of the crispy mixture onto the bottom of a 9x13 inch pan. Slice the ice cream and spread the entire ½+ gallon(Use what you need to evenly create a layer of ice cream)in an even layer over the crispy layer. Top with the remaining crispy mixture. Drizzle the caramel topping over the dessert. (more or less; it’s to your taste)Freeze for at least 1 hour.", "image": "https://static.wixstatic.com/media/75d545_82cc72d4964349d29c40248198e1024a~mv2.jpg"}, {"slug": "crock-pot-barbecue-chicken-serves-4", "title": "Crock-pot Barbecue Chicken", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4 large split breasts(bone in)", "3tbsp steak seasoning", "4tbsp of brown sugar", "1 ½ cup of barbecue sauce"], "instructions": "Make 3-4 large foil balls and fit into the bottom of the crockpot.\nSeason each chicken breast with steak seasoning and brown sugar.\nArrange the chicken breasts on top of the foil balls and pour the barbecue sauce over the top.\nCook on high for 4 hours or until the chicken has reached 165°.\nServe whole or shredded.", "image": "img/crock-pot-barbecue-chicken-serves-4.jpg"}, {"slug": "crock-pot-cheesy-corn-and-peppers-8-servings", "title": "Crock-pot Cheesy Corn and Peppers 8 Servings", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["2lbs frozen corn", "3 Tbsp butter, cut into cubes", "1 large green bell pepper, seeded and chopped", "1 poblano or jalpeño pepper, seeded and chopped", "½ tsp ground cumin", "1 tsp salt", "¼ tsp ground black pepper", "3 oz cream cheese, cut into cubes", "1 cup finely shredded sharp Cheddar cheese"], "instructions": "Coat the inside of a crock-pot with a nonstick butter spray.\nCombine the first 7 ingredients in the crock-pot and cover. Cook on high for 2 hours.\nAdd the cream cheese and the cheddar cheese; stir to combine. Cover and cook for 15 minutes more or until the cheese has completely melted.", "image": "img/crock-pot-cheesy-corn-and-peppers-8-servings.jpg"}, {"slug": "crock-pot-tortilla-soup", "title": "Crock-pot Tortilla Soup", "serves": "", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["2 boneless skinless chicken breast halves, cubed", "1 onion, finely chopped", "1 clove garlic, minced", "3 medium tomatoes, peeled, seeded and chopped", "4 cups chicken broth", "½ tsp salt", "¼ tsp pepper", "1 jalapeno pepper, seeded and chopped", "2 tbsp vegetable oil", "4 corn tortillas, halved and cut into 1/4” strips", "shredded Monterey Jack cheese", "2 tbsp chopped fresh cilantro"], "instructions": "Combine the chicken breasts, onion, garlic, tomatoes, broth, salt pepper, and jalapeno in a crock-pot. Cover and cook on low for 7-8 hours.\nHeat the oil in a large skillet and add the tortilla strips. Cook over medium heat, stirring often, until crisp. Drain on a paper towel.\nIn each serving bowl add a 1-2 tbsp of the Jack cheese and ladle the soup into the bowls. Garnish with the cilantro and the tortilla strips.", "image": "img/crock-pot-tortilla-soup.jpg"}, {"slug": "crockpot-italian-red-sauce-with-vegetables-sausage-meatballs", "title": "Crockpot Italian Red Sauce with Vegetables, Sausage & Meatballs", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-25", "ingredients": ["3 28oz cans Cento Tomato Puree (or your favorite)", "1 28oz can Cento Petite Diced Tomatoes (or your favorite)", "2 6oz cans of Cento Tomato Paste (or your favorite)", "1 7.5oz jar of sundried tomatoes packed in olive oil, and julienned", "2 medium red bell peppers, cut into ½” vertical slices", "2 medium green peppers, cut into ½” vertical slices", "1 large Vidalia onion, cut into 1” wedges"], "instructions": "2lb Premio Italian Sausage with tomato, garlic and rosemary (1 single coiled link)\nBest Ever Meatballs (I double the recipe for this pot of sauce)\n4 cloves of garlic, minced\n4 Bay leaves\n1 cup chopped fresh basil\n4 tbsp chopped fresh oregano leaves, or to taste\n2 tbsp fresh thyme leaves\n2 tbsp granulated sugar\nPreheat the oven to 425°\nIn a large sauté pan, over medium heat, add the jar of sundried tomatoes with the oil, the red pepper, green pepper, garlic and the onions and cook until crisp tender.\nWhile the vegetables are cooking, add the puree and the paste to the crockpot and set to low. Add the fresh herbs and the sugar.\nWhen the vegetables are ready (you will know because the whole house smells yummy at this point) add them to the sauce and cover.\nCut the sausage into 3-4” pieces and place on a foil cookie sheet. Bake for approximately 15 minutes (this is just to brown them, not cook through) and add to the sauce.\nMake the Best Ever Meatballs and them to the sauce.\nCook the sauce for 6-8 hours on low and serve with your favorite pasta and bread.", "image": "img/crockpot-italian-red-sauce-with-vegetables-sausage-meatballs.jpg"}, {"slug": "crockpot-sausage-chili-serves-8", "title": "Crockpot Sausage Chili", "serves": "Serves 8", "category": "Crockpot", "date": "2023-01-10", "ingredients": ["2lbs bulk Italian sausage", "1 medium onion, diced", "1 15oz can dark kidney beans, drained and rinsed", "1 15oz can light red kidney beans, drained and rinsed", "1 15oz can black beans, drained and rinsed", "2 10oz cans Rotel tomatoes with green chiles, undrained", "3 cloves garlic, minced", "½ tsp kosher salt", "1/8 tsp ground black pepper", "1 packet chili seasoning mix (1.25oz packet)", "3 cups beef broth"], "instructions": "In a large saucepot, over medium high heat, brown the sausage breaking into small pieces as it cooks. Drain.\nSpray the crockpot with cooking spray and place all the ingredients (including the sausage) into the crockpot.\nCover and cook on low for 6 hours or high for 3-4 hours.\nServe with shredded cheese, parsley, sour cream and either taco chips or cornbread.", "image": "https://static.wixstatic.com/media/75d545_f3264cea912149f3a1b275cfb2bd7c5b~mv2.png"}, {"slug": "crumb-cake", "title": "Crumb Cake", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["3 cups flour", "4tsp baking powder", "½ tsp salt", "2 eggs", "1 ½ cup sugar", "2/3 cup melted butter", "1 cup milk", "1 ½ tsp vanilla", "confectioner’s sugar"], "instructions": "Preheat the oven to 350°.\nSift the flour with the baking soda and salt. Set aside.\nIn a large bowl, with a mixer, at medium speed beat the eggs until frothy. Add the sugar and butter until well mixed. Beat in the milk and the vanilla.\nStir in the flour mixture until well combined. Pour the batter into a greased and floured jelly roll pan and bake for 15 minutes. Remove the cake from the oven and spread the crumbs (recipe below) on top. Return the cake to the oven and continue baking for another 15 minutes.\nRemove from the oven and let cool. Dust the top of the cake with confectioner’s sugar.\n**Commercial Cake Mix Method**:\n1 box of Duncan Hines Yellow Cake Mix\n3 eggs\n1 1/3 cup water\n1 ½ tsp vanilla\nCombine the ingredients and beat at medium speed with a mixer for 4 minutes. Continue as above directed.\n**Crumbs**:\n1lb butter, 2 sticks softened and 2 sticks melted\n4 cups flour\n1 1/3 cup sugar\n1 tbsp vanilla\n1 tbsp cinnamon\nPinch of salt\nCombine the flour, sugar, vanilla and cinnamon in a large bowl. Add the butter to the flour mixture. Mix well.", "image": "img/crumb-cake.jpg"}, {"slug": "crumb-topped-salmon-serves-4", "title": "Crumb Topped Salmon", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1 ½ cup soft bread crumbs (use your favorite bread)", "2 tbsp minced fresh parsley", "1 tbsp fresh thyme", "2 garlic cloves, minced", "1 tsp grated lemon peel", "½ tsp salt", "¼ tsp lemon pepper", "¼ tsp paprika", "1 ½ lb salmon fillet", "refrigerated butter spray"], "instructions": "Preheat the oven to 350°\nCoat a 13 x 9 baking dish with cooking spray.\nIn a medium bowl, combine the first 8 ingredients and set aside.\nPat the salmon dry. Place, skin side down in the coated baking dish.\nSpray the salmon with the refrigerated butter spray; cover with the crumb mixture. Spray the crumbs with the butter spray.\nBake uncovered for 20-30 minutes or until the fish flakes with a fork.", "image": "img/crumb-topped-salmon-serves-4.jpg"}, {"slug": "crunchy-sesame-chicken-salad-serves-8", "title": "Crunchy Sesame Chicken Salad", "serves": "Serves 8", "category": "Salads", "date": "2022-02-25", "ingredients": ["1 2lb deli rotisserie chicken", "1 16oz bag coleslaw mix", "2 cups Chinese noodles", "1 8oz bag fresh sugar snap peas, strings removed", "1 cup shredded carrots", "1 ¼ cups Asian toasted sesame dressing", "3 medium green onions, sliced"], "instructions": "In a large serving bowl combine all the ingredients except the noodles and onions.\nToss the salad sprinkle the onions over the top and serve with the noodles on the side. (if tossed in the salad leftover s will have soggy noodles)", "image": "img/crunchy-sesame-chicken-salad-serves-8.jpg"}, {"slug": "crustless-spinach-quiche-serves-6", "title": "Crustless Spinach Quiche", "serves": "Serves 6", "category": "Breakfast", "date": "2022-02-25", "ingredients": ["1 tbsp vegetable oil", "1 onion, chopped", "1 (10) oz package frozen spinach, thawed and drained", "5 eggs, beaten", "3 cup shredded Muenster cheese", "¼ tsp salt", "1/8 tsp black pepper"], "instructions": "Preheat the oven to 350°\nLightly grease a 9” pie plate.\nHeat the oil in a large skillet over medium high heat and add the onions. Cook until the onions are soft, stirring occasionally.\nStir in the spinach and cook until the excess water has evaporated. Remove from the heat.\nIn a large bowl, combine the eggs, cheese, salt and pepper. Add the spinach mixture and stir to combine. Pour the mixture into the prepared pie plate.\nBake for 30 minutes or until the eggs have set. Cool for about 10 minutes before cutting.", "image": "img/crustless-spinach-quiche-serves-6.jpg"}, {"slug": "dorito-chicken-casserole-serves-8", "title": "Dorito Chicken Casserole", "serves": "Serves 8", "category": "Casserole", "date": "2022-03-03", "ingredients": ["1 tbsp butter", "1 small Vidalia onion, chopped", "4 oz cream cheese", "1 deli rotisserie chicken, shredded", "2 (10.75 oz) cans cream of chicken soup", "2 (10 oz) cans Rotel tomatoes with green chiles, undrained", "1 can black beans", "2 tsp chili powder", "1 tsp ground cumin", "1 regular size bag Dorito nacho chips", "2 cups Mexican blend shredded cheese", "Preheat oven to 350º"], "instructions": "Spray a 13 x 9 casserole dish with cooking spray and set aside.\nIn a large skillet over medium heat, melt the butter and cook the onion until translucent.\nCut the cream cheese into small cubes and add to the onions. Add the chicken, soup, tomatoes, black beans, chili powder and cumin. Stir until the cream cheese has melted.\nCoarsely crumble with your hands, about a third of the Doritos and spread evenly over the bottom of the casserole.\nPour half of the chicken mixture over the Doritos. Top with half the cheese and then another layer of the chicken mixture.\nTop with the remaining Doritos (coarsely crumbled) and then top with the remaining cheese.\nBake for 30 minutes or the cheese has melted and the mixture is bubbly. Serve with cornbread.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "dried-cherry-farro-salad-serves-6", "title": "Dried Cherry Farro Salad", "serves": "Serves 6", "category": "Salads", "date": "2023-06-26", "ingredients": ["**Salad**", "1/3 cup chopped walnuts", "2 ½ cup chicken broth", "1 cup farro", "½ tsp dried oregano", "½ tsp dried basil", "1 1/2 cup rough chopped green apple", "1 cup dried cherries", "3-4 tbsp chopped parsley", "**Dressing**", "¼ cup extra virgin olive oil", "¼ cup pure maple syrup", "¼ cup apple cider vinegar", "2 tsp granulated sugar", "½ tsp salt"], "instructions": "In a medium bowl, whisk together the dressing ingredients and set aside.\nIn a small skillet, over medium low heat, toss the walnuts until toasted and fragrant. Do not leave unattended or they will burn and be bitter.\nBring the chicken broth, farro, oregano and basil to a boil in a medium saucepan. Reduce the heat and simmer for about 10 minutes. Remove the pan from heat, cover and let sit until the liquid is absorbed. Transfer the farro to a serving bowl and let cool.\nWhen the farro is cool, mix in the cherries, walnuts and apples.\nAdd the dressing and toss to coat. Refrigerate for about 30 minutes.", "image": "https://static.wixstatic.com/media/75d545_fe8d3c6cc7524ca984a353e14244e87c~mv2.jpg"}, {"slug": "easiest-lemon-cookies-makes-3-dozen", "title": "Easiest Lemon Cookies", "serves": "Makes 3 dozen", "category": "Desserts", "date": "2022-02-25", "ingredients": ["1 package lemon cake mix", "2 eggs", "1/3 cup vegetable oil", "1tsp lemon extract", "1/3 cup confectioner’s sugar"], "instructions": "Preheat oven to 375°.\nIn a large bowl, combine the cake mix, eggs, oil, and lemon extract until well blended.\nDrop teaspoons of dough into a bowl of confectioner’s sugar and roll them around until lightly covered.\nPlace the cookie dough on an ungreased cookie sheet and bake for 7 minutes.", "image": "img/easiest-lemon-cookies-makes-3-dozen.jpg"}, {"slug": "easy-chicken-ranch-casserole", "title": "Easy Chicken Ranch Casserole", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["2 tbsp butter", "1 medium onion, chopped", "1 medium green bell pepper, chopped", "1 garlic clove, minced", "¾ cup chicken broth", "1 (10.75oz) can cream of chicken soup", "1 can (10.75oz) can cream of mushroom soup", "2 (10oz) cans diced tomatoes & green chiles, drained", "1 tsp dried oregano", "1 tsp ground cumin", "1 tsp chili powder", "1 (3-4lb) roasted chicken, skinned, boned and shredded", "3 cup shredded cheddar cheese", "3 cups crumbled lime tortilla chips", "**Preheat the oven to 350°**"], "instructions": "Lightly grease a 13 x 9 baking dish and set aside.\nMelt the butter in a large pan over medium high heat and add the onion. Sauté until the onions are translucent.\nAdd the green pepper and garlic and cook about 3 minutes more.\nStir in the chicken broth and the next 6 ingredients. Cook stirring occasionally for another 8 minutes.\nLayer ½ of the chicken in the prepared dish and top with the soup mixture, then 1 cup of the cheddar cheese and then ½ of the tortilla chips. Repaeat the layers once more. Top with the remaining cheese.\nBake for 55 minutes or until bubbly. Let stand for 10 minutes before serving.", "image": "https://static.wixstatic.com/media/75d545_bd8544e545b44d759e5b92373b0021aa~mv2.jpeg"}, {"slug": "easy-chicken-tortilla-soup-serves-8-10", "title": "Easy Chicken Tortilla Soup", "serves": "Serves 8-10", "category": "Soup & Sandwiches", "date": "2022-02-25", "ingredients": ["2-3 cups shredded cooked chicken", "32oz of chicken broth", "3 10.75oz cans of cream of tomato soup", "1 20oz can of black beans with liquid", "1 large can of black olives, sliced", "1 ½ cup shredded Cheddar cheese", "1 package taco seasoning", "2 dashes hot sauce", "2 jalapeno peppers, seeded and chopped", "1 bunch of cilantro chopped", "Tortilla chips"], "instructions": "Combine all of the ingredients except the cilantro and the Tortilla chips, in a crock-pot and cook until heated through. Add the cilantro right before serving and garnish with the tortilla chips.", "image": "img/easy-chicken-tortilla-soup-serves-8-10.jpg"}, {"slug": "easy-cocktail-franks", "title": "Easy Cocktail Franks", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["½ cup currant jelly", "¼ cup Dijon mustard", "1 package cocktail franks"], "instructions": "Mix all ingredients in a medium saucepan or small crock-pot and cook over medium heat until the jelly melts and the franks are heated through.\nServe in a decorative bowl with toothpicks for self service.", "image": "img/easy-cocktail-franks.jpg"}, {"slug": "easy-delicious-crock-pot-or-stove-top-meatball-appetizer", "title": "Easy & Delicious Crock Pot or Stove Top Meatball Appetizer", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["2 (12 oz.) jars Heinz Chili Sauce", "1 (32 oz.) jar Grape Jelly", "1 (32 oz.) bag frozen Meatballs (approx. 65)"], "instructions": "Place chili sauce and grape jelly in crock pot or large pot.\nPot version:\nCook on low flame until jelly is melted and sauce is smooth, stirring often. Add frozen meatballs. Heat until meatballs are thawed then simmer for about 3 hours.\nCrock Pot version:\nAfter combining sauces, stir until combined and sauce is smooth. Add meatballs and coat with sauce. Set to High and cook for 3 hours.\nThis recipe can be enjoyed as a wonderful appetizer or served over sticky rice for a main dish. You can also substitute currant jelly for the grape jelly OR substitute one 18 oz. jar BBQ sauce for the chili sauce.", "image": "img/easy-delicious-crock-pot-or-stove-top-meatball-appetizer.jpg"}, {"slug": "easy-stuffed-peppers-serves-8", "title": "Easy Stuffed Peppers", "serves": "Serves 8", "category": "Casserole", "date": "2022-03-30", "ingredients": ["1 lb ground sirloin", "½ lb ground Italian sausage", "1 (10 oz) can petite diced tomatoes with oregano and basil", "¼ cup chopped fresh parsley", "4 cloves garlic, minced", "2 tsp salt", "1 tsp ground black pepper", "2 large red bell peppers", "2 large yellow peppers", "1 cup long grain rice", "2 cups water", "1 tbsp extra virgin olive oil", "1 onion, minced", "2 cups Rao’s Marinara sauce", "1 cup beef broth", "1 tbsp balsamic vinegar", "¼ tsp red pepper flakes", "1 cup freshly grated parmesan cheese", "Preheat oven to 375º"], "instructions": "Place the rice and water in a medium saucepan and bring to a boil. Reduce the heat to low, cover and cook for about 20 minutes or until the water has been fully absorbed. Remove from heat, fluff with a fork and set aside.\nIn a large skillet over medium heat, brown the sausage and the beef, breaking into small pieces as it cooks. When completely browned, remove to a bowl and set aside.\nIn the same skillet, heat the olive oil and add the onion and garlic. Cook until the onion is translucent.\nAdd the marinara sauce, beef broth, balsamic vinegar and red pepper flakes to the onion and garlic.\nSpread the sauce evenly into a 9 x 13 baking dish.\nIn the same skillet that the sauce was cooked in, add meat, rice, diced tomatoes, parsley, salt and pepper. Stir in half of the parmesan to the meat mixture and stir well to combine.\nHalve the peppers lengthwise, seed and carefully remove the stem.\nPlace the peppers in the baking dish and fill with the meat and rice mixture. Sprinkle with the rest of the parmesan cheese and bake for 20 minutes. You may want to top with shredded mozzarella at this point if desired.", "image": "https://static.wixstatic.com/media/75d545_de5174a08be346e291816edc8e843453~mv2.jpg"}, {"slug": "easy-turkey-gravy-serves-28", "title": "Easy Turkey Gravy", "serves": "Serves 28", "category": "Gravy, Sauce & Dressing", "date": "2022-02-25", "ingredients": ["5 cups turkey stock with pan drippings", "1 (10.75oz) can condensed cream of chicken soup", "1 tsp poultry seasonings", "½ tsp black pepper", "1 tsp seasoned salt", "¼ tsp garlic powder", "1 cup milk", "1/3 cup flour"], "instructions": "Bring the turkey stock to a boil in a large saucepan. Stir in the soup, poultry seasoning, pepper, salt and garlic powder. Blend well.\nReduce the heat and simmer.\nWarm the milk in the microwave and whisk in the flour until smooth.\nReturn the gravy to a boil and gradually add the milk mixture. Continue cooking until thickened, stirring constantly.", "image": "img/easy-turkey-gravy-serves-28.jpg"}, {"slug": "easy-vodka-sauce-serves-10", "title": "Easy Vodka Sauce", "serves": "Serves 10", "category": "Gravy, Sauce & Dressing", "date": "2022-02-25", "ingredients": ["½ cup butter", "1 onion, diced", "1 cup vodka", "2 28oz cans crushed tomatoes", "1 pint heavy cream"], "instructions": "In a skillet over medium heat, sauté the onion in the butter until lightly browned and soft.\nPour in the vodka and let cook for 10 minutes. Mix in the crushed tomatoes and cook for 30 minutes.\nServe with your favorite pasta.", "image": "img/easy-vodka-sauce-serves-10.jpg"}, {"slug": "edamame-quinoa-salad", "title": "Edamame Quinoa Salad", "serves": "", "category": "Salads", "date": "2022-02-25", "ingredients": ["16oz frozen shelled Edamame", "1 ¼ cup frozen corn", "1 ½ cup cooked cooled quinoa", "2 sliced green onions", "1 medium red pepper, diced", "2 tbsp minced fresh cilantro", "2 tbsp extra virgin olive oil", "1 ½ tbsp. lemon juice, freshly squeezed", "1 ½ tbsp. lime juice, freshly squeezed", "½ tsp salt", "½ tsp dried thyme", "½ tsp chili powder", "¼ tsp freshly ground black pepper", "dash of cayenne"], "instructions": "Briefly boil the edamame and the corn, just until tender. Drain and cool completely.\nIn a large bowl combine the edamame, corn, quinoa, green onion, red pepper, and cilantro.\nIn a small bowl whisk the olive oil, lemon juice, lime juice, salt, chili powder, black pepper, thyme and cayenne. Pour over the edamame mixture and toss to coat. Cover and chill for at least 2 hours.", "image": "img/edamame-quinoa-salad.jpg"}, {"slug": "egg-casserole-serves-6", "title": "Egg Casserole", "serves": "Serves 6", "category": "Breakfast", "date": "2022-02-25", "ingredients": ["2 cups croutons, seasoned", "1 cup cheddar cheese, shredded", "4 eggs", "2 cup half and half", "½ tsp salt", "½ tsp prepared mustard", "dash of black pepper", "½ tsp onion salt", "½ lb cooked crumbled bacon or bulk breakfast sausage, cooked and drained"], "instructions": "Butter an 8x8 casserole dish. Place the croutons in the casserole.\nSprinkle the cheddar cheese over the croutons.\nBeat the eggs, half and half, salt, mustard, pepper and onion salt together until well blended. Pour over the croutons. Sprinkle with the bacon or sausage.\nRefrigerate overnight. Bake for 1 hour at 350° uncovered. Let cool for 5 minutes before serving.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "egg-roll-in-a-bowl-serves-6", "title": "Egg Roll in a Bowl", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["1 1/2lb ground chicken", "1 large sweet onion, finely chopped", "2 tbsp sesame oil", "1 1/2 tsp ginger, powdered", "1/2tsp black pepper", "4 garlic cloves, minced", "1 tsp salt", "1 tsp granulated Stevia", "1/2 tsp crushed red pepper", "2 tbsp white wine", "1/3 cup beef broth", "9 cups coleslaw mix(with carrots and red cabbage)", "1 ½ cup shredded carrots", "1-2 tbsp of low sodium soy sauce or coconut aminos", "4 green onions, thinly sliced"], "instructions": "Cook the chicken in a large skillet until browned; breaking into small pieces with a spoon as it cooks.\nAdd the onions, garlic and sesame oil. Cook until the onions afre translucent. Reduce the heat to medium.\nAdd the ginger, black pepper, salt, Stevia, red pepper, wine and broth to the skillet and stir to combine.\nAdd the coleslaw mix and the carrots and cook until the vegetables begin to soften.\nAdd the soy sauce to taste and serve!", "image": "img/egg-roll-in-a-bowl-serves-6.jpg"}, {"slug": "escarole-with-italian-sausage-white-beans", "title": "Escarole with Italian Sausage & White Beans", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["3tbsp extra virgin olive oil", "2lbs ground Italian sausage", "1 cup chopped Vidalia onion", "½ cup chopped prosciutto", "1 ½ tbsp. minced garlic", "1tsp dried crushed red pepper", "1 large head of escarole", "1 ½ cup dry white wine", "3 15oz cans Great Northern beans, rinsed, drained", "3 cups chicken stock or low salt chicken broth", "freshly shaved Parmesan cheese"], "instructions": "Heat the oil in a heavy large pot over medium high heat. Sauté the sausage, breaking it up with a spoon, until cooked through. Remove the sausage with a slotted spoon to a bowl, leaving the drippings in the pot.\nReduce the heat and add the onion. Sauté until translucent, about 5 minutes. Add the prosciutto and sauté for another minute. Mix in garlic and crushed pepper.\nAdd the escarole and sauté until it has wilted, about 2 minutes. Add the wine and cook for 2 minutes.\nAdd the beans, chicken stock and sausage and simmer for 10 minutes. Season with salt and pepper to taste. Transfer to soup bowls and top with shaved Parmesan cheese.", "image": "img/escarole-with-italian-sausage-white-beans.jpg"}, {"slug": "everything-bagel-salmon-serves-4", "title": "Everything Bagel Salmon", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["4 6 oz salmon filets, skin on", "Your favorite everything bagel seasoning", "Honey", "1 ½ tbsp olive oil", "**Preheat oven to 400º**"], "instructions": "Place everything seasoning into a shallow bowl or pie plate.\nBaste the skinless side of the salmon filets with a thin coat of honey and dredge through the everything seasoning to coat.\nHeat the oil in an oven safe pan and add the salmon, seed side down and sear for 3-4 minutes.\nFlip the salmon over and transfer the pan to the oven. Bake for 6-8 minutes or until the fish is fully cooked.\n*If your favorite seasoning does not contain salt, you should salt your salmon filets, to taste, before basting with the honey.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "everything-bagel-seasoning", "title": "Everything Bagel Seasoning", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["¼ cup sesame seeds", "¼ cup poppy seeds", "3 tbsp dried minced onion", "3 tbsp dried minced garlic", "2 tbsp coarse sea salt"], "instructions": "In a small bowl, mix all ingredients and store in an airtight container for up to 1 month.", "image": "https://static.wixstatic.com/media/75d545_4ae4aa35783b48bcb06f0e9dc5b93e89~mv2.jpeg"}, {"slug": "everything-cashews-ii", "title": "Everything Cashews II", "serves": "", "category": "Appetizers & Dips", "date": "2023-06-26", "ingredients": ["2 cups raw whole cashews", "1 ½ tbsp unsalted butter", "3 tbsp honey"], "instructions": "[2 tbsp everything bagel seasoning](https://www.mymomshomecooking.com/post/everything-bagel-seasoning)\nLine a large baking sheet with parchment paper and set aside.\nHeat a large skillet over medium heat and add the cashew to toast until fragrant.\nAdd the butter and honey to the pan and stir to coat. Allow the mixture to bubble and thicken, stirring often.\nOnce thickened, stir in the everything seasoning.\nRemove the cashews to the parchment lined baking sheet, and spread into a single layer. Allow to cool before serving.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "everything-cocktail-franks-makes-about-30", "title": "Everything Cocktail Franks Makes about 30", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 8oz Pillsbury Crescent rolls", "1 package of cocktail franks"], "instructions": "[Everything seasoning](https://www.mymomshomecooking.com/post/everything-bagel-seasoning)\n1 egg, beaten\n**Preheat the oven to 375°**\nLine a cookie sheet with parchment paper.\nOpen the crescent rolls and cut small triangles of dough to fit the cocktail franks.\nRoll each frank with dough as you would to make a crescent roll. Place on the cookie sheet.\nBrush each frank with the beaten egg and sprinkle with the everything seasoning.\nBake for 15 minutes or until the dough is golden brown. Serve with your favorite condiment.", "image": "https://static.wixstatic.com/media/75d545_0a318055bfba4c6ba29e89adcaa3ad59~mv2.jpeg"}, {"slug": "extra-rich-mashed-potatoes", "title": "Extra Rich Mashed Potatoes", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["Use light cream, Half and half, or Crème Fraîche in place of milk.", "**Cheesy Mashed Potatoes**"], "instructions": "Stir in 1 cup of shredded or crumbled cheese. Cheddar, Gruyère, Parmesan or Goat cheese after mashing.", "image": "img/extra-rich-mashed-potatoes.jpg"}, {"slug": "farfalle-vegetable-salad-serves-6", "title": "Farfalle Vegetable Salad", "serves": "Serves 6", "category": "Salads", "date": "2022-03-01", "ingredients": ["1 16 oz box mini farfalle", "2/3 cup light mayonnaise", "2 tbsp red wine vinegar", "1 tsp salt", "½ tsp freshly ground pepper", "6 Roma tomatoes, seeded and diced", "2 large carrots, diced", "2/3 cup chopped fresh basil", "1/3 cup chopped red onion"], "instructions": "Cook pasta according to package directions for al dente. Rinse and set aside.\nIn a small bowl, combine the mayonnaise, vinegar, salt and pepper with a whisk.\nIn a large salad bowl, toss the pasta with the tomatoes, carrots, basil and onion. Add the dressing and toss to coat.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "farro-arugula-salad-serves-6", "title": "Farro Arugula Salad", "serves": "Serves 6", "category": "Salads", "date": "2022-02-25", "ingredients": ["1 cup Farro", "1 cup apple cider", "2 tsp kosher salt", "2 bay leaves", "8 tbsp extra virgin olive oil", "2 tbsp fresh lemon juice", "½ to ¾ cup shaved Parmesan", "½ cup chopped pistachio nuts", "2 cups baby arugula", "1 cup basil leaves, torn", "1 cup mint leaves", "¾ cup halved cherry tomatoes", "1/3 cup sliced radish", "Maldon flaky sea salt"], "instructions": "In a medium saucepan, add the cider, salt, bay leaves, apple cider and 2 cups water. Bring to a simmer. Continue cooking until the faro is tender and the liquid has been absorbed. About 30 minutes. If the liquid evaporates before the faro is done add a little more water.\nLet the faro cool and discard the bay leaves.\nIn a large salad bowl, whisk the olive oil, lemon juice and a pinch of salt.\nAdd the faro, cheese and pistachio nuts. Toss.\nFold in the arugula, basil, tomatoes, radish, and flaky salt to taste. Serve immediately.", "image": "img/farro-arugula-salad-serves-6.jpg"}, {"slug": "farro-tomato-salad-serves-4", "title": "Farro & Tomato Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-28", "ingredients": ["¾ cup uncooked pearl Farro", "½ tsp salt", "3 cups water", "3medium Roma tomatoes, seeded and diced", "½ cup chopped fresh parsley", "3 tbsp small diced red onion", "1 tbsp balsamic vinegar", "1 tbsp extra virgin olive oil", "¼ tsp kosher salt"], "instructions": "In a medium pot, combine the farro, salt and water and bring to boil. Reduce the heat and simmer, covered until the farro is tender. (about 20-30 minutes) Drain and set aside to cool.\nIn a medium bowl, mix the tomatoes, parsley, onion, vinegar, oil and salt.\nWhen the farro has cooled, add it to the tomato mixture and chill before serving. I find stirring a few times while chilling mixes the flavors.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "fish-tacos-with-chipotle-aioli-serves-6-2-tacos-each", "title": "Fish Tacos with Chipotle Aioli Serves 6(2 tacos each)", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["3 cups Panko bread crumbs", "4 eggs", "3lbs Tilapia", "2 tbsp salt", "1tbsp freshly ground black pepper", "1tbsp chipotle powder", "12 white corn tortillas", "4 cups Napa cabbage, shredded", "1 cup mayonnaise", "1 cup sour cream", "2 chipotle peppers, canned in adobo sauce", "2tbsp adobo sauce(from the peppers)", "2tbsp freshly squeezed lime juice", "12 lime wedges", "peanut oil", "**Sauce**:"], "instructions": "In a blender, combine the mayonnaise, sour cream, peppers, adobo sauce and lime juice. Add the salt and the pepper to taste. Place in a bowl and refrigerate for an hour. After chilling, season to taste with salt and pepper.\n**Fish**:\nIn a shallow dish combine the panko, salt, pepper and chipotle powder. Whisk the eggs in another shallow dish with some salt and pepper.\nSlice the fish into 1” x 3-4” long pieces. Dip the fish in the egg and then coat in the panko crumbs. Let them rest for 2-3 minutes before cooking.\nIn a heavy skillet add peanut oil; enough to cover the bottom and cook the fish in. The oil she be about 375°. Cook the fish in batches. Cook for 4-5 minutes until golden brown and crispy. Let drain on a paper towel.\nWarm the tortillas in the oven.\nServe the tacos by placing some sauce on the bottom of each tortilla, then add the fish and the cabbage. Garnish with a lime wedge. Goes well with a [pineapple mango salsa](https://www.mymomshomecooking.com/post/pineapple-mango-salsa-serve-8).", "image": "https://static.wixstatic.com/media/75d545_44ead9365e054d34a09e632db81cb56a~mv2.jpg"}, {"slug": "french-crumb-apple-pie", "title": "French Crumb Apple Pie", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["Pastry for a single 9\" pie crust", "¾ cup sugar", "¼ cup flour", "½ tsp nutmeg", "½ tsp cinnamon", "dash of salt", "6 cups thinly sliced apples ( about 6 medium apples)", "**Crumb topping**", "2 cup flour", "1 cup firm butter, cut into pieces", "1 cup firmly packed light brown sugar", "**Preheat the oven to 425°**"], "instructions": "Prepare the pastry.\nIn a large bowl, mix the sugar, flour, nutmeg cinnamon and salt.\nStir in the apples. Add to the pastry lined pie plate.\nIn a medium bowl, mix the flour and brown sugar until well combined. Cut in the butter until large crumbs form.\nCover the apples with the crumb topping.\nBake for 50 minutes. Watch the pie carefully and when it has become golden brown on top, lightly cover with a large piece of foil. This prevents the crust and the crumbs from burning during the remainder of the baking time.\nServe warm with vanilla ice cream or fresh whipped cream.", "image": "https://static.wixstatic.com/media/75d545_5a7989f671f54895aa52665294d17292~mv2.jpg"}, {"slug": "french-toast", "title": "French Toast", "serves": "", "category": "Breakfast", "date": "2022-02-25", "ingredients": ["3 eggs, slightly beaten", "½ tsp salt", "2 tbsp sugar", "1 cup of milk", "¼ tsp cinnamon, or to taste", "10 slices of bread( thicker the better)"], "instructions": "Mix the first 5 ingredients in a large bowl. Heat a griddle over medium heat, spray with a butter based cooking spray. Dip the bread in the egg mixture coating both sides well. Cook on greased griddle over medium high heat until each side is golden brown.\nServe with butter and hot maple syrup.", "image": "img/french-toast.jpg"}, {"slug": "fresh-raspberries-and-white-chocolate", "title": "Fresh Raspberries and White Chocolate", "serves": "", "category": "Desserts", "date": "2022-02-25", "ingredients": ["Fresh Raspberries", "Ghirardelli White Chocolate Morsels"], "instructions": "Wash the raspberries and drain on a paper towel.\nStuff each raspberry with a white chocolate morsel and carefully place in a small decorative glass bowl for serving. Fill the bowl and serve.\nGreat served alone with a Chardonnay or Prosecco, or as an accompaniment to chocolate desserts.", "image": "https://static.wixstatic.com/media/75d545_f638ead70dc64253b5220626e6baa4cb~mv2.jpg"}, {"slug": "fried-green-tomatoes-serves-8", "title": "Fried Green Tomatoes", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-03-11", "ingredients": ["8 medium green tomatoes, trimmed", "3 ½ tsp coarse sea salt", "1 tsp fresh ground pepper", "5 large eggs, beaten", "1 cup buttermilk", "3 cups flour", "4 cups panko", "1 cup Italian bread crumbs", "Vegetable oil"], "instructions": "Slice the tomatoes ¼” thick and season with salt and pepper.\nIn a shallow bowl or pie plate, whisk the eggs and the buttermilk together.\nIn a second shallow dish, combine the flour, ½ tsp salt and ¼ tsp pepper.\nIn a third shallow dish, combine the panko, the Italian bread crumbs, 1 tsp of the coarse salt and ½ tsp of pepper.\nHeat a cup of oil in a large skillet and place over medium high heat.\nDredge the tomatoes through the flour, coat with the egg mixture and coat with the panko mixture.\nPlace the tomatoes, a few at a time in the oil and fry for about 2-3 minutes per side. Drain on a paper towel.\nAfter frying about half the tomatoes, discard the oil and replace with a fresh cup.\nServe the tomatoes hot with your favorite dipping sauce or aioli.", "image": "https://static.wixstatic.com/media/75d545_3f78f688e381454fa7b56645a594ea2a~mv2.jpeg"}, {"slug": "fruit-dip", "title": "Fruit Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["Large container of Cool Whip", "1 (3.5 oz ) package of instant Pistachio Pudding", "Amaretto"], "instructions": "Mix the pudding, cool whip and 2 shots of Amaretto and refrigerate over night. Add 2-3 more shots and serve.\nGreat with Cantaloupe, Honeydew melon, strawberries and grapes.", "image": "img/fruit-dip.jpg"}, {"slug": "fudgy-keto-brownies-makes-9", "title": "Fudgy Keto Brownies", "serves": "Makes 9", "category": "Desserts", "date": "2022-02-25", "ingredients": ["9 tbsp butter", "1 ¼ cup Swerve confectioners sugar", "½ cup cocoa powder", "½ tsp kosher salt", "2 eggs", "½ tsp vanilla extract", "½ cup + 1 tbsp super fine almond flour"], "instructions": "Preheat oven to 350°\nLine the bottom of a 8” baking pan with parchment paper and use spray butter on the sides of the pan.\nIn a medium bowl, add the butter, sugar, cocoa and salt. Melt in the microwave on medium and at 1 minute intervals. Stirring between to blend the ingredients. Once the butter has melted and you blend the ingredients easily, mix and set aside to cool.\nOnce the chocolate mixture has cooled, add the eggs 1 at a time. Stir until the eggs are well incorporated into the batter. Add the vanilla.\nYour batter should be very smooth at this point. Add the almond flour and mix until blended.\nBake for 23 minutes or until a toothpick inserted in the center comes out clean.\nGarnish with flaky sea salt if desired.\nCalories 102 Carbs 3g Fiber 2g", "image": "img/fudgy-keto-brownies-makes-9.jpg"}, {"slug": "garlic-mashed-cauliflower-serves-4", "title": "Garlic Mashed Cauliflower", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["1 head cauliflower, cut into florets", "1 tbsp extra virgin olive oil", "1 clove garlic, minced", "¼ cup grated parmesan cheese", "1 tbsp reduced fat cream cheese", "½ tsp kosher salt", "1/8 tsp freshly ground black pepper"], "instructions": "Fill a large pot with a steamer insert, just below the bottom of the steamer. Bring the water to a boil and add the cauliflower. Cover and cook until tender. About 10 minutes.\nIn a small frying pan over medium heat cook the garlic in the olive oil until softened. Remove from the heat.\nPlace half of the cauliflower in a food processor and blend on high until smooth. Add the remaining cauliflower to the processor, a few pieces at a time until all the cauliflower is creamy.\nBlend in the garlic, Parmesan, cream cheese, salt and pepper. Serve.", "image": "img/garlic-mashed-cauliflower-serves-4.jpg"}, {"slug": "garlic-panko-crusted-tilapia", "title": "Garlic Panko Crusted Tilapia", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["6 tilapia fillets (if not fresh, than thawed)", "2 cups panko", "1/4 cup chopped parsley", "2 garlic cloves (minced) Or substitute with 2 teaspoons of garlic powder", "2 tablespoons of crushed red pepper flakes", "3 tablespoons melted butter", "salt and pepper to taste", "lemon wedges to serve"], "instructions": "1. Preheat oven to 400 Degrees.\n2. Place fillets onto baking sheet that has been sprayed with cooking oil. (I prefer using olive oil spray) Sprinkle salt and pepper onto the fillets and set aside.\n3. In a small mixing bowl, combine panko, parsley, garlic, red pepper flakes, and butter. Once it is well mixed, use a spoon to scoop an even amount of the mixture onto each fillet.\n4. Spread the mixture across the tops of all fillets giving them each a nice coat. Use a spoon or your hands to gently press the mixture onto the fillets so that they are firmly coated.\n5. Place in the oven and cook, uncovered, for approximately 15-20 minutes. You will see when they are done that they easily flake with a fork, and the meat has a nice white color.Sometimes it is helpful to keep a close eye on them during the last 5 minutes to make sure they don’t over cook.\n6. Slice lemon wedges to place with each serving. And enjoy!", "image": "img/garlic-panko-crusted-tilapia.jpg"}, {"slug": "goat-cheese-sundried-tomato-and-olive-dip-serves-10", "title": "Goat Cheese, Sundried Tomato and Olive Dip", "serves": "Serves 10", "category": "Appetizers & Dips", "date": "2022-02-25", "ingredients": ["12 oz goat cheese", "3tbsp extra virgin olive oil", "1 cup oil packed julienne sun dried tomatoes, drained", "1 cup black olives, chopped", "4tbsp chopped fresh basil", "2tbsp chopped fresh rosemary", "3 cloves garlic, halved"], "instructions": "Slice the goat cheese into 1” slices and place in a single layer on a round platter. Sprinkle olive oil, sun dried tomatoes, black olives, basil and rosemary over the cheese.\nUsing toothpicks, insert the garlic cloves into the cheese evenly around the platter.\nMarinate in the refrigerator for 6 hours, or overnight. Remove the toothpicks and the garlic and serve with thinly sliced French bread.", "image": "img/goat-cheese-sundried-tomato-and-olive-dip-serves-10.jpg"}, {"slug": "gorgonzola-cranberry-walnut-salad", "title": "Gorgonzola & Cranberry Walnut Salad", "serves": "", "category": "Salads", "date": "2022-02-25", "ingredients": ["2 bags of mixed greens or 6 hearts of Romaine, chopped", "1 cup dried cranberries", "1 cup crumbled gorgonzola cheese", "1 ½ cup vinaigrette", "1 cup chopped walnuts"], "instructions": "Toss all the ingredients in a large salad bowl and serve.", "image": "img/gorgonzola-cranberry-walnut-salad.jpg"}, {"slug": "grilled-broccoli-serves-6", "title": "Grilled Broccoli", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["8 cups fresh broccoli florets", "¼ cup fresh lemon juice", "¼ cup extra virgin olive oil", "½ tsp salt", "½ tsp black pepper", "1 ½ cup grated Parmesan cheese"], "instructions": "Place the broccoli in a large bowl. In a small bowl combine the olive oil, lemon juice, salt and pepper; pour over the broccoli and toss to coat. Let stand for 30 minutes.\nPlace the grated Parmesan in a large resealable plastic bag, add the broccoli a few pieces at time and shake to coat. Remove the broccoli to a foil pan coated with an olive oil cooking spray and cover.\nPlace the pan on the grill and grill for 8-10 minutes, shaking the pan from side to side frequently.\nPlace the grilled broccoli in a serving dish and garnish with shaved Parmesan if desired.", "image": "img/grilled-broccoli-serves-6.jpg"}, {"slug": "grilled-corn-on-the-cob-with-herbed-butter", "title": "Grilled Corn on the Cob with Herbed Butter", "serves": "", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["¼ cup butter", "½ tsp garlic salt", "2 tbsp fresh chopped chives", "8 ears fresh sweet corn", "1/3 cup grated parmesan cheese"], "instructions": "Cut a sheet of 30” x 18” non stick foil.\nIn a small bowl, place the butter, garlic salt and chives. Microwave on high until the butter has melted.\nPlace the ears of corn on the foil and baste completely with the butter mixture. Pour the remaining butter evenly over the corn and sprinkle with the parmesan cheese.\nBring up the sides of the foil to cover the corn in a tent like fashion. Seal all the edges with a tight ½” fold. Allow a space for heat to circulate.\nPlace the packet directly on the grill over low heat. Cover the grill and cook for 12-18 minutes. Rotate the packet ½ turn every 6 minutes, until the corn is tender.", "image": "img/grilled-corn-on-the-cob-with-herbed-butter.jpg"}, {"slug": "grilled-garlic-and-cumin-potatoes-serves-4", "title": "Grilled Garlic and Cumin Potatoes", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-25", "ingredients": ["12 unpeeled small red potatoes, quartered", "4 tbsp butter, melted(may substitute olive oil for butter)", "1 tsp garlic powder", "1 tsp ground cumin", "1 tsp paprika", "½ tsp salt", "½ tsp pepper", "¼ cup chopped fresh cilantro"], "instructions": "Place the potatoes in a large bowl and add the butter, garlic, cumin, paprika, salt and pepper. Toss well to coat.\nPlace the potatoes in a foil pan and cover. Place on the grill and grill for 20-30 minutes shaking the pan from side to side frequently throughout cooking.\nRemove from the grill to a serving dish and add the chopped cilantro; toss and serve.", "image": "img/grilled-garlic-and-cumin-potatoes-serves-4.jpg"}, {"slug": "grilled-halibut-with-cilantro-garlic-butter-serves-4", "title": "Grilled Halibut with Cilantro Garlic Butter", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["4 6oz Halibut filets", "1 lime, cut into wedges", "salt and pepper to taste", "3 cloves of garlic, chopped", "½ cup chopped fresh cilantro", "1 tbsp fresh lime juice", "2 tbsp butter", "1 tbsp extra virgin olive oil", "**Preheat the grill for high heat or the oven to 400°**"], "instructions": "Squeeze the juice from each lime wedge on the halibut filets. Season with the salt and pepper.\nCook the fish until it easily flakes with a fork and remove to a warm platter.\nHeat the oil in a skillet over medium heat and add the garlic. Cook and stir just until fragrant. About 2 minutes.\nStir in the butter and the remaining lime juice. Add the cilantro and serve over the fish.", "image": "img/grilled-halibut-with-cilantro-garlic-butter-serves-4.jpg"}, {"slug": "grilled-maple-glazed-herbed-salmon-with-pineapple-salsa", "title": "Grilled Maple Glazed Herbed Salmon with Pineapple Salsa", "serves": "", "category": "Seafood", "date": "2022-02-26", "ingredients": ["Serves 4", "**Salmon**", "4 6oz salmon fillets, no skin", "1 tsp paprika", "1 tsp chili powder", "¼ tsp sugar", "1 tsp kosher salt", "4 tbsp 100% maple syrup", "**Salsa**", "3 cups diced fresh pineapple", "2 tablespoons fresh chopped cilantro", "1 ½ tbsp 100% maple syrup"], "instructions": "In a medium bowl combine all the salsa ingredients and set aside.\nMix the paprika, chili powder, salt and sugar together in a small bowl.\nPlace the salmon in a baking dish and coat with the spice mixture. Cook on an oiled grill, for 6-8 minutes or until almost done; brush with the maple syrup and continue cooking until done.\nRemove the salmon from the grill and serve with the salsa as a garnish. Serve the remaining salsa in a bowl for additional garnish if desired.", "image": "img/grilled-maple-glazed-herbed-salmon-with-pineapple-salsa.jpg"}, {"slug": "grilled-salmon-with-cilantro-butter-sauce-serves-8", "title": "Grilled Salmon with Cilantro Butter Sauce", "serves": "Serves 8", "category": "Seafood", "date": "2022-02-26", "ingredients": ["4lbs Salmon filet, skin removed", "1/2 cup butter", "2 cups chopped cilantro", "2 jalapeno peppers, seeded and chopped", "Old Bay seasoning", "**Preheat the grill for high heat.**"], "instructions": "Place the salmon on a lightly greased piece of foil.\nMelt the butter in a small saucepan. Remove from the heat and stir in the cilantro and the jalapeno. The cilantro will become slightly wilted.\nDrizzle the ¾ of butter sauce over the salmon. The remaining sauce can be used to drizzle over the fish before serving or served with the fish on the side.\nSeason with the Old Bay to taste.\nPlace the the foil sheet on the grill and cook for about 20-25 minutes or until the fish easily flakes.", "image": "img/grilled-salmon-with-cilantro-butter-sauce-serves-8.jpg"}, {"slug": "grilled-salmon-with-spicy-marinade-serves-8", "title": "Grilled Salmon with Spicy Marinade", "serves": "Serves 8", "category": "Seafood", "date": "2022-02-26", "ingredients": ["8 (4oz) salmon filets", "½ cup peanut oil", "4tbsp soy sauce", "4tbsp balsamic vinegar", "4tbsp scallions, thinly sliced", "1tbsp brown sugar", "2 cloves garlic, minced", "1 ½ tsp ground ginger", "2tsp red pepper flakes", "1tsp sesame oil", "½ tsp salt"], "instructions": "Place the salmon filets in s Ziploc bag and set aside.\nIn a medium bowl combine the remaining ingredients and mix well. Pour into the Ziploc bag over the salmon. Manipulate the bag so as to well cover all the filets. Refrigerate for 4-6 hours, turning the bag occasionally.\nPrepare the grill by lightly greasing the grate. Grill the filets about 5” from the coals for 10 minutes per inch of thickness of the salmon. Turn over halfway through the cooking process.", "image": "img/grilled-salmon-with-spicy-marinade-serves-8.jpg"}, {"slug": "grilled-swordfish-oriental-serves-4", "title": "Grilled Swordfish Oriental", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-26", "ingredients": ["Marinade:", "½ cup oil", "3tbsp soy sauce", "2tbsp dry sherry", "1tsp grated fresh ginger", "2 cloves garlic, minced", "4(4oz) swordfish steaks ¾ to 1” thick"], "instructions": "In a glass baking dish, combine all the marinade ingredients and mix well.\nPlace the steaks in the marinade and turn to coat. Cover and refrigerate for 4-6 hours, turning occasionally.\nRemove the fish from the marinade and place on and oiled grill rack 4-6” above coals. Cook 10-14 minutes or until the fish flakes easily with a fork. Be sure to turn the fish at least once, and brushing frequently with the marinade.", "image": "img/grilled-swordfish-oriental-serves-4.jpg"}, {"slug": "grilled-turkey-mozzarella-sandwiches-serves-4", "title": "Grilled Turkey & Mozzarella Sandwiches", "serves": "Serves 4", "category": "Soup & Sandwiches", "date": "2022-02-26", "ingredients": ["1 loaf Rye bread", "¾ lb Thinly sliced deli turkey breast", "½ lb of sliced mozzarella cheese", "1 large green bell pepper, sliced", "butter"], "instructions": "Butter one side of the rye bread for grilling and place 4-5 slices of turkey on unbuttered side. Top with 1-2 slices of mozzarella and a slice or 2 of the green pepper. Top with another slice of buttered rye bread, buttered side up. Grill in a medium frying pan over medium heat until golden (about 4-5 minutes)on both sides and the cheese has melted.", "image": "img/grilled-turkey-mozzarella-sandwiches-serves-4.jpg"}, {"slug": "guacamole-serves-8", "title": "Guacamole", "serves": "Serves 8", "category": "Appetizers & Dips", "date": "2022-02-26", "ingredients": ["3 Ripe Haas avocados", "2 tbsp fresh salsa, I use Top Crop from the produce department", "juice of 1 lime", "fine sea salt", "1 tbsp sour cream"], "instructions": "Cut the avocados in half and remove the pit. Scoop the avocado out of the skin with a spoon and place in a medium size bowl.\nMash the avocados. Don't over mash, it's better with some pieces left.\nAdd the salsa, sour cream and salt. Squeeze the lime juice into the mixture and stir to combine. You may add more salsa or salt to taste at this point.\nServe with your favorite chips.", "image": "https://static.wixstatic.com/media/75d545_0165977cf2f0473093b57d0e150f53b8~mv2.jpg"}, {"slug": "hamburger-cookies-makes-40", "title": "Hamburger Cookies", "serves": "Makes 40", "category": "Desserts", "date": "2022-02-26", "ingredients": ["80 (2 boxes)Nabisco Nilla Wafers for the buns", "40 (1 package) Keebler Grasshopper cookies for the burgers", "1 tube red frosting, ketchup", "1 tube yellow frosting, mustard", "4oz shredded coconut for the lettuce", "green food coloring for the coconut", "honey, to be used as glue", "ground nuts or sesame seeds"], "instructions": "Start with a Nilla wafer for the bottom of the bun, stick the grasshopper cookie to the \"bun\" with a dab of honey.\nOn opposite sides of the \"burger\" put dabs of red and yellow frosting.\nColor the shredded coconut with some of the green food coloring.\nSprinkle the colored coconut on top of the \"burger\".\nTop with another Nilla using another dab of honey.\nPress the wafer down onto the \"burger\" so that the red and yellow frostings ooze out of the edges.\nLightly coat the top of the \"bun\" with honey and sprinkle with either the nuts or the sesame seeds.\nMake a day ahead to give the honey time to dry.", "image": "img/hamburger-cookies-makes-40.jpg"}, {"slug": "hasselback-potatoes-serves-4", "title": "Hasselback Potatoes", "serves": "serves 4", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["4 (8oz) baking potatoes", "5 tbsp butter, melted", "¼ cup seasoned bread crumbs", "¼ cup fresh grated parmesan cheese", "salt and pepper to taste"], "instructions": "Preheat oven to 425° Oil a glass baking dish.\nPeel the potatoes and place in a bowl of cold water to prevent them from discoloring.\nPlace 2 long chop sticks or wooden skewers on either side of the potato on a cutting board. Slice each potato crosswise about 1/8” slices and about ¼” from the bottom of the potato. ( the chopsticks will prevent you from cutting all of the way thru) After cutting each potato return to the water to prevent the discoloring.\nPlace the potatoes cut side up in the baking dish and drizzle with half of the butter. Make sure some gets inside the potato. Season with salt and pepper.\nMix the parmesan cheese, bread crumbs and 1 tbsp of butter in a small bowl. Pat the mixture onto the top of each potato. Cover with aluminum foil and bake for 30 minutes. Remove the foil and bake for an additional 15 minutes .\nRemove from the oven (they should be golden brown and crispy on the outside). Drizzle with the remaining 2 tbsp of butter and serve.", "image": "img/hasselback-potatoes-serves-4.jpg"}, {"slug": "hearts-of-palm-salad-serves-6-8", "title": "Hearts of Palm Salad", "serves": "Serves 6-8", "category": "Salads", "date": "2022-02-26", "ingredients": ["2 14oz cans of hearts of palm", "½ lb fresh mushrooms, sliced thin", "20 cherry tomatoes, cut in ½", "1 small red onion, thinly sliced", "1 clove garlic, minced", "¼ cup lime juice, freshly squeezed", "½ cup extra virgin olive oil", "¼ cup finely chopped fresh parsley", "salt and pepper to taste"], "instructions": "Drain the hearts of palm and cut into ¾” rounds. Add to a large salad bowl. Add the mushrooms, onions, garlic, lime juice, olive oil, parsley, salt and pepper. Toss. At this point you may add more olive oil if desired.\nServe", "image": "img/hearts-of-palm-salad-serves-6-8.jpg"}, {"slug": "hoisin-marinade-for-fish", "title": "Hoisin Marinade for Fish", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-26", "ingredients": ["1 tbsp orange juice", "2 tbsp Hoisin sauce", "2 tsp honey"], "instructions": "Salt & pepper the fish(Salmon is best), brush with the marinade and broil or grill for 10- 15 minutes", "image": "img/hoisin-marinade-for-fish.jpg"}, {"slug": "hoisin-meatballs-makes-3-dozen", "title": "Hoisin Meatballs", "serves": "Makes 3 Dozen", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["1 ½ lb lean ground beef", "2 tbsp Hoisin sauce", "1 tbsp soy sauce", "1 tsp sesame oil", "¼ cup bread crumbs", "3 tbsp chopped green onions", "3 tbsp fresh minced parsley", "2 garlic cloves, minced", "1 tsp fresh ginger", "**Dipping Sauce**", "¼ cup rice vinegar", "¼ cup Hoisin sauce", "2 tbsp water", "2 tbsp sesame oil", "2 tbsp soy sauce", "1 tbsp honey", "2 cloves garlic, minced", "1 tsp fresh ginger", "**Preheat the oven to 350°**"], "instructions": "In a medium bowl combine the ground beef and the remaining 8 ingredients. Mix well.\nShape the meat into 1\" balls and place on a foil cookie sheet sprayed with cooking spray. Bake for 20- 25 minutes or until the meat is no longer pink.\nIn a small saucepan, combine the sauce ingredients and heat. Transfer to a small serving bowl and serve warm with the meatballs.", "image": "https://static.wixstatic.com/media/75d545_6cb1966d0089418f8824e55422ece4d2~mv2.jpg"}, {"slug": "hoisin-meatloaf-serves-4", "title": "Hoisin Meatloaf", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["1lb 90% lean ground beef", "½ cup panko breadcrumbs", "2tbsp lite soy sauce", "4tbsp Hoisin sauce, divided", "2 large scallions, thinly sliced and divided", "1 egg", "1 clove garlic, minced"], "instructions": "Preheat the oven to 350°.\nSpray a foil baking sheet with cooking spray.\nIn a large bowl combine the beef, panko, soy sauce, 2tbsp Hoisin, scallion, egg and garlic. Mix well.\nPlace the meat mixture on the foil baking sheet and form into a loaf. Spread the remaining Hoisin sauce over the top of the loaf, adding more if needed.\nPlace in the oven and bake for 50-60 minutes. Garnish with additional scallions and serve.", "image": "https://static.wixstatic.com/media/75d545_f4e48d3322b645f2bedff151c66a1d09~mv2.jpg"}, {"slug": "hoisin-pork-loin-serves-4", "title": "Hoisin Pork Loin", "serves": "Serves 4", "category": "", "date": "2022-02-26", "ingredients": ["Butter based cooking spray", "3lb pork loin roast", "¾ cup Hoisin sauce", "3 cloves garlic, minced", "2 tbsp freshly grated ginger", "1 tbsp chili paste", "1 tbsp rice wine vinegar", "1 tbsp soy sauce", "2 tbsp dark sesame oil", "4 tsp cornstarch", "3 scallions, thinly sliced", "1/3 cup chopped cilantro, if desired"], "instructions": "Coat the bottom of the crock-pot with the cooking spray and add the pork loin roast.\nIn a small bowl mix the hoisin sauce, garlic, ginger, chili paste, rice wine vinegar, soy sauce and sesame oil. With a wire whisk add in the cornstarch.\nPour the mixture over the top of the pork loin.\nCover the crock-pot and cook on low for 8 hours. 3 ½ hrs on high.\nRemove the pork to a platter and let stand for 10 minutes covered with foil. Slice the roast and serve with liquid from the crock-pot drizzled over the top. Garnish with the scallions and cilantro.", "image": "img/hoisin-pork-loin-serves-4.jpg"}, {"slug": "homemade-brownies", "title": "Homemade Brownies", "serves": "", "category": "Desserts", "date": "2022-02-26", "ingredients": ["1 ½ cup butter, softened", "3 cups sugar", "1 tbsp vanilla extract", "5 eggs", "2 cups flour", "1 cup unsweetened cocoa", "1 tsp baking powder", "1 tsp salt", "**Preheat the oven to 350°**"], "instructions": "Grease a 13 x 9 baking dish and set aside.\nIn a large bowl mix the the butter, sugar and vanilla. Beat in the eggs until well blended,\nStir in the flour, cocoa, baking powder and salt. Blend well.\nSpread the batter in the prepared dish and bake for 50-55 minutes. Or until knife inserted in the center comes out clean.", "image": "img/homemade-brownies.jpg"}, {"slug": "homemade-coleslaw", "title": "Homemade Coleslaw", "serves": "", "category": "Salads", "date": "2022-02-26", "ingredients": ["1 16oz bag coleslaw mix(with red cabbage)", "2 tbsp onion, diced", "2/3 cup Miracle Whip", "3 tbsp vegetable oil", "½ cup sugar", "1 tbsp white vinegar", "½ tsp Kosher salt", "½ tsp poppy seeds"], "instructions": "In a small mixing bowl whisk together the Miracle Whip, vegetable oil, sugar, vinegar, salt and poppy seeds. Set aside.\nIn a medium bowl combine the coleslaw mix and the onion and toss. Season to taste with salt and pepper.\nAdd half of the dressing and refrigerate for several hours. The coleslaw will become too soupy if you add all the dressing before you refrigerate. Add more dressing if desired after refrigeration. (we prefer a dryer coleslaw)", "image": "img/homemade-coleslaw.jpg"}, {"slug": "homemade-vanilla-extract", "title": "Homemade Vanilla Extract", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-03-16", "ingredients": ["2 Madagascar vanilla beans", "12 oz vodka"], "instructions": "Slice the vanilla pods, scrape out the beans and set aside.\nCut the pods into 1-2 inch pieces.\nIn a 2 cup mason jar or bottle, add the vodka, vanilla beans and pods.\nSeal the jar tightly and give it a good shake.\nPlace the jar in a dark place, it is important that the jar be away from sunlight.\nShake the jar once a day for a week and then once a week for 3 months. Then shake the jar once a month for another 3 months.\nAfter 6 months your vanilla should be ready for use.\nIf you would like to make Christmas gifts, use:\n21 vanilla beans\n1.75 liters of vodka\nEmpty ½ of the vodka into another empty vodka bottle and add the beans and pods, split evenly, to the vodka bottles. Seal, shake and store in a dark place.\nFollow the same shaking method and fermenting time. Divide amongst small 4 oz brown bottles, decorate and give as gifts. Your friends and family will love it!", "image": "https://static.wixstatic.com/media/75d545_6a8d3cbc66b841eeae71e64fde538ef8~mv2.jpg"}, {"slug": "honey-buffalo-meatballs-makes-80-meatballs", "title": "Honey Buffalo Meatballs", "serves": "Makes 80 meatballs", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["**Meatballs**", "3lbs lean ground beef", "3 eggs", "33 saltine crackers", "1 medium onion, finely chopped", "1/3 cup plus 3 tbsp whole milk", "2 tbsp light brown sugar", "1 tsp onion powder", "1 tsp salt", "1 ½ tsp garlic powder", "¾ tsp chili powder", "¾ tsp smoked paprika", "¾ tsp ground cumin", "¼ tsp pepper", "**Sauce**", "½ cup Frank’s hot sauce, divided", "½ cup plus 2 tbsp honey", "½ cup apricot preserves", "½ cup light brown sugar", "4 tbsp soy sauce", "3 tbsp corn starch", "**Preheat the oven to 450°**"], "instructions": "In a large bowl, whisk the eggs and add the remaining meatball ingredients. Mix until well combined. Roll the meatballs into 1 ½ inch balls or cocktail size and place on a foil baking sheet. Bake for 8-10 minutes or until lightly brown.\nWhile the meatballs are cooking, using only ¼ cup of hot sauce, mix all the sauce ingredients in a medium bowl.\nMake a layer of meatballs in the bottom of your crockpot and drizzle with some of the sauce. Continue layering until you are out of meatballs and sauce.\nCover and cook on low for 2 hours; gently stir the meatballs halfway through cooking. When done add additional hot sauce to taste.\nServe with rice, pasta or twice baked potatoes.", "image": "img/honey-buffalo-meatballs-makes-80-meatballs.jpg"}, {"slug": "honey-butter-skillet-corn-serves-4", "title": "Honey Butter Skillet Corn", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["2 tbsp butter", "3 tbsp honey", "1 16oz bag of white & golden corn, thawed and drained", "3oz cream cheese", "½ tsp salt", "¼ tsp pepper"], "instructions": "In a medium skillet, over medium heat, melt the butter and add the honey.\nOnce the butter is melted and is well combined with the honey, add the corn. Cook until the corn is heated through.\nAdd the cream cheese, salt and pepper and cook until heated and creamy.\nServe immediately.", "image": "img/honey-butter-skillet-corn-serves-4.jpg"}, {"slug": "honey-garlic-chicken", "title": "Honey Garlic Chicken", "serves": "", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["Serves 4-6", "2lb chicken filets", "Salt & pepper, to taste", "2 large eggs", "2 cup Panko", "1 1/3 cup honey", "8 cloves garlic, minced", "½ cup soy sauce", "1-2 tbsp Sriracha", "1 tbsp cornstarch", "4 green onions, sliced thin", "Toasted sesame seeds", "**Preheat the oven to 400°**"], "instructions": "Lightly spray 2 foil cookie sheets with butter spray.\nCut each chicken filet in half (or thirds depending on how big) you are looking to get nice size strips. Salt and pepper the strips.\nWhisk the eggs in a pie plate. Add the panko to another pie plate.\nCoat the chicken with egg and place in the panko, pressing to coat the entire strip.\nPlace the chicken on the prepared foil cookie sheet and bake for about 20 minutes or until light brown.\nWhile the chicken is baking, prepare the sauce. In a large frying pan add the honey, garlic, soy sauce and Sriracha. Cook over medium heat.\nAdd the cornstarch to 1/3 cup of water and while the sauce is simmering add a little at a time until just thickened. The thickness of the sauce is really a personal choice. If you like a more sticky honey chicken add more if you like it a little more like a sauce, add less.\nAdd the chicken to the sauce and turn to coat. Sprinkle the chicken with some toasted sesame seeds and green onions and serve.", "image": "img/honey-garlic-chicken.jpg"}, {"slug": "honey-glaze-for-roast-turkey", "title": "Honey Glaze for Roast Turkey", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-03-03", "ingredients": ["½ cup honey", "½ cup Dijon mustard", "1 ½ tsp minced fresh rosemary", "1 tsp onion powder", "½ tsp salt", "½ tsp garlic powder", "¼ tsp pepper"], "instructions": "Mix all the ingredients in a small bowl and brush the turkey before roasting. While the turkey roasts, baste, alternating with the pan drippings and the honey glaze .", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "honey-roasted-red-potatoes-serves-8", "title": "Honey Roasted Red Potatoes", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["2lbs small red potatoes, washed and quartered", "4 tbsp diced Vidalia onion", "6 tbsp butter, melted", "3 tbsp honey", "2 ½ tsp ground mustard", "½ tsp salt", "½ tsp freshly ground pepper"], "instructions": "Preheat the oven to 375°.\nLightly coat a large foil cookie sheet with a butter based cooking spray.\nPlace the potatoes in a large mixing bowl and add the onion.\nIn a small bowl combine the melted butter, honey, mustard, salt and pepper. Add to the potatoes and toss to combine. Spread the potatoes on the prepared cookie sheet. Drizzle any remaining liquid in the bowl over the potatoes.\nBake for 35 minutes or until tender, stirring halfway through the bake time.", "image": "img/honey-roasted-red-potatoes-serves-8.jpg"}, {"slug": "honey-sriracha-sauce", "title": "Honey Sriracha Sauce", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-26", "ingredients": ["¼ cup honey", "2 tsp soy sauce", "4 tsp fresh lime juice", "1 tbsp fresh sliced cilantro stems"], "instructions": "Place all the ingredients in a small bowl and whisk together until well blended. Place in a small serving bowl and chill until ready to serve.", "image": "img/honey-sriracha-sauce.jpg"}, {"slug": "hot-chocolate-tiramisu-serves-12", "title": "Hot Chocolate Tiramisu", "serves": "Serves 12", "category": "Desserts", "date": "2022-02-28", "ingredients": ["**Cocoa**", "3 tbsp of baking cocoa", "3 tbsp sugar", "2 tbsp water", "2 cups whole milk", "**Tiramisu**", "3 large egg yolks", "1 cup sugar", "2 cups mascarpone cheese", "1 cup heavy cream", "45 ladyfinger cookies", "¼ cup min semisweet chocolate chips", "2 tsp cinnamon"], "instructions": "In a small saucepan, mix the cocoa, sugar and water with a whisk. Bring the mixture to a boil and cook, stirring constantly for 2 minutes. Stir in the milk and transfer to a shallow bowl. Cool\nIn a medium glass bowl, whisk the eggs and ½ cup of sugar until blended. Place the bowl over a simmering pot of water over medium heat. Whisk constantly until the eggs reach 160º.\nRemove from heat, and with an electric mixer, beat on high until the eggs become thick and pale yellow. Add the mascarpone cheese and beat on medium speed until smooth.\nIn a cold bowl beat the heavy cream until thick and add the remaining sugar (1/2 cup). Beat until soft peaks begin to form. Fold the cream into the Mascarpone mix.\nIn a 13 x 9 casserole spread 1/3 of the new cream mixture.\nQuickly dip half of the ladyfingers half into the cocoa and arrange over the cream in the casserole. Top with the remaining cream. Repeat the layers one more time.\nSprinkle with the mini chocolate chips and the cinnamon.\nCover and refrigerate at least 8 hours before serving.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "hot-crab-cups-makes-30", "title": "Hot Crab Cups", "serves": "Makes 30", "category": "Appetizers & Dips", "date": "2022-03-03", "ingredients": ["3 oz cream cheese", "1 ½ tbsp sour cream", "3 tsp fresh lemon juice", "¾ cup lump crab meat", "1/3 cup shredded mozzarella cheese", "½ tsp Old Bay Seasoning", "2 box mini phyllo cups", "3 tbsp freshly grated parmesan cheese", "Fresh chives, minced", "Preheat oven to 350º"], "instructions": "Place the phyllo cups on a baking sheet or a mini muffin pan.\nIn a medium bowl, mix the cream cheese, sour cream, lemon juice, crab, mozzarella and Old Bay until well combined.\nFill the cups with the crab mixture and sprinkle with the parmesan cheese.\nBake for 15-20 minutes or until the tops begin to brown.\nRemove from the oven and sprinkle with the chives.\nServe warm.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "hot-dirty-martini-makes-1-martini", "title": "Hot & Dirty Martini", "serves": "Makes 1 martini", "category": "Beverage", "date": "2022-02-25", "ingredients": ["2 ½ oz Kettle One vodka", "Splash of olive juice", "4-5 dashes of Tobasco green jalapeño pepper sauce"], "instructions": "Shake all the ingredients with ice and serve. Garnish with a slice of jalapeño.", "image": "img/hot-dirty-martini-makes-1-martini.jpg"}, {"slug": "hot-german-potato-salad-serves-5", "title": "Hot German Potato Salad", "serves": "Serves 5", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["1 ½lb red potatoes", "5 slices of bacon", "1 medium onion, chopped", "1 tbsp flour", "1 tbsp sugar", "1 tsp salt", "¼ tsp celery seed", "dash of pepper", "½ cup water", "¼ cup white vinegar"], "instructions": "In a medium size pot bring lightly salted water to a boiling and add the potatoes. Reduce the heat, cover and cook until tender. About 20 minutes.\nDrain the potatoes and cool.\nFry the bacon until crisp; drain on a paper towel.\nCook the onion in the bacon fat until tender. Stir in the flour, sugar, salt, celery seed and pepper. Cook over low heat, stirring constantly until the mixture is bubbly. Remove from the heat.\nStir in the water and vinegar. Return to heat and bring to a boil, stirring constantly. Cook for 1 minute. Remove from the heat.\nCrumble the bacon into the hot mixture.\nSlice the warm potatoes and add to the mixture. Return to the heat. Stirring gently to coat the potatoes, heat until hot and bubbly.\nServe", "image": "img/hot-german-potato-salad-serves-5.jpg"}, {"slug": "hot-mexican-spinach-dip-56-servings", "title": "Hot Mexican Spinach Dip 56 servings", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-26", "ingredients": ["1 16oz jar of salsa", "1 10oz package of frozen chopped spinach, thawed and drained", "2 cups shredded Monterey Jack cheese", "1 8oz package cream cheese, diced and softened", "1 cup evaporated milk", "1 2.25oz chopped black olives", "1 tbsp red wine vinegar", "salt and pepper to taste"], "instructions": "Preheat the oven to 400°.\nIn a medium casserole dish mix all the ingredients well. Bake for 12-15 minutes or until bubbly hot. Serve with pita chips or tortilla chips.", "image": "img/hot-mexican-spinach-dip-56-servings.jpg"}, {"slug": "hot-mustard-sauce-makes-2-cups", "title": "Hot Mustard Sauce", "serves": "Makes 2 cups", "category": "Gravy, Sauce & Dressing", "date": "2022-02-26", "ingredients": ["½ cup dry mustard", "½ cup white vinegar", "1 egg", "1/3 cup sugar", "1 cup mayonnaise", "salt"], "instructions": "In a glass bowl or jar mix the dry mustard and the vinegar. Cover and let stand over night.\nIn a double boiler, beat the egg, stir in the sugar and a dash of salt. Add the mustard mixture.\nCook over hot(not boiling) water until the mixture thickens.\nLet cool. Before serving add the mayonnaise.", "image": "img/hot-mustard-sauce-makes-2-cups.jpg"}, {"slug": "ice-cream-sandwich-dessert", "title": "Ice Cream Sandwich Dessert", "serves": "", "category": "Desserts", "date": "2022-02-26", "ingredients": ["19 ice cream sandwiches", "1 12oz container of whipped topping", "1 12oz jar hot fudge ice cream topping", "1 cup salted peanut, optional"], "instructions": "Cut one ice cream sandwich in half and place with one whole sandwich along the short side of an ungreased 13x9x2 glass baking dish. Arrange 8 sandwiches in the opposite direction in the pan.\nSpread with ½ of the whipped topping. Spoon the hot fudge by teaspoonful onto the whipped topping. Sprinkle with ½ cup of the peanuts.\nRepeat the above for another layer. Cover and freeze. Remove from the freezer 20 minutes before serving.", "image": "img/ice-cream-sandwich-dessert.jpg"}, {"slug": "irish-soda-bread", "title": "Irish Soda Bread", "serves": "", "category": "Breads & Stuffings", "date": "2022-02-26", "ingredients": ["2 cups flour", "1 ½ tsp double acting baking powder", "½ tsp baking soda", "½ tsp salt", "1 tbsp sugar", "¼ cup chilled butter", "1 egg, beaten", "2/3 cup buttermilk", "½ -1 cup raisins", "2tsp caraway seeds"], "instructions": "Preheat the oven to 375°.\nIn a medium/large bowl combine the flour, baking powder, baking soda, salt, sugar and chilled butter, with a fork or pastry blender, until the mixture has a consistency of coarse cornmeal.\nStir in the raisins and the caraway seeds and set aside.\nIn a small bowl mix together the beaten egg and the buttermilk. Add to the dry ingredients and mix well. Turn the dough onto a floured surface and knead briefly. Place in a foil loaf pan and press down slightly. With a sharp knife cut a bold cross in the top of the dough, so the bread will not crack during baking.\nBrush the top of the dough with buttermilk and bake for 35-40 minutes or until a knife inserted in the center comes out clean.", "image": "https://static.wixstatic.com/media/75d545_1ac33e1d11764e65b3709937677b1df2~mv2.jpeg"}, {"slug": "italian-pasta-salad-serves-8", "title": "Italian Pasta Salad", "serves": "Serves 8", "category": "Salads", "date": "2022-02-26", "ingredients": ["1(12oz) package tricolor rotini", "1 (16oz) bottle Newman's Own Olive Oil & Vinegar dressing", "1 (6oz) stick of Genoa salami, cubed", "1 red bell pepper, diced", "1 green bell pepper, diced", "1 yellow bell pepper, diced", "1 cup of diced baby carrots", "1 cup grape tomatoes, halved", "1 (8oz) container mozzarella pearls or diced fresh mozzarella", "1 cup chopped flat leaf parsley"], "instructions": "Boil water in a large pot and cook the pasta according to package directions for al dente.\nDrain and rinse the pasta in cold water. Return to the pot.\nPour half of the bottle of dressing over the pasta and stir. Add the remaining ingredients and toss. Cover and refrigerate for an hour. Remove and add remaining dressing as desired. Toss to coat and refrigerate until ready to serve.", "image": "img/italian-pasta-salad-serves-8.jpg"}, {"slug": "italian-sausage-peppers-onions", "title": "Italian Sausage, Peppers & Onions", "serves": "", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["2lbs Premio Sweet Italian sausage", "4 tbsp butter", "1 large Vidalia onion, cut into wedges", "½ red onion, cut into wedges", "4 cloves garlic, minced", "1 large red pepper, sliced", "1 green bell pepper, sliced", "2 tsp dried basil", "2 tsp dried oregano", "½ cup white wine"], "instructions": "Place the sausage in a large skillet and brown over medium heat. Remove to from the heat and set aside.\nMelt the butter in the skillet and cook the onion, red onion, peppers and garlic for 2-3 minutes.\nAdd the basil and oregano. Stir in the white wine and continue to cook until the peppers are tender.\nReturn the sausages to the pan, reduce the heat to low, cover and cook for 15 minutes to heat the sausage through.\nServe with warm Italian rolls.", "image": "img/italian-sausage-peppers-onions.jpg"}, {"slug": "jellied-cranberry-sauce-makes-2-cups", "title": "Jellied Cranberry Sauce", "serves": "Makes 2 cups", "category": "Side Dishes", "date": "2022-03-01", "ingredients": ["2 12 oz bags fresh cranberries", "2 cup sugar", "1 cup water"], "instructions": "In a medium sauce pot, combine the cranberries, sugar and water.\nCook over medium low heat, stirring occasionally. Cook until all the berries have popped and the sauce has thickened.\nTest the thickness of the sauce by coating the back of a wooden spoon with the sauce and running your finger over the back of the spoon. If the sauce stays separated it is done.\nMash the cranberries in a fine sieve or food mill over a bowl. The sauce from the mashed cranberries will collect in the bowl as you mash them. Throw out the seeds and pulp.\nPour the sauce into a decorative bowl for serving, cover and refrigerate for at least 2 hours.", "image": "https://static.wixstatic.com/media/75d545_5450774f0adc4857ba8185e23b348754~mv2.jpg"}, {"slug": "juicy-turkey-burger-makes-8", "title": "Juicy Turkey Burger", "serves": "Makes 8", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["**Burgers**", "2 ½ lb lean ground turkey", "½ c Avocado oil mayonnaise", "4 tsp Worcestershire sauce", "2 tsp garlic powder", "2 tsp ground cumin", "3 tsp Kosher salt", "½ c Panko", "6 tbsp fresh parsley, finely chopped", "½ c red onion, finely chopped", "2 medium Portobello mushroom caps, gills removed and finely chopped", "3 tbsp extra virgin olive oil", "3tsp Sriracha", "**Sauce**", "2 tsp Sriracha,", "½ c light mayonnaise or avocado oil mayonnaise if preferred", "**Directions**"], "instructions": "Remove the gills from the mushroom cap. Chop the cap up into 1” pieces and add to a food processor. Add the red onion and parsley and pulse until chopped.\nIn a large bowl, combine the turkey, mushroom mixture, and the remaining ingredients.\nShape into burgers using a burger patty press and place on serving dish or cutting board. Cover and chill for 10 minutes or up to 2 hours.\nMeanwhile combine the ingredients for the sauce and refrigerate until ready to serve.\nThe burgers may be cooked inside with 2 tbsp of olive oil in nonstick skillet or grilled. (about 5 minutes each side)", "image": "img/juicy-turkey-burger-makes-8.jpg"}, {"slug": "keto-parmesan-oven-baked-tomatoes-serves-4", "title": "Keto Parmesan Oven Baked Tomatoes", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["4 medium tomatoes, center of stem removed and cut in half", "2 slices of Thin slim bread, torn into pieces", "½ cup freshly grated Parmesan cheese", "2 cloves garlic, minced", "2 tbsp extra virgin olive oil", "2tbsp fresh chopped parsley", "2tbsp fresh chopped basil", "2 tbsp fresh chopped oregano", "Salt and pepper to taste", "**Preheat oven to 400°**"], "instructions": "Using a blender or chopper, process the bread slices into breadcrumbs. Transfer to a medium bowl.\nAdd the remaining ingredients to the breadcrumbs and toss.\nPlace the halved tomatoes into a medium foil baking pan, season with salt and pepper. Top each tomato with breadcrumb mixture, be generous.\nBake for 15-20 minutes or until the topping is golden brown.", "image": "img/keto-parmesan-oven-baked-tomatoes-serves-4.jpg"}, {"slug": "key-lime-cookies-makes-4-dozen-cookies", "title": "Key Lime Cookies", "serves": "Makes 4 Dozen Cookies", "category": "Desserts", "date": "2023-12-24", "ingredients": ["1 cup butter, softened", "¾ cup sugar", "1 large egg", "Zest of 3 key limes, preferred (or 1 regular lime)", "2 cups flour", "½ tsp baking powder", "½ tsp salt", "Glaze", "1 ½ cup powdered sugar", "2 tbsp key lime juice (or regular lime juice)", "1 tbsp heavy cream"], "instructions": "Preheat the oven to 375°\nLine cookie sheets with parchment paper and set aside.\nIn a large bowl, mix the butter and sugar until creamy. Add the egg until well blended.\nAdd the lime zest and blend.\nAdd the flour ½ cup at a time until completely blended.\nUsing a small cookie scoop or tablespoon scoop the dough and form into a ball. Place the ball on a cookie sheet and slightly flatten with your palm.\nBake for 9-10 minutes or until the center is set. Th cookies will not brown. Let the cookies completely cool on a cooling rack or parchment paper.\nIn a small shallow bowl, mix the glaze ingredients until smooth.\nOnce the cookies have cooled, dip the tops of the cookies into the glaze and return them to the rack or paper to dry.\nThese cookies taste great refrigerated.", "image": "https://static.wixstatic.com/media/75d545_f4487a3b014042179d4f3c23c6112f7d~mv2.png"}, {"slug": "key-lime-crunch-cake", "title": "Key Lime Crunch Cake", "serves": "", "category": "Desserts", "date": "2022-02-26", "ingredients": ["8 (2 bar packs)from 2 boxes Nature Valley Crunchy Granola bars", "¼ cup flour plus 2 tbsp", "6 tbsp butter, melted", "2 ½ tbsp brown sugar", "1 (8oz) container Cool Whip", "1 (14oz) can sweetened condensed milk", "½ cup key lime juice", "2 tbsp lime zest", "whipped cream", "**Preheat the oven to 350°**"], "instructions": "Line an 8 x 8 baking pan with parchment paper and set aside.\nPlace the granola bars in a blender or chopper and process the bars into fine crumbs.\nIn a medium size bowl, blend half the crumbs, the flour, melted butter and brown sugar.\nPress the crumb mixture into the bottom of the prepared pan and bake for 10 minutes. Cool.\nIn a large bowl, whisk together the Cool Whip, sweetened condensed milk, lime juice and lime zest.\nSpread the lime mixture over the crust and sprinkle the remaining granola crumbs over the top.\nFreeze for 4 hours. Serve with whipped cream.", "image": "img/key-lime-crunch-cake.jpg"}, {"slug": "key-lime-pie-shooters-makes-approx-40", "title": "Key Lime Pie Shooters Makes Approx. 40", "serves": "", "category": "Desserts", "date": "2022-02-26", "ingredients": ["1 (9 inch) graham cracker pie crust, I use Keebler", "1 14oz can sweetened condensed milk", "2 8oz container of cool whip", "¼ cup fresh key lime juice", "¼ cup fresh lemon juice", "½ cup crushed macadamia nuts", "4 tbsp lime zest", "Small cups such as those used for takeout salad dressing"], "instructions": "Arrange the cups on a tray or baking sheet.\nCrumble the pie crust into a medium bowl and then divide amongst the cups.\nIn a medium bowl, mix the sweetened condensed milk and 1 container of cool whip together. Add the key lime juice and lemon juice and blend well.\nSpoon the filling into the cups. There should be about a ¼” left to the top of each cup. Chill for at least 3 hours.\nBefore serving add additional cool whip to each cup and sprinkle macadamia nuts and top with the lime zest.", "image": "https://static.wixstatic.com/media/75d545_fc0c38e712e14a78b526ce72f444d5b1~mv2.jpeg"}, {"slug": "key-lime-pie", "title": "Key Lime Pie", "serves": "", "category": "Desserts", "date": "2022-02-26", "ingredients": ["1 ½ cup graham cracker crumbs", "¼ cup packed light brown sugar", "¼ tsp kosher salt", "6 tbsp unsalted butter, melted", "8 large egg yolks", "2 (14oz) cans sweetened condensed milk", "1 ¼ cup Key lime juice", "pinch of kosher salt", "Whipped cream", "Key lime slices", "**Preheat the oven to 350°**"], "instructions": "In a medium bowl combine the graham cracker crumbs with the brown sugar and salt with a whisk. Add the melted butter and stir until well combined.\nPress the crumb mixture onto the bottom and up the sides of a 10\" pie plate. Bake for 10 minutes. Let cool completely.\nIn a large bowl whisk the egg yolks, condensed milk, lime juice and salt together until smooth. Pour the filling into the cooled crust.\nLower the oven temperature to 325° and bake the pie for 20-25 minutes, until set around the edge and slightly jiggly in the middle.\nRemove from the oven and let cool. Refrigerate for at least 6 hours before serving.\nGarnish with whipped cream and a lime slice.", "image": "img/key-lime-pie.jpg"}, {"slug": "lamb-and-rice-stuffed-cabbage-with-tomato-sauce", "title": "Lamb and Rice Stuffed Cabbage with Tomato Sauce", "serves": "", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["Salt", "2 large heads of Savoy cabbage, separated into leaves", "4tbsp extra virgin olive oil", "1lb ground lamb", "1 egg", "2 medium onion, chopped fine", "3 cloves garlic, minced", "1 medium carrot, shredded", "1 medium parsnip, shredded", "¾ cup short grain rice", "½ cup white wine", "salt and freshly ground black pepper", "1 28oz can crushed tomatoes", "½ tsp crushed red pepper"], "instructions": "Preheat the oven to 350°.\nCut around the stem of the cabbage but do not remove the core. In a very large pot bring water to a boil and cook the cabbage for 5 minutes. Remove to a colander and rinse under cold water until the cabbage can be handled. Carefully separate the cabbage leaves.\nCoarsely chop the small inside leaves and use to line a casserole dish. Set aside.\nPut 2tbsp of olive oil in a large pan and heat over medium high heat. When the oil is hot add ½ the chopped onion, 1 tbsp of the garlic, the carrot and the parsnip. Cook until tender, about 5 minutes. Sprinkle with salt and pepper and transfer to a bowl and add the lamb and rice. Mix well until combined.\nAdd the white wine and the egg.\nWith a paper towel, wipe the pan and add the remaining 2tbsp of olive oil. Turn the heat up to medium high. When the oil is hot add the remaining onion and garlic and cook until tender, 1-2 minutes. Add the tomatoes, red pepper, and a good sprinkling of salt. Cook over medium low heat while preparing the cabbage leaves.\nCut the cabbage leaves in half by running a sharp knife along each side of the stem, removing the stem in the process. Trim the top and the bottom so a rectangle remains.\nPut a heaping tbsp. of the meat mixture in the center of the cabbage leaf and fold in the sides of the leaf and roll it up like a burrito.\nAdd the cabbage rolls seam side down to the casserole dish. Top the rolls with the sauce mixture and cover.\nBake for 1 hour.", "image": "img/lamb-and-rice-stuffed-cabbage-with-tomato-sauce.jpg"}, {"slug": "lasagna-serves-10", "title": "Lasagna", "serves": "Serves 10", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["9 Lasagna noodles", "1 tbsp extra virgin olive oil", "1 lb lean ground beef", "1 lb bulk Italian sausage", "1 ½ tsp garlic salt", "1 ½ tsp dried oregano", "¾ tsp dried thyme", "½ tsp dried basil", "3 28oz cans tomato sauce", "1 28oz can petite diced tomatoes(drained)", "salt and pepper to taste", "1 15oz container of Ricotta cheese", "3 eggs, beaten", "1/3 cup grate Parmesan cheese", "1lb shredded Mozzarella cheese"], "instructions": "Preheat the oven to 350°.\nBring a large pot of lightly salted water to a boil and add the lasagna noodles and olive oil. Cook until al dente (8-10 minutes); drain and rinse.\nCook the ground beef and sausage in a large skillet over medium heat; drain. Stir in the garlic salt, oregano, thyme, basil and tomato sauce. Season with salt and pepper; simmer for 30 minutes.\nIn a medium bowl mix together the ricotta, eggs, and Parmesan.\nLadle enough of the meat sauce into a 13x9 baking dish to cover the bottom in a thin layer. Place 3 of the lasagna noodles over the meat sauce to form a layer. Spread about ¼ of the ricotta cheese mixture over the noodles. Sprinkle with about a third of the mozzarella over the ricotta layer. Then a third of the meat sauce over the mozzarella cheese.\nRepeat the layering twice more, topping with the remaining mozzarella cheese.\nBake for 90 minutes. Allow the lasagna to sit for 10-15 minutes before cutting", "image": "img/lasagna-serves-10.jpg"}, {"slug": "lemon-broccoli-rice-serves-4", "title": "Lemon Broccoli Rice", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["1 can 10.5oz Campbell's chicken broth", "1 cup fresh small broccoli florets", "1/3 cup shredded carrots", "1 ¼ cup instant rice, uncooked", "2 tsp fresh lemon juice", "Pepper to taste", "Fresh Tarragon"], "instructions": "In a 2qt saucepan, over high heat, bring the chicken broth to a boil.\nAdd the broccoli and the carrots, and return to a boil. Cook for 5 minutes or until the vegetable are tender.\nStir in the rice, lemon juice and pepper. Remove from the heat and cover. Let stand for 5 minutes or until all the liquid is absorbed.\nFluff the rice with a fork and transfer to a serving dish and garnish with fresh tarragon if you like.", "image": "img/lemon-broccoli-rice-serves-4.jpg"}, {"slug": "lemon-chicken-with-artichoke-heartsserves-3-to-4", "title": "Lemon Chicken with Artichoke HeartsServes 3 to 4", "serves": "Serves 3", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["3 tbs. olive oil", "½ medium white onion, finely chopped", "4 medium garlic cloves, chopped", "Dash of salt and ground pepper", "2 lbs. boneless skinless chicken breasts, cut into 1 inch pieces", "2 cups jarred quartered marinated artichoke hearts (keep marinade)", "¾ cup dry white wine", "1 tablespoon freshly squeezed lemon juice"], "instructions": "Heat oil in large frying pan over medium heat. Add onion and garlic, season with salt and ground pepper. Cook until golden, about 5 minutes. Add chicken pieces and cook, turning and stirring until well browned on all sides, about 5-8 minutes. Put artichoke hearts in small bowl. Using scissor, cut each quartered artichoke heart into three pieces so they are good size to eat. Add artichoke hearts with their marinade to pan and cook about 5 minutes.\nAdd wine and lemon juice to the pan. Stir everything being sure to scrape bottom of the pan to incorporate flavors. Cover and simmer until sauce is slightly reduced, about 15-20 minutes. Enjoy!", "image": "img/lemon-chicken-with-artichoke-heartsserves-3-to-4.jpg"}, {"slug": "lemon-glazed-carrots", "title": "Lemon Glazed Carrots", "serves": "", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["1 lb sliced carrots", "2 tbsp butter", "2 tbsp dark brown sugar", "2 tbsp freshly squeezed lemon juice", "salt & pepper to taste"], "instructions": "Cook the carrots in boiling lightly salted water, 12- 15 minutes, or until “crisp tender”. Drain and place in a serving dish.\nMelt the butter in a small saucepan and add the sugar, lemon juice and salt and pepper. Pour over the carrots and toss. Garnish with a few lemon slices.", "image": "img/lemon-glazed-carrots.jpg"}, {"slug": "lemon-lime-white-chocolate-chip-cookies-makes-4-dozen", "title": "Lemon Lime White Chocolate Chip Cookies", "serves": "Makes 4 dozen", "category": "Desserts", "date": "2023-07-04", "ingredients": ["2 ¼ cup flour", "1 tsp baking powder", "¼ tsp Kosher salt", "1 cup butter, room temperature", "¾ cup light brown sugar", "¾ cup sugar", "1 large egg", "2 tbsp lemon zest", "2 tbsp lime zest", "1 tbsp vanilla extract", "12 oz bag white chocolate chips", "**Preheat oven to 375°**"], "instructions": "Line a baking sheet with parchment paper and set aside.\nIn a medium bowl, combine the flour, baking soda and salt.\nIn a large bowl, cream the butter and sugars with a mixer until light in color. Add the egg and beat until blended.\nAdd the lemon zest, lime zest and vanilla. Mix to combine.\nAdd the dry ingredients in small batches; after the dry ingredients have been mixed in, add the white chocolate chips.\nPlace the cookie batter on the cookie sheet using about a tablespoon per cookie.\nBake for about 9 minutes or until light golden in color.", "image": "https://static.wixstatic.com/media/75d545_ab2095c054ca4e9c97b4efdc12cd4d6b~mv2.png"}, {"slug": "lemon-olive-oil-roasted-potatoes-serves-6", "title": "Lemon Olive Oil Roasted Potatoes", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-26", "ingredients": ["2lb Tri color potatoes", "1 cup plus 2 tbsp extra virgin olive oil", "1 tsp kosher salt", "1 tsp freshly ground black pepper", "6 cloves garlic, peeled and sliced", "2 lemons, quartered", "**Preheat the oven to 400°**"], "instructions": "In a large bowl toss the potatoes, ¼ cup of olive oil, ½ tsp of salt, pepper and garlic.\nPlace on a foil baking sheet and roast until browned. About 35-40 minutes.\nMeanwhile in a blender or electric chopper, purée the remaining olive oil, ½ tsp salt and the lemons.\nWhen the potatoes are done, transfer them to a serving dish and through a fine mesh strainer, pour the lemon purée over the potatoes. Toss and serve.", "image": "img/lemon-olive-oil-roasted-potatoes-serves-6.jpg"}, {"slug": "lemon-parsley-chicken-serves-4", "title": "Lemon Parsley Chicken", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["1 lb thin sliced chicken filets", "8tbsp melted butter", "½ cup seasoned bread crumbs", "4tbsp chopped fresh parsley", "4tbsp chopped scallions", "2tsp minced garlic", "2 lemons, sliced thin, no pits"], "instructions": "Preheat the oven to 350°\nSeason the filets with salt and pepper. Pour 6tbsp of the butter into a baking dish and add the chicken, turning to coat with the butter.\nCombine the bread crumbs, parsley, onions, and garlic in a medium bowl. Spoon over the chicken to cover. Drizzle the remaining butter over the chicken and place 2 lemon slices on each filet.\nBake for 30 minutes.", "image": "img/lemon-parsley-chicken-serves-4.jpg"}, {"slug": "light-shrimp-scampi-serves-4", "title": "Light Shrimp Scampi", "serves": "Serves 4", "category": "Main Dish", "date": "2022-03-18", "ingredients": ["1 ½ lb large shrimp, peeled and deveined", "8 oz whole wheat pasta of your choice, I prefer linguine", "2 tbsp butter", "2 tbsp extra virgin olive oil", "3 green onions, thinly sliced, green part only", "½ cup julienne cut sundried tomatoes, dry", "2 tbsp minced fresh garlic", "1 cup chicken broth", "1 tbsp + 1 tsp lemon zest", "6 tbsp lemon juice", "¼ tsp salt", "½ tsp fresh ground pepper", "crushed red pepper to taste", "¼ cup fresh chopped parsley", "Grated parmesan cheese"], "instructions": "Remove the tails from the shrimp and cut in half lengthwise. Set aside.\nCook the pasta according to the package directions for al dente.\nIn a large skillet, heat the butter and olive oil over medium high heat. Add the sundried tomatoes and sauté until they begin to soften. Add the shrimp, onions and garlic.\nCook until the shrimp turns pink, 2-3 minutes. Remove the shrimp from the pan to a dish.\nAdd the broth, lemon zest, lemon juice, salt, pepper and red pepper flakes to the same skillet and bring to a boil.\nCook until the liquid has slightly reduced and add the shrimp back to the pan.\nDivide the pasta among 4 bowls and top with the shrimp mixture. Sprinkle with some chopped parsley and parmesan cheese.", "image": "https://static.wixstatic.com/media/75d545_9d598b27539a49bcb193c54219706d08~mv2.jpeg"}, {"slug": "linguine-white-clam-sauce-serves-6", "title": "Linguine & White Clam Sauce", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["1 cup extra virgin olive oil", "1 Vidalia onion, chopped", "12 cloves garlic, chopped", "2 tsp red pepper flakes", "¾ tsp dried basil", "1 tsp salt", "¾ tsp dried oregano", "1 cup dry white wine", "2 8oz bottles Bar Harbor clam juice", "2 10oz cans baby clams, drained, juice reserved", "1 6.5oz can minced clams, drained, juice reserved", "2 6.5oz cans chopped clams, drained, juice reserved", "1lb linguine", "4 tbsp cold unsalted butter, cut into small pieces", "3 tbsp chopped fresh parsley", "Salt & pepper to taste"], "instructions": "Heat the oil in a large saucepot over medium high heat and add the onion; sauté until golden. About 4 minutes.\nAdd the garlic, red pepper flakes, salt and oregano. Cook, stirring frequently until the garlic is golden.\nStir in the wine and clam juice. Bring to a boil and continue cooking until the liquid is slightly reduced. Stirring occasionally.\nCook the pasta according to package with 1 bottle of clam juice, the reserved clam juice from the canned clams and water, until al dente, and drain.\nWhile the pasta is cooking, add the clams to the sauce and simmer; Remove from heat and add the butter until melted.\nAdd the pasta to the sauce with the parsley. Season with the salt & pepper and toss.\nServe with your favorite bread or salad.", "image": "img/linguine-white-clam-sauce-serves-6.jpg"}, {"slug": "lisa-s-baked-lobster-tails-serves-5", "title": "Lisa's Baked Lobster Tails", "serves": "Serves 5", "category": "Seafood", "date": "2022-02-25", "ingredients": ["6 6oz lobster tails, cut in half", "½ clove from elephant garlic", "1 stick butter", "½ cup olive oil", "½ tsp dried oregano", "¼ tsp black pepper", "juice of half lemon", "3 tbsp lemon flavored cooking wine (or chardonnay if you prefer)", "2 tbsp Italian bread crumbs", "1 lemon", "**Preheat the oven to 400**°"], "instructions": "Place the cut lobster tails in a glass or foil baking pan and loosen the meat.\nIn a small saucepan, melt the butter and add the olive oil; add the garlic and cook just until fragrant. Add the oregano and pepper. (can add more to taste)\nAdd the juice of ½ lemon and the white wine. Add the bread crumbs.\nSpoon the mixture under the meat of the tails and then drizzle the remaining marinade over the tops of the tails.\nCover with foil and marinate in the refrigerator for 3-4 hours.\nBake covered for ½ hour(longer if tails are bigger) then remove the foil and continue to cook for another 10 minutes or until slightly browned.", "image": "img/lisa-s-baked-lobster-tails-serves-5.jpg"}, {"slug": "lobster-bisque-serves-8", "title": "Lobster Bisque", "serves": "Serves 8", "category": "Soup & Sandwiches", "date": "2022-02-27", "ingredients": ["3lbs cooked lobster meat, cut into bite sized chunks", "8 cloves garlic, minced", "1 medium red onion, minced", "1 ½ cup carrots, minced (I bought shredded carrots and cut them)", "2 cup finely diced celery", "2 tbsp extra virgin olive oil", "4 cups white wine", "1 cup tomato paste", "2qt fish stock", "¼ cup brandy", "2 cups heavy cream", "6 bay leaves", "1 tbsp salt", "1 tsp peppercorns", "½ tsp red pepper flakes", "2 tsp smoked paprika", "2 tsp dried thyme leaves", "1 tsp xanthan gum", "Fresh parsley, minced for garnish"], "instructions": "Prepare all your vegetables.\nAdd the olive oil to a large sauce pot and cook the onion until translucent. Add the garlic and cook until the onions begin to brown and appear crusty.\nAdd the white wine, carrots, celery, fish stock and tomato paste. Stir well to combine and add the spices. Simmer for an hour.\nRemove the bay leaves and add the cream.\nWith an emulsifier, blend the vegetables and broth until creamy. (you can use a blender as well, I find the emulsifier to be much easier)\nAdd the lobster and serve, garnished with fresh parsley.", "image": "img/lobster-bisque-serves-8.jpg"}, {"slug": "lobster-risotto-with-peas-serves-4", "title": "Lobster Risotto with Peas", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-27", "ingredients": ["3 tbsp extra virgin olive oil, divided", "32oz of chicken broth", "2 (6oz) lobster tails in the shell, thawed", "½ cup chopped sweet onion", "½ cup Arborio rice", "½ cup white wine", "¾ cup frozen peas, thawed", "1 tsp fresh lemon zest", "¾ cup freshly grated Parmesan cheese, divided"], "instructions": "Bring the chicken broth to a boil in a large saucepan and add the lobster tails; reduce the heat and simmer for 4-5 minutes. Remove the lobster from the broth (do not discard the broth, you will need 3½ cup for the rice) and cool for 10 minutes.\nHeat 2tbsp of olive oil in a medium skillet over medium high heat and add the onion; sauté for 3 minutes. Add the rice and sauté for 2 minutes more. Add the wine and simmer until it is completely absorbed by the rice.\nBegin adding the 3 ½ cup of reserved broth ½ cup at a time to the rice, keep the liquid at a gentle simmer and stir frequently. When the broth is just about absorbed add the next ½ cup.\nMeanwhile shell the lobster and cut the meat into bite size chunks.\nWhen all the reserved broth has been absorbed by mixture should be creamy. Remove from the heat; stir in ½ cup of the cheese, the remaining tbsp. of olive oil and the lemon zest. Season to taste with salt and pepper.\nGarnish with the remaining cheese and serve.", "image": "img/lobster-risotto-with-peas-serves-4.jpg"}, {"slug": "low-carb-bbq-meatballs-makes-12", "title": "Low Carb BBQ Meatballs", "serves": "Makes 12", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1lb lean ground beef", "1 cup crushed pork rinds", "½ cup grated cheddar", "1 egg", "2 tbsp heavy cream", "2 tbsp water", "½ tsp garlic powder", "½ tsp salt", "½ tsp ground pepper", "1 tsp McCormick Grill Mates Smokehouse Maple", "2 tbsp reduced sugar ketchup", "2 tbsp Italian salad dressing", "**Preheat oven to 400°**"], "instructions": "Spray a foil baking sheet with butter cooking spray.\nIn a large mixing bowl combine the ground beef with the next 9 ingredients until well mixed.\nRoll into 12 meatballs about 2” each. Bake for 15 minutes or until cooked.\nIn a small bowl whisk the ketchup and salad dressing together and brush the meatballs with the mixture. Use all of it. Sprinkle the meatballs with the Grill Mates for added flavor.\nReturn the meatballs to the oven and turn on the broiler. Broil for 1-2 minutes or until the sauce begins to caramelize.\nServe hot with your favorite low carb sides.\nCalories 94 Carb 1g", "image": "https://static.wixstatic.com/media/75d545_254d07b60b8849e882e8da47919b4d00~mv2.jpeg"}, {"slug": "low-carb-brownie-cheesecake", "title": "Low Carb Brownie Cheesecake", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["½ cup butter", "2 oz unsweetened chocolate", "½ cup almond flour", "¼ cup cocoa powder", "1/8 tsp salt", "¼ cup chopped pecans", "4 large eggs", "1 ¼ cup Stevia(artificial sweetener)", "¾ tsp vanilla", "2 8oz packages of cream cheese", "¼ cup heavy cream", "**Preheat the oven to 325°**"], "instructions": "Butter a 9” spring form pan. Wrap the outside of the pan(bottom ½ only) with aluminum foil.\nMelt the butter and unsweetened chocolate together in a microwaveable bowl for 30 second intervals. Stir after each interval.\nIn a small bowl combine the almond flour, cocoa powder and salt. Set aside.\nIn a large bowl beat 2 eggs, ¾ cup of Stevia and ¼ tsp of vanilla until smooth. Add the pecans.\nSpread evenly in the prepared pan. Bake for 25 minutes or until set around the edges and still soft in the center. Let cool for 20 minutes.\n**Reduce the oven temperature to 300°**\nIn a large bowl, beat the cream cheese until smooth. Add the remaining 2 eggs one at a time, blending well after each addition. Add the remaining ½ cup of Stevia, the cream and ½ tsp of vanilla, beat until combined.\nPour the filling over the brownie crust, spread evenly. Place the pan on a cookie sheet and and bake for 40 minutes or until the edges are set and the center just barely jiggles. Remove from the oven and cool.\nRun a knife around the edges to loosen", "image": "https://static.wixstatic.com/media/75d545_912202cc1f0a42918be509f1bb53e217~mv2.jpg"}, {"slug": "low-carb-cheesecake-with-strawberries", "title": "Low Carb Cheesecake with Strawberries", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["1 1/2lb cream cheese, room temperature", "4 eggs", "2 tsp vanilla", "1 1/3 cup Truvia or Swerve", "Fresh strawberries", "Sugar free whipped ceam", "**Crust**", "1 cup almond meal", "2 tbsp Truvia brown sugar", "2 tbsp butter, melted", "**Preheat the oven to 350°**"], "instructions": "Grease a 9\" springform pan and line the bottom with parchment paper.\nIn a medium bowl, combine the almond meal, brown sugar and melted butter. Press in the bottom of the prepared pan and bake for 8 minutes. Allow to cool.\nIncrease the oven temperature to 400°.\nIn a large bowl, whip the cream cheese. Add the eggs one at a time until blended. Add the vanilla and the Truvia and whip until fluffy. Pour over the crust.\nPlace the cheesecake on a cookie sheet and add about ¾ cup of water to the cookie sheet. (this helps prevent cracks in the top of the cheesecake)\nPlace on the center rack of the oven and turn the temperature down to 350°. Bake for 50-60 minutes. (cake should be firm and slightly soft in the middle) Cool slightly then place in the refrigerator to cool completely.\nServe with whipped cream and sliced strawberries.\nNet carbs: 4.3 (2 sliced medium strawberries and sugar free whipped cream included)", "image": "https://static.wixstatic.com/media/75d545_792058f10c0d443a8bb371aafa5f4f79~mv2.jpg"}, {"slug": "low-carb-chicken-pot-pie-serves-4", "title": "Low Carb Chicken Pot Pie", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["(4) 5.5” personal pie plates", "Filling", "3 tbsp butter", "½ cup finely diced onion", "½ cup finely diced celery", "1 cup carrot slices", "3 cloves of garlic, minced", "Salt & pepper, to taste", "1lb thin sliced chicken filets, cut into small cubes", "¾ cup heavy cream", "½ cup chicken stock", "2 tbsp Dijon mustard", "¾ cup shredded white cheddar cheese", "¾ cup frozen baby peas", "Dough", "1 ½ cup fancy shredded mozzarella cheese", "3 tbsp cream cheese, softened", "¾ cup Paleo Baking Flour", "1 large egg, slightly beaten", "1 tsp garlic powder", "1 tsp onion powder", "1 tsp Italian seasoning", "1 tsp sea salt", "½ tsp black pepper"], "instructions": "Preheat the oven to 375°\nMelt the butter in a large skillet over medium heat. Add the onion, celery, carrots and garlic. Season with a little salt and pepper and sauté until the vegetables are begin to soften.\nAdd the chicken to the skillet and stir until cooked.\nAdd the cream, chicken stock, and mustard and bring to a boil over medium high heat. Reduce the heat to low and simmer for 5 minutes.\nAdd in the cheddar cheese and peas and stir until the cheese has melted. Remove from heat and prepare the dough.\nIn a medium microwaveable bowl, combine the mozzarella cheese and the cream cheese. Microwave for 1 minute on high. Remove from the microwave and stir. Microwave 1 more minute.\nAdd the flour, egg, garlic powder, onion powder, Italian seasoning, sea salt and black pepper to the cheese mixture and mix well.\nForm the dough into a large ball and roll out onto a large piece of parchment paper with a rolling pin. Turn one of the pie plates upside down on the dough and trace and cut 4 circles with a sharp knife.\nEvenly split the pie filling amongst the 4 pie plates and top with a piece of the dough, tucking the edges under around the edge of the plate.\nPlace the pie plates on a large cookie sheet and bake for 30 minutes or until the tops have browned.\nNet carbs 13.9", "image": "https://static.wixstatic.com/media/75d545_b086c4c919ec433bafcce36549b03a21~mv2.jpeg"}, {"slug": "low-carb-flounder-with-lemon-soy-vinaigrette-serves-4", "title": "Low Carb Flounder with Lemon Soy Vinaigrette", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-27", "ingredients": ["4 large flounder fillets", "2 garlic cloves, minced", "¼ cup fresh lemon juice", "1 tbsp + 1 tsp soy sauce", "1 teaspoon Swerve granulated", "¾ tsp salt", "¼ cup extra virgin olive oil"], "instructions": "Preheat the oven to 450°\nPlace the flounder fillets on a foil baking sheet.\nIn a small mixing bowl, combine the garlic, lemon juice, soy sauce, Swerve, salt and olive oil. Whisk vigorously to make sure the lemon juice, soy sauce and olive oil become combined.\nPour the sauce over the fish and bake for 8 minutes. Cooking times may vary slightly depending on the size of your fillets.\nFlounder is ready when no longer translucent.", "image": "img/low-carb-flounder-with-lemon-soy-vinaigrette-serves-4.jpg"}, {"slug": "low-carb-grilled-spiced-salmon-serves-3", "title": "Low Carb Grilled Spiced Salmon", "serves": "Serves 3", "category": "Seafood", "date": "2022-02-27", "ingredients": ["1 lb salmon filets", "1/4 cup mayo", "1.5 tsp paprika", "1 tsp garlic powder", "1 tsp celery seed", "1/2 tsp of salt", "1 tsp lemon zest", "Juice of half a lemon"], "instructions": "Preheat the grill or grill pan over medium-high heat and oil as necessary to prevent sticking.\nCombine all the ingredients except for the salmon. Spread a thin layer over all sides of the salmon.\nGrill over medium high heat for 4-5 mins. per side or until cooked through.\nGrilled Spiced Salmon: 6.5 net carbs (for the entire recipe)", "image": "img/low-carb-grilled-spiced-salmon-serves-3.jpg"}, {"slug": "low-carb-pizza-chicken-serves-4", "title": "Low Carb Pizza Chicken", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1lb Perdue thin slice chicken filets", "1 tbsp garlic powder", "1 tbsp Italian seasoning", "1 tbsp sea salt", "1 tbsp ground pepper", "3 tbsp extra virgin olive oil", "1 cup Rao’s pasta sauce", "1 lb mozzarella cheese, sliced thick", "1/2 cup freshly grated parmesan cheese", "1 package sliced pepperoni", "Fresh basil, chiffonade", "**Preheat oven to 375°**"], "instructions": "Season each chicken filet with the Italian seasoning, salt, pepper and garlic powder on both sides.\nAdd the olive oil to a large skillet and heat until hot. Add the chicken to the pan a few at a time and cook until each side has browned. Remove to baking sheet.\nSprinkle some parmesan on each chicken breast. Top with the sauce, more herbs and the remaining parmesan. Place 2 slices of mozzarella on top of each filet and add a 3-4 slices of pepperoni to each.\nBake for 25-30 minutes or until the cheese has melted.\nTop with the fresh basil and serve.\nCalories 227 Carb 6g Fiber 1g", "image": "https://static.wixstatic.com/media/75d545_d980d722e450478aa6b54dc097e33b5e~mv2.jpeg"}, {"slug": "low-carb-pizza-serves-1", "title": "Low Carb Pizza", "serves": "Serves 1", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1 low carb wrap", "2 -3 tbsp Pizza Sauce", "¼ cup shredded mozzarella cheese", "8 slices pepperoni", "**Preheat the oven to 375°**"], "instructions": "Spray a foil cookie sheet with spray olive oil and place the wrap on the cookie sheet.\nSpray the top of the wrap with the olive oil and place in the oven. Bake for 3-5 minutes, or just until lightly crisp. (no longer floppy)\nRemove from the oven and top with the pizza sauce, mozzarella cheese and pepperoni. Bake for 3-5 minutes, or until the cheese has melted and the sauce is hot.\nServe with your favorite pizza spices.", "image": "https://static.wixstatic.com/media/75d545_eee03000b9a2409cb0b23e4bd7c1b732~mv2.jpg"}, {"slug": "low-carb-zuppa-toscana-soup-serves-6", "title": "Low Carb Zuppa Toscana Soup", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-02-27", "ingredients": ["2lb Mild or Hot bulk Italian sausage", "2 tbsp extra virgin olive oil", "1 cup finely diced Vidalia onion", "6 garlic cloves, minced", "72 ounces chicken stock", "8 cups bite size cauliflower florets", "6 cups chopped fresh Kale, center vein removed", "1 tsp red pepper flakes", "2 tsp salt", "1 tsp ground black pepper", "1 cup heavy cream"], "instructions": "Brown the sausage over medium high heat, in a large skillet; breaking into small pieces as it cooks. Remove the cooked sausage from the skillet with a slotted spoon and add to am 8qt saucepot.\nIn the same skillet that the sausage was cooked in, add the olive oil. Cook the onion and the garlic over medium heat until the onions are translucent and the garlic is fragrant. Transfer the cooked onions and garlic to the saucepot.\nAdd the chicken stock, cauliflower and kale to the saucepot and stir to combine.\nAdd the red pepper flakes, salt & pepper and mix.\nCover the pot and simmer over low heat for 1-2 hours or until the cauliflower and kale are tender.\nAdd the heavy cream and continue to simmer until the soup is hot again.\nServe and enjoy. 5.6 carbs per cup", "image": "https://static.wixstatic.com/media/75d545_867ed8acc0274475b7ed9a77afdd44ca~mv2.jpeg"}, {"slug": "low-fat-banana-bread", "title": "Low Fat Banana Bread", "serves": "", "category": "Breads & Stuffings", "date": "2022-03-03", "ingredients": ["5 large very ripe bananas", "1 cup whole wheat flour", "1 cup flour", "2 tsp baking powder", "1 tsp baking soda", "½ tsp salt", "5 tsp butter, softened", "½ cup brown sugar, packed", "1 large egg", "¼ cup skim milk", "½ cup chopped walnuts", "Preheat oven to 350º"], "instructions": "Spray a 9 x 5 loaf pan with cooking spray and set aside.\nPeel and mash 3 of the bananas in a small bowl. Cut the remaining 2 bananas into chunks and place in a separate bowl.\nAdd the flour, baking soda, baking powder and salt to a large sifter and sift into a medium bowl.\nIn a large mixing bowl, combine the butter and sugar with an electric mixer until fluffy. Add the egg and beat until mixed.\nWith the mixer, add the mashed bananas, flour, milk and butter mixture alternating in batches as you add. Do not over beat.\nAdd the banana chunks and walnuts, and spoon the batter into the prepared pan.\nBake for about an hour, or until a knife inserted into the center comes out clean.\nCool for at least 15 minutes and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "low-fat-creamy-key-lime-pie", "title": "Low Fat Creamy Key Lime Pie", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["**1**graham cracker crust", "14oz fat free sweetened condensed milk", "8oz regular liquid egg substitute", "fresh lime juice", "¾ cup(s), from key limes", "fat free whipped topping", "**Preheat oven to 325°F.**"], "instructions": "Place crust on a baking sheet; set aside.\nIn a medium bowl, whisk together milk, egg substitute and lime juice; pour into crust.\nBake pie until center looks set but still shakes a little when you tap it, about 15 minutes; remove to a wire rack and cool completely. Transfer cooled pie to refrigerator; chill for 1 to 2 hours.\nCut chilled pie into 12 slices; garnish each piece with 1 tablespoon whipped topping and serve. Yields 1 piece per serving.\n8 WW points", "image": "img/low-fat-creamy-key-lime-pie.jpg"}, {"slug": "low-fat-eggplant-rollatini-serves-4", "title": "Low Fat Eggplant Rollatini", "serves": "Serves 4", "category": "Main Dish", "date": "2022-03-04", "ingredients": ["2 medium eggplants", "2 tsp olive oil", "2 cloves garlic, sliced", "Sauce", "2 cups canned crushed tomatoes", "2 tbsp fresh basil, chopped", "Filling", "¼ cup onion, diced", "1 small zucchini, diced", "1 large clove of garlic, minced", "½ cup part skim ricotta", "2 tbsp fresh parsley, chopped", "2 tbsp fresh basil, chopped", "3 tbsp freshly grated parmesan cheese", "1 large egg, slightly beaten", "¼ tsp salt", "¼ tsp freshly ground black pepper", "Preheat oven to 450º"], "instructions": "Spray a foil baking sheet with cooking spray and set aside.\nRemove the ends of the eggplant and slice with a mandolin into ¼” slices, **lengthwise**.\nPlace the slices on the prepared baking sheet and lightly spray the tops with additional cooking spray.\nBake for about 10 minutes, or until the eggplant has browned and then flip and cook for another 10 minutes. ( if the eggplant gets too brown it will not roll without breaking after cooled) Remove from the oven and let cool.\n**Reduce oven to 400º**\nIn a medium sauce pot, heat the oil over medium high heat and add the slices of garlic. Sauté for 1-2 minutes or until it just begins to brown. Be careful it doesn’t cook too long or it will become bitter.\nAdd the crushed tomatoes and reduce the heat to low. Add the 2 tbsp chopped basil and simmer for about 10 minutes. Remove from heat.\nSpray a large skillet with cooking spray and heat over medium high heat; add the onion and zucchini and cook until the onion begins to brown. Add the chopped garlic and cook until just fragrant. Remove from the heat.\nIn a small bowl, mix the ricotta, parsley, basil, and 2 tbsp of parmesan cheese. Add the vegetable mixture from the skillet and combine.\nAdd the egg, salt and pepper and mix well.\nAdd a few tablespoons of tomato sauce to a small shallow casserole dish to coat the bottom.\nAdd about 2-3 tbsp of the cheese mixture to the narrow end of the eggplant slices and roll up. Place in the casserole dish with the seam side down.\nSpoon the tomato sauce over the top of the rollatini and sprinkle with the remaining fresh parmesan.\nBake for 15 minutes or until the sauce begins to bubble.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "low-fat-ranch-chicken-serves-4", "title": "Low Fat Ranch Chicken", "serves": "Serves 4", "category": "Main Dish", "date": "2022-03-03", "ingredients": ["½ cup light sour cream", "2 cups corn flakes, crushed", "6 tbsp ranch dressing seasoning", "1 lb chicken filets", "Preheat oven to 350º"], "instructions": "Spray a baking sheet with cooking spray and set aside.\nPlace crushed corn flakes in a pie plate and toss with the ranch dressing.\nWith a pastry brush, put a thin layer of sour cream on both sides the filets, and press into the corn flake mixture on both sides. Place the chicken on the prepared baking sheet.\nSprinkle the remaining corn flakes evenly over the tops of the chicken breasts and bake for 30-35 minutes.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "low-fat-sriracha-aioli", "title": "Low Fat Sriracha Aioli", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["2 Tbsp. Light Mayo 1/4 C. Plain Fat Free Greek Yogurt 1 Tbsp. Sriracha 2 Tsp. Distilled White Vinegar Salt & Pepper to Taste"], "instructions": "Whisk all ingredients together in a small bowl.", "image": "img/low-fat-sriracha-aioli.jpg"}, {"slug": "macadamia-coconut-crusted-fish", "title": "Macadamia Coconut Crusted Fish", "serves": "", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["3 pieces (about 6 ounces each) Tilapia filets", "1 teaspoon salt", "Freshly ground pepper", "1/2 cup dry roasted macadamia nuts, finely chopped", "1/2 cup panko breadcrumbs", "1/3 cup flaked or shredded unsweetened coconut", "2 tablespoons chopped fresh parsley", "1/4 teaspoon ground ginger", "1 egg, whisked", "4 tablespoons vegetable oil", "Lemon wedge"], "instructions": "Heat oven to 450 degrees. Pat fish dry. Sprinkle with salt and pepper to taste.\nMix chopped nuts, breadcrumbs, coconut, parsley, ginger, 1/2 teaspoon salt and pepper to taste in a shallow dish. Put egg and remaining 1/4 teaspoon salt into another shallow dish\nDip fish into egg wash; let excess drip off. Coat fish on both sides in nut crumb mixture.\nHeat oil in large skillet over medium-high. Add fish and saute´ until light brown on both sides. Gently remove fish to a cookie sheet and put into oven. Cook for about, 12 to 15 minutes. Or until fish flakes.\nServe with lemon wedges and topped with pineapple salsa if desired", "image": "img/macadamia-coconut-crusted-fish.jpg"}, {"slug": "magic-cookie-bars-makes-36-bars", "title": "Magic Cookie Bars", "serves": "Makes 36 bars", "category": "Desserts", "date": "2022-02-27", "ingredients": ["½ cup butter", "1 ½ cup graham cracker crumbs", "1 (14oz) can sweetened condensed milk", "1 (6oz) package semi sweet chocolate chips", "1 (3.5oz)package flaked coconut, about 1 1/3 cup", "1 cup chopped nuts", "**Preheat the oven to 350° (325° for glass dish)**"], "instructions": "In a 13 x 9 baking dish, melt the butter in the oven.\nSprinkle the cracker crumbs over the melted butter.\nPour the condensed milk over the crumbs.\nTop evenly with the remaining ingredients. Press down firmly and bake for 25-30 minutes or until lightly browned. Cool.\nChill thoroughly. Cut into bars and serve.", "image": "img/magic-cookie-bars-makes-36-bars.jpg"}, {"slug": "make-ahead-white-wine-gravy-makes-about-4-cups", "title": "Make Ahead White Wine Gravy Makes about 4 cups", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-03-01", "ingredients": ["6 tbsp butter", "2 medium shallots, thinly sliced", "2 tbsp chopped fresh sage", "1/3 cup flour", "3 cups chicken or turkey broth", "Kosher salt & fresh ground pepper", "Pan drippings from turkey", "1 cup dry white wine, Sauvignon Blanc"], "instructions": "Melt the butter in a large skillet over medium heat. Add the shallots and cook until softened.\nAdd the sage and cook for another 2 minutes. Add the flour and stir to completely blend with the shallots. Add the broth and bring to a boil. Let boil for 5 minutes or until thickened. Remove from the heat and season with salt & pepper.\nAt this point you can strain any small lumps if there are any.\nAllow the gravy to cool and then refrigerate until needed. The gravy at this point can be stored up to 3 days.\n**Finishing the gravy**\nWhen the turkey is done roasting, strain the pan drippings into a fat separator measuring cup.\nPlace the roasting pan over 2 burners and add the wine. Bring to a boil, scraping the brown bits on the bottom of the pan. Simmer until the wine has reduced slightly.\nReduce the heat to low and add the refrigerated gravy base. Simmer until the gravy has thickened.\nThe gravy can be thinned with the pan drippings if needed.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "margarita-cheesecake-mousse-makes-10-cup-servings", "title": "Margarita Cheesecake Mousse", "serves": "Makes 10 ½ cup servings", "category": "Desserts", "date": "2023-06-26", "ingredients": ["**Crust**", "1 ¼ cup graham cracker crumbs", "5 tbsp melted butter", "2 tbsp brown sugar", "**Mousse**", "2 8oz cream cheese, softened", "2 cup powdered sugar", "3 tbsp tequila", "Juice and zest of 1 lime", "1 tsp vanilla", "¼ tsp kosher salt"], "instructions": "[1 cup whipped cream](https://www.mymomshomecooking.com/post/whipped-cream-16-servings)\nIn a medium bowl combine all the crust ingredients together and set aside.\nIn a large bowl, beat the cream cheese and powdered sugar until smooth. Add the tequila, lime juice, zest, vanilla and salt. Mix until well combined.\nGently fold the whipped cream into the mousse.\nDivide the graham cracker crust among 10 small serving bowls and lightly pack the crust down with a spoon. Save a little a little of the crumbs for garnish.\nPlace the mousse into a piping bag or icing plunger and in a circular motion, pipe ½ cup of mousse into each cup.\nRefrigerate for about an hour or overnight.\nBefore serving, top with a ¼ slice of a lime and whipped cream.", "image": "https://static.wixstatic.com/media/75d545_768669e210ad44babaf5ec8c9f374b61~mv2.jpg"}, {"slug": "marmalade-glazed-turkey", "title": "Marmalade Glazed Turkey", "serves": "", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["2 tsp herbes de Provence", "¼ tsp black pepper", "½ tsp kosher salt", "¼ tsp garlic powder", "1/8 tsp crushed red pepper", "1 10-12lb turkey", "vegetable oil", "2/3 cup apple brandy", "½ cup orange marmalade", "2 tbsp cider vinegar", "½ tsp kosher salt", "1 tbsp butter", "2 tsp orange zest"], "instructions": "Preheat the oven to 325°.\nIn a small glass bowl combine the herbes de Provence, black pepper, salt, garlic powder, and red pepper.\nLoosen the skin of the turkey without tearing it from one end to the other. Rub the herb mixture underneath the skin. Make sure the herbs are rubbed all over the entire breast and down to the thighs.\nRub the oil and remaining herbs all over the exterior of the bird.\nStuff with your favorite stuffing recipe if desired.\nGlaze:\nIn a small saucepan, combine the brandy, marmalade, vinegar, and salt. Bring to a boil. Reduce the heat and simmer uncovered for 8-10 minutes. Glaze should be reduced to about 1 cup. Remove from the heat and stir in the butter and orange zest.\nBrush the turkey with the glaze and bake as usual. Baste often with the glaze until the turkey is done. ( 175° on a meat thermometer)", "image": "img/marmalade-glazed-turkey.jpg"}, {"slug": "maryland-crab-soup-serves-6-8", "title": "Maryland Crab Soup", "serves": "Serves 6-8", "category": "", "date": "2024-04-03", "ingredients": ["4 tbsp butter", "1 large Vidalia onion, finely chopped", "1 cup of diced celery", "2 qt chicken stock", "2 qt beef stock", "2 tbsp Old Bay", "4 tbsp Worcestershire sauce", "2 bay leaves", "1 cup lima beans", "1 cup sliced carrots, fresh or frozen", "1 cup corn, fresh or frozen", "1 28 oz can crushed tomatoes", "2 lb lump crabmeat", "Salt and pepper to taste"], "instructions": "Melt the butter in a large sauce pot and sauté the onion and celery until the onion is translucent.\nAdd the chicken and beef stock to the pot. Add the Old Bay seasoning, Worcestershire sauce, bay leaves, vegetables, crushed tomatoes and salt and pepper to taste.\nBring mixture to a boil and reduce the heat. Add the crabmeat and continue to cook until the crab meat is heated.\nAt this point you can add more of any of the seasonings or even hot sauce if you desire. The soup can be thinned at any point by adding additional stock.\nRemove the bay leaves and serve!", "image": "https://static.wixstatic.com/media/75d545_b4f0bd0631b3487a85e71370338a588a~mv2.jpg"}, {"slug": "mascarpone-fig-appetizers-makes-24", "title": "Mascarpone & Fig Appetizers", "serves": "Makes 24", "category": "Appetizers & Dips", "date": "2022-03-13", "ingredients": ["24 mini frozen phyllo cups", "1 (8oz) package of Mascarpone cheese", "Fig Preserves", "Honey", "Glazed chopped pecans"], "instructions": "Remove the cheese from the refrigerator about an hour before needed.\nPlace the cheese into a cake decorating bottle or pastry bag with a decorative tip and pipe into each cup. About ¾ full. You need enough room for the fig preserves and the pecans.\nDrizzle a little honey over the top of the cheese and top with about a 1/2 tsp of fig preserves.\nSprinkle the tops of each cup with some chopped pecans and serve.\nIf making ahead wait to add the pecans as they will become less crisp.", "image": "https://static.wixstatic.com/media/75d545_c0b0e3e62d55438c9697d4bd0d0e9fa4~mv2.jpeg"}, {"slug": "mashed-red-potatoes-serves-6", "title": "Mashed Red Potatoes", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["3lbs red potatoes, cut into quarters", "8 tbsp butter, cut into pieces", "1 cup heavy cream", "¼ cup fresh chives, finely chopped", "¼ cup parsley, finely chopped (optional)", "kosher salt", "freshly ground black pepper"], "instructions": "Place the potatoes in a large pot and cover with water. Bring to a boil and continue boiling for about 25 minutes, or until the potatoes can easily be pierced with a fork.\nDrain the potatoes and return to the pot. Add the butter and mash. Add ¾ cup of the cream and continue to mash. If you are happy with the consistency of the potatoes do not add the remaining cream.\nStir in the chives, salt and pepper to taste.\nServe.", "image": "img/mashed-red-potatoes-serves-6.jpg"}, {"slug": "meatloaf-wellington", "title": "Meatloaf Wellington", "serves": "", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1 ½ lb ground beef", "¼ cup chopped onion", "3tbsp chopped fresh parsley or 1tbsp dried", "1 10.5oz jar of beef gravy", "salt and pepper to taste", "1 egg, slightly beaten", "1 cup bread crumbs", "1 package of refrigerated crescent rolls"], "instructions": "Preheat the oven to 375°.\nMix the ground beef, onion, salt and pepper to taste, egg, ¼ cup gravy and the breadcrumbs. Form the meat into loaf and place in a pan.\nBake for 45 minutes and drain the fat. Separate the crescent rolls and cover the entire meatloaf overlapping the triangles. Bake for an additional 15 minutes.\nServe with gravy.", "image": "img/meatloaf-wellington.jpg"}, {"slug": "mediterranean-shrimp-and-vegetables-serves-8", "title": "Mediterranean Shrimp and Vegetables", "serves": "Serves 8", "category": "Seafood", "date": "2023-07-04", "ingredients": ["3 lb colossal or jumbo shrimp, peeled, deveined and tails removed", "2 bunches of asparagus, trimmed", "½ cup extra virgin olive oil, divided", "4 cloves of garlic, minced", "2 small red onions", "1 yellow bell pepper", "1 orange bell pepper", "2 red bell peppers", "2 tbsp fresh oregano", "4 tsp smoked paprika", "Salt and pepper, to taste", "2 whole lemons, juiced", "2 cups of kalamata olives, pitted", "2 cups of either Feta or Goat cheese", "2/3 cup fresh Parsley", "**Preheat the oven to 450°**"], "instructions": "In large bowl, season the shrimp with ¼ cup of olive oil, garlic, salt, pepper, paprika, oregano and lemon juice.\nLay the asparagus in an even layer over a large jelly roll pan or baking sheet with sides. Drizzle about 2 tbsp of olive oil over the asparagus.\nCut the peppers into about 1” pieces and the onion into small\n(1/4” wedges).\nPlace the shrimp over the asparagus in an even layer and top with the onion and peppers.\nBake for about 20 minutes, the peppers should be crisp tender and the shrimp edges are beginning to brown.\nRemove from the oven and drizzle with the remaining 2 tbsp of olive oil.\nServe topped with the cheese and olives or serve on the side for your guests to use as they choose.\nServe with warm crusty bread.", "image": "https://static.wixstatic.com/media/75d545_5a31dd5e21ac4055ab601ae0f489fdb9~mv2.jpg"}, {"slug": "mexican-baked-beans-serves-12", "title": "Mexican Baked Beans", "serves": "Serves 12", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["2 tbsp vegetable oil", "2 medium Vidalia onions, diced", "2 medium green bell peppers, diced", "¼ cup light brown sugar", "4 28oz cans baked beans, New England style", "4 tsp chili powder", "2 tsp salt", "1 tsp dried oregano", "1 bag of Fritos corn chips", "**Preheat the oven to 350°**"], "instructions": "Grease a 13 x 9 baking dish(I use a little larger for more room but 13 x 9 works)and set aside.\nHeat the vegetable oil in a large skillet over medium heat and add the onions and green pepper. Stir n the brown sugar and cook until the vegetables are tender. About 10 minutes.\nIn the baking dish, combine the baked beans with the vegetables, chili powder, salt and oregano.\nTop with about 2 cups of crushed Fritos. (add more or less as desired).\nBake for 45 minutes until hot throughout.", "image": "https://static.wixstatic.com/media/75d545_09e8def5bcc743cfa856951ddf68f3af~mv2.jpg"}, {"slug": "mexican-casserole-serves-12", "title": "Mexican Casserole", "serves": "Serves 12", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1 lb ground beef", "1 can 15 oz creamed corn", "1 can tomato soup", "½ lb of sliced American cheese", "1 onion, chopped", "1 green pepper, chopped", "1 8oz package of egg noodles"], "instructions": "Preheat the oven to 350°.\nPlace the meat in a large skillet break apart and simmer covered for several minutes. Do not brown.\nAdd the onion, green pepper, corn, and the soup; cover and cook slowly, frequently stirring until the vegetables are tender.\nCook the noodles in salted water as directed on the package and drain.\nLayer the noodles, cheese, and vegetable meat mixture in a large greased casserole until all has been used.\nBake for 30 minutes or until heated through.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "mexican-chicken-chowder-serves-6", "title": "Mexican Chicken Chowder", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-02-27", "ingredients": ["2 ½ cup chopped cooked chicken", "1 can whole kernel corn", "1 can condensed cream of potato soup", "4oz diced green chiles, undrained", "2tbsp snipped fresh cilantro", "1 envelope of taco seasoning", "3 cup chicken broth", "8oz sour cream", "4oz Cheez Wiz"], "instructions": "Combine chicken, corn, potato soup, green chiles, cilantro, taco seasoning, and chicken broth in a crock-pot and cover. Cook on low for 8-10 hours or on high for 4-5 hours.\nIn a small bowl combine the sour cream with 1 cup of the soup from the crock-pot until blended. Pour the sour cream mixture into the crock-pot and add the cheez wiz. Cover. Cook for additional 5-10 inmutes.", "image": "img/mexican-chicken-chowder-serves-6.jpg"}, {"slug": "mexican-dip", "title": "Mexican Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["_1 16oz_", "_2 15oz cans Hormel Chili NO BEANS_", "_16oz jar salsa_", "_chopped scallions_"], "instructions": "_Cut the cheese into chunks. Mix everything together in a microwaveable bowl. Cover and microwave on high for about 7 minutes._\n_Remove from the microwave and stir well or the chili will harden. Return to the microwave for another 5 minutes._\n_Serve hot with your favorite chips._", "image": "img/mexican-dip.jpg"}, {"slug": "mexican-italian-salsa-serves-10", "title": "Mexican-Italian Salsa", "serves": "Serves 10", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["3 plum tomatoes, chopped", "½ onion, finely chopped", "1 2.25oz can sliced black olives", "1 6oz jar marinated artichoke hearts, drained and chopped", "2 tbsp lemon juice", "2 cloves garlic, minced", "3 tbsp chopped fresh basil", "¼ tsp red pepper flakes", "¼ tsp Italian seasoning", "¼ tsp ground cumin", "3 tbsp chopped fresh cilantro", "½ tsp salt", "¼ tsp fresh ground pepper"], "instructions": "In a medium bowl gently combine the tomatoes, onion, olives, and artichoke hearts. Set aside.\nIn a small bowl combine the lemon juice, garlic, basil, red pepper, Italian seasoning, cumin, cilantro, salt and pepper with a small whisk. Add to the tomato mixture.\nServe with warm tortilla chips.", "image": "img/mexican-italian-salsa-serves-10.jpg"}, {"slug": "mexican-meatloaf-serves-8", "title": "Mexican Meatloaf", "serves": "Serves 8", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["Mexican Meatloaf Serves 8", "2 eggs, slightly beaten", "1 (14.5oz) Ro*tel diced tomatoes with green chiles", "¼ cup onion, diced", "1 tsp Worcestershire sauce", "1 tsp salt", "¼ tsp black pepper", "2lb 90% lean ground beef", "1 cup crushed Cheezits hot and spicy crackers", "**Topping**:", "1 cup shredded cheddar cheese", "1 cup chunky salsa"], "instructions": "Preheat the oven to 350°.\nIn a large bowl combine the ground beef, eggs, tomatoes, onion, Worcestershire, salt and pepper. Add the crackers. Mix well to combine all the ingredients.\nPlace the meat mixture in a foil or glass baking dish and form into a loaf shape. Bake for 40 minutes.\nRemove the meatloaf from the oven and spread a layer of salsa on the top of the loaf. Sprinkle with the cheddar cheese. Return the meatloaf to the oven and continue baking for another 15-20 minutes or until the internal temperature reads 160 degrees and the meat is no longer pink in the center.", "image": "img/mexican-meatloaf-serves-8.jpg"}, {"slug": "mexican-orzo-salad-serves-18", "title": "Mexican Orzo Salad", "serves": "Serves 18", "category": "Salads", "date": "2022-02-27", "ingredients": ["1 ½ (16oz) packages of orzo pasta", "1 ½ small red pepper, chopped", "1 ½ small yellow pepper, chopped", "1 ½ bunch green onions, chopped", "1 ½ small red onion, finely chopped", "1 ½ (15oz) cans chickpeas, rinsed and drained", "1 ½ (15oz) cans red kidney beans, rinsed and drained", "1 ½ (15oz) cans black beans, rinsed and drained", "1 ½ (8.75oz) cans whole kernel corn, drained", "1 ½ cups chopped cilantro", "salt to taste", "pepper to taste", "7 ½ limes juiced", "½ cup and tbsp. of canola oil"], "instructions": "Cook the orzo according to the package instructions for “firm” or al dente. Drain.\nIn a large salad bowl mix the orzo, red pepper, yellow pepper, green onions, red onion, chickpeas, kidney beans, black beans, corn, cilantro and salt and pepper. Pour the lime juice and oil over the salad and toss. Refrigerate for at least 2 hours before serving.", "image": "img/mexican-orzo-salad-serves-18.jpg"}, {"slug": "mexican-pork-bowls-serves-4", "title": "Mexican Pork Bowls", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["20 oz ground pork", "1 cup Jasmine rice", "2 tbsp vegetable oil", "2 limes", "4 tbsp light mayonnaise", "2 tsp chili powder", "2 15 oz cans of sweet corn, drained", "2 tbsp of mild taco seasoning", "1 tsp salt", "1/3 cup Beef stock", "½ cup shredded Monterey Jack cheese", "½ cup sour cream", "1 jalapeño pepper, minced", "Fresh cilantro"], "instructions": "In a small pot, combine the rice, 1 ½ cup water and a pinch of salt. Bring to a boil then cover and reduce the heat to low and cook until the rice is tender. 15-18 minutes.\nIn a large skillet over high heat, heat 1 tbsp of oil and add the corn. Cook, stirring often, until the corn is golden brown.\nTransfer the corn to a covered dish.\nIn the same large skillet, heat another tbsp of oil and cook the pork over medium high heat. Add the taco seasoning, 1 tsp of chili powder and salt.\nStir in the beef stock and bring to a simmer until the pork mixture is of a saucy consistency. Season with salt and pepper to taste and remove from the heat.\nWhile the pork is cooking, mix the mayonnaise, half the cheese, 1 tsp chili powder and the juice of 1 lime with the charred corn.\nSeason with salt and pepper to taste and add as much of the minced jalapeño as you like.\nFluff the rice and season with salt & pepper. Divide between 4 bowls and top with the pork. Top with the remaining cheese, a dollop of sour cream and a sprinkle of fresh cilantro.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "mini-cheesecakes-with-salted-caramel-makes-12", "title": "MINI CHEESECAKES WITH SALTED CARAMEL", "serves": "Makes 12", "category": "Desserts", "date": "2022-02-27", "ingredients": ["9 sheets of Graham crackers, crushed (about 1 1/8 cups)", "1 1/2 tablespoons sugar", "3 1/2 tablespoons salted butter, melted", "16 ounces cream cheese, at room temperature", "3/4 cup sugar", "1 1/2 tablespoons all purpose flour", "2 large eggs", "1 tsp vanilla extract", "1/4 cup sour cream", "1/4 cup heavy cream", "Your favorite quality caramel sauce", "Fleur de sel", "**Preheat the oven to 350º**"], "instructions": "Line a 12 cup muffin pan with paper liners, or spray a mini cheesecake pan with spray oil.\nIn a small bowl or the bowl, mix together the crushed graham crackers, 1 1/2 Tbsp sugar, and melted butter. Divide the mixture among the muffin cups, and with a spoon, tamp it down into an even layer with some of the Graham cracker mixture coming up the sides.\nBake the crust in the oven for 5 minutes. Remove the pan and let cool while you make the filling.\nIn a large bowl, mix the cream cheese and sugar with a mixer on low speed until smooth. Stir in the flour.\nAdd the eggs, one at a time, and mix until just combined. Add the vanilla, sour cream, and heavy cream, and mix until combined.\nTap the mixing bowl on the counter to release any air bubbles.\nDivide the batter among the muffin cups to about 2/3 full and bake for 20 to 25 minutes.\nRemove from the oven and let cool for an hour. Once they are cooled, refrigerate, covered loosely with wax paper and plastic wrap, for at least 2 hours.\nTo serve, top with a small amount of warmed caramel and a sprinkling of sea salt.", "image": "img/mini-cheesecakes-with-salted-caramel-makes-12.jpg"}, {"slug": "mini-lemon-phyllo-tarts-makes-15", "title": "Mini Lemon Phyllo Tarts", "serves": "Makes 15", "category": "Desserts", "date": "2022-02-27", "ingredients": ["15 mini phyllo shells", "buttery cooking spray", "1/4 cup fresh lemon juice", "¼ cup fresh orange juice", "zest of 2 lemons and 1 small orange (about 1/3 cup)", "2 large eggs", "2 large egg yolks only", "4 tbsp unsalted butter, cut into pats", "½ cup granulated sugar", "2-4 tbsp granulated sugar for sprinkling", "Whipped cream", "Turbinado sugar", "**Preheat the oven to 350°**"], "instructions": "Place the phyllo cups on a baking sheet and spray with the cooking spray. Sprinkle with 2-4 tbsp of sugar. And bake for 5- 10 minutes or until golden brown. Let cool completely.\nWhisk the eggs, egg yolks and the ½ cup of sugar in a bowl until fluffy. Add the lemon and orange zest. Stir to combine. Add the lemon and orange juice and stir to combine.\nIn a medium saucepan cook the egg mixture over medium heat, stirring constantly, until thickened. 10- 15 minutes. Pour the mixture into a bowl and set in an ice bath.\nStir in the butter, one pat at a time. Place in the refrigerator to cool. About 5 minutes. The mixture should be cool to the touch.\nFill a pastry bag with the lemon filling and pipe into the tart shells. Freeze for 1 hour. Garnish with whipped cream and a sprinkle of the Turbinado sugar before serving.", "image": "img/mini-lemon-phyllo-tarts-makes-15.jpg"}, {"slug": "mini-red-velvet-cheesecakes-makes-12", "title": "Mini Red Velvet Cheesecakes", "serves": "Makes 12", "category": "Desserts", "date": "2022-02-27", "ingredients": ["**For the crust:**10 Oreo cookies 2 tablespoons butter, melted**For the cheesecake:**12 oz. cream cheese, softened 1 tablespoon sour cream 1/2 cup granulated sugar 3 tablespoons cocoa powder 1 teaspoon vanilla extract 4 teaspoons red food coloring 1 large egg, room temperature**For the topping:**1/2 cup heavy cream, cold 2 tablespoons powdered sugar 1/2 teaspoon vanilla extract**Preheat oven to 350º**"], "instructions": "Lightly grease or line a 12 cup muffin pan. In a food processor, add Oreo cookies and pulse into fine crumbs. Transfer crumbs to a small bowl and pour in melted butter. Use a fork to mix in melted butter until all crumbs are evenly moistened.Scoop a heaping tablespoon of crumbs into each muffin cup. Use the back of a spoon to press down and compact the crumbs into an even layer.Bake for 5 minutes. Then, remove from the oven and reduce oven temperature to 325 degrees F.In a medium-sized bowl, using an electric hand mixer, beat together cream cheese, sour cream, and granulated sugar until well-blended and smooth. Add cocoa powder and vanilla, and beat until incorporated. Beat in red food coloring. Lastly, beat in egg just until combined.Bake cheesecakes for 13-15 minutes, or until tops are set. Turn off the oven, and leave the cheesecakes in there for 5 minutes with the oven door open.Then, remove from the oven and let cool to room temperature, before transferring to the refrigerator overnight.In a small bowl, using an electric hand mixer, beat together heavy cream, powdered sugar, and vanilla extract until soft peaks form. Remove mini cheesecakes from pan and decorate with whipped cream as desired before serving.", "image": "img/mini-red-velvet-cheesecakes-makes-12.jpg"}, {"slug": "mixed-greens-and-apple-salad-serves-4", "title": "Mixed Greens and Apple Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-28", "ingredients": ["1 5 oz container spring mix or favorite mixed greens", "2 large Honeycrisp apples, cored and thinly sliced", "1 lemon, juiced"], "instructions": "In a large bowl, toss the greens and apples with a large drizzle of olive oil and as much of the lemon as you like.\nSeason with salt & pepper and serve!", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "mixed-greens-and-beet-salad", "title": "Mixed Greens and Beet Salad", "serves": "", "category": "Salads", "date": "2022-02-27", "ingredients": ["1 11oz can Mandarin orange sections in juice , undrained", "½ cup light raspberry vinaigrette dressing", "1 8oz package mixed greens", "1 14oz can julienne style beets", "½ cup slivered almonds", "½ small red onion, thinly sliced"], "instructions": "Drain the Mandarin oranges, reserving 2tbsp of juice.\nIn a small bowl combine the raspberry vinaigrette with the reserved juice.\nMix the greens, Mandarin oranges, red onion and almonds in a large bowl. Toss lightly with a little of the dressing.\nTop the salad with the beets and add more dressing. Ready to serve.", "image": "img/mixed-greens-and-beet-salad.jpg"}, {"slug": "mixed-greens-salad-with-strawberries-red-onions-and-candied-almonds", "title": "Mixed Greens Salad with Strawberries Red onions and Candied Almonds", "serves": "", "category": "Salads", "date": "2022-02-27", "ingredients": ["Mixed greens", "Strawberries, hulled and quartered", "½ cup slivered almonds", "½ red onion, thinly sliced", "2 tbsp sugar", "balsamic vinaigrette"], "instructions": "Add the almonds and the sugar to a small sauté pan. Heat on low until the sugar starts to melt, and the almonds become toasted. Take your time with this step. Cool on a sheet of waxed paper.\nToss the greens, strawberries and red onion with the vinaigrette and top with the candied almonds.", "image": "img/mixed-greens-salad-with-strawberries-red-onions-and-candied-almonds.jpg"}, {"slug": "mixed-olive-crostini-2-dozen", "title": "Mixed Olive Crostini 2 Dozen", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["1 can (4 ¼ oz) chopped ripe olives", "½ cup pimento stuffed olives, finely minced", "½ cup grated parmesan cheese", "¼ cup butter, softened", "1 tbsp extra virgin olive oil", "2 garlic cloves, minced", "¾ cup shredded mozzarella cheese", "¼ cup minced fresh parsley", "1 French bread baguette"], "instructions": "Preheat Broiler.\nIn a medium bowl, combine the first 6 ingredients and stir in the mozzarella and parsley. Mix well.\nSlice the baguette into 24 ¼” thick slices and place on an ungreased cookie sheet.\nSpread with the olive mixture and broil 3-4” from the heat for 2-3 minutes or until the cheese has melted. Watch carefully.", "image": "img/mixed-olive-crostini-2-dozen.jpg"}, {"slug": "mushroom-turnovers-6-8-dozen", "title": "Mushroom Turnovers 6-8 dozen", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["**Dough for turnovers**:", "8 oz cream cheese", "1/2 lb butter", "2 ¼ cup flour", "1tsp salt", "1 egg, slightly beaten", "**Mushroom filling**:", "3tbsp butter", "1 large onion, finely chopped", "½ lb fresh mushrooms", "¼ tsp thyme", "½ tsp salt", "freshly ground pepper", "2tbsp flour", "¼ cup heavy cream"], "instructions": "Mix the cream cheese, butter, flour and salt as for a pie crust and roll into a ball. Chill for 4 hours.\nMeanwhile, heat the butter for the filling in a large skillet and brown the onion. Add the mushrooms and cook 3 minutes. Add the thyme, salt and pepper. Sprinkle with flour and stir in the cream until thickened.\nRoll out onto a floured board to 1/8” thick and cut with a 2 ½ “ round biscuit cutter.\nPlace 1 small tsp of filling on each round and fold over to make a half circle. Seal the edges with a fork dipped in water. Poke a small hole in the top of each turnover and brush lightly with egg. Bake in a 325° oven for 30 minutes or until brown.\nThese may be frozen before baking. Do not brush with egg until ready to bake. Place on a cookie sheet to freeze and then transfer to a plastic bag.\nThe pastry can also be filled with liver, crab, shrimp, lobster or chicken.", "image": "img/mushroom-turnovers-6-8-dozen.jpg"}, {"slug": "nacho-chicken-casserole-serves-5", "title": "Nacho Chicken Casserole", "serves": "Serves 5", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["2 cups diced cooked chicken", "½ cup uncooked instant rice", "1 can(14.5oz) diced tomatoes, drained", "1 can(10.75oz) condensed cream od chicken soup"], "instructions": "1 can(11oz) Green Giant Mexicorn, whole kernel corn with red and green peppers, drained\n1 can(4.5oz) Old el Paso chopped green chiles(undrained)\n1tsp Old el Paso taco seasoning mix(from 1.25oz envelope)\n1 ½ cup shredded cheddar cheese\n1 cup broken tortilla chips\nPreheat oven to 350°.\nSpray a 2qt casserole with cooking spray. In the casserole, stir together the chicken, rice, tomatoes, soup, corn, chiles, taco seasoning, and 1 cup of cheese.\nCover and bake about an hour or util the rice is tender and the mixture is heated through. Top with tortilla chips and sprinkle with the remaining cheddar cheese. Bake about 10 minutes longer or until the filling is bubbly and the cheese has melted.", "image": "img/nacho-chicken-casserole-serves-5.jpg"}, {"slug": "napa-cabbage-noodle-salad-serves-14", "title": "Napa Cabbage Noodle Salad", "serves": "Serves 14", "category": "Salads", "date": "2022-02-27", "ingredients": ["2 large heads of napa cabbage, shredded", "2(3oz) packages ramen noodles, crushed", "1 cup sesame seeds", "6oz blanched slivered almonds", "1 cup extra virgin olive oil", "2 cups canola oil", "1 tbsp + 1 tsp soy sauce", "1 1/3 cup white sugar", "¼ cup balsamic vinegar", "1 cup white wine vinegar"], "instructions": "In a large bowl mix the cabbage, sesame seeds, almonds and olive oil. Chill for 30 minutes.\nPrepare the dressing.\nMix the canola oil, sugar, soy sauce, balsamic, and the white wine vinegar with a wire whisk or blender.\nJust before you are ready to serve toss the dressing and the ramen noodles into the cabbage mixture.", "image": "img/napa-cabbage-noodle-salad-serves-14.jpg"}, {"slug": "no-bake-banana-split-cake", "title": "No Bake Banana Split Cake", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["**Crust**", "3 cups almond flour", "2 tsp cinnamon", "1/3 cup Baking Truvia", "6 tbsp butter, melted", "**Filling**", "2 8oz packages cream cheese", "1 cup confectioner's sweetener (Swerve or Truvia)", "1 cup butter, melted", "**Topping**", "2 pints of strawberries, sliced", "1 ½ banana, chopped", "1 tbsp lemon juice", "4 cups Stabilized Whipped Cream (whipped cream that doesn't separate)", "Low Carb Chocolate Sauce"], "instructions": "Line the bottom of a 9 x 13 pan with parchment paper and set aside.\nIn a medium bowl mix together the almond flour, cinnamon, 1/3 cup of sweetener and 6 tbsp of melted butter until well combined. Press into the bottom of the prepared baking dish.\nIn a large bowl combine the cream cheese, confectioner's sweetener, and 1 cup of melted butter with an electric mixer until smooth. Spread over the crust.\nIn a medium bowl combine the strawberries, banana and lemon juice. Spoon evenly over the top of the cream cheese mixture.\nTop with the Stabilized Whipped Cream and garnish with chocolate sauce and strawberries or add your favorite nuts.", "image": "img/no-bake-banana-split-cake.jpg"}, {"slug": "no-knead-artisan-bread", "title": "No Knead Artisan Bread", "serves": "", "category": "Breads & Stuffings", "date": "2023-01-10", "ingredients": ["3 cups bread flour (you can use regular flour, I prefer bread flour)", "2 tsp RAPID rise yeast*", "2 tsp Kosher salt"], "instructions": "1 ½ cup very warm tap water (not boiling but warm enough you would enjoy sitting in it for a bath)\nMix the flour, yeast* and salt in a large bowl. Add the water and mix with the handle of a wooden spoon. You may need to add a little more water. The dough should not be runny but should be wet and sloppy enough that you can’t knead it.\nCover with plastic wrap and set on the counter for 2-3 hours until it doubles in size. (the room should be no less than 72°) The dough will be wobbly and be bubbly on top when ready.\nPreheat the oven to **450°**and place a covered dutch oven in for 30 minutes before baking.\nSprinkle some flour on a large cutting board or clean counter and scrape the dough out of the bowl onto the surface. Sprinkle the top of the dough with a tbsp of flour and gently fold the dough onto itself an inward about 6 folds, and shape into a roundish shape.\nTransfer to a piece of parchment paper and place in the preheated pot. Place the lid bake on and bake for 30 minutes covered, then 10-12 minutes uncovered. Bread should be crispy and golden.\nCool for 10 minutes.\n*if you can’t find rapid rise yeast and need to use normal yeast, then dissolve the yeast in water first and immediately add to the flour and salt mixture. The rising time will be longer.", "image": "https://static.wixstatic.com/media/75d545_8a1ede911140452f92be88957ee788e6~mv2.jpeg"}, {"slug": "nutella-swirl-pound-cake", "title": "Nutella Swirl Pound Cake", "serves": "", "category": "Breads & Stuffings", "date": "2022-02-27", "ingredients": ["1 ½ cup flour", "4 large eggs", "2 tsp vanilla extract", "¾ tsp baking powder", "¼ tsp salt", "1 cup unsalted butter, softened", "1 ¼ cup sugar", "1 (13oz) jar Nutella", "**Preheat the oven to 325°**"], "instructions": "Lightly grease and flour a 9 x 5 loaf pan and set aside.\nIn a small bowl whisk the eggs and the vanilla together.\nIn a medium bowl combine the flour and the baking powder.\nIn a large bowl beat the butter and the sugar together with an electric mixer until fluffy. With the mixer on a low speed blend in the egg mixture.\nWith the mixer on a low speed add the flour mixture in small batches until well blended. Mix for 30 seconds more.\nSpread 1/3 of the batter in the prepared pan, then ½ of the Nutella on top.\nAdd another 1/3 of the batter on top of the Nutella and then the remaining ½ of of the Nutella on top of the batter just added.\nTop with the remaining batter and lightly swirl the batter with a dinner knife. **Be careful not to over mix.**\nBake the cake for 1 hour and 15 minutes or until a toothpick inserted in the center comes out clean. Let the cake cool for 15 minutes and then invert onto a baking rack, turn right side up and cool completely.\nEnjoy!\n(original recipe can be found on Delish.com)", "image": "https://static.wixstatic.com/media/75d545_8aee6c75cf3d4652bd76cb130e6ec6dc~mv2.jpg"}, {"slug": "oatmeal-scotchies-makes-48-3-cookies", "title": "Oatmeal Scotchies", "serves": "Makes 48 (3\" cookies)", "category": "Desserts", "date": "2022-02-27", "ingredients": ["2 cups unsifted flour", "2 tsp baking powder", "1 tsp baking soda", "1 tsp salt", "1 ½ cup brown sugar", "2 eggs", "1 cup butter", "1 tsp water", "1 ½ cup quick oats, uncooked", "½ tsp orange extract", "1 12oz package butterscotch morsels", "**Preheat the oven to 375°**"], "instructions": "In a small bowl combine the flour, baking powder, baking soda and salt. Set aside.\nIn a large bowl with an electric mixer, combine the butter, sugar, eggs and water until creamy. Gradually add the flour mixture.\nStir in the oats, butterscotch morsels and orange extract.\nDrop by spoon onto a greased cookie sheet and bake for 10-12 minutes.", "image": "img/oatmeal-scotchies-makes-48-3-cookies.jpg"}, {"slug": "old-bay-shrimp-saute-serves-4", "title": "Old Bay Shrimp Saute´", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-27", "ingredients": ["2lb Jumbo shrimp, peeled, deveined and tails off", "4 tbsp freshly squeezed lemon juice", "5 dashes Tabasco sauce", "¾ tsp Worcestershire sauce", "3 tbsp Extra Virgin Olive Oil", "1-2 tbsp butter"], "instructions": "1 tbsp Old Bay (you can do less, it’s really according to taste)\n2 tsp fresh thyme leaves, chopped (you can use dry if you prefer, just use less)\nFresh ground pepper to taste\nIn a small bowl, mix the lemon juice, Tabasco and Worcestershire sauce; set aside.\nHeat the olive oil and 1 tbsp butter in a large frying pan until the butter has melted and appears foamy. Add the shrimp and Old Bay and cook until the shrimp are opaque.\nAdd the lemon juice mix, 1 tbsp butter and the thyme and stir to combine. Season with the pepper and serve.", "image": "img/old-bay-shrimp-saute-serves-4.jpg"}, {"slug": "old-fashioned-corn-casserole-serves-6-8", "title": "Old Fashioned Corn Casserole", "serves": "Serves 6-8", "category": "Vegetable", "date": "2022-11-13", "ingredients": ["2 tbsp Extra virgin olive oil", "½ sweet onion, minced", "1 tbsp minced fresh garlic", "2 tsp salt", "2 tbsp minced fresh parsley", "1 tsp cayenne pepper", "1 jalapeño pepper, minced (optional)", "1 box Jiffy cornbread mix", "1 15oz can whole kernel corn", "1 15oz can creamed corn", "2 eggs, lightly beaten", "½ cup sour cream", "½ cup butter, melted", "4 tbsp freshly grated Parmesan cheese", "¾ cup Panko", "3 tbsp butter, melted", "**Preheat the oven to 375°**"], "instructions": "Spray a medium casserole dish with cooking spray( I prefer butter cooking spray)and set aside.\nIn a medium pan over medium high heat, sauté the onion in the olive oil until translucent. Add the garlic and salt and cook for about 30 seconds or until the garlic is fragrant.\nAdd 1 tbsp of parsley, the cayenne, whole kernel corn and jalapeño if using. Remove from heat.\nIn a large mixing bowl add the cornbread mix, corn mixture, creamed corn, eggs, sour cream and ½ cup melted butter. Mix well to combine. Pour into the prepared casserole dish.\nSprinkle the parmesan cheese over the top, sprinkle the remaining tbsp of minced parsley and add a little more cayenne to taste.\nBake for 25 minutes.\nWhile the casserole is baking, mix the panko and 3 tbsp of melted butter.\nRemove the casserole to add the panko over the top and return to the oven for another 25 minutes. Cover the top if the panko appears to be browning too fast.\nRemove and serve!", "image": "img/old-fashioned-corn-casserole-serves-6-8.jpg"}, {"slug": "old-fashioned-pancakes-serves-12", "title": "Old Fashioned Pancakes", "serves": "Serves 12", "category": "Breakfast", "date": "2022-02-27", "ingredients": ["2 ½ cups all purpose flour", "2 tbsp baking powder", "2 tsp salt", "1 ½ tbsp granulated sugar", "2 cup milk", "2 eggs, beaten", "1/3 cup butter, melted"], "instructions": "In a large bowl, sift together the flour, baking soda, salt and sugar. Make a well in the center and pour the milk, egg and melted butter; mix until smooth.\nHeat a lightly oiled griddle over medium high heat. Pour or ladle the batter onto the griddle, using approximately ¼ cup for each pancake. Brown on both sides and serve hot with warm Maple syrup.", "image": "img/old-fashioned-pancakes-serves-12.jpg"}, {"slug": "orecchiette-sausage-and-arugula-serves-3", "title": "Orecchiette, Sausage and Arugula", "serves": "Serves 3", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["3 Tbsp Extra Virgin Olive Oil", "1 medium onion diced", "salt to taste", "½ lb sweet sausage with basil, casings removed", "2 cloves of garlic, minced", "2 tsps of dry oregano", "4 cups of chicken broth (more if adding more pasta)", "1 ½ cups of orecchiette pasta, add more if you wish", "1 cup of chopped arugula, you may add more", "grated parmesan cheese"], "instructions": "Heat the olive oil in a large skillet over medium heat. Cook the onion and garlic with a pinch of salt stirring until the onion is translucent, 4-5 minutes. Add the sausage and oregano and stir until the sausage is cooked, about another 5 minutes. Add\nAdd 2 cups of the chicken broth and bring to a boil, stirring frequently to loosen onion and sausage from the bottom of the pan. Add the pasta, (keeping in mind that if you add more pasta you will need to add more chicken broth). When the broth has been just about absorbed by the pasta add the remaining broth. Cook until the pasta is cooked through and most of the broth has been absorbed. About 15 minutes.\nStir in the arugula and toss until it wilts.\nServe with grated parmesan cheese.", "image": "img/orecchiette-sausage-and-arugula-serves-3.jpg"}, {"slug": "orzo-pasta-salad-serves-8-10", "title": "Orzo Pasta Salad", "serves": "Serves 8-10", "category": "Pasta, Rice & Beans", "date": "2022-04-03", "ingredients": ["Salad", "2 cups whole wheat orzo", "1 pint cherry tomatoes, halved", "1 pint yellow cherry tomatoes, halved", "2 mini seedless cucumbers, chopped", "1 cup halved black olives", "¼ cup finely diced red onion", "2 ears sweet corn, kernels cut from cob", "½ cup crumbled goat cheese", "4 tbsp chopped dry packed sundried tomatoes", "3 tbsp chopped flat parsley", "Dressing", "¼ cup extra virgin olive oil", "3 tbsp fresh lemon juice", "1 tbsp honey", "½ tsp salt", "¼ tsp fresh ground black pepper"], "instructions": "Cook the orzo according to the package directions. Drain and rinse under cold water until no longer warm.\nAdd all the salad ingredients, including pasta to a large salad bowl and toss to combine.\nIn a small mixing bowl, add all the dressing ingredients and whisk until well blended.\nAdd the dressing to the salad and toss to combine. Refrigerate to chill, until ready to serve.", "image": "https://static.wixstatic.com/media/75d545_9020c786c6964fc6b999766812ecf816~mv2.jpeg"}, {"slug": "orzo-risotto-with-buttery-shrimp-serves-4", "title": "Orzo Risotto with Buttery Shrimp", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["6oz of fresh asparagus tips", "1/2 lb medium shrimp, shelled and deveined", "salt and pepper", "3oz butter", "12oz orzo", "1 cup chicken broth", "½ cup grated Parmesan cheese", "2 tbsp chopped fresh parsley"], "instructions": "Bring 2 quarts of water to a boil. When the water begins to boil add 1 tbsp salt and stir until dissolved. Cook the asparagus until tender(4 minutes). Remove from the water and set aside.\nAdd the orzo to the same water and cook until al dente (9 minutes). Reserve ¼ cup of the pasta water before draining.\nMeanwhile melt 6 tbsp of butter in a large skillet. Let the butter brown and then add the shrimp; lightly salt and pepper the shrimp. Cook for 1 minute on each side. Remove the cooked shrimp to the same dish as the asparagus.\nAdd the chicken broth to the skillet to deglaze. Add the ¼ cup of reserved pasta water. Add the orzo and cook over medium heat until the liquid thickens.\nAdd the asparagus and the shrimp and heat through. Remove from the heat and add the chopped parsley and the grated Parmesan cheese.\nSalt and pepper to taste and serve.", "image": "https://static.wixstatic.com/media/75d545_ce7e438646ae464d96f81f3ba2554feb~mv2.jpeg"}, {"slug": "orzo-taco-casserole-serves-6-8", "title": "Orzo Taco Casserole", "serves": "Serves 6-8", "category": "Casserole", "date": "2023-01-10", "ingredients": ["1lb lean ground beef", "1 small onion, diced", "3 cloves garlic, minced", "1 red bell pepper, diced", "2 cups dry orzo", "1 15oz can whole kernel corn, drained", "1 15oz can black beans, rinsed", "1 10oz can of Rotel tomatoes with green chiles", "3 cups chicken low sodium broth", "½ tsp salt", "¼ tsp ground pepper", "1 Taco seasoning packet", "1 tbsp Sriracha", "2 cups shredded cheese (I used 4 cheese Mexican)", "Green onions, chopped"], "instructions": "In a large skillet, over medium high heat, brown the ground beef until no longer pink and breaking it up as it cooks into small pieces.\nAdd the onion, garlic and red bell pepper, and cook until the pepper is tender.\nTurn the heat to low and add the orzo. Stir to combine. Stir in the taco seasoning, Rotel tomatoes, and chicken broth.\nAdd the corn and black beans. Season with salt, pepper and Sriracha. Cook uncovered for 10 to 12 minutes or until the liquid is absorbed and the orzo is tender; Stirring occasionally.\nAdd the cheese and stir to combine. Garnish with green onions before serving.\nServe with chopped fresh tomatoes, sliced black olives, sour cream, and cilantro.\nBiscuits or cornbread go well with this recipe.", "image": "img/orzo-taco-casserole-serves-6-8.jpg"}, {"slug": "oven-baked-baby-back-ribs-serves-6", "title": "Oven Baked Baby Back Ribs", "serves": "Serves 6", "category": "Pork", "date": "2023-06-26", "ingredients": ["3 3lb packages of baby back ribs", "McCormick Montreal Steak Seasoning", "**Preheat oven to 300°**"], "instructions": "Remove the thin membrane covering the back of the ribs, by gently sliding a sharp knife under the membrane, and with your fingers, lift and pull it away from the bones.\nPlace a long piece of foil on the counter and lay the ribs on top. Season all over with the seasoning and seal the foil over the ribs.\nPlace the foil wrapped ribs on a baking sheet in a single layer and bake for 3-4 hours.\nRemove from the oven and either serve with barbecue sauce on the side or baste the ribs and bake for another 3 to 4 minutes under the broiler.", "image": "https://static.wixstatic.com/media/75d545_f3264cea912149f3a1b275cfb2bd7c5b~mv2.png"}, {"slug": "oven-roasted-clams-serves-4", "title": "Oven Roasted Clams", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["4 dozen littleneck clams, rinsed", "4 tbsp butter", "2 tbsp extra virgin olive oil", "½ cup white wine", "3 cloves garlic, minced", "2 tbsp fresh parsley, minced", "1 tsp fresh oregano, minced", "lemon wedges", "**Preheat the oven to 350°**"], "instructions": "Place the clams in a large baking dish and bake for 10-15 minutes or until all the clams have opened**. Check often**.\nRemove the open clams to a warm serving dish with a pair of tongs, being careful to keep juices in the clam and keep warm with a tented piece of foil.\nWhile the clams are cooking melt the butter in a small saucepan and add the olive oil, garlic, wine, parsley and oregano. Simmer while waiting for the clams.\nWhen all the clams have been moved the serving dish spoon the herbed butter over the clams and serve with lemon wedges.", "image": "img/oven-roasted-clams-serves-4.jpg"}, {"slug": "overnight-cinnamon-baked-french-toast-casserole-serves-10-12", "title": "Overnight Cinnamon Baked French Toast Casserole", "serves": "Serves 10-12", "category": "", "date": "2022-02-27", "ingredients": ["1 loaf Sourdough Or French Bread, cut into chunks", "8 whole eggs", "2 cups whole milk", "1/2 cup heavy whipping cream", "3/4 cups Sugar", "2 Tablespoons Vanilla Extract", "TOPPING", "3/4 cup flour", "3/4 cup firmly packed brown sugar", "3 teaspoons cinnamon", "1/2 teaspoon salt", "1 1/2 stick butter, cut in pieces"], "instructions": "Grease a 9 x 13 casserole dish with butter and scatter the bread in the bottom of the dish.\nWhisk together eggs, milk, cream, sugar and vanilla. Pour over the bread.\nCover and store in refrigerator overnight.\nIn another bowl, mix 1/2 cup flour, 1/2 cup brown sugar, 1 tsp cinnamon and salt. Add butter and mix until crumbs form. Store the crumb mixture in the fridge overnight.\nIn the morning,\n**Preheat oven to 350º**\nSprinkle the crumb mixture over the casserole and bake for 50-60 minutes or until firm throughout.\nSprinkle a little powdered sugar and serve with Maple syrup.", "image": "img/overnight-cinnamon-baked-french-toast-casserole-serves-10-12.jpg"}, {"slug": "pan-seared-gnocchi-with-browned-butter-sage", "title": "Pan-Seared Gnocchi with Browned Butter & Sage", "serves": "", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1 package gnocchi", "3/4 tsp kosher salt", "3tbsp unsalted butter, cut into 3 pieces", "8 Tbs. unsalted butter, cut into 1-inch cubes (for sauce)", "18 large fresh sage leaves", "1 tsp. finely grated lemon zest", "Kosher salt", "Freshly ground black pepper"], "instructions": "Bring a large pot of well-salted water to a boil over high heat. Add the gnocchi and cook per package directions.\nMeanwhile, heat 1 Tbsp. of the butter in a 12-inch nonstick skillet over medium-high heat. When the butter is completely melted, use a large slotted spoon or a strainer to transfer the cooked gnocchi from the boiling water to the skillet, shaking off as much water as possible first.\nThe gnocchi should form a single layer in the skillet. (If the butter is melted before the gnocchi cook, take it off the heat; if the gnocchi cook before the butter is fully melted, it’s fine to add the gnocchi.)\nSprinkle with 1/4 tsp. salt and cook, shaking the pan occasionally to turn the gnocchi, until they’re lightly browned, about 2 minutes. Transfer to a large plate.\nWipe the skillet, and put it over medium-high heat and add the butter. When the butter has almost completely melted, stir in the sage leaves. Cook, stirring occasionally, until the butter turns a light brown color (be careful not to let it burn) and the sage leaves darken and crisp up slightly, 2 to 3 minutes. Remove from the heat.\nAdd the reserved gnocchi and the lemon zest to the pan and toss to coat well. Season to taste with salt and pepper. Serve immediately.", "image": "img/pan-seared-gnocchi-with-browned-butter-sage.jpg"}, {"slug": "pancakes-makes-18-4-pancakes", "title": "Pancakes", "serves": "Makes 18 4” pancakes", "category": "Breakfast", "date": "2022-02-27", "ingredients": ["2 eggs", "2 cup flour", "2 ¼ cup milk", "¼ cup vegetable oil", "2tbsp melted butter", "1 ½ tbsp. baking powder", "1tsp salt"], "instructions": "Beat the eggs with a wire whisk until fluffy; beat in the remaining ingredients until well blended.\nLadle onto a greased griddle and cook over medium heat until golden on both sides. About 1 minute each side.\nServe with butter and warm maple syrup.", "image": "img/pancakes-makes-18-4-pancakes.jpg"}, {"slug": "panera-copycat-broth-bowl-serves-2", "title": "Panera Copycat Broth Bowl", "serves": "Serves 2", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["½ tbsp. vegetable oil", "½ Vidalia onion, diced small", "1 clove garlic, minced", "1 cup cooked lentils", "¼ cup uncooked Quinoa", "¼ cup julienne sundried tomatoes", "3 cups chicken broth", "1 cup fresh baby spinach", "1 cup chopped fresh kale", "1 bay leaf", "¼ tsp sweet paprika", "½ tbsp. Miso paste", "1 tbsp water", "Dash of Cayenne", "Salt and pepper to taste", "8oz cooked shredded chicken"], "instructions": "Dissolve the miso paste in the water and set aside.\nHeat the oil in a large saucepan over medium heat and add the onion and garlic. Cook until the onions are translucent.\nAdd the broth, quinoa, lentils, tomatoes, bay leaf, seasonings and the miso. Stir to combine.\nBring the mixture to a boil and then reduce the heat to low. Cover and simmer for 10 minutes or until the quinoa is cooked.\nJust before you are ready to serve, stir in the spinach and the kale and allow them to wilt in the broth.\nPlace in serving bowls and top with the chicken.", "image": "img/panera-copycat-broth-bowl-serves-2.jpg"}, {"slug": "panko-crusted-asparagus", "title": "Panko Crusted Asparagus", "serves": "", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["1lb asparagus, trimmed", "1 ½ cup Panko", "¾ cup freshly grated Parmesan", "½ cup flour", "3 eggs, beaten", "salt and pepper to taste", "olive oil cooking spray", "**Preheat the oven to 425°**"], "instructions": "Lightly spray a baking sheet with the olive oil.\nPlace the flour in a Ziploc bag and set aside.\nIn another Ziploc bag, combine the Panko, parmesan, salt and pepper.\nBeat the eggs in a rectangular shallow dish.\nPlace the asparagus, in small batches into the bag with the flour and shake until the asparagus is coated.\nRemove from the bag and place in the egg. Evenly coat with the egg and then add to the bag with the panko and parmesan. Shake until well coated with the mixture.\nPlace the asparagus on the prepared baking sheet.\nBake for 10 minutes, or until golden.", "image": "img/panko-crusted-asparagus.jpg"}, {"slug": "panko-crusted-salmon-ii-serves-4", "title": "Panko Crusted Salmon II", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-27", "ingredients": ["2/3 cup Panko", "2 tbsp finely chopped parsley", "1 ½ tsp grated lemon zest", "½ tsp Kosher salt", "½ tsp black pepper", "2 tbsp extra virgin olive oil", "1 ½ lb salmon filet, skinned", "salt & pepper, to taste", "2 tbsp Dijon mustard", "butter cooking spray", "1 Lemon, cut into wedges", "**Preheat the oven to 350°**"], "instructions": "In a small bowl combine the first 5 ingredients and mix well. Add the olive oil and blend with a fork until the panko is evenly coated.\nLightly coat a cookie sheet or baking pan with the cooking spray. Place the salmon on the pan and generously brush the mustard on the top. Sprinkle with salt and pepper.\nPress the panko mixture on top of the salmon.\nBake uncovered for 20-30 minutes, or until the fish flakes with a fork. Check halfway through to make sure the panko is not browning too quickly. If it is, loosely place a piece of foil over the top.\nServe with the lemon wedges.", "image": "img/panko-crusted-salmon-ii-serves-4.jpg"}, {"slug": "panko-crusted-salmon-serves-4", "title": "Panko Crusted Salmon", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["4 (6oz) salmon filets, skin removed", "salt and pepper to taste", "2 tbsp honey mustard", "2 tsp fresh thyme leaves", "2/3 cup panko", "4 tsp extra virgin olive oil", "2 tbsp chopped Italian parsley (flat leaf)", "½ tsp paprika", "**Preheat the oven to 400°**"], "instructions": "Lightly spray a foil lined cookie sheet or a foil baking sheet with cooking spray and place the salmon on the sheet. Sprinkle with salt and pepper.\nIn a small bowl combine the mustard and 1 tsp of thyme. In another small bowl mix the panko with the remaining thyme, olive oil, parsley and paprika. Add a little salt and pepper.\nSpread the mustard mixture on the salmon and top with the panko mixture.\nBake for 12-15 minutes or until the fish flakes.", "image": "img/panko-crusted-salmon-serves-4.jpg"}, {"slug": "panko-shrimp-with-aioli-serves-4", "title": "Panko Shrimp with Aioli", "serves": "Serves 4", "category": "Main Dish", "date": "2022-03-03", "ingredients": ["2 cups Panko", "2 tbsp extra virgin olive oil", "1 tsp garlic powder", "Kosher salt & fresh ground pepper", "2 large eggs", "1 lb uncooked jumbo shrimp, peeled and deveined", "1 cup flour", "2 tbsp light mayonnaise", "2 tbsp sweet chili sauce", "1 tbsp sriracha sauce", "1 lime, juiced", "1 tsp honey", "Chopped fresh parsley"], "instructions": "**Preheat oven to 400º**\nPlace a piece of parchment on a baking sheet and set aside.\nIn a small bowl, mix the olive oil, panko, and garlic powder. Season with salt and pepper, to taste.\nIn a medium bowl, whisk the eggs. Place the flour in a pie plate and with a fork or tongs, dredge the shrimp (one at a time) in the flour, dip in the egg and then dredge through to panko until coated.\nPlace the shrimp on the parchment paper and bake for 12-15 minutes or until the panko is golden brown.\nWhile the shrimp are baking, make the sauce by whisking the mayonnaise, chili sauce, sriracha, lime juice and honey in a small bowl. Season with salt and pepper to taste.\nDrizzle the sauce over the shrimp and garnish with the parsley.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "parmesan-and-lemon-crusted-flounder-serves-4", "title": "Parmesan and Lemon Crusted Flounder", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-27", "ingredients": ["Butter Cooking Spray", "1 ½ cups Panko", "2 lemons, zested and juiced", "½ cup freshly grated Parmesan cheese", "2 tbsp extra virgin olive oil", "4 cloves garlic, minced", "2 eggs", "4 large flounder filets", "**Preheat the oven to 375°**"], "instructions": "Coat a baking sheet with the cooking spray and set aside.\nIn a large pie plate mix together the panko, lemon zest, grated Parmesan, olive oil and garlic.\nIn another large pie plate whisk the eggs. Take each flounder filet and dip in the eggs, coating both sides. Press each filet into the Panko mixture coating completely on both sides. Place on the baking sheet.\nSprinkle remaining Panko mixture over the filets and drizzle with 2-4 tbsp of lemon juice. (to taste)\nLightly spray the top of the fish with the cooking spray and bake for 20-25 minutes.", "image": "img/parmesan-and-lemon-crusted-flounder-serves-4.jpg"}, {"slug": "parmesan-asparagus-serves-6", "title": "Parmesan Asparagus", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["30 medium fresh asparagus spears, trimmed", "2 tbsp extra virgin olive oil", "3 tbsp freshly grated Parmesan cheese", "½ tsp garlic salt", "**Preheat the oven to 400°**"], "instructions": "Brush the asparagus spears wit the oil; place on a baking sheet coated with olive oil cooking spray.\nBake uncovered for 6 minutes, turn the asparagus. Bake for an additional 6 minutes or until the asparagus is tender.\nCombine the Parmesan and garlic salt in a small bowl and sprinkle over the asparagus.", "image": "img/parmesan-asparagus-serves-6.jpg"}, {"slug": "parmesan-brussel-sprouts-serves-2", "title": "Parmesan Brussel Sprouts", "serves": "Serves 2", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["6 Brussel sprouts, trimmed and halved", "3 tbsp butter, divided", "2 cloves garlic, chopped", "2 tbsp fresh grated Parmesan cheese, or more to taste", "salt and pepper to taste"], "instructions": "Heat a medium frying pan over medium high heat until hot (about 3 minutes). Melt 1 tbsp of butter and cook the garlic until fragrant, 30 seconds.\nAdd 1 tbsp butter more and the Brussel sprouts, cut side down. Cover and cook until golden brown, 4-6 minutes.\nFlip the sprouts and add 1 more tbsp. of butter. Cover and cook until the other side is browned.\nTransfer to a serving plate and sprinkle with the cheese, salt and pepper.", "image": "img/parmesan-brussel-sprouts-serves-2.jpg"}, {"slug": "parmesan-roasted-acorn-squash-serves-4", "title": "Parmesan Roasted Acorn Squash", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["2 acorn squash, halved and seeded", "3 -4 tbsp extra virgin olive oil", "4 tsp fresh thyme", "½ tsp kosher salt, or to taste", "¼ tsp freshly ground black pepper, or to taste", "¼ -1/2 cup freshly grated parmesan cheese", "**Preheat the oven to 400°**"], "instructions": "Slice the squash into ¾\" slices and place in a large bowl. Drizzle with the olive oil and toss to coat evenly. Add the thyme, salt and pepper and toss.\nPlace on a jelly roll pan or foil cookie sheet. Sprinkle with the parmesan cheese and roast for 25-30 minutes.,", "image": "https://static.wixstatic.com/media/75d545_ae1c063850424fec8bbd924d204602dd~mv2.jpg"}, {"slug": "pasta-fagioli-serves-8-10", "title": "Pasta Fagioli", "serves": "Serves 8-10", "category": "", "date": "2024-01-30", "ingredients": ["1lb ground sweet Italian sausage", "2 Tbsp Extra Virgin Olive Oil", "1 ½ cup shredded carrots", "1 medium Vidalia onion, diced small", "4 stalks celery, diced small", "6 cloves of garlic, minced", "17oz Pomi tomato sauce", "28 oz can petite diced tomatoes, undrained", "2 32oz chicken broth", "4 Tbsp lightly dried parsley (Gourmet Garden)", "1 Tbsp lightly dried basil(Gourmet Garden)", "½ tsp red pepper flakes", "Salt and Pepper, to taste", "16oz ditalini pasta or orecchiette", "2 15oz cans of cannellini beans", "5oz baby spinach", "Grated parmesan, for garnish"], "instructions": "Cook sausage over medium heat in a large saucepan until no longer pink, breaking into small pieces as it cooks. Drain and set aside.\nIn the same pan used for the sausage, heat the olive oil and stir in the carrots, garlic, celery and onion and cook until tender. About 5 minutes.\nPlace the vegetable mixture in a large stock pot and add the tomato sauce, diced tomatoes, ditalini, chicken broth, parsley, basil, red pepper flakes, and black pepper. Reduce the heat and simmer for 20 minutes.\nAdd the beans, spinach, and sausage to the soup and simmer for another couple of minutes or until the spinach has wilted and the beans are heated through.\nServe garnished with Parmesan cheese, and with your favorite warm bread!", "image": "https://static.wixstatic.com/media/75d545_70390e999d4d47f5b96800975a75cc67~mv2.jpeg"}, {"slug": "pasta-ground-turkey-bake-serves-8-10", "title": "Pasta, Ground Turkey Bake", "serves": "Serves 8-10", "category": "Casserole", "date": "2022-03-22", "ingredients": ["16 oz medium shell pasta", "20 oz lean ground turkey", "4 tbsp extra virgin olive oil", "1 tbsp fresh minced garlic", "1 large red bell pepper, diced", "8 oz sliced white mushrooms, optional", "½ large Vidalia onion, diced", "1 tsp salt", "½ tsp pepper", "1 tbsp dried Italian seasoning", "1 14 oz can petite diced tomatoes, undrained", "4 tbsp flour", "4 cups beef broth", "1 15 oz can tomato sauce", "1 cup heavy cream", "Crushed red pepper, to taste", "1 cup freshly grated parmesan cheese", "**Preheat oven to 350º**"], "instructions": "Cook the pasta according to the package directions for al dente.\nWhile the pasta cooks heat 2 tbsp olive oil in a shallow oven safe saucepot and cook the turkey. Be sure to break the turkey up into small pieces as it browns. Once the turkey is cooked through, season with salt and pepper to taste and remove to a bowl.\nDrain the pot of any excess liquids from cooking the turkey and add the remaining olive oil.\nOver medium high heat, cook the garlic, red pepper, mushrooms, and onions until the onions are translucent. Add the tomatoes, crushed red pepper, salt, pepper and Italian seasoning. Stir well to combine.\nSprinkle the flour over vegetable mixture and stir to blend. Add the beef broth and tomato sauce.\nAdd the turkey back to the pot and stir in the pasta shells.\nAdd the heavy cream and ½ the parmesan cheese. Heat through.\nSprinkle the remaining parmesan and bake for 20 minutes.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "pasta-pilaf", "title": "Pasta Pilaf", "serves": "", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["2 tbsp butter", "1 large onion, finely chopped", "2 clove garlic, minced", "2 medium tomatoes, peeled, seeded and chopped", "1 tsp dry basil", "¼ cup water", "1 cup dry orzo", "1 cup frozen peas", "½ cup heavy cream", "¾ cup grated parmesan cheese", "salt and pepper to taste"], "instructions": "Melt the butter I a large frying pan over medium heat and add the onion and garlic. Stir frequently and cook until the onion is tender but not brown.\nAdd the tomatoes, basil and ¼ cup of water; reduce the heat and simmer for 10 minutes.\nMeanwhile in a 4 quart saucepan cook the orzo until tender (about 10 minutes). Drain.\nAdd the peas and cream to the tomato mixture and increase the heat to high bringing the mixture to a boil. Stir in the orzo.\nRemove from the heat and stir in ½ cup of the parmesan cheese. Season with the salt and pepper to taste.\nServe with the remaining cheese on top.", "image": "img/pasta-pilaf.jpg"}, {"slug": "pastry-for-single-pie-crust", "title": "Pastry for Single Pie Crust", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["1 ½ cup flour", "½ tsp salt", "1/3 cup shortening", "4 tbsp cold water, more if needed"], "instructions": "In a medium bowl combine the flour, and salt; cut in the shortening until crumbly.\nGradually add in the water tossing with a fork until the dough forms a ball.\nRoll out with a rolling pin to fit a 9\" or 10\" pie plate.\nTransfer the pastry to the pie plate.\nFill or bake the shell according to your recipe directions.", "image": "img/pastry-for-single-pie-crust.jpg"}, {"slug": "pearl-couscous-and-arugula-salad-serves-6-8", "title": "Pearl Couscous and Arugula Salad", "serves": "Serves 6-8", "category": "Salads", "date": "2023-03-13", "ingredients": ["1 cup dry couscous", "1/2 cup apple cider", "1 cup water", "1 tsp kosher salt", "2 bay leaves", "1 lemon, juiced", "½ cup extra virgin olive oil", "½ cup shaved parmesan cheese", "½ cup shelled pistachio nuts", "5 oz baby arugula, roughly chopped", "½ cup of roughly chopped fresh basil leaves", "1 ½ cup halved cherry tomatoes", "½ cup thinly sliced radishes", "Flaky sea salt"], "instructions": "Bring the water and apple cider to a boil, in a small sauce pot and add the salt, bay leaves and couscous. Cover, reduce the heat to a simmer for 8-10 minutes, stirring occasionally until the liquid has been absorbed. Fluff with a fork and discard the bay leaves.\nIn a large bowl, whisk the lemon juice and olive oil together.\nAdd the couscous to the lemon and olive oil and toss to coat.\nAdd the arugula leaves, basil, tomatoes, radishes, cheese and nuts. Season with the flaky salt to taste and serve.", "image": "https://static.wixstatic.com/media/75d545_a718ed222a6b4c9481697871bad150ba~mv2.jpeg"}, {"slug": "pecan-crusted-chicken-serves-4", "title": "Pecan Crusted Chicken", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["4 chicken*cutlets", "2 tbsp butter", "Extra virgin olive oil", "2 oz chopped pecans", "½ cup panko", "2 tbsp Emeril’s Original Essence", "1 ½ tbsp honey", "4 tbsp light mayonnaise", "4 tsp Dijon mustard", "Salt & pepper", "**Preheat oven to 450º**"], "instructions": "Spray a foil cookie sheet with cooking spray.\nIn a medium microwave safe bowl, melt the butter. Cool slightly.\nAdd the panko, pecans, and 1 tbsp of Essence to the butter and mix. Stir in a drizzle of oil and season with salt and pepper.\nIn a small bowl blend the mayonnaise and the Dijon mustard together with a whisk.\nPat the chicken dry. Place between 2 sheets of plastic wrap and pound to thinner cutlet, if they are extra thick.\nSeason each cutlet with the remaining Essence and salt & pepper.\nPlace on the prepared cookie sheet. With a pastry brush, evenly spread a thin layer of the mustard mixture over the tops of the cutlets. Mound the pecan mixture on top of the mustard layer.\nBake the cutlets for 15-20 minutes depending on the size of your cutlets. * I buy 2 large breasts ( no skin or bone ), cut them in half and pound to half the thickness.", "image": "img/pecan-crusted-chicken-serves-4.jpg"}, {"slug": "pecan-crusted-flounder-serves-4", "title": "Pecan Crusted Flounder", "serves": "Serves 4", "category": "Seafood", "date": "2022-02-27", "ingredients": ["4 flounder filets", "2 eggs", "1 tbsp soy sauce", "1/2 tsp seasoned salt", "½ tsp garlic powder", "1 ½ tsp lemon pepper", "½ tsp paprika", "1½ cup pecans, chopped into “rough” meal in a food chopper", "**Preheat the oven to 400°**"], "instructions": "In a medium bowl, whisk the eggs. And put the pecan meal in a shallow dish.\nDredge each piece of fish in the egg and then in the meal. Place on a foil baking dish. After all the fish is on the baking sheet, sprinkle the remaining nut mixture over the fish and press down.\nBake for 15-20 minutes or until the fish flakes. Remove from the oven and serve.", "image": "img/pecan-crusted-flounder-serves-4.jpg"}, {"slug": "pecan-pie", "title": "Pecan Pie", "serves": "", "category": "Desserts", "date": "2022-03-01", "ingredients": ["9” pie crust (your favorite recipe or store bought)", "1 cup sugar", "3 tbsp brown sugar", "½ tsp salt", "1 cup light corn syrup", "1/3 cup melted butter", "1 tsp vanilla", "3 whole eggs", "1 heaping cup chopped pecans", "Preheat oven to 350º"], "instructions": "Make your pie crust if not store bought. Do not bake.\nIn a large bowl, combine the sugar, brown sugar, salt, corn syrup, butter and vanilla.\nIn a separate bowl, beat the eggs until frothy and very light in color, with an electric mixer. Add to the sugar mixture and stir to combine.\nPlace the pecans in the bottom of the pie crust and top with the egg batter.\nLightly cover the top of the pie and the crust with foil and bake for 30 minutes. Remove the foil and bake for another 20 minutes or until just set. It should jiggle just a little in the center. If it needs longer to bake than suggested you should cover the center again.\nWatch your crust, you may need to cover it again with the foil so it doesn’t get too dark.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "penne-alla-vodka-serves-4", "title": "Penne Alla Vodka", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1 small onion, finely chopped", "1 can (28 oz.) crushed tomatoes", "1 tbsp. olive oil", "1 tbsp. butter", "1 cup heavy cream", "¼ cup vodka", "Salt and pepper to taste", "1/8 tsp. crushed red pepper flakes (optional)", "1 lb. penne"], "instructions": "Melt butter in saucepan and add olive oil. Add the onion and sauté for about 5 minutes until the onion is translucent. Add the tomatoes to the onion mixture. Cook tomatoes for about 25 minutes; add heavy cream and vodka. Cook for an additional 5 minutes. Add salt, pepper, and red pepper if desired.\nSauce can be refrigerated and used next day. Can also be frozen.\nBring water to boil in large pot. When water is boiling, add 1/8 teaspoon of salt and 1 lb penne. Cook until al dente. Pour sauce over pasta; add Parmigiano cheese and serve.\nVariations:\nFor lighter sauce, you can substitute heavy cream with light cream. When doubling recipe or making for crowd, use half light cream, half heavy cream.\nFor one dish meal add to sauce last ten minutes: (1) 15 oz. can peas, drained\n¼ lb. of sliced pancetta (cut into small pieces with scissor)", "image": "img/penne-alla-vodka-serves-4.jpg"}, {"slug": "penne-sausage-kale-in-light-cream-sauce-serves-5", "title": "Penne, Sausage & Kale in Light Cream Sauce", "serves": "Serves 5", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1 14 oz package Penne pasta", "Extra virgin olive oil spray", "1 lb Premio ground italian sausage", "1 package Julienne cut sun dried tomatoes", "3 cloves of garlic, minced", "1/3 cup Pinot Grigio", "½ cup chicken broth", "1 5oz plastic container of baby kale, chopped(4 cups)", "4 tsp salt and pepper", "2 tbsp butter", "3 tbsp flour", "1 ¾ cup whole milk", "1/3 cup heavy cream", "½ cup freshly grated Parmesan cheese"], "instructions": "Cook the pasta according to the package directions. Keep ½ cup of the pasta water before draining (use to smooth the sauce only if needed). Transfer to a large bowl and set aside.\nSpray a large skillet with a few sprays of the olive oil, cook for minute or 2 over medium high heat and then add the sausage. Break the sausage into small pieces and cook through.\nAdd the sun dried tomatoes and the garlic, sauté for another minute.\nRemove from the heat and add the Pinot Grigio, scraping all the bits from the bottom of the pan.\nReturn the pan to the heat; add the chicken broth and kale. Cook and toss until the kale is wilted, about 5 minutes.\nSeason with salt and pepper to taste. Remove with a slotted spoon to the large bowl with the pasta and cover to keep warm.\nIn the same skillet add the flour and the butter and whisk together. Add the\nWhole milk slowly and whisk vigorously to blend with the flour mixture and remove any lumps.\nAdd the cream and the Parmesan to finish the sauce. Pour the sauce over the pasta, sausage and kale and toss.\nServe with additional Parmesan cheese.", "image": "https://static.wixstatic.com/media/75d545_841adae1781441dab02e1e1e97b6cb75~mv2.jpg"}, {"slug": "pepperoni-stuffed-mushrooms-makes-24", "title": "Pepperoni Stuffed Mushrooms", "serves": "Makes 24", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["24 large mushrooms, 1.5” to 2” in diameter", "¼ cup finely diced onion", "2tbsp finely diced red or green pepper", "1 clove garlic, minced", "¼ tsp dried oregano", "¼ tsp dried basil", "2 tbsp butter", "1/3 cup finely diced pepperoni", "2 tbsp bread crumbs"], "instructions": "Preheat the oven to 425°.\nWash the mushrooms and drain on a paper towel. Remove the stems and set the caps aside. Chop enough of the stems to make 2 cups.\nCook the stems, onion, pepper, garlic, oregano and basil in butter for 4-5 minutes or until tender, stirring frequently. Remove from the heat and stir in the pepperoni and breadcrumbs.\nSpoon about 1 tbsp of the mixture into each mushroom cap, pressing lightly into the cap.\nArrange the mushrooms on a baking sheet and bake uncovered for 8-10 minutes or until heated through.", "image": "img/pepperoni-stuffed-mushrooms-makes-24.jpg"}, {"slug": "perfect-burgers-serves-4", "title": "Perfect Burgers", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-27", "ingredients": ["1lb lean ground beef", "1 egg", "1 tsp of your favorite mustard", "1 tsp Worcestershire sauce", "½ cup of finely chopped onion", "1 clove garlic, minced", "½ tsp salt", "½ tsp pepper", "1 tbsp barbecue sauce", "2 tsp Cajun seasoning"], "instructions": "Mix all the the ingredients together and grill. Top with your favorite cheese.", "image": "img/perfect-burgers-serves-4.jpg"}, {"slug": "perfect-filet-mignon", "title": "Perfect Filet Mignon", "serves": "", "category": "Main Dish", "date": "2022-02-25", "ingredients": ["A petite filet of beef is typically between 4 and 6 oz. of steak cut from the center of the tenderloin. Many people consider it to be the most tender cut of steak, and the petite portion makes it a more waistline-friendly red meat option. To get the best out of this rather expensive cut, make sure you are seasoning and cooking the meat properly, as undercooked beef can be a health hazard and overcooked beef can be dry and tasteless.", "**Preheat your oven to 350 degrees F.**", "3 tbsp. olive oil", "McCormick Grill Mates Montreal Steak", "2 tbsp Vegetable oil"], "instructions": "Season beef on both sides with seasoning.\nHeat the oil in a heavy skillet over medium high heat.\nPlace filet in pan to sear, each side will take three to four minutes. Use your tongs to turn the steaks.\nTransfer the steaks a baking dish and bake in the oven to desired temperature, turning them halfway through. Check temperature with a meat thermometer. Cook to 145 degrees for medium rare and to 160 degrees for medium, according to the USDA.\nRemove steaks from oven. Wrap them in foil and let them rest for five minutes. This allows the beef to absorb all of its own juices before being cut.", "image": "img/perfect-filet-mignon.jpg"}, {"slug": "pesto-tomato-crostini-serves-12", "title": "Pesto Tomato Crostini", "serves": "Serves 12", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["12 slices of French bread (1/4\" thick)", "2/3 cup Pesto", "2 Roma tomatoes, seeded and chopped", "1 cup shredded mozzarella cheese", "**Preheat the oven to 375°**"], "instructions": "Place the slices of bread on an ungreased foil baking sheet.\nSpread each slice with a tablespoon of pesto and top with tomatoes.\nSprinkle each crostini with cheese and bake for about 8 minutes or until the cheese has melted.", "image": "img/pesto-tomato-crostini-serves-12.jpg"}, {"slug": "picnic-baked-beans-serves-a-crowd", "title": "Picnic Baked Beans Serves a Crowd", "serves": "", "category": "Side Dishes", "date": "2022-02-27", "ingredients": ["2 (31oz) cans baked beans", "1 onion, sliced thin", "½ cup maple syrup", "3 tbsp mustard", "½ cup brown sugar", "2 ½ cup ketchup", "1lb bacon, cut into 1\" strips", "**Preheat the oven to 325°**"], "instructions": "Mix the first 6 ingredients together and place in a large casserole dish. Top with extra syrup and the bacon strips to cover.\nBake for 4 ½ hours.", "image": "img/picnic-baked-beans-serves-a-crowd.jpg"}, {"slug": "pineapple-carrot-cake", "title": "Pineapple Carrot Cake", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["**Cake:**", "2 cups flour", "½ tsp baking soda", "1 tsp baking powder", "1 tsp salt", "2 tsp cinnamon", "1 ¾ cup sugar", "1 cup vegetable oil", "3 eggs", "1 tsp vanilla extract", "2 cup grated carrots", "1 cup flaked coconut", "1 cup chopped walnuts", "1 8oz can crushed pineapple", "**Frosting:**", "2 8oz packages of cream cheese, softened", "½ cup butter, softened", "4c confectioner’s sugar", "½ tsp vanilla"], "instructions": "Preheat the oven to 350°.\nPeel and grate the carrots.\nSift the flour, baking soda, baking powder and salt together over a large bowl. Add the cinnamon.\nIn a small bowl beat the eggs and the sugar. Add to the flour mixture and blend well. Add the oil and the vanilla and beat for 1 minute.\nWith a wooden spoon add the carrots, coconut, pineapple and walnuts; mix well. Turn the batter into 2 buttered and floured cake pans. Bake for 45 minutes or until the cake is no longer moist in the center and it begins to pull away from the edges of the pan. Remove from the oven and cool.\nBeat the cream cheese and butter with ½ tsp vanilla extract. Gradually add in the confectioner’s sugar until the frosting is a spreadable consistency.\nFrost the cake while slightly warm.", "image": "img/pineapple-carrot-cake.jpg"}, {"slug": "pineapple-mango-salsa-serve-8", "title": "Pineapple Mango Salsa", "serves": "Serve 8", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["1 whole Pineapple, peeled and diced", "2 Champagne mangos, diced", "½ medium red onion, finely diced", "1 jalapeno, seeded and diced", "Fresh cilantro, to taste (optional)", "1 lime, Juiced", "dash of kosher salt", "sugar, to taste (optional)"], "instructions": "Combine the pineapple, mango, onion, and jalapeno. At this point if you choose to use the cilantro it too should be added.\nAdd the lime juice and salt. The sugar may be added also.\nServe with chips or as garnish with fish or chicken.", "image": "https://static.wixstatic.com/media/75d545_7a1ff14580404f8cac5df0663059bbe6~mv2.jpg"}, {"slug": "pizza-dip", "title": "Pizza Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["1 8oz package of cream cheese", "½ cup of good pizza sauce", "2 cloves of garlic, minced", "½ cup chopped pepperoni"], "instructions": "1 can(2 ½ oz) sliced ripe olives, drained. Add more if desired.\n1/3 cup finely diced red pepper\n5 medium green onions, thinly sliced\n½ cup finely shredded mozzarella cheese\n¼ cup shredded fresh basil leaves\ntortilla chips\nSet oven to broil.\nMix the cream cheese, pizza sauce and garlic. Spread a thin layer of the mixture over a 12” or 13” round oven proof serving dish, using all of it.\nTop with the pepperoni, olives, pepper, and onions. Sprinkle with the mozzarella cheese.\nBroil 4” from the element, for 1-2 minutes or until the cheese has melted. Garnish with the basil and serve with the tortilla chips.", "image": "img/pizza-dip.jpg"}, {"slug": "pot-roast-dinner-serves-6-7", "title": "Pot Roast Dinner", "serves": "Serves 6-7", "category": "Crockpot", "date": "2022-02-27", "ingredients": ["1 (3-3 1/2lb) beef rump roast", "½ tsp salt", "½ tsp seasoned salt", "¼ tsp pepper", "¼ tsp paprika", "1 celery stalk, chopped", "1 onion, cut into 8 wedges", "3 carrots, cut into 1\"", "4 potatoes, cut into 8ths", "1 cup beef broth", "¼ cup water", "3 tbsp cornstarch"], "instructions": "Trim visible fat from the meat.\nIn a small bowl combine the seasonings and rub all sides of the meat with the spice blend.\nPlace all the vegetables in the bottom of the crockpot. Pour the broth over the vegetables. Place the seasoned roast on top of the vegetables, cover and cook on low for 8-9 hours.\nRemove the meat and vegetables to a platter and keep warm.\nTurn the control to high. In a measuring cup, dissolve the cornstarch in the water and stir into the crockpot juices. Cover and cook on high for 15-20 minutes, or until slightly thickened.\nServe with the meat and vegetables.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "potato-gnocchi-recipe", "title": "Potato Gnocchi Recipe", "serves": "", "category": "Pasta, Rice & Beans", "date": "2022-02-27", "ingredients": ["2 lb. russet potatoes (about 4 medium), scrubbed"], "instructions": "6-3/4 oz. (1-1/2 cups) unbleached all-purpose flour, more for kneading and rolling\n1 tsp. kosher salt\n1 large egg, lightly beaten\nPut the unpeeled potatoes in a large pot. Fill the pot with enough cold water to cover the potatoes by at least 2 inches and bring to a simmer over medium-high heat. Reduce the heat to medium, partially cover the pot, and simmer the potatoes until they are completely tender and easily pierced with a skewer, 30 to 35 minutes.\nDrain the potatoes, let them cool just enough that you can handle them, and then peel them. Cut them in half crosswise and pass them through a ricer into a large bowl. Let cool until almost at room temperature, at least 20 minutes.\nLightly flour a work surface. In a small bowl, mix the flour with the salt. Add the egg to the potatoes and then add the flour mixture. Mix with your hands until the flour is moistened and the dough starts to clump together; the dough will still be a bit crumbly at this point. Gather the dough together and press it against the bottom of the bowl until you have a uniform mass. Transfer it to the floured surface and wash your hands.\nKnead gently until the flour is fully incorporated and the dough is soft, smooth, and a little sticky, 30 seconds to 1 minute. (Don’t overmix it, or the gnocchi will be tough; the dough should feel very delicate.) Move the dough to one side, making sure the surface underneath it is well floured. Cover it with a clean kitchen towel.\nCover two large rimmed baking sheets with parchment and sprinkle lightly with flour.\nRemove any lingering bits of dough from your work surface and lightly reflour the surface. Tear off a piece of dough about the size of a large lemon and put the towel back on the rest of the dough so it doesn’t dry out.\nWith a sharp knife or a bench knife, cut the rope crosswise every 3/4 inch to make roughly 3/4-inch-square gnocchi. Arrange the gnocchi in a single layer on the parchment-covered baking sheets, making sure they don’t touch. Repeat until you run out of dough, reflouring the work surface as needed. When all the gnocchi have been cut and spread out on the baking sheets, sprinkle them with a little more flour.\n**Make Ahead Tips**\nYou can serve freshly made gnocchi right away or within a couple of hours, or you can freeze them for later use. Put the gnocchi in the freezer while they’re still on the baking sheets and freeze until they are hard to the touch, at least one hour. Transfer them to a large zip-top bag or several smaller bags and freeze for up to two months. Cook frozen gnocchi in boiling water in two batches. Frozen gnocchi cause the temperature of the cooking water to drop, so they’ll fall apart before the water returns to a boil if there are too many in the pot. Don’t refrigerate fresh gnocchi for more than two or three hours, as they tend to ooze water and become soggy.\n**To save time, skip the fork:**Classic Italian homemade gnocchi are pressed on a fork to curl them and impart the traditional ridges. To save time, I just cut them in small squares and leave them as cute little pillows. I think they look prettier, and they’re a lot less fussy to make.", "image": "img/potato-gnocchi-recipe.jpg"}, {"slug": "potato-green-bean-casserole-serves-12", "title": "Potato Green Bean Casserole", "serves": "Serves 12", "category": "Casserole", "date": "2022-02-27", "ingredients": ["1 15.5oz can French Style green beans, drained", "1 15oz can sliced potatoes, drained", "1 10.75oz can cream of celery soup", "1 1/8 cup milk", "French Fried onions", "Salt and pepper to taste", "Garlic powder to taste", "1 12oz package stuffing mix", "**Preheat the oven to 350°**"], "instructions": "Mix the green beans and potatoes together in a 2qt casserole dish. Add the cream of celery soup and the milk. Season with salt, pepper and garlic powder to taste.\nStir in about a 3tbsp of the onions. Then sprinkle about a handful of the onions over the top.\nBake for 30 minutes. While the casserole is baking, prepare the stuffing mix according to the package directions. After the 30 minutes, spread the stuffing mix over the top of the casserole.\nReturn the casserole to the oven and bake for 10 minutes longer. In the last minute or 2 you can turn the oven to broil to make the stuffing a bit crunchy. Either way is ok.", "image": "https://static.wixstatic.com/media/75d545_f6821a238c7d4d508d493a109ebf2d01~mv2.jpg"}, {"slug": "potatoes-for-a-crowd", "title": "Potatoes for a Crowd", "serves": "", "category": "Potato", "date": "2022-02-27", "ingredients": ["1 32oz package of hash browns, thawed", "8oz sour cream", "1 can cream of chicken soup", "1 stick of butter, melted", "2 cups grated cheddar cheese", "2 cups crushed corn flakes", "½ stick butter, melted"], "instructions": "Preheat the oven to 350°.\nGrease a 13x9 inch pan.\nPlace the thawed hash browns into the prepared pan.\nIn a large bowl combine the stick of melted butter, sour cream, soup and cheese. Pour over the hash browns and spread evenly.\nIn a small bowl combine the corn flakes and the ½ stick of melted butter. Sprinkle over the top of the hash brown mixture.\nBake for 45-60 minutes or until heated through and golden.", "image": "https://static.wixstatic.com/media/75d545_d978be62144c44209ac64534801be82b~mv2.jpg"}, {"slug": "princess-brownies", "title": "Princess Brownies", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["1 package family size brownie mix", "1 8oz package cream cheese, softened", "1/3 cup of sugar", "1 egg", "½ tsp vanilla"], "instructions": "Preheat the oven to 350°\nPrepare the brownie mix as directed on the package.\nCombine the softened cream cheese and sugar and mix well. Add the egg and the vanilla.\nSpread ½ of the brownie mixture onto the bottom of a greased 13x9 inch baking pan. Cover with the cream cheese mixture; spoon on the remaining brownie mix. Cut through the batter with a knife several times for a marble effect.\nBake 35 to 40 minutes or until a wooden toothpick inserted in the center comes out clean. Cool.\nFrosting\n3tbsp butter, softened\n3tbsp Nestlé unsweetened cocoa\n½ tsp vanilla\n2tbsp milk\n1 ¼ cup confectioner’s sugar\nCream the butter and the cocoa in a small bowl with a mixer. Add the vanilla and the sugar. Blend in the milk, adding more if needed. Beat until the mixture reaches spreading consistency.\nChocolate Satin Glaze\n2tbsp sugar\n2tbsp water\n½ cup semi sweet chocolate mini morsels\nCombine the sugar and water in a small saucepan; cook over medium heat, stirring constantly until the mixture boils and the sugar is dissolved. Remove from the heat and add the mini morsels, stirring until melted. Continue stirring until the glaze is the desired consistency.\nFrost the brownies and then top with the glaze.", "image": "img/princess-brownies.jpg"}, {"slug": "prosciutto-and-melon-bites-makes-20", "title": "Prosciutto and Melon Bites", "serves": "Makes 20", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["1 large honeydew melon", "1 large cantaloupe", "¼ lb thinly sliced prosciutto", "red leaf lettuce leaves"], "instructions": "Prepare a fruit bowl: cut a very thin slice off the bottom of the honeydew melon, so that it sits flat. Insert a knife at a 45° angle into the rind slightly above the middle of the melon. Push the knife all the way through to the center. Continue in this manner around the whole melon, cutting in a saw tooth pattern. Lift the top off and remove the seeds.\nUse a melon baller to scoop out the fruit and set aside.\nCut the cantaloupe, remove the seeds and use the melon baller to scoop the fruit. Set aside.\nCut the prosciutto into strips. Wrap 1 strip around each melon ball and fasten with a toothpick.\nLine the honeydew with the red leaf lettuce and then fill it with the wrapped melon balls.", "image": "https://static.wixstatic.com/media/75d545_e34fb7a4d1ad4786930a0a6a67114dff~mv2.jpg"}, {"slug": "prosciutto-wrapped-asparagus", "title": "Prosciutto Wrapped Asparagus", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["Allow 2-3 asparagus stalks per person"], "instructions": "Slices of very thin Prosciutto\nTrim the asparagus and blanch them until just tender (2-4 minutes).\nTo blanch: Bring water to a boil in a large pot, and add the asparagus. Cook as per above. While the asparagus is cooking fill a large bowl with ice and water and set aside.\nRemove the asparagus from the boiling water and immediately immerse in the cold water. After the stalks have cooled, drain and refrigerate until ready for wrapping.\nTo wrap, cut very thinly sliced Prosciutto into thirds, lengthwise and wrap the strips around the stalks in a spiral fashion.\nServe cold on a decorative dish.", "image": "img/prosciutto-wrapped-asparagus.jpg"}, {"slug": "pull-apart-pizza-bread", "title": "Pull Apart Pizza Bread", "serves": "", "category": "Appetizers & Dips", "date": "2022-03-03", "ingredients": ["2 cans of Pillsbury Pizza dough or biscuits", "2 cups shredded mozzarella cheese", "1 (5 oz) package mini pepperoni slices", "1 cup freshly shredded Parmesan cheese", "½ cup fresh basil, chopped", "2 tbsp oregano, chopped", "¼ cup chopped parsley", "2 cloves of garlic, grated", "1/3 cup olive oil", "1 cup pizza sauce", "Preheat oven to 350º"], "instructions": "Spray a 10” pizza pan with cooking spray and place a small dipping sauce bowl in the center.\nIn a large bowl, combine the mozzarella, pepperoni, parmesan, basil, parsley and oregano.\nIn a whisk bowl, stir together the olive oil and garlic. Add to the cheese mixture.\nCut the dough into 2” pieces and toss them with the cheese mixture. Place the dough (in multiple layers) around the sauce bowl on the pizza pan.\nBake for 30-45 minutes or until the biscuits have browned. If the top biscuits begin to brown earlier than the rest, gently lay a piece of foil over the top.\nWhile the bread is baking, heat the pizza sauce.\nRemove from the oven, fill the sauc", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "puppy-chow", "title": "Puppy Chow", "serves": "", "category": "Desserts", "date": "2022-02-27", "ingredients": ["9 cups crispy rice cereal squares", "½ cup peanut butter", "1 cup semi sweet chocolate chips", "1 ½ cup confectioner's sugar"], "instructions": "In a large saucepan over low heat, melt the chocolate. Add the peanut butter and stir until smooth.\nRemove from the heat and add the cereal. Stir gently until completely covered in the chocolate.\nPour the powdered sugar into a tall unscented plastic trash bag and add the cereal. Shake the bag until all the cereal is well coated with the sugar.\nRemove the cereal from the bag and store in a covered container in the refrigerator.\nKid favorite!", "image": "img/puppy-chow.jpg"}, {"slug": "quiche-lorraine", "title": "Quiche Lorraine", "serves": "", "category": "Breakfast", "date": "2022-02-27", "ingredients": ["9” pie crust", "12 slices bacon, cooked and crumbled", "1 cup shredded Swiss cheese", "1/3 cup finely chopped onion", "4 eggs", "2 cups heavy cream", "¾ tsp salt", "¼ tsp pepper", "1/8 tsp ground red pepper"], "instructions": "Preheat the oven to 425°.\nPrepare the pastry.\nSprinkle the bacon, cheese and onion in the pastry lined pie plate.\nBeat the eggs slightly and add the remaining ingredients. Pour into the pie plate.\nBake uncovered for 15 minutes and reduce the oven temperature to 300°. Bake until a knife inserted in the center comes out clean.\nLet stand 10 minutes before cutting.", "image": "img/quiche-lorraine.jpg"}, {"slug": "raspberry-brie-bites-30-mini-cups", "title": "Raspberry Brie Bites 30 mini cups", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["1/3 lb brie, double cream preferred", "30 miniature phyllo cups", "1/3 cup seedless raspberry jam"], "instructions": "Preheat the oven to 350°.\nCut the brie into ¾” cubes and gently press into each phyllo cup. Top each cup with a ¼ tsp of raspberry jam.\nBake for 15-20 minutes or until the brie has melted. Watch carefully.", "image": "img/raspberry-brie-bites-30-mini-cups.jpg"}, {"slug": "raspberry-brie-bites-ii-15-cups", "title": "Raspberry Brie Bites II 15 cups", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["6 oz brie, rind removed and cut into ¾” cubes", "1 package mini phyllo cups", "15 raspberries"], "instructions": "Preheat the oven to 350°.\nPlace the tart shell on an ungreased cookie sheet. Place a brie cube in each phyllo cup and top with a raspberry. Bake for 5-8 minutes or until the brie has melted.", "image": "img/raspberry-brie-bites-ii-15-cups.jpg"}, {"slug": "raspberry-brie-bites-makes-12", "title": "Raspberry Brie Bites", "serves": "Makes 12", "category": "Appetizers & Dips", "date": "2022-02-27", "ingredients": ["12 wonton wraps", "buttery cooking spray", "8 ounces Brie, rind removed", "1/4 cup raspberry preserves", "fresh raspberries (frozen if in a pinch)"], "instructions": "Preheat oven to 375º.\nLightly spray 12 slots of mini muffin tin with cookie spray. Insert one wonton skin in each slot, forming a cup.\nCut brie into pieces that will fit into bottom of each cup.\nTop each piece of brie with ¼ tsp of raspberry preserves.\nPlace a fresh raspberry inside of each wonton.\nBake for 10-12 minutes or till shells are nicely browned.\nNote: you can save the fresh raspberry placement until after baking if preferred", "image": "img/raspberry-brie-bites-makes-12.jpg"}, {"slug": "raspberry-sauce", "title": "Raspberry Sauce", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-27", "ingredients": ["3 cups fresh raspberries", "¼ cup plus 2tbsp sugar", "3tbsp orange juice", "3tbsp cornstarch", "1 ½ cup **cold** water"], "instructions": "Combine the raspberries, sugar and orange juice in a sauce pan.\nWhisk the cornstarch onto the cold water until smooth. Add to the saucepan and bring to a boil.\nSimmer for 5 minutes, stirring constantly until thickened. (the sauce also thickens as it cools)\nPuree in a blender and strain through a fine sieve or use a food mill. The sauce can be served warm or cold.", "image": "img/raspberry-sauce.jpg"}, {"slug": "red-sangria", "title": "Red Sangria", "serves": "", "category": "Beverage", "date": "2022-02-27", "ingredients": ["1 bottle (750ml) dry red wine", "¼ cup brandy", "¼ cup orange liqueur", "2 tbsp sugar", "2 sliced oranges", "1 sliced green apple", "1 ½ cup seltzer"], "instructions": "Mix together in a pitcher and serve!", "image": "img/red-sangria.jpg"}, {"slug": "reuben-cups-makes-24", "title": "Reuben Cups", "serves": "Makes 24", "category": "Appetizers & Dips", "date": "2022-03-01", "ingredients": ["24 wonton wrappers", "½lb thinly sliced deli corned beef, chopped", "1/3 cup sauerkraut, drained", "1/3 cup thousand island dressing", "2/3 cup shredded swiss cheese", "**Preheat oven to 350º**"], "instructions": "Spray a mini muffin pan with cooking spray and gently press wontons into each cup.\nIn a small bowl, combine the corned beef, sauerkraut and dressing.\nSpoon the corned beef mixture into each wonton cup and top with the shredded cheese.\nBake for 8-10 minutes or until heated through and cheese is melted.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "rice-and-broccoli-casserole-serves-10", "title": "Rice and Broccoli Casserole", "serves": "Serves 10", "category": "Casserole", "date": "2022-02-27", "ingredients": ["6 boxes frozen chopped broccoli or 60oz total", "4 cup cooked minute rice", "1½ can Campbell’s cream of mushroom soup", "10oz Cheez Whiz", "1 cup chopped celery", "½ cup chopped onion", "garlic powder", "bread crumbs with Roman Cheese", "freshly grated Parmesan cheese"], "instructions": "Preheat the oven to 350°.\nCook the broccoli and drain.\nIn a 13x9 glass baking dish, combine the broccoli, rice, soup, cheez whiz, celery and onion.\nSprinkle the garlic powder over the top, then a light layer of the bread crumbs. Top with the fresh Parmesan.\nBake for 1 hour.", "image": "img/rice-and-broccoli-casserole-serves-10.jpg"}, {"slug": "rice-pilaf-serves-6", "title": "Rice Pilaf", "serves": "Serves 6", "category": "Pasta, Rice & Beans", "date": "2022-02-27", "ingredients": ["4 tbsp butter", "1 cup orzo", "1 cup diced onion", "4 cloves of garlic, minced", "1 cup uncooked long grain rice", "4 cups chicken broth", "freshly grated or chopped parsley", "½ cup freshly grated Parmesan cheese"], "instructions": "Melt the butter in a lidded large saucepot over medium low heat. Cook and stir the orzo and rice until golden and add the onion. Cook until the onion becomes translucent and then add the garlic and cook for another minute.\nAdd the chicken broth. Increase the heat to high and bring to a boil. Reduce the heat to medium low, cover and simmer until the rice is tender and the broth has been absorbed. (20-25 minutes).\nRemove from the heat and add grated parsley for color and to taste. Add ¼ cup of the Parmesan and combine. Sprinkle with the remaining Parmesan just before serving.", "image": "img/rice-pilaf-serves-6.jpg"}, {"slug": "ricotta-eggplant-rolls-serves-8", "title": "Ricotta Eggplant Rolls", "serves": "Serves 8", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["½ cup extra virgin olive oil", "4 cloves garlic, minced", "1 28oz can crushed tomatoes in puree", "1 10oz can tomato sauce", "4tbsp Italian seasonings", "1tsp salt", "1tsp sugar", "½ tsp black pepper", "2 cups plain dried bread crumbs", "1 cup flour", "2 eggs", "¼ cup heavy cream", "2 large eggplants peeled, & sliced (lengthwise) into ¼” slices", "1 15oz container ricotta", "2 cups shredded mozzarella", "½ cup grated parmesan", "¾ cup chopped fresh parsley"], "instructions": "Preheat the oven to 400°\nHeat 1tbsp olive oil in a large saucepan over medium heat. Add the garlic and cook until fragrant and lightly browned.\nPour the crushed tomatoes and sauce into the pan. Season with the Italian seasonings, salt, sugar and pepper. Simmer covered over medium low heat for 30 minutes, stirring occasionally. Remove from the heat and set aside.\nIn a large shallow dish stir together the bread crumbs and flour. In a separate dish whisk together the eggs and the cream.\nHeat the remaining oil in a skillet over medium high heat. Dip each eggplant slice into the egg mixture then coat with the bread crumbs.\nCook each slice until golden brown, turning once. Drain on a paper towel.\nSpread a thin layer of the sauce in the bottom of a 9”x13” baking dish.\nIn a large bowl stir together the ricotta, mozzarella, Parmesan cheese and the parsley.\nSpread 2-3tbsp of the cheese mixture onto one side of each slice of eggplant. Roll them up and place in the baking dish seam side down.\nSpoon the remaining sauce over the rolls. Cover the baking dish with foil and bake for 30 minutes. Garnish with additional chopped parsley and serve.", "image": "img/ricotta-eggplant-rolls-serves-8.jpg"}, {"slug": "ro-tel-hormel-chili-cheese-dip", "title": "Ro-Tel Hormel Chili Cheese Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 10oz can Ro-Tel tomatoes and diced green chiles", "1 15oz can Hormel chili, no beans", "1lb Velveeta"], "instructions": "Cut the cheese into cubes and melt in a double boiler over low heat while stirring.\nStir in the Ro-Tel tomatoes and the chili. Serve with your favorite chips.\nCrockpot works well with this recipe.", "image": "img/ro-tel-hormel-chili-cheese-dip.jpg"}, {"slug": "roast-beef-bruschetta-crostini-makes-30", "title": "Roast Beef Bruschetta Crostini", "serves": "Makes 30", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 French bread baguette, cut into 30, 1/4 “ slices", "2-3 tbsp extra virgin olive oil", "Philadelphia soft cream cheese with chives and onions", "½ lb thinly sliced, very lean cooked roast beef", "fresh black pepper", "tomato bruschetta", "¾ cup chopped green onions"], "instructions": "Preheat the oven to 375°.\nBrush both sides of each bread slice with the oil. Place on an ungreased cookie sheet and bake for about 5 minutes or until crisp. Cool for 5 minutes.\nCut each slice of roast beef into 2-3 smaller pieces.\nSpread the cream cheese on each bread slice and top with a piece of roast beef. Sprinkle each with a little pepper.\nTop each crostini with bruschetta and then garnish each with green onions.", "image": "https://static.wixstatic.com/media/75d545_e4ad7a7482534b51afd2c3eefac419c6~mv2.jpg"}, {"slug": "roasted-acorn-squash", "title": "Roasted Acorn Squash", "serves": "", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["2 Acorn squash, quartered lengthwise and seeded", "1 tbsp extra virgin olive oil", "coarse salt and ground black pepper", "4 tbsp butter", "1/8 tsp cinnamon", "**Preheat the oven to 450°**"], "instructions": "In a large bowl, toss the squash with the oil. Transfer to a rimmed cookie sheet and season with the salt and pepper to taste. Place the cut sides down and roast for 35-45 minutes or until easily pierced with a fork.\nIn a small saucepan, melt the butter over medium high heat until golden brown. Add the cinnamon.\nPlace the squash on a platter and top with the cinnamon butter.", "image": "img/roasted-acorn-squash.jpg"}, {"slug": "roasted-butternut-squash-serves-4", "title": "Roasted Butternut Squash", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["1 large butternut squash; peeled, seeded and cut into 1” cubes", "3tbsp extra virgin olive oil", "3 cloves of garlic, minced", "salt and pepper to taste"], "instructions": "Preheat oven to 400°\nToss the squash, garlic and olive oil in a large bowl.\nArrange the squash on a baking sheet and season with salt and pepper.\nBake for 25-30 minutes or until the squash is tender and lightly browned.", "image": "img/roasted-butternut-squash-serves-4.jpg"}, {"slug": "roasted-garlic-brussels-sprouts", "title": "Roasted Garlic Brussels Sprouts", "serves": "", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["2 tbsp extra virgin olive oil", "2 cloves garlic, minced", "½ tsp cumin seeds", "1tsp kosher salt", "1 tbsp brown sugar", "½ lemon, juiced", "crushed red pepper flakes, to taste", "1 ¼ lb Brussels sprouts, halved", "cilantro, torn (to taste)"], "instructions": "Preheat the oven to 450°.\nHeat 2 tbsp of oil in a small skillet over medium heat; add the garlic, cumin seeds and salt and cook for 2 minutes.\nStir in the brown sugar, lemon juice and pepper flakes. Remove from the heat.\nIn a large bowl toss the Brussels sprouts with the oil and seasoning mixture until well coated. Transfer to a baking sheet and roast for 20-30 minutes, or until tender. Toss with torn cilantro, if desired and serve.\nGreat at Thanksgiving or with grilled fish.", "image": "img/roasted-garlic-brussels-sprouts.jpg"}, {"slug": "roasted-heirloom-tomatoes-serves-4", "title": "Roasted Heirloom Tomatoes", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["4 cups Heirloom tomatoes", "4 cloves of garlic, sliced", "3 tbsp extra virgin olive oil", "salt & pepper to taste", "**Preheat the oven to 450°**"], "instructions": "Use a foil cookie sheet or a cookie sheet covered in foil.\nPlace the tomatoes and the garlic in a large bowl and toss with the olive oil until evenly coated. Season with salt & pepper and spread on the foil sheet.\nBake for 15 to 20 minutes or until the skins have popped and the tomatoes have begun to brown.", "image": "https://static.wixstatic.com/media/75d545_df5d5171f4324949895caa287356d3c9~mv2.jpg"}, {"slug": "roasted-new-potatoes-serves-6", "title": "Roasted New Potatoes", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["**Preheat the oven to 450°.**", "2lb new potatoes, quartered", "3tbsp extra virgin olive oil", "3 garlic cloves, minced", "¾ tsp dried rosemary", "¾ tsp dried thyme", "¾ tsp salt", "¼ tsp blak pepper"], "instructions": "In a large ziploc bag combine all of the ingredients and toss. Empty the bag onto a foil cookie sheet or a 13x9 baking pan.\nBake uncovered for 35 minutes or until the potatoes are tender and browned.", "image": "img/roasted-new-potatoes-serves-6.jpg"}, {"slug": "rolo-brownie-bites", "title": "Rolo Brownie Bites", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["1 box of fudge brownie mix plus necessary ingredients per package instructions.", "24 Rolo candies", "4tbsp butter", "4 oz cream cheese", "2tbsp caramel sauce", "1 cup confectioner’s sugar"], "instructions": "Preheat the oven to 325°\nRemove all of the wrappers and refrigerate the candies. Prepare the brownie mix according to the package instructions.\nGrease a 24 cup mini muffin pan with softened butter. Fill each cup ¾ full with the brownie batter.\nBake for 15- 20 minutes or until a wooden toothpick inserted in the center of a brownie comes out clean.\nRemove from the oven and immediately press a Rolo, with the smaller end down, into the center of each brownie. The the top of the Rolo should be even with top of the brownie. Cool for a couple of minutes.\nRemove the brownie bites to a serving tray and allow to cool completely.\nTo make the frosting, whip the butter and the cream cheese together until smooth. Add the caramel sauce and blend. Add the confectioner’s sugar and whip until creamy and smooth. Using a pastry bag or cookie press with a decorative tip, pipe the frosting onto the top of each brownie. Chill in the refrigerator before serving.", "image": "https://static.wixstatic.com/media/75d545_042b46280c9c474a84e314046f89a29f~mv2.jpg"}, {"slug": "rosemary-buttermilk-ranch-chicken-kabobs-8-10-kabobs", "title": "Rosemary Buttermilk Ranch Chicken Kabobs 8-10 kabobs", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["2lbs chicken cutlets", "1 cup buttermilk", "1/3 cup extra virgin olive oil", "2 tbsp Worcestershire sauce", "1 oz hidden valley ranch dressing mix", "½ tsp fresh ground pepper", "½ tsp salt", "2 tbsp minced rosemary"], "instructions": "Soak bamboo skewers in water for at least 30 minutes.\nCut the chicken into 1” cubes.\nMix the remaining ingredients for the marinade and add the chicken. Toss to coat.\nCover and refrigerate for at least 30 minutes.\nThread the chicken onto soaked skewers and grill on oiled grill for 10-15 minutes or until the chicken is no longer pink in the center. Turn halfway through cooking.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "rosemary-ranch-chicken-kabobs", "title": "Rosemary Ranch Chicken Kabobs", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["½ cup extra virgin olive oil", "½ cup ranch dressing", "2 tbsp Worcestershire sauce", "1 tbsp fresh rosemary, minced", "2 tsp salt", "1 tsp lemon juice", "1 tsp vinegar", "¼ tsp fresh ground pepper", "1 tbsp sugar", "1 ½ lb chicken cutlets"], "instructions": "In a large bowl and with a whisk, combine the olive oil, ranch dressing, Worcestershire sauce, lemon, rosemary, salt, vinegar, sugar and pepper.\nCube the chicken into 1” pieces and place in the ranch dressing mixture. Toss the chicken to coat. Cover the bowl and refrigerate for at least 30 minutes. The longer the better!\nSoak bamboo skewers in water for 30 minutes.\nPlace the chicken on the skewers. Toss the marinade.\nOil the grill and cook the chicken for 10-12 minutes or until the chicken is no longer pink.", "image": "img/rosemary-ranch-chicken-kabobs.jpg"}, {"slug": "salmon-cucumber-appetizer-makes-about-48", "title": "Salmon Cucumber Appetizer Makes about 48", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 7.75oz can of salmon, drained", "1 3oz package cream cheese, softened", "1 tbsp fresh lemon juice", "¼ tsp salt", "¼ tsp dried dill", "2 seedless cucumbers", "1 jar of julienne pimentos"], "instructions": "In a medium bowl combine the salmon, cream cheese, lemon juice, salt, dill and pepper.\nSlice the cucumber into ¼” slices. Spread 1 tsp of the salmon mixture onto each cucumber slice and garnish with a piece of pimento. Place on a serving platter, cover and chill until ready to serve.", "image": "img/salmon-cucumber-appetizer-makes-about-48.jpg"}, {"slug": "salmon-with-coconut-and-macadamia-crust-serves-4", "title": "Salmon with Coconut and Macadamia Crust", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["4 4oz salmon filets, skin removed", "2 eggs, whisked", "1 package NutCrusters Macadamia Coconut coating mix"], "instructions": "Preheat oven to 425°.\nWhisk eggs in a medium bowl. Add the coconut and macadamia mix to another medium bowl. Dredge the salmon filets in the eggs and then thoroughly coat in the coconut mixture.\nPlace on a foil baking sheet and bake for 35- 40 minutes.\nServe with a lemon wedge.", "image": "img/salmon-with-coconut-and-macadamia-crust-serves-4.jpg"}, {"slug": "salmon-with-lime-cilantro-butter-serves-6", "title": "Salmon with Lime Cilantro Butter", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["Marinade", "4 tbsp fresh lime juice", "4 tbsp soy sauce", "4 tbsp vegetable oil", "Salmon", "2lb salmon fillet, skin removed", "Lime Cilantro Butter", "½ cup butter, melted", "4 tbsp fresh lime juice", "4 tbsp chopped fresh cilantro"], "instructions": "In a large glass baking dish, whisk together the marinade ingredients. Add the salmon, turning once to coat. Cover the dish and refrigerate for 30-60 minutes.\nIn a small bowl combine the butter ingredients and set aside.\nPreheat the oven to 425° if baking. Bake for 30-40 minutes or until the fish flakes.\nHeat the grill and oil the rack. Grill over medium to high heat for 10-17 minutes or until the fish flakes.\nRemove from heat and baste the salmon with the lime cilantro butter before serving.", "image": "img/salmon-with-lime-cilantro-butter-serves-6.jpg"}, {"slug": "salted-caramel-sauce-makes-1-cup", "title": "Salted Caramel Sauce", "serves": "Makes 1 cup", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["1 cup granulated sugar", "1 tbsp light corn syrup", "¼ cup water", "½ cup heavy cream, warmed", "2 tbsp butter, softened", "2 tsp fine grain sea salt", "1 ½ tsp vanilla extract"], "instructions": "In a medium size heavy gauge pot, over medium/ low heat, stir together the sugar, corn syrup and water. Place a candy thermometer in the pot, making sure that the tip is in the sugar mixture.\nOver medium/high heat, stir the sugar until it completely dissolves and the syrup is bubbly. Stop stirring and allow the mixture to boil until it turns a deep amber. (the mixture should be at 350° when this occurs)\nImmediately remove the pot from the heat, and slowly add the warm cream.\nStir the mixture until smooth. (if lumps appear, return to the heat to dissolve)Stir in the butter and salt. Mix well.\nAllow to cool for 3-4 minutes and add the vanilla.\nKeeps in the refrigerator for approximately 3 weeks.", "image": "img/salted-caramel-sauce-makes-1-cup.jpg"}, {"slug": "sangria-makes-1-gallon", "title": "Sangria", "serves": "Makes 1 gallon", "category": "Beverage", "date": "2022-02-28", "ingredients": ["1 ½ liter red table wine (Lambrusco)", "1 cup Grenadine", "2 cups cranberry juice cocktail", "1 ¼ cup sweet vermouth", "Sugar water", "½ cup sugar", "½ water", "Strawberries cut into thirds", "Oranges sliced thin, then quartered", "Crushed ice"], "instructions": "Mix everything together in a large pitcher or punch bowl and enjoy", "image": "img/sangria-makes-1-gallon.jpg"}, {"slug": "sausage-apple-stuffing", "title": "Sausage & Apple Stuffing", "serves": "", "category": "Breads & Stuffings", "date": "2022-02-28", "ingredients": ["½ lb ground pork breakfast sausage", "2 tbsp butter", "½ cup chopped celery", "¼ cup chopped onion", "2 4oz cans of sliced water chestnuts", "1 12oz package of dry stuffing with herbs", "3 apples; peeled cored and cubed", "1 tbsp dry chicken broth"], "instructions": "Cook the sausage in a large skillet over medium heat until browned. Drain and set aside.\nMelt the butter in a large saucepan over medium heat, stir in the celery, onion and water chestnuts. Cook until the celery is tender, stirring frequently. Remove from the heat.\nPrepare the herbed stuffing according to the package directions. Mix in the sausage, celery mixture, apples and the chicken broth.\nTransfer to the turkey.\nThis stuffing may be baked in a large baking dish in a 325° oven for 30 minutes.", "image": "img/sausage-apple-stuffing.jpg"}, {"slug": "sausage-stuffed-mushrooms-makes-24", "title": "Sausage Stuffed Mushrooms", "serves": "Makes 24", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["24 mushrooms, 1.5”-2” diameter", "¼ cup chopped green onion", "1 tbsp butter", "2 tsp flour", "1/8 tsp black pepper", "2 tbsp white wine", "2 tbsp water", "½ cup sausage, cooked", "2 tbsp Parmesan cheese"], "instructions": "Preheat the oven to 350°.\nWash the mushrooms and drain on a paper towel. Remove the stems and place the mushrooms on a baking sheet. Chop the enough of the stems to make 1 cup.\nCook the stems and the green onion in the butter just until tender. Stir in the flour and pepper; add the wine and water. Stir until thickened(happens pretty quickly)and bubbly. Stir in the sausage and the Parmesan. Remove from the heat.\nFill each mushroom cap with the sausage mixture. Bake for 15-20 minutes or until the caps are tender.", "image": "img/sausage-stuffed-mushrooms-makes-24.jpg"}, {"slug": "sausage-white-bean-soup-serves-8", "title": "Sausage & White Bean Soup", "serves": "Serves 8", "category": "Soup & Sandwiches", "date": "2022-12-05", "ingredients": ["6 Italian sausage links, casings removed", "2 medium Vidalia onions, chopped", "4 large garlic cloves, minced", "3 15oz cans cannellini beans", "2 (32oz) Tuscany Chicken broth", "4 cups water", "1 ½ cup white wine", "½ tsp pepper", "1 10oz package of baby spinach", "Shredded Parmesan"], "instructions": "Cook the sausage and the onion together in a large pot over medium high heat. Cook until the sausage is no longer pink; drain and add back to the pot.\nAdd the garlic and cook for another minute.\nStir in the beans, broth, water, wine and pepper. Bring to a boil and add the spinach. Stir until the spinach has wilted. Serve with shredded Parmesan as a garnish.", "image": "img/sausage-white-bean-soup-serves-8.jpg"}, {"slug": "sautéed-apples-serves-8", "title": "Sautéed Apples", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["¼ cup butter", "4 large Granny Smith Apples, peeled, cored and sliced ¼” thick", "2 tsp cornstarch", "½ cup cold water", "½ cup packed brown sugar", "¾ tsp cinnamon"], "instructions": "In a large skillet melt the butter over medium heat and add the apples. Cook until the apples are almost tender, stirring constantly.\nDissolve the cornstarch in the water and add to the skillet. Add the brown sugar and cinnamon and stir. Boil for 2 minutes, stirring frequently. Remove from the heat and serve warm.\nGreat side to pork dishes.", "image": "img/sautéed-apples-serves-8.jpg"}, {"slug": "sautéed-brussels-sprouts-with-lemon-serves-4", "title": "Sautéed Brussels Sprouts with Lemon", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["16oz Brussel sprouts, quartered", "salt and lemon pepper to taste", "3 tbsp Extra Virgin Olive Oil", "½ of a fresh a lemon, squeezed", "Directions"], "instructions": "In a skillet (that has a lid) combine the Brussels sprouts with ½ cup of water. Add salt and pepper to taste. Bring to a low boil over medium heat. Cover. Cook until the water has been mostly absorbed and the sprouts are near tender, 5-7 minutes. You may add a small amount of additional water if the pan becomes too dry during this phase.\nAdd the oil to the skillet and increase the heat to medium-high. Cook uncovered for 5-7 minutes. Do not stir. Allow the sprouts to carmelize (golden brown). 5-8 minutes.\nRemove from the heat and stir in the lemon juice. Salt and pepper to taste.", "image": "img/sautéed-brussels-sprouts-with-lemon-serves-4.jpg"}, {"slug": "sautéed-cabbage-serves-6", "title": "Sautéed Cabbage", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["2 ½ lb white cabbage", "3 tbsp butter", "2 tsp kosher salt", "2 tsp freshly ground black pepper"], "instructions": "Cut the cabbage in half and remove the core. Slice the cabbage as thinly as possible.\nMelt the butter in a large pan over medium high heat. Add the cabbage, kosher salt and pepper. Sauté for 10 to 15 minutes stirring often. Cook until the cabbage is tender and has begun to brown.\nRemove from the heat and season with additional salt and pepper to taste.\nServe immediately.", "image": "https://static.wixstatic.com/media/75d545_014f83c9b53a466d959598c5d231f9f0~mv2.jpg"}, {"slug": "sautéed-green-beans-with-shallot-crisps", "title": "Sautéed Green Beans with Shallot Crisps", "serves": "", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["2 lbs green beans, trimmed", "Shallot Crisps:", "1/3 cup vegetable oil", "½ cup thinly sliced shallots ( about 6)", "2 tbsp butter", "2 tbsp extra virgin olive oil"], "instructions": "In a large skillet, heat the vegetable oil and add the shallots. Cook until they are browned. Remove to a paper towel to drain.\nHeat the butter and olive oil in a large skillet and add the green beans. Sauté, stirring frequently until the beans are bright green. (about 5 minutes) Season with salt and pepper.\nRemove the beans to a serving dish and garnish with the shallots.", "image": "img/sautéed-green-beans-with-shallot-crisps.jpg"}, {"slug": "seafood-casserole-ii-serves-8", "title": "Seafood Casserole II", "serves": "Serves 8", "category": "Casserole", "date": "2022-03-02", "ingredients": ["½ cup butter", "1 Vidalia onion, chopped", "½ red bell pepper, chopped", "1 cup chopped celery", "2 cloves of garlic, minced", "1lb peeled, tail off uncooked large shrimp", "1lb lobster tail meat, chopped", "1/2lb jumbo lump crabmeat", "1 10.75oz can condensed cream of mushroom soup", "1 10.74oz can condensed cream of celery soup", "1 cup whole milk", "4 cups cooked Basmati rice", "3 tbsp green onions, chopped", "3 tbsp chopped fresh parsley", "1 tbsp Hot sauce", "Salt & Freshly ground pepper", "1 ½ cup panko bread crumbs", "2 tbsp butter, melted", "1 cup shredded cheddar cheese", "Preheat the oven to 350°"], "instructions": "Melt the butter in a large pot over medium high heat; Add the onion, pepper, celery and garlic. Cook until the vegetables become tender and the garlic is fragrant.\nAdd the shrimp and lobster cook until they turn pink. Do not overcook or your seafood will become chewy!\nAdd the condensed soups and the milk; simmer for about 5 minutes.\nGently fold in the crabmeat, rice, green onions, parsley and hot sauce. Season with salt & black pepper to taste.\nIn a small bowl, toss the Panko with the melted butter to coat.\nPour the mixture into a 9 x 13 baking dish. Sprinkle the Panko evenly over the top of the casserole and then repeat with the cheddar cheese. (you do not have to use all of the cheese.\nBake for 20 minutes or until bubbly and golden brown on top.\nYou may also divide the casserole mixture between 2 pie shells and then add toppings.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "seafood-casserole-serves-6", "title": "Seafood Casserole", "serves": "Serves 6", "category": "Casserole", "date": "2022-02-28", "ingredients": ["½ cup Vidalia onion, diced", "1/4 cup butter", "¼ cup flour", "1 cup whole milk", "1 cup light cream", "1 tsp salt", "1 tsp pepper", "1 tbsp chopped pimento", "1 8oz can sliced water chestnuts, drained", "2 tbsp fresh lemon juice", "1 tbsp fresh parsley, minced", "1 cup lump crabmeat", "1 cup cooked small shrimp, peeled and deveined", "2 cups cooked rice", "1 cup shredded cheddar cheese", "**Preheat the oven to 350°**"], "instructions": "In a large saucepan, sauté the onion in the butter and blend in the flour. Add the milk and the cream and cook until thickened and bubbly; stirring often.\nRemove from the heat and season with the salt and pepper. Add the pimento, water chestnuts, lemon juice, parsley, crab and shrimp.\nStir in the rice and half of the cheddar cheese.\nSpoon into a 2.5qt casserole dish and bake for 25 minutes or until heated through. Remove from the oven and sprinkle with the remaining cheese.", "image": "img/seafood-casserole-serves-6.jpg"}, {"slug": "seafood-crepes", "title": "Seafood Crepes", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["5 tbsp butter", "3 tbsp minced scallions", "4 tbsp flour", "1 cup chicken broth, hot", "½ cup light cream", "3 tbsp sherry", "2 cups of small shrimp, crab and salmon(combined)", "Tabasco to taste", "Salt, to taste", "½ cup heavy cream", "¼ tsp nutmeg", "2 tbsp minced fresh parsley", "Crepes", "Lemon slices", "**Preheat the oven to 350°**"], "instructions": "Butter a 13 x 9 baking dish and set aside.\nIn a large skillet melt the butter over medium heat. Add the scallions and cook for 2 minutes. Sprinkle the flour over the scallions and stir to blend. Slowly add the hot chicken broth and stir until thick and smooth.\nAdd the light cream and the sherry. Cook for 5 minutes stirring constantly until thick and smooth. Add the fish and season with the tabasco and salt; stir a minute and remove from the heat.\nFill each crepe with 3 tbsp of the fish filling, roll and place seam side down in the baking dish. Spoon the extra filling around the edges of the crepes and in between.\nLightly whip the heavy cream and add the nutmeg. Spread over the crepes and bake for 20-25 minutes.\nSprinkle with fresh minced parsley and top with the lemon slices before serving.", "image": "img/seafood-crepes.jpg"}, {"slug": "sherry-mushroom-and-shallot-turkey-gravy-makes-8-cup-servings", "title": "Sherry Mushroom and Shallot Turkey Gravy", "serves": "Makes 8 ¼ cup servings", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["1-2 cup chicken broth", "pan drippings from the turkey", "2tbsp to ¼ cup melted butter", "¼ cup flour", "salt", "ground black pepper", "2-3 tbsp sherry", "2 cup sliced crimini or button mushrooms, cooked", "1 clove garlic, minced", "1tbsp fresh thyme", "¼ cup chopped shallots"], "instructions": "Cooked Mushrooms:\nMelt 2 tbsp of butter over medium high heat; add 2 cups of fresh mushrooms, chopped shallots and 1 clove of minced garlic. Cook until the mushrooms begin to brown.\nGravy:\nStir 1 cup of broth into pan drippings in the roasting pan from the turkey, stirring to scrape up any crusty brown bits. Pour the drippings into a 2 cup glass measuring cup. Skim and reserve fat from the drippings. If necessary add enough melted butter to the reserved fat to make ¼ cup.\nAdd enough broth to the drippings in the measuring cup to make 2 cups. Add the sherry.\nPour the ¼ cup of fat into a medium saucepan and stir in the flour. Add the broth mixture all at once to the flour mixture. Stir with a whisk until smooth. Cook and stir for 1 minute more.\nStrain the gravy and add the mushrooms and fresh thyme(or 1 tsp dried)", "image": "img/sherry-mushroom-and-shallot-turkey-gravy-makes-8-cup-servings.jpg"}, {"slug": "shoepeg-corn-casserole-serves-10", "title": "Shoepeg Corn Casserole", "serves": "Serves 10", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["½ cup diced onion", "½ cup diced celery", "¼ cup diced green pepper", "½ cup shredded mild cheddar cheese", "1 11oz can white corn, drained", "1 14.5oz can French cut green beans, drained", "1 10.75oz can cream of celery soup", "1 8oz container of sour cream", "¼ of a 16oz package of Ritz crackers, crushed", "½ cup butter, melted"], "instructions": "Preheat the oven to 350°.\nIn a large bowl, combine the onion, celery, green pepper, cheese, corn, green beans, soup and sour cream. Spoon into a 2 quart casserole dish.\nIn a small bowl combine the crushed crackers and the melted butter and sprinkle on top of the vegetables.\nBake for 45 minutes.", "image": "img/shoepeg-corn-casserole-serves-10.jpg"}, {"slug": "shredded-brussels-sprout-kale-and-romaine-salad-serves-8", "title": "Shredded Brussels Sprout, Kale and Romaine Salad", "serves": "Serves 8", "category": "Salads", "date": "2022-02-28", "ingredients": ["1.5lb brussels sprouts", "1 bunch kale", "1 head romaine lettuce", "½ cup walnut oil", "¼ cup white wine vinegar", "2 tsp Dijon mustard", "1tsp honey", "Kosher salt", "Fresh ground Black pepper", "½ cup fresh pomegranate seeds", "1 cup chopped walnuts", "Shaved Parmesan cheese"], "instructions": "Using your food processor, thinly slice the brussels sprouts and add to a large bowl.\nRemove the center vein from the kale leaves and julienne the leaves. Add to the bowl.\nWith a sharp knife cut the romaine into thin bite size strips and add to the bowl.\nToss the greens well and more of any of the greens that you prefer. This is a salad that can be tailored to your personal preference.\nIn a small bowl combine the walnut oil, vinegar, mustard, honey and season with the salt and pepper to taste.\nWhen you are ready to serve, pour the dressing over the greens and toss. Add the pomegranate seeds, walnuts, and cheese (again add more or less, to your liking) and serve.", "image": "img/shredded-brussels-sprout-kale-and-romaine-salad-serves-8.jpg"}, {"slug": "shredded-parmesan-brussels-sprouts-serves-6", "title": "Shredded Parmesan Brussels Sprouts", "serves": "Serves 6", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["3lbs Brussels Sprouts, trimmed and washed", "½ cup extra virgin olive oil", "Salt & pepper to taste", "3/4 cup freshly grated Parmesan"], "instructions": "Preheat oven to 425°\nIn a food processor with a slicing blade, shred the Brussels sprouts.\nOn a large jelly roll pan or 2 cookie sheets, spread the shredded sprouts out and toss with the olive oil. Evenly spread over the pan and season with salt and pepper.\nRoast for 30 minutes stirring halfway through. Sprinkle with the cheese and bake for 1 minute more. Transfer to a serving dish.", "image": "img/shredded-parmesan-brussels-sprouts-serves-6.jpg"}, {"slug": "shrimp-and-penne-with-asparagus-serves-4", "title": "Shrimp and Penne with Asparagus", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["2 tbsp cornstarch", "1 can(14.5oz) chicken broth", "1 tbsp extra virgin olive oil", "2 cloves garlic, minced", "½ tsp dried dill", "2 cup 1” asparagus pieces", "1 small red pepper, diced", "¼ cup sliced green onions", "1 tbsp fresh lemon juice", "8 oz Penne, cooked", "1lb medium shrimp, peeled, deveined and tails removed", "2 tbsp fresh grated Parmesan cheese, or more to taste"], "instructions": "In a small bowl, combine the cornstarch and ¼ cup of the chicken broth and set aside.\nIn a 3qt saucepan over medium heat, warm the oil. Add the shrimp and garlic and cook until the shrimp is pink, about 5 minutes. Remove the shrimp and garlic to a bowl and set aside.\nIn the same pan, bring the remaining broth and dill to a boil. Add the asparagus, red pepper and green onions and return to a boil. Reduce the heat to low, cover and cook until the vegetables are “crisp tender”, about 5 minutes.\nStir the cornstarch mixture and add it to the vegetables. Cook stirring constantly until the mixture boils and thickens. Add the shrimp and lemon juice and heat through.\nToss the shrimp and vegetable mixture with the cooked Penne. Sprinkle with the Parmesan cheese and serve.", "image": "img/shrimp-and-penne-with-asparagus-serves-4.jpg"}, {"slug": "shrimp-and-vegetable-risotto-serves-4", "title": "Shrimp and Vegetable Risotto", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1 package (5.6oz) risotto Primavera mix", "3tbsp vegetable oil", "1 medium red onion, diced", "1 small zucchini, cut into ½” pieces", "1 large tomato, seeded and cut into ½” pieces", "1lb large uncooked shrimp, shelled and deveined"], "instructions": "Prepare the risotto according to the package directions.\nIn a large skillet, over medium heat in 2tbsp of oil, cook the onion until translucent. Stir in the zucchini and 2tbsp water. Cook until the zucchini is tender. Add the tomato and heat. Remove the vegetable mixture to a bowl and set aside.\nIn the same skillet over medium high heat in 1tbsp of oil, cook the shrimp until they are opaque and lightly browned.\nStir in the risotto and vegetable mixture and heat through.", "image": "img/shrimp-and-vegetable-risotto-serves-4.jpg"}, {"slug": "shrimp-cocktail-serves-8", "title": "Shrimp Cocktail", "serves": "Serves 8", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["2lbs jumbo shrimp, shelled and deviened", "4 cloves garlic", "3 bay leaves", "2tbsp salt", "1tbsp coarse black pepper", "2 tsp celery seed", "1tbsp Old Bay", "1tsp thyme leaves"], "instructions": "Fill a large pop with water and add all the seasonings.\nBring the water to a boil and let it boil for 5 minutes.\nPlace the shrimp to the water.\nOnce the shrimp turns pink and floats to the top it’s cooked.\nRemove the shrimp to a strainer and cool.\nArrange on a platter and serve with your favorite cocktail sauce and lemon.", "image": "https://static.wixstatic.com/media/75d545_47374bc4d1764546a68741fc171ac431~mv2.jpeg"}, {"slug": "shrimp-edamame-stir-fry-serves-6", "title": "Shrimp Edamame Stir Fry", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["2lb jumbo shrimp, peeled, deveined, tails off", "6 cloves garlic, minced", "2 tbsp peanut oil", "2 tsp minced ginger, dry or fresh", "1 12oz bag frozen shelled edamame, thawed preferrably", "½ large Vidalia onion, sliced thin", "2 8oz cans sliced water chestnuts", "3/4 cup rice vinegar", "½ cup soy sauce", "2 tbsp+ 2 tsp cornstarch", "2 tsp sesame oil", "2 tsp chile garlic sauce or Sriracha", "3/4 tsp fish sauce"], "instructions": "In a small bowl, mix the rice vinegar, soy sauce, sesame oil, fish sauce, and cornstarch. Set aside.\nIn a wok or large saute´ pan, heat the oil and add the garlic and ginger; add the shrimp. Cook until the shrimp are opaque. Remove the shrimp to a bowl and set aside.\nIn the same pan add the onion and cook until translucent: add the edamame and waterchestnuts. Cook until the vegetables are heated through and then add the shrimp back.\nAdd the sauce and stir to combine. Cook until everything is heated and serve over your favorite rice.", "image": "img/shrimp-edamame-stir-fry-serves-6.jpg"}, {"slug": "shrimp-egg-roll-bowl-serves-6-8", "title": "Shrimp Egg Roll Bowl", "serves": "Serves 6-8", "category": "", "date": "2024-02-21", "ingredients": ["2lb large shelled and deveined shrimp, tails removed", "4 tbsp peanut oil", "4 tsp minced fresh garlic", "2 tsp mince ginger", "1 ½ cup minced sweet onion", "2 cup diced zucchini", "1 cup store shed carrots", "1(10 0z) bag Pero Vegetable Slaw", "4 tbsp soy sauce", "Salt & pepper, to taste", "4 green onions, sliced thin", "1 package Ka-Me Chinese Noodles (ramen)", "Sauce", "½ cup light mayonnaise", "2 tbsp sriracha", "2 tbsp soy sauce", "4 tsp maple syrup"], "instructions": "Combine all the sauce ingredients in a small mixing bowl and refrigerate.\nSeason the shrimp with salt and pepper.\nIn a large sauté pan over medium heat, add 2 tbsp of the peanut oil. When the oil is hot, add the shrimp and cook. Cook, stirring occasionally until pink. When the shrimp is cooked, remove them to a bowl and set aside.\nIf there is any liquid in the pan from the shrimp, drain and place back on the stove.\nWhile the shrimp is cooking, prepare the noodle according to the package directions.\nAdd 2 tbsp of peanut oil to the pan and heat. Add the diced onion, garlic, ginger, carrots and zucchini. Cook until crisp tender. About 3-4 minutes.\nAdd the vegetable slaw to the pan and season with salt and pepper. Toss the cabbage with other vegetables and cook until slightly softened.\nAdd the shrimp to the vegetables and the 4 tbsp of soy sauce. Mix and continue to heat until desired texture of the cabbage.\nServe the shrimp and vegetables over the ramen noodles, topped with the sliced green onions\nand drizzled with the sauce.", "image": "img/shrimp-egg-roll-bowl-serves-6-8.jpg"}, {"slug": "shrimp-pasta-salad-1", "title": "Shrimp Pasta Salad", "serves": "", "category": "Salads", "date": "2022-02-28", "ingredients": ["1/2lb Rotini, cooked", "1lb large shrimp, cleaned, shelled and cooked", "10ozfrozen peas, thawed and drained", "½ cup chopped green pepper", "½ cup chopped celery", "1 can sliced waterchestnuts", "¼ cup chopped red onion", "½ cup sour cream", "2tbsp mayonnaise", "1tbsp horseradish", "1tbsp white wine vinegar", "1tsp Dijon mustard", "1tsp dried basil"], "instructions": "In a large bowl combine the pasta, shrimp, peas, peppers, celery, waterchestnuts and onion, mix well. Cover and refrigerate.\nIn a separate bowl mix the sour cream, mayonnaise, horseradish, vinegar, mustard and basil; mix until blended and refrigerate.\nToss the pasta with the dressing just before serving.", "image": "img/shrimp-pasta-salad-1.jpg"}, {"slug": "shrimp-pasta-salad", "title": "Shrimp & Pasta Salad", "serves": "", "category": "Seafood", "date": "2022-02-28", "ingredients": ["1/2lb Rotini, cooked", "1lb medium shrimp, cleaned and cooked", "10oz frozen peas, thawed and drained", "½ cup green pepper, diced", "½ cup celery, chopped", "½ cup(1 can) sliced water chestnuts", "¼ cup chopped red onion", "½ cup sour cream", "2 tbsp light mayonnaise", "1 tbsp horseradish", "1 tbsp white wine vinegar", "1 tsp Dijon mustard", "1 tsp dried basil"], "instructions": "In a large bowl combine the pasta, shrimp, peas, peppers, celery, water chestnuts and onion; mix well.\nIn a separate small bowl mix the sour cream, mayonnaise, horseradish, vinegar, mustard and basil; whisk together until well blended.\nRefrigerate the salad and the dressing separately until ready to serve.\nJust before serving toss the salad with the dressing.", "image": "img/shrimp-pasta-salad.jpg"}, {"slug": "shrimp-salmon-and-cappellini-in-a-white-wine-sauce", "title": "Shrimp, Salmon and Cappellini in a White Wine Sauce", "serves": "", "category": "", "date": "2022-02-28", "ingredients": ["8 tbsp butter", "1 cup extra virgin olive oil", "1 cup thinly sliced green onions", "2 large tomatoes, peeled, seeded and chopped", "1 cup white wine", "4 tbsp freshly squeezed lemon juice", "4 cloves garlic, minced", "1 cup finely chopped parsley", "1 ½ lb shrimp, cooked, peeled and deveined", "2 medium salmon portions, cooked and broken into small pieces", "1 ½ lb cappellini, cooked"], "instructions": "Melt the butter in the oil in a large frying pan, over medium heat. Add the onions, garlic, tomatoes and wine. Bring to a boil stirring often. Boil gently for about 2 minutes and add the lemon juice, shrimp, salmon and parsley. Stir gently and heat until the seafood is heated through. Season with salt and pepper to taste.\nServe over cooked cappellini.", "image": "img/shrimp-salmon-and-cappellini-in-a-white-wine-sauce.jpg"}, {"slug": "shrimp-sausage-skewers-serves-4-2-skewers-each", "title": "Shrimp & Sausage Skewers Serves 4 (2 skewers each)", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["¼ cup butter, melted", "1 tbsp chili paste", "2 cloves of garlic, minced", "½ tsp salt", "½ tsp ground black pepper", "1 package Andouille (the spicier the sausage the better)", "1 1/2lb large raw shrimp, peeled and deveined", "8 skewers"], "instructions": "Soak the skewers in water (if bamboo) for ½ hour. Preheat the grill to medium high.\nUsing a small bowl, whisk together the butter, chili paste, garlic, salt and pepper. Set aside.\nCut each of the sausages into 8 even slices. Alternately add the shrimp and the sausage slices (cut side facing out) onto a skewer. 4 shrimp and 4 sausage slices per skewer.\nBrush both sides of the skewers with the butter mixture. Grill on nonstick foil until the shrimp are cooked through. Place on the open flame for decorative grilling marks and serve.\n**2.5 Net Carbs per skewer**", "image": "img/shrimp-sausage-skewers-serves-4-2-skewers-each.jpg"}, {"slug": "shrimp-scampi-ii-serves-4", "title": "Shrimp Scampi II", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1 (8oz) package angel hair pasta", "½ cup butter", "4 cloves garlic, minced", "1lb large shrimp, peeled and deveined", "1 cup white wine", "¼ tsp fresh ground black pepper", "¾ cup freshly grated Parmesan cheese", "1 tbsp chopped fresh parsley"], "instructions": "Boil the pasta until al dente. Drain.\nMelt the butter in a large skillet over medium heat.\nStir in the garlic and the shrimp. Cook, stirring constantly for 3-5 minutes. Add the wine and pepper, and bring to a boil. Cook for another 30 seconds, stirring constantly.\nIn a large serving bowl combine the pasta with the shrimp and sprinkle with the cheese and parsley.\nServe!", "image": "img/shrimp-scampi-ii-serves-4.jpg"}, {"slug": "shrimp-scampi-iii", "title": "Shrimp Scampi III", "serves": "", "category": "Main Dish", "date": "2022-02-26", "ingredients": ["3 garlic cloves, minced", "¼ cup butter", "¼ cup extra virgin olive oil", "1lb uncooked medium shrimp, peeled, deveined and tails removed", "¼ cup fresh lemon juice", "½ tsp pepper", "½ tsp dried oregano", "½ cup freshly grated Parmesan", "¼ cup dry bread crumbs", "¼ cup minced fresh parsley", "8oz linguine pasta"], "instructions": "In a large skillet sauté the garlic in the butter and olive oil until fragrant. Add the shrimp, lemon juice, and pepper. Cook until the shrimp turns pink.\nIn a small bowl, combine the oregano, parmesan, bread crumbs and parsley. Sprinkle on top of the shrimp and broil for 2-3 minutes or until the breads crumbs start to brown.\nServe over linguine.", "image": "img/shrimp-scampi-iii.jpg"}, {"slug": "shrimp-scampi-over-rice-serves-4", "title": "Shrimp Scampi over Rice", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["3 tbsp garlic, minced", "2 tbsp extra virgin olive oil", "4 tbsp butter", "½ cup white wine", "2 ½ lb shrimp (26-30 ct)", "3 tbsp freshly squeezed lemon juice", "a dash of tobacco", "2 tsp chopped fresh parsley", "salt and pepper to taste"], "instructions": "Sauté the garlic in the olive oil and butter just until the garlic ”blooms.” Add the wine and tobasco and stir.\nAdd the shrimp and a pinch of salt. Stir to coat the shrimp with the oil mixture and cook until the shrimp are pink. About 3-5 minutes.\nAdd the lemon juice, parsley and salt and pepper to taste.\nArrange the shrimp over cooked rice and top with the sauce from the pan.\nServe with warm crusty bread.", "image": "img/shrimp-scampi-over-rice-serves-4.jpg"}, {"slug": "shrimp-scampi-serves-6", "title": "Shrimp Scampi", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["¾ lb angel hair pasta", "2 ½ cup plus 2 tbsp chicken broth", "3 garlic cloves, minced", "¼ tsp lemon pepper seasoning", "¼ cup plus 2 tbsp chopped green onions, divided", "¼ cup plus 2 tbsp minced fresh parsley", "1 ½lb uncooked shrimp, peeled, deveined and tails removed"], "instructions": "Cook the pasta according to the package directions.\nMeanwhile, in a large saucepan, combine the broth, garlic, lemon pepper and 3 tbsp each of green onion and parsley; cook for 3-5 minutes or until the shrimp has turned pink.\nDrain the pasta and place in a large serving bowl. Top with the shrimp mixture and the remaining onions and parsley.\nServe with freshly grated Parmesan cheese and warm crusty bread", "image": "https://static.wixstatic.com/media/75d545_536c3377fb174ca7b517674e2722bbe4~mv2.jpg"}, {"slug": "simple-roasted-red-potatoes-serves-8", "title": "Simple Roasted Red Potatoes", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["3lb small red potatoes, halved", "¼ cup extra virgin olive oil", "1 tsp salt", "1 tsp fresh ground black pepper", "**Preheat the oven to 450°**"], "instructions": "Adjust the oven rack to the lowest position.\nIn a large bowl, toss the potatoes with the olive oil, salt and pepper.\nArrange the potatoes, cut side down on a large foil cookie sheet.\nRoast for 20-30 minutes or until golden brown and tender.\nTransfer to a serving dish.", "image": "img/simple-roasted-red-potatoes-serves-8.jpg"}, {"slug": "slow-burn-martini-makes-1-martini", "title": "Slow Burn Martini", "serves": "Makes 1 Martini", "category": "Beverage", "date": "2022-02-28", "ingredients": ["2 oz Kettle One Vodka", "½ oz vermouth", "5 drops tobasco", "1 slice jalapeño pepper", "4-5 ice cubes"], "instructions": "Combine the vodka, vermouth, tobasco and ice in a shaker. Cover and shake vigorously. Strain into a martini glass and garnish with the jalapeño.", "image": "img/slow-burn-martini-makes-1-martini.jpg"}, {"slug": "snow-pea-pods-with-pepper-cheese", "title": "Snow Pea Pods with Pepper Cheese", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["50-60 snow peas", "½ lb Boursin pepper cheese, softened"], "instructions": "Remove the stem end of the peas, remove the string and blanche them in a large pot of boiling water for 30 seconds. Plunge them immediately into cool water to stop the cooking and preserve the green color.\nWith a sharp knife, slit open the straight seam of each snow pea and add the cheese.", "image": "img/snow-pea-pods-with-pepper-cheese.jpg"}, {"slug": "snow-peas-and-water-chestnuts-serves-4", "title": "Snow Peas and Water Chestnuts", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["2 cup snow pea pods", "1 can sliced water chestnuts", "2 tsp walnut oil", "1 dash of sesame oil", "1 dash salt and black pepper"], "instructions": "Trim the ends and the stings off of the snow pea pods.\nRinse and drain the water chestnuts. Dry on a paper towel.\nIn a large skillet, heat the oil and add the pea pods. Stir fry for about 2 minutes. Add the water chestnuts and stir fry for an additional 2 minutes.\nSeason with the salt and pepper and serve.", "image": "img/snow-peas-and-water-chestnuts-serves-4.jpg"}, {"slug": "southwestern-salad-serves-5", "title": "Southwestern Salad", "serves": "Serves 5", "category": "Salads", "date": "2022-02-28", "ingredients": ["3 Romaine hearts, chopped", "1 package grape tomatoes, halved", "½ seedless cucumber, diced", "¼ cup diced red onion", "1 can(11oz) Mexican style corn", "1 can(15oz) black beans, rinsed", "1 package of Fajita seasoning", "1lb thin sliced chicken fillets", "1-2 tbsp vegetable oil", "1 4oz can sliced black olives", "1-2 avocados, cubed", "tortilla strips", "**Cilantro Lime Dressing**", "1/4 cup fresh lime juice ( 1 good sized lime)", "1/4 cup fresh cilantro", "1/3 cup honey", "1 garlic clove peeled & minced", "1 med sized jalapeno de-seeded de-ribbed", "3/4 tsp grated fresh ginger", "2 tsp balsamic vinegar", "salt to taste ( I used 6 pinches of kosher salt)", "1/2 cup extra virgin olive oil"], "instructions": "Combine all ingredients in a food processor.\nIn a large bowl combine the lettuce, tomato, cucumber, onion, corn and black beans; toss well. Sprinkle the tortilla strips over the salad.\nRub both sides of the chicken fillets with the fajita seasoning. Heat the oil in a large skillet and cook the chicken over medium high heat for about 4 minutes each side. Do not over cook.\nSlice each fillet and either toss with the salad or place on the top of individual servings.", "image": "img/southwestern-salad-serves-5.jpg"}, {"slug": "soy-ginger-dipping-sauce", "title": "Soy Ginger Dipping Sauce", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["½ Cup Soy Sauce", "¼ Cup Rice wine vinegar", "2 Tablespoons Fresh Ginger, finely minced", "2 Garlic cloves, minced", "2 teaspoon sugar", "1 teaspoon sesame oil", "2 teaspoon sesame seeds"], "instructions": "Add all the ingredients to a jar and top with a lid. Shake well to combine and let rest for at least one hour to have the flavors combine.", "image": "img/soy-ginger-dipping-sauce.jpg"}, {"slug": "soy-ginger-salmon-serves-4", "title": "Soy Ginger Salmon", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1lb Salmon filet, with skin", "1/3 cup light brown sugar", "2 tsp lemon pepper", "1 tsp garlic powder", "1/3 cup soy sauce", "1 tbsp extra virgin olive oil", "1 tbsp grated fresh ginger", "1/3 cup orange juice", "**Preheat the broiler**"], "instructions": "Rub the salmon with 1 tbsp of brown sugar. Lightly sprinkle the salmon with 1 tsp of lemon pepper and 1 tsp of garlic powder and rub the seasonings into the fish.\nIn a small saucepan, over medium heat, cook the soy sauce, olive oil, ginger, remaining brown sugar, lemon pepper and garlic powder. Bring to a gentle simmer stirring constantly until the sugar has dissolved. Remove from the heat and stir in the orange juice.\nPlace the fish and the marinade in a large zip loc bag or a large casserole dish that can be covered, and refrigerate for at least 3 hours.\nPlace the fish on a foil baking sheet (reserving the marinade) skin side up. Broil for 2 minutes. Remove from the oven and pull the skin off and baste with the marinade.\nReturn the fish to the oven and broil for another 2 minutes. Turn the fish and broil until the fish flakes easily (about 4 minutes more).\nRemove from the oven and let stand for 5 minutes before serving.", "image": "img/soy-ginger-salmon-serves-4.jpg"}, {"slug": "spaghetti-squash-gratin-serves-8", "title": "Spaghetti Squash Gratin", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["1 3lb spaghetti squash", "1 tbsp extra virgin olive oil", "1 medium Vidalia onion, finely chopped", "2 garlic cloves, minced", "salt and pepper to taste", "3 large eggs, beaten", "½ cup 1% milk", "2 tbsp chopped fresh basil", "2 oz Gruyere cheese, grated ( ½ cup)", "2 tbsp freshly grated Parmesan cheese", "**Preheat the oven to 375°**"], "instructions": "Pierce the squash several times with a sharp knife. Place in a foil baking pan or on a cookie sheet covered in foil. Bake for 1 hour, turning the squash every 20 minutes. Remove from the heat(the squash should be soft and easy to cut)and allow to cool so you can handle it.\nCut the squash in half lengthwise and cool a little longer. Remove the seeds and discard. Rake the pulp with a fork and place in a large bowl. Chop the spaghetti strands coarsely. Measure out 4 cups for the gratin.\nGrease a 2qt baking dish and set aside. Heat the olive oil over medium heat and add the onion. Cook, stirring often until tender. Add the garlic and a ¼ tsp of salt. Cook for another minute and add the squash. Cook, stirring often for about 5 minutes or until the squash is a little more tender.\nSeason with salt and pepper to taste. Remove from the heat.\nIn a large bowl, beat the eggs, and add the milk, ½ tsp salt, ½ tsp pepper and the basil. Stir in the squash mixture and the Gruyere cheese. Blend well.\nPlace the squash mixture into the prepared baking dish and top with the Parmesan cheese. Gently press the cheese down to moisten.\nBake for 40-45 minutes until golden brown and bubbly. Remove from the heat and cool for 10-15 minutes before serving.", "image": "img/spaghetti-squash-gratin-serves-8.jpg"}, {"slug": "spaghetti-squash-with-roasted-shrimp-serves-3", "title": "Spaghetti Squash with Roasted Shrimp", "serves": "Serves 3", "category": "", "date": "2022-02-28", "ingredients": ["1 large spaghetti squash", "Kosher salt", "Freshly ground pepper", "1lb large shrimp, peeled and deveined", "2 tbsp extra virgin olive oil", "juice of 1 lemon", "2 tbsp fresh parsley, chopped", "Preheat the oven to 375°"], "instructions": "Cut the squash lengthwise and remove the seeds. Season with the salt and pepper. Place cut side down in a large glass baking dish and add ¾ cup of water. Roast for approximately 45 minutes. Skin should be tender when pierced with a knife.\nIn a large bowl, toss the shrimp with 1 tbsp of olive oil and season with salt and pepper.\nWhen there is about 15 minutes left on the squash, place the shrimp on a baking sheet and roast for 10-15 minutes.\nScrape the flesh of the squash with a fork and place the \"spaghetti\" in a large serving bowl. Add the shrimp and cooking juices, the lemon juice and 1 tbsp of olive oil. Toss to combine.\nSeason with salt and pepper and top with the parsley. Serve with lemon wedges if desired.\nNet Carbs per serving: 16.9", "image": "https://static.wixstatic.com/media/75d545_12e9948efc334ace827cb0ced6ca97ec~mv2.jpg"}, {"slug": "spaghetti-squash-with-sweet-sausage-peppers-serves-6", "title": "Spaghetti Squash with Sweet Sausage & Peppers", "serves": "Serves 6", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1 large spaghetti squash", "6 sweet sausage, cut into bite sized pieces", "2 green bell peppers, diced", "½ red onion diced", "3 garlic cloves, minced", "2 14.5oz Muir Glen diced tomatoes, undrained", "2 tsp fresh oregano, minced", "2 tsp fresh basil, minced", "½ tsp salt", "½ tsp fresh ground pepper", "1 cup shredded Parmesan cheese", "**Preheat the oven to 375°**"], "instructions": "Grease a 13 x 9 baking dish or large casserole dish and set aside.\nPierce the spaghetti squash with a knife and place in a baking dish. Bake for 1 hour. Remove from the oven and cool to the point of being able to handle. Remove the seeds and then shred the pulp with a fork, creating strands that resemble spaghetti.\nReduce the oven temperature to 350°.\nWhile the squash is cooking, cook the sausage in a large skillet over medium heat until no longer pink. Add the peppers, onion and garlic and cook until the vegetables are tender.\nAdd the squash, tomatoes, basil, oregano, salt and pepper and heat through. Remove from the heat and drain the excess liquid. Mix in ¾ cup of the Parmesan cheese and transfer the mixture to the prepared baking dish.\nBake uncovered for 30 minutes. Top with remaining cheese for the last 5 minutes of baking.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "spaghetti-with-shrimp-sauce", "title": "Spaghetti with Shrimp Sauce", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["3 tbsp extra virgin olive oil", "1 small onion, chopped", "1lb of shrimp or lobster, cleaned and shelled", "1/3 cup white wine", "10oz plum tomatoes, peeled and chopped", "salt and pepper, to taste", "1lb spaghetti", "1 tbsp chopped fresh Italian parsley"], "instructions": "In a large pot boil water (salted).\nIn a large skillet heat the olive oil over low heat and add the onion; sauté until translucent.\nAdd the shrimp or lobster, raise the heat to medium and cook stirring constantly for 2 minutes. Add the wine and cook until it evaporates, about another 2 minutes. Add the tomatoes and season to taste. Cook for another 2 minutes.\nMeanwhile cook the spaghetti until almost al dente. Drain and transfer to the skillet and add the parsley. Cook over medium heat stirring frequently for another 2 minutes. Serve.", "image": "img/spaghetti-with-shrimp-sauce.jpg"}, {"slug": "spanakopita-artichoke-dip-serves-8", "title": "Spanakopita & Artichoke Dip", "serves": "Serves 8", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["2 tbsp extra virgin olive oil", "6 green onions, chopped", "1 clove of garlic, minced", "6 oz baby spinach, torn", "¼ cup fresh dill, finely chopped", "14 oz small artichoke hearts, drained", "6 oz cream cheese, softened", "¼ cup light mayonnaise", "¼ light sour cream", "8 oz feta cheese, crumbled", "1 cup shredded mozzarella cheese", "Sriracha sauce", "Salt and pepper to taste", "**Preheat oven to 425º**"], "instructions": "Spray a medium baking dish with olive oil spray and set aside.\nIn a large pan over medium heat, heat the olive oil and add the green onions. Cook for 2-3 minutes, stirring often.\nAdd the spinach and heat until just wilted, again stirring often.\nAdd the garlic and cook for an additional 30 seconds or until the garlic is fragrant. Remove from the heat.\nDrain any excess liquid from the pan, if any.\nRemove excess liquid from the surface of the artichokes with a paper towel and chop.\nIn a large bowl. Combine the spinach mixture, artichoke, dill, cream cheese, sour cream, mayonnaise, ½ of the feta and 2/3 of the mozzarella cheese. Add the sriracha sauce and salt & pepper to taste.\nSpread the mixture into your prepared baking dish and top with the remaining mozzarella and feta. Bake for 20-25 minutes or until the top starts to brown.\nServe with vegetables, and pita chips.", "image": "img/spanakopita-artichoke-dip-serves-8.jpg"}, {"slug": "sparkling-cranberry-bites-makes-16-20", "title": "Sparkling Cranberry Bites", "serves": "Makes 16-20", "category": "", "date": "2022-02-28", "ingredients": ["2 cups fresh cranberries", "1 cup pure maple syrup", "1 cup sugar", "16-20 Butter crisp crackers", "8oz Brie, sliced", "raspberry jam", "fresh mint leaves"], "instructions": "Rinse the cranberries, sort through and remove any soft wilted berries. Place the cranberries in a medium bowl.\nHeat the maple syrup in a small saucepan over medium low heat just until warm.\nPour the warm syrup over the cranberries. (if the syrup is too hot the cranberries will pop and ruin the result). Cool, cover and refrigerate. (overnight preferably) 4-6 hours minimum.\nDrain the cranberries. Place the sugar in a shallow bowl and roll the cranberries in the sugar, a few at at time. Place the sugared cranberries on a baking sheet to dry. About an hour.\nAssemble the crackers with 1 slice of brie, a tsp or so of raspberry jam, 3 cranberries and a mint leaf(I use just the tip of the leaf and tuck it under a cranberry)", "image": "https://static.wixstatic.com/media/75d545_5c4b72231d7342c797dab30c0d966745~mv2.jpg"}, {"slug": "spicy-beef-mushrooms-in-a-pita-serves-4", "title": "Spicy Beef & Mushrooms in a Pita", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1 tbsp vegetable oil", "¼ cup chopped walnuts", "1 lb 90% ground beef", "1 medium onion diced", "¼ lb mushrooms, sliced", "1 16oz can diced tomatoes, undrained", "1 tsp sugar", "½ tsp crushed red pepper", "¼ tsp salt", "4 large lettuce leaves", "2 6” pitas"], "instructions": "In a large skillet heat the vegetable oil over medium high heat. Cook the walnuts until golden (3-5 minutes) drain on a paper towel.\nIn the same skillet, over medium high heat, cook the ground beef and onion until all the pan juices evaporate, breaking up the ground beef into small pieces.\nAdd the mushrooms, tomatoes, sugar, crushed pepper and salt. Heat to a boiling and reduce the heat to medium low; cook uncovered for 10 minutes.\nCut the 2 pitas in half stuff with a lettuce leaf and add the spicy beef mixture. Top with with the walnuts and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "spicy-fried-rice-serves-8", "title": "Spicy Fried Rice", "serves": "Serves 8", "category": "Pasta, Rice & Beans", "date": "2022-02-28", "ingredients": ["1 tsp sesame oil", "1 tbsp extra virgin olive oil", "¾ cup shredded carrots", "1 ½ jalapeño, seeded and chopped", "4 green onions, sliced", "4 cloves garlic, minced", "1 tbsp fresh grated ginger or ¼ tsp ground", "4 cups cooked, cooled brown rice", "3 tbsp Mirin", "3 tbsp soy sauce", "1 tsp crushed red pepper flakes", "sea salt and pepper to taste", "3 tbsp chopped fresh parsley"], "instructions": "Heat the oils in a large sauté pan over medium high heat. Add the carrots, jalapeños, green onions and garlic. Sauté for 1 minute.\nAdd the brown rice and stir to combine. Sauté for 4 to 5 minutes. Rice should begin to brown.\nAdd the Mirin and the soy sauce. Stir. Add the pepper flakes and season with the salt and pepper to taste.\nRemove from the heat and add the parsley. Serve.", "image": "img/spicy-fried-rice-serves-8.jpg"}, {"slug": "spicy-grilled-salmon-serves-8", "title": "Spicy Grilled Salmon", "serves": "Serves 8", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["8 (4oz) salmon fillets", "½ cup peanut oil", "4tbsp soy sauce", "4tbsp balsamic vinegar", "5tbsp scallions, chopped", "3tsp brown sugar", "2 cloves of garlic, minced", "1 ½ tsp ground ginger", "2tsp crushed red pepper flakes", "1tsp sesame oil ½ tsp salt"], "instructions": "Place the salmon in a ziploc bag or glass dish.\nIn a medium bowl combine the remaining ingredients with a whisk and pour over the fish. Marinate in the refrigerator for 4-6 hours.\nGrill over medium heat for about 10 minutes per inch of thickness, turning once half way through cooking.", "image": "img/spicy-grilled-salmon-serves-8.jpg"}, {"slug": "spinach-balls", "title": "Spinach Balls", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["2 10oz packages of frozen chopped spinach", "2 cups herb stuffing, firmly crushed", "1 cup Parmesan cheese", "½ cup melted butter", "2 medium onions, finely chopped", "3 eggs", "dash of nutmeg"], "instructions": "Preheat the oven to 350°\nCook the spinach according to the package directions and drain well.\nCombine the spinach and all the other ingredients. Shape into 1” balls.\nYou may freeze the spinach balls at this point for later use.\nBake for 10-15 minutes and serve with a [hot mustard sauce](https://www.mymomshomecooking.com/post/hot-mustard-sauce-makes-2-cups).", "image": "img/spinach-balls.jpg"}, {"slug": "spinach-basil-pasta-salad-serves-10", "title": "Spinach Basil Pasta Salad", "serves": "Serves 10", "category": "Salads", "date": "2022-02-28", "ingredients": ["1lb Farfalle pasta", "12 oz of fresh baby spinach", "2 cups fresh basil leaves", "½ cup extra virgin olive oil", "3 cloves garlic, minced", "6 oz sliced prosciutto, shredded into bite size pieces", "salt and pepper to taste", "¾ cup freshly grated parmesan cheese", "½ cup toasted pine nuts"], "instructions": "Cook the pasta according to the package directions for al dente. Rinse with cold water, drain and set aside.\nIn a large bowl toss the spinach and basil together and set aside.\nHeat the olive oil in a large skillet over medium heat. Add the garlic and cook for about a minute. Stir in the prosciutto and cook, stirring constantly for 2 to 3 minutes. Remove the pan from the heat.\nAdd the spinach and basil to the skillet and toss well. Add in the pasta and combine well. Season with the salt and pepper and sprinkle with the pine nuts and Parmesan; Toss well to combine all the ingredients.\nServe with warm crusty bread such as Sourdough.", "image": "https://static.wixstatic.com/media/75d545_d08ca4213d614c63a3d9746c517d0ec7~mv2.jpg"}, {"slug": "spinach-dip", "title": "Spinach Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 pkg Frozen chopped spinach", "1 16oz container of sour cream", "1 cup light mayonnaise", "1 medium onion, chopped fine", "1 box Knorr’s vegetable soup mix", "1 2ilb round loaf of pumpernickel", "1 loaf unsliced pumpernickel and rye"], "instructions": "Cook the spinach according to the package directions and drain VERY well.\nCombine the spinach with the next 4 ingredients and refrigerate until ready to use.\nHollow the round pumpernickel and fill it with the dip. Surround the loaf with pieces of the unsliced pumpernickel/rye loaf and serve", "image": "img/spinach-dip.jpg"}, {"slug": "spinach-feta-phyllo-serves-16", "title": "Spinach Feta Phyllo", "serves": "Serves 16", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["10 sheets frozen Phyllo dough", "2 10oz packages of frozen spinach, thawed and drained", "1 ½ cup finely chopped onion", "½ cup butter", "½ lb feta cheese, chopped", "4 eggs, beaten", "1 tsp dried dill", "½ tsp nutmeg", "½ cup fresh chopped parsley", "salt and fresh ground pepper", "1 cup sweet butter, melted"], "instructions": "Preheat the oven to 375°.\nRemove the Phyllo dough from the freezer and thaw to room temperature.\nBrown the onion in the ½ cup of butter and add all remaining ingredients except for the sweet butter. Stir to combine. And remove from the heat.\nUnroll the Phyllo dough and cover with a damp paper towel. Remove 1 sheet and brush with the melted butter. Fold it in thirds, lengthwise; brush the top with the butter. Place one end of the folded sheet in the center of a 12-14 inch pizza pan. Repeat with the remaining 9 sheets, arranging the strips in a spoke fashion evenly around the pan.\nSpread the spinach mixture in an 8” circle in the center of the pastry. Lift the end of the Phyllo strip and bring it forward to the center of the filling. Holding the end with both hands, twist the end several times; coil and tuck the end under to form a rosette. Lay the rosette over the filling, leaving a 3” circle of filling visible in the center. Repeat with the remaining strips.\nDrizzle the remaining butter over the entire pastry. Bake for 35-40 minutes or until golden. Cut into wedges and serve warm.", "image": "img/spinach-feta-phyllo-serves-16.jpg"}, {"slug": "sriracha-aoli", "title": "Sriracha Aioli", "serves": "", "category": "", "date": "2022-02-28", "ingredients": ["1 cup light mayonnaise", "2 tbsp Sriracha", "1 tsp smoked paprika", "1 clove garlic, finely minced", "zest of 1 lime", "juice of 1 lime", "pinch of salt"], "instructions": "In a small bowl combine all the ingredients and stir to combine.\nServe with burgers, fish tacos and French fries.", "image": "https://static.wixstatic.com/media/75d545_f5e8b70631824afa8092fe7d83206804~mv2.jpg"}, {"slug": "steam-baked-lobster-tails-serves-6", "title": "Steam-Baked Lobster Tails", "serves": "Serves 6", "category": "Seafood", "date": "2022-02-27", "ingredients": ["8 (6-8 ounce) lobster tails, thawed completely", "melted butter", "Kosher salt", "Cocktail Sauce", "Lemon wedges"], "instructions": "Preheat the oven to 400º F.\nWith a sharp pair of scissors cut the lobster tails in half and place in a large baking dish and brush the tail meat with melted butter.\nAdd 1 cup of water to the baking dish. Cover the dish with a piece of aluminum foil. Bake for about 10-12 minutes.\nFor larger tails, increase the baking time. A 10-12oz tail will take about 12-14 minutes and a 12-14oz tail will bake for approximately 14-16 minutes.\nRemove from the baking dish and place on a serving plate. Serve with lemon wedges, cocktail sauce and melted butter.", "image": "img/steam-baked-lobster-tails-serves-6.jpg"}, {"slug": "steamed-lobster-tails-serves-4", "title": "Steamed Lobster Tails", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1 tbsp sea salt", "4 (6oz) lobster tails", "½ cup butter, melted"], "instructions": "In a large pot, add 1” of water and bring to a boil. Add the salt and a steamer to the pot. The steamer should sit just above the water level.\nPut the tails in the steamer and cover the pot. Steam for 8 minutes. (16 minutes for 1lb tails). Don’t lift the cover to peek!\nServe with the melted butter.", "image": "img/steamed-lobster-tails-serves-4.jpg"}, {"slug": "stir-fried-chicken-in-a-pita-serves-4", "title": "Stir Fried Chicken in a Pita", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1lb thin chicken breast fillets", "¼ cup soy sauce", "2 tbsp cooking sherry", "1 tbsp cornstarch", "1 tsp sugar", "¼ tsp red pepper", "¼ tsp ground ginger", "1 small head of cabbage", "1 can sliced water chestnuts", "2 medium carrots", "¼ tsp salt", "vegetable oil", "4 6” pita pockets"], "instructions": "Cut the chicken into match stick size pieces. In a medium bowl combine the chicken and the next 6 ingredients. Set aside.\nCut the cabbage and carrots into matchstick size pieces.\nIn a large pot or wok over medium high heat, add 2 tbsp of vegetable oil and ¼ tsp salt. Stir fry the cabbage, carrots and water chestnuts until crisp tender, stirring frequently.\nRemove to a large bowl. Add 2 tbsp vegetable oil to the same pan and stir fry the chicken mixture until the meat is cooked and tender. Stirring frequently.\nWhile the chicken is cooking, cut the pitas in half and warm in the oven.\nWhen the chicken is done, add the vegetables back to the pan and mix. Stuff the warm pockets and serve.\nCan be served with the pitas on a platter and vegetable mixture in a bowl for serve yourself style.", "image": "https://static.wixstatic.com/media/75d545_41442e45b28e4bd38646ea1508199fd1~mv2.jpeg"}, {"slug": "strawberries-watercress-on-wheat-crackers", "title": "Strawberries & Watercress on Wheat Crackers", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 8oz package of cream cheese", "2 tbsp of orange marmalade", "1 cup of chopped fresh watercress", "18 medium fresh strawberries", "36 round wheat crackers"], "instructions": "In a small bowl combine the cream cheese, marmalade and the watercress and mix well. Cover and refrigerate until you are ready to serve.\nCut each strawberry in 1/2 lengthwise. Refrigerate the berries until you are ready to serve.\nJust before your guest arrive, spread the cheese mixture onto each cracker and top with a strawberry half (cut side down).\nDecorate each cracker with a small piece of watercress for a more professional\nlook.", "image": "https://static.wixstatic.com/media/75d545_8dd7639a0af34afeb62f8946ab3c7bfc~mv2.png"}, {"slug": "strawberry-brownie-torte-serves-8-10", "title": "Strawberry Brownie Torte", "serves": "Serves 8-10", "category": "Desserts", "date": "2022-02-28", "ingredients": ["1 family size fudge brownie mix", "1 (14oz) can sweetened condensed milk", "½ cup cold water", "1 4oz package instant vanilla pudding mix", "1 8oz container of Cool Whip", "1 quart fresh strawberries, cleaned and quartered", "Chocolate syrup", "**Preheat the oven to 350°**"], "instructions": "Grease 2 9\" round cake pans and line with wax paper extending up the sides of the pans. Spray the wax paper with butter cooking spray.\nPrepare the brownie mix as directed on the package for cake like brownies. Bake for 20 minutes or until the top springs back when touched. Cool.\nIn a large bowl mix the condensed milk and the water, beat in the pudding mix. Chill for 5 minutes.\nFold in 1 ¾ cup of whipped topping.\nPlace one brownie layer on a serving dish and top with ½ of the pudding mixture and ½ of the strawberries. Repeat the process. Drizzle with your favorite chocolate syrup.", "image": "img/strawberry-brownie-torte-serves-8-10.jpg"}, {"slug": "strawberry-tart", "title": "Strawberry Tart", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["1 sheet of refrigerated pie pastry", "4 oz German sweet chocolate, melted", "2 (8oz) pkg of cream cheese", "3 Tbsp heavy cream", "2 tsp vanilla extract", "1 ¾ cup confectioner’s sugar", "2 ½ cup sliced strawberries", "½ cup red currant jelly"], "instructions": "Press the pastry onto the bottom and up the sides of an ungreased 9” tart pan with a removable bottom.\nPlace on a baking sheet and bake at 350° for 10 minutes or until golden. Cool.\nMelt the chocolate in the microwave at 35 second intervals, stirring after each. Spread the melted chocolate on the bottom of the cooled crust and refrigerate for 5-10 minutes or until the chocolate is almost set.\nIn a large bowl beat the cream cheese, cream and vanilla until smooth. Gradually add the sugar. Spread over the chocolate layer. Arrange the strawberries over the filling in a decorative fashion and brush with the jelly. Cover and refrigerate for at least 2 hours.", "image": "https://static.wixstatic.com/media/75d545_14b21a31bc3349598ecc2da007d99b48~mv2.jpg"}, {"slug": "stuffed-tomatoes-serves-4", "title": "Stuffed Tomatoes", "serves": "Serves 4", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["8 medium ripe tomatoes", "olive oil cooking spray", "4 oz lean ground beef", "4 cloves garlic, sliced", "½ cup steamed brown rice", "1 oz grated parmesan or to taste", "1 small zucchini, grated", "salt and pepper to taste", "½ cup whole wheat panko bread crumbs"], "instructions": "Preheat the oven to 400°\nCut ½” off the top of the tomatoes and discard.\nUsing a melon baller, scoop out the core from the middle of the tomatoes, chop the pulp and set aside.\nSpray 6 seconds of cooking spray in a nonstick skillet; place over medium heat and add the beef. Cook until browned, about 4 minutes. Add the garlic and cook until golden brown, about 2 minutes.\nAdd the tomato pulp; cook until the liquid evaporates. Add the rice. Remove from the heat.\nAdd the next 2 ingredients and season with salt and pepper to taste.\nSeason the inside of the tomatoes with salt and pepper. Add the beef and tomato mixture to the seasoned tomatoes.\nIn a small bowl combine the panko and salt and pepper to taste. Sprinkle over the top of the tomatoes.\nPlace the tomatoes in a baking dish and bake until warmed and browned. About 8 minutes. Serve warm or cold.", "image": "img/stuffed-tomatoes-serves-4.jpg"}, {"slug": "sugar-free-chocolate-chip-cookies-makes-about-45", "title": "Sugar Free Chocolate Chip Cookies Makes About 45", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["2 ¼ cup flour", "1 tsp baking soda", "1 tsp salt", "1 cup butter, softened", "¾ cup Swerve granulated sugar replacement", "¾ cup Swerve brown sugar replacement", "2 eggs", "1 ½ tsp vanilla extract", "8-10 oz sugar free chocolate chips( Lily’s or Hershey’s)", "**Preheat the oven to 375°**"], "instructions": "Prepare a cookie sheet for nonstick, your favorite way.\nIn a medium bowl mix the flour, baking soda and salt and set aside.\nIn a large bowl, add the softened butter and sugars and mix until creamy and well blended. Add the eggs and vanilla and mix well.\nAdd the dry ingredients and chocolate chips. You can add more or less depending on your taste.\nSpoon the cookie batter onto the prepared baking sheet and cook for about 9 minutes or until they begin to brown.\nCool on a paper towel and enjoy!\n(About 5 net carbs per cookie.)", "image": "img/sugar-free-chocolate-chip-cookies-makes-about-45.jpg"}, {"slug": "sugar-free-chocolate-syrup-makes-1-5-cups", "title": "Sugar Free Chocolate Syrup", "serves": "Makes 1.5 cups", "category": "Desserts", "date": "2022-02-28", "ingredients": ["¾ cup unsweetened cocoa", "1/8 tsp cinnamon", "1 ¼ cup water", "1-2 tsp vanilla", "½ cup Stevia (artificial sweetener)"], "instructions": "In a small saucepan, combine the cocoa, cinnamon, and water with a small whisk. Stir and cook over medium heat until the mixture come to a boil.\nReduce the heat and gently boil for 5 minutes. Stir often. The mixture will become thick and smooth.\nCool slightly and add the vanilla to taste. Add the Stevia.\nPour into a container with a lid and refrigerate for up to 3 weeks.", "image": "img/sugar-free-chocolate-syrup-makes-1-5-cups.jpg"}, {"slug": "summer-beer-serves-4", "title": "Summer Beer", "serves": "Serves 4", "category": "Beverage", "date": "2022-02-28", "ingredients": ["4 cup ice cubes", "1 6oz frozen lemonade concentrate", "1 12oz bottle beer", "12 oz vodka"], "instructions": "In a blender crush the ice. Pour in the lemonade concentrate, beer and vodka. Blend until smooth. Pour into chilled glasses and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "summer-corn-salad-serves-8", "title": "Summer Corn Salad", "serves": "Serves 8", "category": "Salads", "date": "2022-02-28", "ingredients": ["8 ears of Bi-color corn", "2 qts cherry tomatoes, halved", "3 tbsp of a good balsamic vinegar", "1 medium red onion, diced large", "1 qt sugar snap peas, cut in half or thirds depending on size", "Maldon sea salt(coarse salt)", "Freshly ground pepper"], "instructions": "With8 a sharp knife, strip the corn from the ears.\nIn a serving large bowl, combine the corn, tomatoes and sugar snap peas.\nAdd the vinegar and salt and pepper to taste. Toss to combine.\nChill and Serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "summer-pasta-serves-6", "title": "Summer Pasta", "serves": "Serves 6", "category": "Pasta, Rice & Beans", "date": "2022-02-28", "ingredients": ["1 16oz package of linguini", "6 plum tomatoes, chopped", "1lb shredded mozzarella cheese", "½ tsp garlic salt", "ground black pepper to taste", "1/3 cup chopped fresh basil", "6 cloves garlic, minced", "½ cup extra virgin olive oil"], "instructions": "Combine the tomatoes, cheese, basil, garlic, olive oil, garlic salt and black pepper in a large bowl.\nMeanwhile cook the pasta according to the package directions. Drain and transfer to a large serving bowl and toss with the tomato mixture.\nServe with fish or chicken and warm crusty bread.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "sun-dried-tomato-spinach-and-salmon-serves-4", "title": "Sun-dried Tomato, Spinach and Salmon", "serves": "Serves 4", "category": "Main Dish", "date": "2022-03-05", "ingredients": ["4 salmon filets, skin removed", "3 tsp olive oil", "3 tbsp butter", "6 cloves garlic, minced", "½ cup finely chopped onion", "7 oz jar julienne sun-dried tomato in oil, drained", "2/3 cup vegetable broth", "2 cups heavy cream", "5 cups baby spinach", "¾ cup freshly grated parmesan cheese", "2 tbsp fresh parsley, chopped", "Salt & pepper to taste"], "instructions": "Season both sides of the salmon filets with salt and pepper to taste.\nIn a large skillet over medium high heat, heat the olive oil and cook the salmon for about 4 minutes per side or until desired temperature. Remove from the pan and set aside.\nIn the same skillet, melt the butter and add the garlic. Cook just until fragrant and add the sun-dried tomatoes. Stir and cook for about 2 minutes.\nAdd the vegetable broth and cook until the liquid has reduced slightly. Reduce the heat to low.\nAdd the heavy cream and season with salt and pepper to taste. Cook, stirring often, for about 1o minutes.\nAdd the spinach and stir until just wilted. Add in the parmesan cheese. Stir until the cheeses has melted.\nPlace the salmon filets back in the skillet and spoon the sauce over the tops. Sprinkle with the chopped parsley and serve.\nServe over pasta or rice.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "sweet-potato-casserole-serves-8", "title": "Sweet Potato Casserole", "serves": "Serves 8", "category": "Potato", "date": "2022-03-01", "ingredients": ["4 large sweet potatoes", "½ cup sugar", "1/2 cup butter, melted", "1 tbsp vanilla extract", "1 tsp kosher salt", "2 large eggs", "**Topping**", "½ cup flour", "1 cup packed brown sugar", "½ cup butter, melted", "1 cup chopped pecans", "**Preheat oven to 425º**"], "instructions": "Prick the sweet potatoes all over with a fork and bake for 30 minutes. Turn the potatoes and bake for another 30 minutes. A fork should easily penetrate the skin and the potato should feel soft. Remove from the oven and let cool to the touch.\n**Reduce the oven temperature to 375º.**\nButter a 2qt casserole dish and set aside.\nScoop the insides of the potato into a large bowl and add the sugar, salt vanilla, eggs and melted butter. Beat with an electric mixer for about 4 minutes or until fluffy.\nPour the sweet potato mixture into the prepared casserole and bake for 25 minutes.\nIn a small bowl mix the topping ingredients until crumbs form.\nSprinkle the sweet potatoes with the topping and bake for an additional 15 minutes.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "sweet-soy-glaze", "title": "Sweet Soy Glaze", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2023-07-04", "ingredients": ["2/3 cup light brown sugar", "½ cup soy sauce", "1/3 cup sugar", "¼ cup water", "2 tbsp white wine vinegar", "2 tsp rice vinegar", "1 tsp ground ginger"], "instructions": "Combine all of the ingredients in a medium saucepan over medium high heat and stir to combine.\nBring the mixture to a simmer and lower the heat to medium low heat. Let the mixture simmer for 30 minutes and then remove from the heat.\nAllow to cool for an hour to thicken. At this point it can be used immediately or saved in the refrigerator as an ingredient in other recipes.", "image": "https://static.wixstatic.com/media/75d545_6afcb2d6c97c431d87a00e40305658bc~mv2.png"}, {"slug": "taco-dip-serves-20", "title": "Taco Dip", "serves": "Serves 20", "category": "", "date": "2022-02-28", "ingredients": ["2 16oz cans refried beans", "2 avocados, peeled and pitted", "1 4oz can chopped jalapeno peppers", "1 envelope taco seasoning", "2tbsp fresh lemon juice", "½ cup fresh salsa", "1 small jar salsa", "1 ½ cup sour cream", "3 cups shredded lettuce", "1 ½ cup grated cheddar cheese"], "instructions": "Sliced black olives, to taste\nMix the refried beans, jalapenos and taco seasoning in a medium bowl. Spread on a platter.\nBlend the avocados, lemon juice and fresh salsa. Spread on top of the beans.\nSpread the sour cream on the top of the avocado mixture. Add a layer of shredded lettuce, cheddar cheese and jar of salsa. Top with black olives.\nServe with tortilla chips.", "image": "img/taco-dip-serves-20.jpg"}, {"slug": "taco-stuffed-shells-serves-6-8", "title": "Taco Stuffed Shells", "serves": "Serves 6-8", "category": "", "date": "2022-03-01", "ingredients": ["2 tbsp vegetable oil", "1 large Vidalia onion, diced", "2 large red bell pepper, chopped", "2 lb lean ground beef", "2 package Taco seasoning", "2 15 oz can of black beans, rinsed and drained", "4 cups of shredded Mexican cheese", "3 cup frozen corn, thawed", "½ cup green onion diced", "1 box jumbo pasta shells, cooked according to package directions", "Sliced green onion for garnish, optional"], "instructions": "**Preheat oven to 350º**\nSpray (2)13 x 9 baking dishes with cooking spray.\nIn a large skillet over medium high heat, heat the oil and add the onion and pepper; cook until the pepper is tender.\nAdd the beef and taco seasoning and cook until the beef is no longer pink, breaking it up as it cooks.\nRemove from the heat and add the beans, 2 cups of cheese, corn and green onions.\nFill each pasta shell with the beef mixture and place in the prepared casserole dish. 1 layer per casserole.\nSprinkle with the remaining cheese, cover and bake for 15 minutes.\nUncover and bake until golden brown, about another 5 minutes.\nGarnish and serve.", "image": "https://static.wixstatic.com/media/75d545_2ab1e7362c2e4b91aa37715e6804c6e2~mv2.jpeg"}, {"slug": "tgi-friday-copycat-jack-daniels-sauce", "title": "TGI Friday Copycat Jack Daniels Sauce", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-03-03", "ingredients": ["1 tbsp extra virgin olive oil", "2/3 cup water", "1 cup pineapple juice (preferably fresh)", "¼ cup teriyaki sauce", "1 tbsp soy sauce", "1 1/3 cup dark brown sugar", "1 tbsp minced fresh garlic", "3 tbsp freshly squeezed lemon juice", "3 tbsp chopped Vidalia onion", "1 tbsp Jack Daniels whiskey", "1 tbsp crushed pineapple (preferably fresh)", "¼ tsp cayenne pepper"], "instructions": "In a medium sauce pot, over medium high heat, mix the water, pineapple juice, teriyaki, soy sauce and brown sugar. Bring the mixture to a boil and stir occasionally. Reduce the heat to simmer.\nAdd the garlic, onion, lemon juice, whiskey, crushed pineapple and pepper. Let the sauce simmer for 40-50 minutes or until reduced by half and thick.\nGreat on fish, chicken or beef.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "tgi-friday-s-vanilla-bean-cheesecake", "title": "TGI Friday’s Vanilla Bean Cheesecake", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["**Crust**:", "1 ½ cup graham cracker crumbs", "¼ cup sugar", "½ cup butter, melted", "1 egg yolk, beaten", "¼ tsp vanilla"], "instructions": "Preheat the oven to 375°.\nIn a large bowl combine the graham cracker crumbs and sugar. Add the egg yolk and vanilla, then stir in the melted butter.\nLine a spring form pan with non stick foil and press the graham cracker mixture into the pan. Bake for 8 minutes or until the edges are golden brown. Remove from the oven and cool.\n**Cheesecake**:\nReduce the oven to 350°.\n2 8oz packages cream cheese, softened\n1 cup sour cream\n2 tbsp corn starch\n1 cup sugar\n2 tbsp butter, softened\n½ tsp vanilla\nvanilla beans, from 1 pod\nIn a large bowl, combine the cream cheese, sour cream corn starch and sugar until the sugar is dissolved. Add the butter, vanilla and beans. Blend until smooth.\nAdd to the crust and bake on a cookie sheet with about ½ “ of water in it. Bake for 30-35 minutes. Cool for 1 hour.\n**White Chocolate Mousse**:\n1 cup heavy cream\n2 tbsp confectioner’s sugar\n4 oz cream cheese\n4 oz white chocolate baking squares, melted\nIn a cold mixing bowl beat the cream until soft peaks form. Gradually add the sugar until stiff peaks form. Put the mixture in another bowl and then refrigerate. Do not clean the bowl you just used!\nIn the same mixing bowl from the cream, beat the cream cheese until fluffy. Add the white chocolate and beat until smooth.\nFold in the whipped topping. Spread the mousse on top of the cooled cheesecake. Refrigerate.\n**Vanilla Bean Whipped Cream**:\n1 cup heavy cream\n1 tbsp confectioner’s sugar\nvanilla beans, from 1 pod\nIn a cold mixing bowl, beat the cream until soft peaks form. Gradually add the sugar, vanilla and beans and beat until stiff peaks form. Refrigerate for 1 hour then spread on top of the cheesecake.\nThis cheesecake should be refrigerated for several hours before serving.", "image": "img/tgi-friday-s-vanilla-bean-cheesecake.jpg"}, {"slug": "thin-sliced-chicken-cutlets-with-bacon-and-sherry-cream-sauce", "title": "Thin Sliced Chicken Cutlets with Bacon and Sherry Cream Sauce", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["3 tbsp Olive Oil, separated", "4Tbs Butter, separated", "4 tbs. real bacon pieces (I like Hormel in jar)", "½ cup finely chopped shallots", "½ cup flour for dredging", "½ tsp onion powder", "½ tsp paprika", "1 ½ lbs. skinless, boneless, thin chicken cutlets", "Salt", "Ground Pepper", "¾ cup dry sherry", "1/4 cup heavy cream", "1 tbsp chopped fresh parsley"], "instructions": "Heat 2 tbsp. olive oil and 2 tbsp. butter in a large skillet on medium high heat. Add the chopped shallots and cook until translucent and very lightly browned. Add in the bacon pieces, stir and sauté, lowering heat to medium. Cook a minute or two. Remove the shallots and bacon pieces from the pan and put in bowl aside, leaving some of the fat in the pan.\nCombine the flour, salt, pepper, onion powder, and paprika on a shallow plate for dredging. Lightly dredge the cutlets in the flour mixture.\nAdd two additional tablespoons butter to skillet and one tablespoon olive oil to the remaining fat in the skillet from earlier. Add the cutlets and cook until golden brown on both sides. If necessary add more olive oil to the pan. Transfer cooked cutlets to a plate and set aside.\nDeglaze the skillet with the sherry, scraping up any browned bits that may have accumulated at the bottom. Let the sherry boil for a minute then stir in the cream. Let it boil until the sauce thickens, just a minute or two. Add the shallots and bacon pieces back to the skillet. Return the chicken cutlets to the pan and turn to coat each side of cutlets with the creamy Sherry sauce.\nSprinkle evenly with freshly chopped parsley.", "image": "img/thin-sliced-chicken-cutlets-with-bacon-and-sherry-cream-sauce.jpg"}, {"slug": "tomato-basil-crab-bisque-serves-6", "title": "Tomato Basil Crab Bisque", "serves": "Serves 6", "category": "Soup & Sandwiches", "date": "2022-02-28", "ingredients": ["2 cups chicken broth", "1 can (14.5oz) fire roasted diced tomatoes", "½ cup celery, finely diced", "¼ cup thinly sliced green onions (white part only)", "6 tbsp butter", "2tbsp flour", "2 ½ cup half and half", "¼ cup white wine", "½ tsp salt", "¼ tsp black pepper", "12oz lump crabmeat", "2tbsp chopped fresh basil"], "instructions": "Ina medium saucepan, cook the broth, tomatoes, celery and onions over medium high heat until the celery becomes tender.\nIn a large saucepan, melt the butter over low heat. Stir in the flour using a whisk. Cook for 1 minute stirring constantly Stir in the half and half, stirring constantly. Gradually add the tomato mixture, (1 cup at a time) stirring until blended after each addition.\nAdd the wine, salt and pepper. Heat the soup to a boiling over medium high heat. Reduce the heat to low and add the crabmeat and basil.\nCover and simmer of 30 minutes; stirring often.\nServe with warm corn bread.", "image": "img/tomato-basil-crab-bisque-serves-6.jpg"}, {"slug": "tomato-cheese-crostini", "title": "Tomato-Cheese Crostini", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 french bread baguette", "3 tbsp extra virgin olive oil", "8 oz goat cheese with herbs", "3/4 cup of ricotta cheese", "2 cups of finely shredded mozzarella cheese", "1 clove of garlic, minced", "Julienne sundried tomatoes"], "instructions": "Preheat the oven to 300°\nSlice the bread into ¼” slices. Brush the top of each slice with the olive oil and place on a baking sheet. Bake for approximately 12 minutes or until golden brown.\nIncrease the oven temperature to 350°\nMix the goat cheese, ricotta cheese, mozzarella and the garlic with a dash of black pepper in a bowl.\nSpread the cheese mixture on each bread slice, being careful not to break them. Top each with a piece or two of the julienne tomatoes.\nBake for 3 minutes or until the cheese begins to melt.", "image": "https://static.wixstatic.com/media/75d545_f4df68f96b3b4fdf9dad92d8bcee6171~mv2.jpeg"}, {"slug": "tomato-onion-salad-serves-4", "title": "Tomato Onion Salad", "serves": "Serves 4", "category": "Salads", "date": "2022-02-28", "ingredients": ["¾ lb plum tomatoes, quartered lengthwise", "½ small red onion, thinly sliced", "2tbsp chopped fresh basil or 2tsp dried basil", "2tbsp red wine vinegar", "2tbsp extra virgin olive oil", "1 clove garlic, minced", "1/8 tsp freshly ground black pepper"], "instructions": "In a medium bowl, combine the all the ingredients, tossing well to coat. Refrigerate.\nToss the salad just before serving.", "image": "img/tomato-onion-salad-serves-4.jpg"}, {"slug": "tomato-pasta-toss-serves-6", "title": "Tomato Pasta Toss", "serves": "Serves 6", "category": "Pasta, Rice & Beans", "date": "2022-02-28", "ingredients": ["4 ½ cup uncooked Farfelle", "3 medium tomatoes, chopped", "3 clove garlic, minced", "3 tsp extra virgin olive oil", "salt and pepper to taste", "6 tbsp grated parmesan cheese or ½ cup shaved"], "instructions": "Cook the pasta according to the package directions.\nIn a large serving bowl, combine the tomato, garlic, oil, salt and pepper.\nDrain the pasta and add to the tomato mixture. Sprinkle with the parmesan and toss. Serve immediately.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "tortellini-pest-salad", "title": "Tortellini & Pest Salad", "serves": "", "category": "Pasta, Rice & Beans", "date": "2022-02-28", "ingredients": ["1 9oz pkg of refrigerated Tortellini", "½ cup of prepared pesto", "4oz mozzarella cheese, cubed(should get a cup)", "3 large Roma tomatoes, chopped"], "instructions": "Cook the tortellini, drain and rinse with cold water.\nIn a large bowl combine all the ingredients and refrigerate for several hours.\nServe.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "turkey-stuffing-bundles", "title": "Turkey Stuffing Bundles", "serves": "", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["1 package Pepperidge farm frozen puff pastry sheets (2 sheets)", "2 cups cubed cooked turkey or chicken if you prefer", "½ cup cooked vegetable (peas, corn, green beans or carrots)", "1 (12oz) jar Pepperidge Farm gravy", "2 cups prepared Pepperidge Farm stuffing", "½ cup jellied cranberry sauce"], "instructions": "Thaw the pastry sheets at room temperature for 30 minutes.\n**Preheat the oven to 400°**\nIn a medium bowl, mix the turkey, vegetable and ½ cup of the gravy and set aside.\nUnfold the pastry sheets on a lightly floured surface and roll into 14\" squares. Cut each into four 7\" squares.\nPlace ¼ cup of stuffing in the center of each square. Top with about 1/3 cup of the vegetable mixture and 2 tbsp of the cranberry sauce.\nBrush the edges of the pastry squares with water and fold corners to center on top of the filling. Pinch the edges to seal.\nBake for 25 minutes or until golden brown.\nServe with gravy and cranberry sauce.", "image": "img/turkey-stuffing-bundles.jpg"}, {"slug": "turnip-fries", "title": "Turnip Fries", "serves": "", "category": "Vegetable", "date": "2022-02-28", "ingredients": ["3lbs of turnips", "2tbsp vegetable oil", "1/2 cup grated Parmesan cheese", "2 tsp garlic salt", "1 tsp paprika", "1 tsp onion powder"], "instructions": "Preheat the oven to 425°\nLightly grease a foil baking sheet.\nPeel the turnips and cut into French fry sized sticks. Place in a large bowl and toss with the oil until evenly coated.\nIn a large ziploc bag mix the Parmesan, garlic salt, paprika and onion powder.\nPlace the cut turnips in the bag and shake to coat. Spread out onto the prepared baking sheet.\nBake until the outside of the turnip is crispy. About 20-30 minutes.\nLow carb alternative to French fries.", "image": "https://static.wixstatic.com/media/75d545_e70c03c968b74291af609783a2cb3047~mv2.jpg"}, {"slug": "tuscan-herb-butter", "title": "Tuscan Herb Butter", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2023-06-26", "ingredients": ["1 cup unsalted butter", "4 sundried tomatoes, finely chopped", "¼ cup grated parmesan cheese", "2 tbsp chopped basil", "1 large garlic clove, grated", "1 tsp kosher salt", "Freshly ground pepper"], "instructions": "In a medium bowl, using a hand mixer, mix the butter until it has a whipped consistency. Combine all other ingredients in a smaller bowl and fold the mixture into the butter.\nTransfer to a small serving bowl and serve or save for use in cooking.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "tuscan-spinach-dip-copycat-t-g-i-friday", "title": "Tuscan Spinach Dip copycat T.G.I Friday", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["10 oz pkg. frozen chopped spinach, thawed", "6.5 oz jar artichoke hearts, rinsed and chopped", "extra virgin olive oil", "1 tbsp diced onion", "1 tbsp diced red bell pepper", "2 cloves garlic, minced", "4 oz cream cheese, softened", "½ cup shredded Parmesan cheese", "¼ cup shredded Romano cheese", "1/3 cup heavy cream", "¼ tsp salt", "1/8 tsp ground black pepper", "2 dashes hot sauce", "Diced tomato", "Shredded Parmesan cheese", "Minced parsley"], "instructions": "Sauté the onion and red bell pepper in a small amount of olive oil until the onion is almost translucent. Add garlic and sauté about 30 minutes, stirring constantly. Remove from the heat and set aside.\nSqueeze the excess water from the thawed spinach. In a saucepan, combine the heavy cream, salt and pepper. Add the sautéed onion mixture and the spinach and heat over very low heat.\nCut the cream cheese in cubes and add to the saucepan. Stir until smooth. Add the Parmesan and Romano cheese and stir to combine.\nPlace the chopped artichokes in a small microwaveable bowl and microwave on high just until warm. Drain and add to the saucepan.\nAdd the hot sauce. Heat the mixture until hot.\nPlace the mixture in a serving bowl and garnish with shr", "image": "img/tuscan-spinach-dip-copycat-t-g-i-friday.jpg"}, {"slug": "tuscan-spinach-salmon", "title": "Tuscan Spinach Salmon", "serves": "", "category": "Main Dish", "date": "2022-03-03", "ingredients": ["1 lb Salmon filets, skin removed", "2 tbsp olive oil", "1 tbsp butter", "1 tsp smoked paprika", "Kosher salt & fresh ground pepper, to taste", "1 tsp Italian seasoning", "1 small Vidalia onion, chopped", "4 cloves garlic, grated", "1 pint cherry tomatoes, halved", "6 oz fresh baby spinach", "½ cup fresh basil, chopped", "¼ cup chicken stock", "¼ cup dry white wine", "2 tbsp extra virgin olive oil"], "instructions": "In a small bowl, combine the paprika and Italian seasoning.\nSeason both sides of the salmon filets with salt, pepper and paprika seasoning.\nIn a large skillet, heat the olive oil over medium low heat.\nAdd the salmon filets to the pan and cook on both sides for 3-5 minutes per side over medium heat.\nRemove the salmon filets to a plate and set aside.\nIn the same pan, over medium heat, melt 1 tbsp butter and cook the garlic and onion until the onion is translucent.\nAdd the tomatoes, basil, spinach, wine and chicken stock. Continue to cook until the spinach is JUST wilted. Season with salt & pepper to taste.\nAdd the salmon back to the skillet and drizzle with olive oil and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "twice-baked-potatoes-serves-8", "title": "Twice Baked Potatoes", "serves": "Serves 8", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["6 large baking potatoes (you will need more potato than skins)", "1 stick of butter, divided", "milk"], "instructions": "Preheat the oven to 425°\nWash the potatoes and prick all over with a fork.\nPlace on the rack in the oven and bake for 1 hour or until a fork is easily inserted into the center.\nWhile still hot, slice the potatoes in half and scoop the potato into a bowl. Be careful not to damage the skin. Leave a thin layer of potato in the skin.\nAdd half of the butter and enough milk to mash the potatoes into a creamy but not soupy consistency.\nMelt the other half of the butter in the microwave and with a basting brush, baste the inside and outside of the skins.\nPlace the skins open side down in a baking dish and bake for about 10- 15 minutes to crisp them up.\nReduce the oven temperature to 350°\nStuff the 8 skins with the mashed potatoes and either save for later, or bake for 15-20 minutes to warm them up. If saving for later, heat in a 350° oven for ½ hour.\nTop with shredded cheddar, Paprika or add some broccoli and American cheese.", "image": "https://static.wixstatic.com/media/75d545_b36f72c9e9e64796b17d6c8687d6565b~mv2.jpg"}, {"slug": "vanilla-mousse-cheesecake-serves-16", "title": "Vanilla Mousse Cheesecake", "serves": "Serves 16", "category": "Desserts", "date": "2022-02-28", "ingredients": ["40 Nabisco Nilla wafers, crushed", "3 tbsp butter, melted", "4(8oz) packages of cream cheese, softened", "1 cup sugar", "4 tsp vanilla extract", "3 eggs", "1(8oz) tub of Cool Whip", "**Preheat the oven to 325°**"], "instructions": "In a medium bowl mix together the wafer crumbs and the butter and press onto the bottom of a 9\" spring form pan.\nIn a large bowl beat 3 packages of the cream cheese with ¾ cup sugar and 1 tbsp of vanilla until well blended.\nAdd the eggs 1 at a time mixing on low speed until blended. Pour the mixture over the crust.\nBake for 50-55 minutes or until the center is almost set. Run a knife around the rim of the pan to loosen the cake. Cool completely.\nIn another large bowl beat the remaining cream cheese, sugar and vanilla until well blended. Whisk in the Cool Whip and spread over the cooled cheesecake. Refrigerate for at least 4 hours.", "image": "img/vanilla-mousse-cheesecake-serves-16.jpg"}, {"slug": "vegetable-shooters", "title": "Vegetable Shooters", "serves": "", "category": "Appetizers & Dips", "date": "2022-03-01", "ingredients": ["Favorite Hummus or Tzatziki dip", "Cucumber", "Celery stalks", "Carrot sticks", "Green beans", "Snap peas", "Grape tomatoes"], "instructions": "Add about a tablespoon of dip to the bottom of a shot glass.\nUsing bamboo skewers, thread 2 or 3 vegetables and stand in the glass. Arrange a few small celery and carrot sticks behind the skewer. Arrange the shot glasses on a serving tray and serve.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "veggie-cheese-dip", "title": "Veggie Cheese Dip", "serves": "", "category": "Appetizers & Dips", "date": "2022-02-28", "ingredients": ["1 tbsp vegetable oil", "2 cups cherry tomatoes, quartered", "1 ½ cup fresh baby spinach, chopped", "½ cup diced green bell pepper", "½ cup diced red onion", "2 ½ cup button mushrooms, cut into small chunks", "1 cup fresh sweet corn(you may use frozen if you have to)", "1 15.5oz jar of Tostitos brand reduced fat zesty cheese dip", "1 tbsp fresh parsley, chopped"], "instructions": "Heat the oil in a nonstick pan over medium high heat and add the tomatoes, pepper, onion, spinach, mushrooms and corn. Cook the vegetables for about 4 minutes.\nRemove the vegetables from the pan into a heat ceramic or glass bowl. Add the cheese and the parsley and combine well. Serve in this bowl or pour into a serving. Serve while hot with chips or fresh vegetables for dipping.", "image": "img/veggie-cheese-dip.jpg"}, {"slug": "vinaigrette-about-cup", "title": "Vinaigrette About ¼ cup", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["3 tbsp extra virgin olive oil", "2 tbsp white vinegar (wine vinegar or cider vinegar can also be used)", "salt & pepper to taste"], "instructions": "Whisk together and let stand for 10 minutes.", "image": "img/vinaigrette-about-cup.jpg"}, {"slug": "warm-kale-caesar-salad-serves-2-4", "title": "Warm Kale Caesar Salad", "serves": "Serves 2-4", "category": "Salads", "date": "2022-02-28", "ingredients": ["Topping", "2 tbsp extra virgin olive oil", "1 tbsp unsalted butter", "½ cup panko", "1 garlic clove, grated", "1/3 cup freshly grated Parmesan", "Dressing", "2 tbsp mayonnaise", "1 garlic clove grated", "1 tsp anchovy paste (add more if you like)", "1 tsp Worcestershire sauce", "¼ tsp Kosher salt", "freshly ground black pepper, to taste", "3 tbsp extra virgin olive oil", "6-8 cups chopped Kale", "1 tbsp extra virgin olive oil"], "instructions": "In a medium pan, over medium heat, prepare the topping by adding the 2 tbsp of EVOO and the 1 tbsp of butter. Add the garlic and saute´ until fragrant. Add the panko and stir until a light golden brown color. Remove from heat and place on a paper towel to remove excess oil.\nTo make the dressing, use a medium bowl and add all the dressing ingredients. Whisk briskly to emulsify.\nIn the same medium pan heat 1 tbsp of EVOO, add the kale and saute´ until wilted. Remove from heat.\nAdd the dressing to the kale and toss to coat. Remove to plates or serving bowl.\nPlace the Panko in a bowl and add the grated Parmesan, toss to combine.\nAdd the topping to the salad and serve.", "image": "img/warm-kale-caesar-salad-serves-2-4.jpg"}, {"slug": "wasabi-panko-salmon-with-orange-ginger-sauce-serves-4-recipe-by-emeril-lagasse", "title": "Wasabi Panko Salmon with Orange-Ginger Sauce Serves 4(recipe by Emeril Lagasse)", "serves": "Serves 4", "category": "Main Dish", "date": "2022-02-28", "ingredients": ["2 tbsp wasabi powder", "2 tbsp water", "2 tbsp rice wine vinegar", "½ tsp soy sauce", "4 salmon fillets, no skin", "1 tsp Essence, recipe below", "1 ½ cup panko crumbs", "¼ cup vegetable oil", "Orange Ginger Sauce, recipe below", "¼ cup toasted black and white sesame seeds, optional", "**Essence**", "2 ½ tbsp. paprika", "2 tbsp salt", "2 tbsp garlic powder", "1 tbsp black pepper", "1 tbsp onion powder", "1 tbsp cayenne pepper", "1 tbsp dried oregano", "1 tbsp dried thyme"], "instructions": "In a small plastic container mix all the above ingredients. Cover with a lid and keep with your spices.\n**Orange Ginger Sauce**\n¼ cup minced shallots\n1 tbsp minced fresh ginger\n2 tbsp orange zest\n1 cup white wine\n1 cup fresh orange juice\n½ cup heavy cream\n2 sticks cold unsalted butter, cut into pieces\n1 tsp soy sauce\nsalt\n1/8 tsp wasabi powder", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "whipped-cream-16-servings", "title": "Whipped Cream 16 Servings", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["1 cup heavy whipping cream", "3tbsp confectioner’s sugar", "1tsp vanilla extract"], "instructions": "Place a medium glass bowl and beaters in the freezer while gathering your ingredients. Remove the bowl & beaters from the freezer and beat the whipping cream until it begins to thicken. Add the confectioner’s sugar and vanilla; beat until soft peaks form. Store in the refrigerator or serve immediately. (I prefer to make the whipped cream right before I need it)", "image": "img/whipped-cream-16-servings.jpg"}, {"slug": "white-bean-turkey-chili", "title": "White Bean & Turkey Chili", "serves": "", "category": "Casserole", "date": "2022-02-28", "ingredients": ["4 tbsp vegetable oil", "2lb lean ground turkey (Butterball suggested)", "3 cloves of garlic, minced", "1 medium Poblano pepper, small diced", "1 large Vidalia onion, diced", "1 tsp oregano", "1 ½ tsp ground cumin", "¾ tsp ground black pepper", "½ tsp salt", "1 ½ tsp chili powder", "¼ cup flour", "3 cups Progresso chicken broth", "5 plum tomatoes, diced", "1 12oz bag frozen shoepeg corn", "5 15.5 oz cans Northern White Beans, drained and rinsed", "sour cream", "Fresh cilantro, minced for garnish"], "instructions": "In a 5qt pot, add 2 tbsp of vegetable oil and cook the turkey; breaking into small pieces as it browns. Remove from heat.\nIn a medium sauté pan add the remaining vegetable oil and cook the garlic, onion and pepper until the onion is translucent. Add to the turkey in the 5qt pot.\nReturn the pot to low-medium heat and add the next 6 ingredients and combine well.\nAdd the chicken broth and stir to combine. Stir in the corn, tomato and the beans.\nCover and cook on low for about an hour or until the chili has thickened; stirring often.\nServe with a dollop of sour cream and garnish with fresh cilantro.\nGreat with warm bread of your choice.", "image": "img/white-bean-turkey-chili.jpg"}, {"slug": "white-cheddar-havarti-mac-n-cheese", "title": "White Cheddar & Havarti Mac-n-Cheese", "serves": "", "category": "Pasta, Rice & Beans", "date": "2022-02-28", "ingredients": ["1/2 c. butter (melted)", "1/2 c. flour", "4 c. milk", "1/4 c. cream cheese", "1/2 tsp salt", "1/4 tsp pepper (white pepper if you prefer)", "1 c. Havarti cheese (shredded)", "1 c. sharp white cheddar (shredded)", "6 c. macaroni noodles (cooked)", "~", "**Toasted Bread Crumbs:**", "1/4 c. butter (melted)", "1 c. panko breadcrumbs", "1 green onion", "pinch of salt", "small handful of finely chopped parsley"], "instructions": "(Simply stir everything together and toast slightly in a non-stick pan for a minute or two. Set aside for later use.)\n~\n**Instructions:**\nNow that the bread crumbs are finished, you can go ahead and start making your sauce.\nPop the first six ingredients into your blender, and give it a whiz. Now, pour it into a large pot and set to medium-low heat.\nOnce the milk mixture is warm, stir in your shredded cheese and test to see if you need more salt. Continue to cook for about 10 minutes, stirring occasionally until the sauce has thickened.\nPour the sauce over the macaroni noodles, and give it a stir. I like to serve this in individual bowls, garnished with the toasted bread", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "white-cheddar-mashed-potatoes", "title": "White cheddar Mashed Potatoes", "serves": "", "category": "Potato", "date": "2022-02-28", "ingredients": ["2lbs small red potatoes", "1 tsp salt", "6oz shredded White cheddar cheese(you can use Jack cheese instead)", "4oz *garlic butter", "2/3 cup heavy cream", "2 tsp fresh parsley, chopped"], "instructions": "Wash the potatoes. Fill a large pot with water and add the tsp of salt. Add the potatoes and bring to a boil. Cook for 5-10 minutes or until the potatoes are tender. Drain.\nPut the potatoes back in the pot after draining or in a mixing bowl and add the cheese, cream, garlic butter, salt and pepper. Add more seasoning to taste if you wish.\nMash until smooth.\n***Garlic Butter**\nSauté 1 tsp minced garlic in 1 tbsp extra virgin olive oil for about 2 minutes or just until softened. Do not brown. Mix with 4oz of room temperature butter and add 2 tsp of parsley.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "white-chocolate-cheesecake-serves-8", "title": "White Chocolate Cheesecake", "serves": "Serves 8", "category": "Desserts", "date": "2022-02-28", "ingredients": ["1 ¼ cup chocolate wafer crumbs", "1/3 cup butter, melted", "½ cup sugar, divided", "2 4oz package premium white chocolate(1 for the garnish)", "2 8oz packages of cream cheese", "2 eggs", "1 tsp vanilla", "2 tbsp vegetable shortening(for the garnish recipe)", "white chocolate wedges for garnish(recipe follows)", "fresh raspberries for garnish"], "instructions": "Preheat the oven to 375°\n**Cheesecake**\nIn a small bowl combine the chocolate wafer crumbs, butter and ¼ cup of sugar. Press the mixture into a 9” pie plate and refrigerate.\nMelt 1 package of white chocolate over hot(not boiling) water.\nIn a large bowl, combine the cream cheese and the remaining ¼ cup of sugar with an electric mixer until smooth. Add the eggs 1 at a time, beating well after each. Blend in the melted chocolate and the vanilla.\nPour the cream cheese mixture into the prepared crust.\nBake for 30 minutes or until the edges are very lightly browned. Cool completely. Place in the refrigerator.\nPrior to serving garnish with the white chocolate wedges and raspberries.\n**White chocolate wedges**\nMelt 1 package of white chocolate over hot not boiling water with 2 tbsp vegetable shortening. Stir until smooth. Spread the mixture into a waxed paper lined 8” round cake pan. Refrigerate until softly set but not hard. With a sharp knife score the circle into 8-10 wedges; Loosen the circle from the edge of the pan and refrigerate until firm. About 20 minutes. Remove the wedges from the pan and use as your garnish.", "image": "img/white-chocolate-cheesecake-serves-8.jpg"}, {"slug": "white-chocolate-craisin-cookies", "title": "White Chocolate Craisin Cookies", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["Preheat the oven to 350°.", "3 cup flour", "1tsp baking soda", "¾ tsp salt", "1 cup unsalted butter", "1 cup light brown sugar, packed", "¾ cup sugar", "2 eggs", "1tbsp vanilla extract", "1 cup craisins", "1 ½ cup white chocolate chips", "1 cup chopped macadamia nuts"], "instructions": "Line a cookie sheet with parchment paper.\nCream the butter and sugars together until fluffy. Beat in the eggs and the vanilla. Set aside.\nIn another bowl combine the flour, baking soda and salt.\nAdd the flour mixture to the butter and sugar a cup at a time, blending well after each addition. Add the craisins, white chocolate chips and macadamias. Mix well.\nUsing heaping spoonfuls place the dough on the cookie sheet and bake for 11-15 minutes.", "image": "https://static.wixstatic.com/media/75d545_8b921e44cd524e0d890107751e04ae6b~mv2.jpg"}, {"slug": "white-chocolate-mousse-pie", "title": "White Chocolate Mousse Pie", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["13 Oreo cookies, ground", "3 tbsp unsalted butter, melted", "17 vanilla and chocolate Milano cookies", "1 ¼ tsp unflavored gelatin", "1 ¼ cup heavy cream", "4oz cream cheese, softened", "12oz white chocolate, chopped", "1 tsp vanilla extract"], "instructions": "Set aside 1 tbsp of ground Oreos for garnish.\nIn a medium bowl, stir together the remaining ground Oreos and the butter until well combined.\nPress the mixture into the bottom of a 9\" pie plate. Arrange the Milanos around the edge alternating the chocolate and the vanilla facing out.\nIn a small glass bowl, sprinkle the gelatin over ¼ cup of the cream and let stand for 5 minutes to soften.\nIn a small saucepan combine the cream cheese, white chocolate and the gelatin mixture. Heat over medium low heat for 6 minutes, stirring constantly until smooth. Remove from the heat and stir in the vanilla.\nPour the mixture into a large bowl and place over an ice bath. Stir until thickened and cooled.\nWhip the remaining 1 cup of cream in a large bowl until soft peaks form. Fold the whipped cream (1/3 at a time)into the white chocolate mixture until combined.\nSpoon the mixture into the prepared crust and refrigerate for at least 3 hours.\nGarnish with a mound of Cool whip or fresh whipped cream in the center of the pie. Top the whipped cream with fresh cut strawberries and the reserved Oreo crumbs.", "image": "img/white-chocolate-mousse-pie.jpg"}, {"slug": "white-chocolate-raspberry-cheesecake", "title": "White Chocolate Raspberry Cheesecake", "serves": "", "category": "Desserts", "date": "2022-03-01", "ingredients": ["2 cup graham cracker crumbs", "3 tbsp sugar", "½ cup butter, melted", "5 (8) oz packages of cream cheese", "1 cup sugar", "2 large eggs", "1 tbsp vanilla extract", "12 oz white chocolate, melted and cooled slightly", "¾ cup raspberry preserves (seedless if possible)", "Fresh raspberries for garnish", "Preheat oven to 350º"], "instructions": "Grease a 9” springform pan.\nCombine the first 3 ingredients in a medium bowl and press into the bottom of the prepared pan. Bake for 8 minutes. Cool slightly.\nIn a large bowl, beat the cream cheese with an electric mixer on medium speed until creamy. Gradually add 1 cup of sugar and add the eggs 1 at a time, beating after each addition.\nStir in the vanilla and the melted chocolate, making sure to fully blend.\nMicrowave the preserves in a small bowl on high for 30 seconds to 1 minute until melted.\nSpoon ½ of the cream cheese filling into the crust and then evenly spread ½ of the preserves over the batter. Leave about a ¾” border around the edge of the cheesecake.\nSpoon the remaining batter around the edges of the pan, spreading the batter toward the center.\nCover the remaining preserves and refrigerate for later.\nBake the cheesecake for 50 minutes or until it is just set and slightly browned.\nRemove from the oven and cool completely. Cover and chill for at least 8 hrs.\nRun a knife around the edge of the pan and release the sides.\nBefore serving:\nReheat the remaining preserves to melt and pour over the top of the cheesecake. Garnish with fresh raspberries and serve.\n*If the preserves have seeds, press them through a fine wire mesh strainer using the back of a spoon.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "white-sangria", "title": "White Sangria", "serves": "", "category": "Beverage", "date": "2022-02-28", "ingredients": ["1 bottle (750ml) dry white wine", "¼ cup light rum", "3 tbsp elderflower liqueur", "2 tbsp sugar", "2 sliced nectarines", "2 sliced plums", "1 ½ cup seltzer"], "instructions": "Mix together in a pitcher and serve!", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "white-trash-candy", "title": "White Trash Candy", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["2 cups mini pretzels", "1 cup rice cereal squares", "1 cup golden grahams", "2 cups peanuts(optional)", "2 12oz bags white chocolate"], "instructions": "Mix all the crunchy ingredients in a large bowl. Separate the mixture into 2 equal portions.\nMelt one bag of chocolate until smooth in the microwave. Pour over one portion and stir to coat the cereal evenly. Spread onto a piece of wax paper in a 1” layer. Repeat the process with the second batch.\nAfter about 10 minutes break the layer into bite sized pieces and serve.", "image": "img/white-trash-candy.jpg"}, {"slug": "white-velvet-cake", "title": "White Velvet Cake", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["_Cake_ 1 (6-ounce) package white chocolate baking bars, broken into small pieces 2 tablespoons milk 2 cups all-purpose flour 3/4 teaspoon baking soda 1/2 teaspoon salt 1/4 teaspoon baking powder 1/2 cup (1 stick) butter, softened 3/4 cup sugar 1 teaspoon vanilla extract 4 eggs 1 cup sour cream"], "instructions": "_Frosting_ 1 cup butter, softened 2 cups confectioners' sugar 6 ounces white chocolate or 6 ounces white baking bar, melted and cooled 3-5 tablespoons whipping cream or 3-5 tablespoons half-and-half\nPreheat oven to 350 degrees F. Lightly grease two (8-inch) round baking pans with cooking spray, then line bottoms with waxed paper.\nIn a medium saucepan, combine white chocolate and milk over low heat, stirring constantly until chocolate is melted and mixture is smooth. Set aside.\nCombine flour, baking soda, salt, and baking powder in a medium bowl and set aside. In a large bowl, beat butter and sugar until light and fluffy. Blend in melted baking bars and vanilla extract. Add eggs one at a time, beating well after each addition. Add flour mixture alternately with sour cream. Pour into prepared pans.\nBake 30 to 35 minutes or until a tester inserted in center comes out clean. Cool 10 to 15 minutes, then remove from pans and peel off waxed paper. Place in a wire rack to cool completely.\nTo make the white chocolate butter cream frosting, combine the butter and confectioners sugar in a large bowl and beat at low speed until fluffy. Add in melted white chocolate and whipping cream, 3 tablespoons at a time and add in more to achieve desired consistency. Beat on high speed for 3-4 minutes, scraping the bowl with a spatula. Spread frosting on top and sides of the cooled White Velvet Cake.", "image": "img/white-velvet-cake.jpg"}, {"slug": "white-wine-cake", "title": "White Wine Cake", "serves": "", "category": "Desserts", "date": "2022-02-28", "ingredients": ["1 (15.25oz) box moist white cake mix, plus 1/3 cup of cake flour or cake mix", "1 (5oz) box instant vanilla pudding mix", "1 tsp ground nutmeg", "¾ cup vegetable oil", "¾ cup white wine", "4 eggs", "**Preheat the oven to 350°**", "Grease and flour a 10\" fluted cake pan. Set aside"], "instructions": "In a large bowl combine the cake mix, the 1/3 cup of flour or mix, instant pudding mix, nutmeg, vegetable oil, white wine and eggs. Beat with an electric mixer for 4-5 minutes.\nPour into the prepared cake pan and bake for 50 minutes or until a toothpick inserted in the center comes out clean.\nLet the cake cool in the pan for 10 minutes and remove to a wire rack to cool completely.\nGarnish with confectioner's sugar. Serve with fresh strawberries and whipped cream if desired.", "image": "img/white-wine-cake.jpg"}, {"slug": "white-wine-gravy", "title": "White Wine Gravy", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-02-28", "ingredients": ["1 large onion, finely chopped", "1 ½ cup white wine", "5 cups of either turkey or chicken stock", "1/3 cup flour"], "instructions": "Skim fat from the pan juices and reserve ½ cup.\nOn top of the stove, deglaze the pan with the wine over medium high heat. Stirring to scrap up the brown bits on the bottom of the pan. Boil until reduced to ½ cup.\nAdd 4 cups of stock to the pan and simmer. Pour the mixture into a sieve over a medium/large saucepot.\nIn a large skillet over medium/high heat, sauté the onion in ¼ cup of the reserved fat. Stir often until lightly browned.\nStir in the flour and cook over low heat for 2-3 minutes. Add the wine mixture all at once, whisking constantly to prevent lumps.\nSimmer, stirring occasionally for 10-15 minutes. Use the remaining stock to thin the gravy if needed. Add salt and pepper to taste.", "image": "img/white-wine-gravy.jpg"}, {"slug": "white-wine-turkey-gravy", "title": "White Wine Turkey Gravy", "serves": "", "category": "Gravy, Sauce & Dressing", "date": "2022-03-03", "ingredients": ["4 tbsp flour", "5 tbsp lukewarm water", "3 ½ cup turkey stock", "¾ cup white wine", "Salt & pepper to taste"], "instructions": "In a 1 cup measuring cup or ramekin, mix the water and flour until smooth.\nPour the turkey stock to a large sauce pot and bring to a simmer.\nGradually add the flour mixture to the turkey stock with a whisk until fully incorporated.\nCook over medium heat, stirring often, until the stock has thickened.\nAdd the wine and cook for an additional 5-10 minutes.\nThe stock will thicken as it cooks.", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "zucchini-fritters-makes-8", "title": "Zucchini Fritters", "serves": "Makes 8", "category": "Side Dishes", "date": "2022-02-28", "ingredients": ["1lb zucchini, grated", "2 tsp sea salt", "2 eggs, beaten", "3 scallions, chopped", "4 cloves garlic, minced", "½ tsp baking powder", "¾ cup super fine almond flour", "½ cup shredded cheddar", "¼ cup extra virgin olive oil"], "instructions": "Place the grated zucchini in a colander, in the sink and sprinkle with the salt and mix. Let the zucchini stand for about 20 minutes and then squeeze out the excess water and transfer to a mixing bowl.\nAdd the eggs, scallions, cheese and garlic and mix.\nAdd the baking powder and flour to the zucchini and mix well.\nHeat the oil in a large pan over medium high heat and drop about ¼ cup full of the zucchini mixture into the pan; flatten slightly with the back of a large spoon or spatula.\nCook for about 5 minutes on the first side or until a deep golden brown. Flip and cook a few minutes longer. Drain on a paper towel and then move to a serving platter. You can keep them warm in the oven. Serve hot with your favorite dressing or topping.\nCalories 176 Carb 4g Fiber 1g", "image": "https://static.wixstatic.com/media/75d545_e31bff11b12f4586ae36dff50e306b2e~mv2.png"}, {"slug": "zucchini-parmesan-crisps", "title": "Zucchini Parmesan Crisps", "serves": "", "category": "", "date": "2022-02-28", "ingredients": ["Olive Oil cooking spray", "2 tbsp extra virgin olive oil", "½ cup Panko crumbs", "freshly ground black pepper", "2 medium zucchinis", "½ cup freshly grated Parmesan cheese", "¼ tsp salt"], "instructions": "Preheat the oven to 450°.\nCoat a baking sheet with the cooking spray.\nSlice the zucchini into ¼” slices.\nIn a medium bowl toss the zucchini with the olive oil until coated.\nIn a small bowl combine the Parmesan, bread crumbs, salt, and pepper to taste.\nDip each zucchini slice into the Parmesan mixture, pressing slightly to coat both sides. Place in a single layer on the baking sheet.\nBake until browned and crisp. Approximately 20 minutes.\nServe with Horseradish Aoli or your favorite dipping sauces.", "image": "img/zucchini-parmesan-crisps.jpg"}, {"slug": "zucchini-pie", "title": "Zucchini Pie", "serves": "", "category": "", "date": "2024-07-31", "ingredients": ["3 cups shredded zucchini ( 1 medium zucchini should do it)", "½ tsp salt", "4 eggs, lightly beaten", "1 cup Bisquik or Carbquik for low carb", "½ cup minced Vidalia onion", "1 stick butter, melted", "½ cup shredded white cheddar cheese", "½ cup freshly grated Parmesan cheese", "1 tsp chopped fresh rosemary", "1 tsp chopped parsley, fresh or freeze dried", "1/2 tsp fresh ground pepper", "**Preheat the oven to 350°**"], "instructions": "Grease a 9” pie plate and set aside.\nPlace the shredded zucchini in a small bowl and sprinkle with the salt. Toss and set aside for about 15 minutes.\nPlace the zucchini in a paper towel and compress to remove as much moisture as you can.\nIn a medium bowl combine the zucchini, eggs, baking mix, onion, butter, chesses, herbs and pepper. Spread the mixture into your prepared pie plate and bake for about 40 to 45 minutes.\nIf your pie begins to brown to quickly, lay a piece of foil over the top to prevent from burning and continue to bake until a knife inserted into the center comes out clean.", "image": "https://static.wixstatic.com/media/75d545_052b20a693574e9cb100c86d5dd31897~mv2.png"}, {"slug": "zuppa-toscana", "title": "Zuppa Toscana", "serves": "", "category": "Soup & Sandwiches", "date": "2022-02-28", "ingredients": ["1lb Italian sausage, ½ sweet ½ hot, skin removed", "3 medium potatoes, peeled and chopped", "½ large Vidalia onion, chopped", "¼ cup cooked and crumbled bacon", "4 cloves garlic, minced", "32oz chicken broth", "1 cup chopped kale", "1 cup heavy cream", "2 tbsp flour", "Salt and pepper", "cayenne"], "instructions": "Brown the sausage in a skillet, breaking it up(not too small) as it browns.\nPlace the cooked sausage, chicken broth, garlic, potatoes and onion in a crockpot and add just enough water to cover the ingredients. Cook on high for 4 hours (low for 6) until the potatoes are tender.\nWith 30 minutes left to cook, mix the flour with the cream, whisking to remove any lumps. Add to the soup.\nAdd the kale and the bacon and stir. Cook on high for 30 minutes or until the soup has thickened. Add the seasonings to taste.", "image": "img/zuppa-toscana.jpg"}];